namespace CodeBrix.Platform.TclTk._Tests //was previously: Eagle._Tests;
{
    /// <summary>
    /// This class provides a general-purpose test object used throughout the
    /// TclTk test suite.  It exercises a wide range of language and interop
    /// features -- including fields, properties, methods, events, indexers,
    /// operators, delegates, and disposal semantics -- so that the behavior of
    /// the script engine and its object subsystem can be verified.
    /// </summary>
    [ObjectId("e1257294-a012-4164-b0ea-3763dd06eec2")]
    public class Default : IMaybeDisposed, IDisposable
    {
        #region Private Constants
        //
        // HACK: This is purposely not read-only.
        //
        /// <summary>
        /// The name of the test command used to log package installation
        /// activity.
        /// </summary>
        private static string PkgInstallLogCommandName = "pkgInstallLog"; /* COMPAT: TclTk. */

        ///////////////////////////////////////////////////////////////////////////////////////////////

        //
        // HACK: These are purposely not read-only.
        //
        /// <summary>
        /// The regular expression used to match names consisting solely of
        /// acceptable characters.
        /// </summary>
        private static Regex GoodNameOnlyRegEx = RegExOps.Create(
            "^[A-Z][0-9A-Z_]*$", RegexOptions.IgnoreCase |
            RegexOptions.Compiled);

        ///////////////////////////////////////////////////////////////////////////////////////////////

        //
        // HACK: These are purposely not read-only.
        //
        /// <summary>
        /// The regular expression used to match acceptable names, including
        /// those containing periods.
        /// </summary>
        private static Regex GoodNameRegEx = RegExOps.Create(
            "^[A-Z][0-9A-Z\\._]*$", RegexOptions.IgnoreCase |
            RegexOptions.Compiled);

        /// <summary>
        /// The regular expression used to detect unacceptable name patterns.
        /// </summary>
        private static Regex BadNameRegEx = RegExOps.Create(
            "\\.\\.|\\.$");

        ///////////////////////////////////////////////////////////////////////////////////////////////

#if REMOTING
        /// <summary>
        /// The name of the remoting channel used for testing.
        /// </summary>
        private static readonly string RemotingChannelName = String.Empty;
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The name of the custom informational box used for testing.
        /// </summary>
        private static readonly string TestCustomInfoBoxName = "TestCustomInfo";

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The error message used when the object command is invoked with the
        /// wrong number of arguments.
        /// </summary>
        private static readonly string ObjectWrongNumArgs =
            "wrong # args: should be \"object ?options? member ?arg ...?\"";

        ///////////////////////////////////////////////////////////////////////////////////////////////

        //
        // HACK: These are purposely not read-only.
        //
#if DEBUGGER
        /// <summary>
        /// The script evaluated to trigger an emergency debugger break.
        /// </summary>
        private static string DebugEmergencyScript = "debug emergency now";

        /// <summary>
        /// The script evaluated to trigger a normal debugger break.
        /// </summary>
        private static string DebugBreakScript = "debug break";
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////////

#if SHELL
        /// <summary>
        /// The placeholder value used to represent an empty command line
        /// argument.
        /// </summary>
        private static readonly string EmptyArgument = "##empty##";
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////////

#if NETWORK
        //
        // HACK: These are purposely not read-only.
        //
        /// <summary>
        /// The security protocol value saved prior to modification, if any.
        /// </summary>
        private static SecurityProtocolType? SavedSecurityProtocol = null;

        /// <summary>
        /// The best available security protocol value, if any.
        /// </summary>
        private static SecurityProtocolType? BestSecurityProtocol = null;

        /// <summary>
        /// The security protocol bits to be masked off, if any.
        /// </summary>
        private static SecurityProtocolType? MaskOffSecurityProtocol = null;

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// When this is non-zero, no security protocol bits are masked off.
        /// </summary>
        private static bool NoMaskOffSecurityProtocol = false;

        /// <summary>
        /// When this is non-zero, security protocols considered broken are not
