#endif

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default exit code used when a fail-safe abort occurs.
        /// </summary>
        private const ExitCode DefaultFailSafeExitCode = ExitCode.FailSafe;

        /// <summary>
        /// The default format string used to build a fail-safe abort error
        /// message.
        /// </summary>
        private const string DefaultFailSafeErrorFormat = "FATAL abort due to fail-safe: {0}";

        /// <summary>
        /// The default trace category used when reporting a fail-safe abort.
        /// </summary>
        private const string DefaultFailSafeCategory = "Default";

        /// <summary>
        /// The default trace priority used when reporting a fail-safe abort.
        /// </summary>
        private const TracePriority DefaultFailSafePriority = TracePriority.FailSafeFatal;

        ///////////////////////////////////////////////////////////////////////////////////////////////

        //
        // HACK: These are purposely not read-only.
        //
        /// <summary>
        /// The exit code used when a fail-safe abort occurs.
