        /// <summary>
        /// The trace category used when reporting a fail-safe abort.
        /// </summary>
        private static string FailSafeCategory = DefaultFailSafeCategory;

        /// <summary>
        /// The trace priority used when reporting a fail-safe abort.
        /// </summary>
        private static TracePriority FailSafePriority = DefaultFailSafePriority;

        /// <summary>
        /// The number of fail-safe aborts that have occurred.
        /// </summary>
        private static int FailSafeCount = 0;
        #endregion

