        /// <summary>
        /// This delegate represents a method used to refresh the input, output,
        /// and error streams associated with an interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose streams are being refreshed.
        /// </param>
        /// <param name="channelType">
        /// The type of channel(s) to be refreshed.
        /// </param>
        /// <param name="force">
        /// Non-zero to force the streams to be refreshed even if they appear to
        /// be current.
        /// </param>
        /// <param name="strict">
        /// Non-zero to enable strict processing, where any error is considered
        /// fatal.
        /// </param>
        /// <param name="inputStream">
        /// Upon input, the current input stream; upon output, the refreshed
        /// input stream.
        /// </param>
        /// <param name="outputStream">
        /// Upon input, the current output stream; upon output, the refreshed
        /// output stream.
        /// </param>
        /// <param name="errorStream">
        /// Upon input, the current error stream; upon output, the refreshed
        /// error stream.
        /// </param>
        /// <param name="error">
        /// Upon failure, this parameter receives an error message that
        /// describes why the streams could not be refreshed.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        [ObjectId("d79b0f58-a2a6-4281-9987-97b2e613b181")]
        public delegate ReturnCode RefreshStreamsCallback(
            Interpreter interpreter, /* in */
            ChannelType channelType, /* in */
            bool force,              /* in */
            bool strict,             /* in */
            ref Stream inputStream,  /* in, out */
            ref Stream outputStream, /* in, out */
            ref Stream errorStream,  /* in, out */
            ref Result error         /* out */
        );
        #endregion

