        #region Public Static Methods
        #region Methods for AssemblyFilePluginNames
        /// <summary>
        /// This method loads the well-known assembly file plugin names from the
        /// specified assembly's embedded syntax data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="assembly">
        /// The assembly from which to load the plugin names; if null, the global
        /// assembly is used.
        /// </param>
        /// <param name="flags">
        /// The package-if-needed flags to use.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// The loaded assembly file plugin names, or null if they could not be
        /// loaded.
        /// </returns>
        public static AssemblyFilePluginNames TestGetAssemblyFilePluginNames(
            Interpreter interpreter,    /* in: NOT USED */
            Assembly assembly,          /* in */
            PackageIfNeededFlags flags, /* in: NOT USED */
            ref Result error            /* out */
            )
        {
            Stream stream = null;

            try
            {
                if (assembly == null)
                    assembly = GlobalState.GetAssembly();

                stream = RuntimeOps.GetStream(
                    assembly, FileNameOnly.WellKnownAssemblyFilePluginNames,
                    ref error);

                if (stream == null)
                    return null;

                using (StreamReader streamReader = new StreamReader(stream))
                {
                    SyntaxData data = null;

                    if (SyntaxOps.LoadData(
                            streamReader.ReadToEnd(), false, true,
                            ref data, ref error) != ReturnCode.Ok)
                    {
                        return null;
                    }

                    return data;
                }
            }
            catch (Exception e)
            {
                error = e;
                return null;
            }
            finally
            {
                if (stream != null)
                {
                    stream.Close();
                    stream = null;
                }
            }
        }

