        /// <summary>
        /// This method serves as a test parse data callback that writes the
        /// metadata and current row to the interpreter host.
        /// </summary>
        /// <param name="metadata">
        /// The metadata describing the parsed columns, if any.
        /// </param>
        /// <param name="row">
        /// The fields of the current row being parsed.
        /// </param>
        /// <param name="clientData">
        /// The extra data supplied to the parse operation; may be modified by
        /// the callback.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// True if the row was processed successfully; otherwise, false.
        /// </returns>
        public static bool TestParseDataCallback(
            IEnumerable<IPair<string>> metadata, /* in */
            IEnumerable<string> row,             /* in */
            ref IClientData clientData,          /* in, out */
            ref Result error                     /* out */
            )
        {
            Interpreter interpreter = Interpreter.GetActive();

            if (interpreter == null)
            {
                error = "invalid active interpreter";
                return false;
            }

            IHost host = interpreter.Host;

            if (host == null)
            {
                error = "interpreter host not available";
                return false;
            }

            string formatted = String.Format(
                "metadata = {0}, row = {1}", FormatOps.WrapOrNull(
                (metadata != null) ? new StringPairList(metadata) :
                null), FormatOps.WrapOrNull(row));

            return host.WriteLine(formatted);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method parses the specified text as delimited data, invoking the
        /// test parse data callback for each row.
        /// </summary>
        /// <param name="text">
        /// The text to parse as delimited data.
        /// </param>
        /// <param name="flags">
        /// The flags that control how the text is parsed.
        /// </param>
        /// <param name="clientData">
        /// The extra data to pass to the parse callback; may be modified during
        /// parsing.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestParseData(
            string text,                /* in */
            SyntaxDataFlags flags,      /* in */
            ref IClientData clientData, /* in */
            ref Result error            /* out */
            )
        {
            char[] commentChars = null;
            char[] lineChars = null;
            char[] fieldChars = null;
            char[] wrapChars = null;
            char[] escapeChars = null;

            if (!SyntaxOps.GetLoadChars( /* TODO: Rename "GetParseChars"? */
                    ref commentChars, ref lineChars, ref fieldChars,
                    ref wrapChars, ref escapeChars, ref error))
            {
                return ReturnCode.Error;
            }

            if (SyntaxOps.ParseData(
                    text, new StringDataRowCallback(TestParseDataCallback),
                    commentChars, lineChars, fieldChars, wrapChars, escapeChars,
                    flags, ref clientData, ref error) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            return ReturnCode.Ok;
        }

