        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method serves as a test execute callback that concatenates its
        /// arguments into a single string and returns it as the result.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data supplied when the callback was registered, if any.
        /// </param>
        /// <param name="arguments">
        /// The arguments passed to the callback.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the concatenated arguments; upon failure,
        /// receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAppendArgsExecuteCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* in, out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount < 1)
            {
                result = "wrong # args: should be \"appendArgs ?arg ...?\"";
                return ReturnCode.Error;
            }

            StringBuilder builder = StringBuilderFactory.Create();

            for (int index = 1; index < argumentCount; index++)
                builder.Append(arguments[index]);

            result = StringBuilderCache.GetStringAndRelease(ref builder);
            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method serves as a test execute callback that appends its
        /// arguments to a list and returns that list as the result.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data supplied when the callback was registered, if any.
        /// </param>
        /// <param name="arguments">
        /// The arguments passed to the callback.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the list of appended arguments; upon failure,
        /// receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestLappendArgsExecuteCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* in, out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount < 1)
            {
                result = "wrong # args: should be \"lappendArgs ?arg ...?\"";
                return ReturnCode.Error;
            }

            StringList list = new StringList();

            for (int index = 1; index < argumentCount; index++)
                list.Add(arguments[index]);

            result = list;
            return ReturnCode.Ok;
        }

