        /// <summary>
        /// This method registers the built-in test execute callbacks (for
        /// example, the append and lappend argument callbacks) on the
        /// interpreter, recording their tokens.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data to associate with the added callbacks, if any.
        /// </param>
        /// <param name="stopOnError">
        /// Non-zero to stop processing on the first error encountered.
        /// </param>
        /// <param name="tokens">
        /// Upon return, receives the tokens of the added callbacks.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddBuiltInExecuteCallbacks(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in: OPTIONAL */
            bool stopOnError,        /* in */
            ref LongList tokens,     /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            long token; /* REUSED */
            Result result; /* REUSED */

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback(
                    "appendArgs", new ExecuteCallback(
                    TestAppendArgsExecuteCallback),
                    clientData, ref token,
                    ref result) == ReturnCode.Ok)
            {
                if (tokens == null)
                    tokens = new LongList();

                tokens.Add(token);
            }
            else
            {
                if (result != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(result);
                }

                if (stopOnError)
                    return ReturnCode.Error;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback(
                    "lappendArgs", new ExecuteCallback(
                    TestLappendArgsExecuteCallback),
                    clientData, ref token,
                    ref result) == ReturnCode.Ok)
            {
                if (tokens == null)
                    tokens = new LongList();

                tokens.Add(token);
            }
            else
            {
                if (result != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(result);
                }

                if (stopOnError)
                    return ReturnCode.Error;
            }

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method scans the specified assembly for methods matching the
        /// execute callback signature and registers each one as an execute
        /// callback on the interpreter, recording their tokens.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="assembly">
        /// The assembly to scan for execute callback methods.
        /// </param>
        /// <param name="plugin">
        /// The plugin to associate with the added callbacks, if any.
        /// </param>
        /// <param name="clientData">
        /// The extra data to associate with the added callbacks, if any.
        /// </param>
        /// <param name="flags">
        /// The command flags to use for the added callbacks.
        /// </param>
        /// <param name="includePattern">
        /// A pattern that matching type names must satisfy to be included, if
        /// any.
        /// </param>
        /// <param name="excludePattern">
        /// A pattern that matching type names must not satisfy to be included,
        /// if any.
        /// </param>
        /// <param name="stopOnError">
        /// Non-zero to stop processing on the first error encountered.
        /// </param>
        /// <param name="tokens">
        /// Upon return, receives the tokens of the added callbacks.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddExecuteCallbacks(
            Interpreter interpreter, /* in */
            Assembly assembly,       /* in */
            IPlugin plugin,          /* in: OPTIONAL */
            IClientData clientData,  /* in: OPTIONAL */
            CommandFlags flags,      /* in */
            string includePattern,   /* in: OPTIONAL */
            string excludePattern,   /* in: OPTIONAL */
            bool stopOnError,        /* in */
            ref LongList tokens,     /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            if (assembly == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid assembly");
                return ReturnCode.Error;
            }

            BindingFlags bindingFlags = ObjectOps.GetBindingFlags(
                MetaBindingFlags.TransferHelper, true); /* STATIC */

            MethodInfo matchMethod = typeof(Default).GetMethod(
                "TestNopExecuteCallback", bindingFlags); /* SELF */

            if (matchMethod == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid match method");
                return ReturnCode.Error;
            }

            Type matchType = typeof(ExecuteCallback);

            try
            {
                Type[] types = assembly.GetTypes(); /* throw */

                foreach (Type type in types)
                {
                    if (type == null)
                        continue;

                    if (!type.IsClass)
                        continue;

                    string typeName = type.FullName;

                    if ((includePattern != null) && !StringOps.Match(
                            interpreter, MatchMode.Glob, typeName,
                            includePattern, false))
                    {
                        continue;
                    }

                    if ((excludePattern != null) && StringOps.Match(
                            interpreter, MatchMode.Glob, typeName,
                            excludePattern, false))
                    {
                        continue;
                    }

                    MethodInfo[] methodInfos = type.GetMethods(
                        bindingFlags);

                    if (methodInfos == null)
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(String.Format(
                            "could not query type {0} methods",
                            MarshalOps.GetErrorTypeName(type)));

                        if (stopOnError)
                            return ReturnCode.Error;
                        else
                            continue;
                    }

                    foreach (MethodInfo methodInfo in methodInfos)
                    {
                        if (methodInfo == null)
                            continue;

                        if (!MarshalOps.MatchReturnType(
                                methodInfo.ReturnType,
                                matchMethod.ReturnType,
                                false, true))
                        {
                            continue;
                        }

                        if (!MarshalOps.MatchParameterTypes(
                                methodInfo.GetParameters(),
                                matchMethod.GetParameters(),
                                false, true))
                        {
                            continue;
                        }

                        Delegate @delegate = null;

                        try
                        {
                            @delegate = Delegate.CreateDelegate(
                                matchType, methodInfo, true);
                        }
                        catch (Exception e)
                        {
                            /* IGNORED */
                            RuntimeOps.MaybeGrabExceptions(
                                e, VerboseExceptions, ref errors);

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }

                        if (@delegate == null)
                        {
                            if (errors == null)
                                errors = new ResultList();

                            errors.Add(String.Format(
                                "expected to create {0} delegate of {1}",
                                MarshalOps.GetErrorTypeName(matchType),
                                MarshalOps.GetErrorMemberName(methodInfo)));

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }

                        if (!(@delegate is ExecuteCallback))
                        {
                            if (errors == null)
                                errors = new ResultList();

                            errors.Add(String.Format(
                                "created delegate {0} not actually an {1}",
                                FormatOps.WrapOrNull(@delegate),
                                MarshalOps.GetErrorTypeName(matchType)));

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }

                        long token = 0;
                        Result result = null;

                        if (interpreter.AddExecuteCallback(
                                ScriptOps.MemberNameToEntityName(
                                    methodInfo.Name, false),
                                (ExecuteCallback)@delegate, clientData,
                                ref token, ref result) == ReturnCode.Ok)
                        {
                            if (tokens == null)
                                tokens = new LongList();

                            tokens.Add(token);
                        }
                        else
                        {
                            if (result != null)
                            {
                                if (errors == null)
                                    errors = new ResultList();

                                errors.Add(result);
                            }

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }
                    }
                }

                return ReturnCode.Ok;
            }
            catch (Exception e)
            {
                /* IGNORED */
                RuntimeOps.MaybeGrabExceptions(
                    e, VerboseExceptions, ref errors);

                return ReturnCode.Error;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        //
        // WARNING: Do not remove this.  It is the officially supported external
        //          entry-point that will be used in the future to enable script
        //          commands or sub-commands that are either experimental and/or
        //          officially unsupported, to the specified interpreter.
        //
        /// <summary>
        /// This method adds the officially unsupported command to the
        /// interpreter, if it is not already present, associating it with the
        /// core plugin.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data to associate with the added command, if any.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddUnsupportedCommands(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in: OPTIONAL */
            ref Result error         /* out */
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            IPlugin plugin = interpreter.GetCorePlugin(ref error);

            if (plugin == null)
                return ReturnCode.Error;

            if (interpreter.InternalDoesIExecuteExistViaResolvers(
                    "unsupported") != ReturnCode.Ok)
            {
                ICommand command = new Unsupported(
                    new CommandData("unsupported", null, null, null,
                    typeof(Unsupported).FullName, CommandFlags.None,
                    plugin, 0));

                long token = 0;

                if (interpreter.AddCommand(
                        command, clientData, ref token,
                        ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }

                if (token != 0)
                {
                    bool pluginHadTokens;
                    LongList tokens = plugin.CommandTokens;

                    if (tokens != null)
                    {
                        pluginHadTokens = true;
                    }
                    else
                    {
                        tokens = new LongList();
                        pluginHadTokens = false;
                    }

                    tokens.Add(token);

                    //
                    // HACK: Force the command tokens for the
                    //       isolated plugin to be updated.
                    //
                    // HACK: Also, update the plugin command
                    //       tokens if they were null.
                    //
                    if (!pluginHadTokens
#if ISOLATED_PLUGINS
                        || AppDomainOps.IsIsolated(plugin)
#endif
                        )
                    {
                        plugin.CommandTokens = tokens;
                    }
                }
            }

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method scans the specified assembly for command types and adds
        /// each matching command to the interpreter, recording their tokens.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="assembly">
        /// The assembly to scan for command types.
        /// </param>
        /// <param name="plugin">
        /// The plugin to associate with the added commands, if any.
        /// </param>
        /// <param name="clientData">
        /// The extra data to associate with the added commands, if any.
        /// </param>
        /// <param name="commandFlags">
        /// The command flags to use for the added commands.
        /// </param>
        /// <param name="includePattern">
        /// A pattern that matching type names must satisfy to be included, if
        /// any.
        /// </param>
        /// <param name="excludePattern">
        /// A pattern that matching type names must not satisfy to be included,
        /// if any.
        /// </param>
        /// <param name="stopOnError">
        /// Non-zero to stop processing on the first error encountered.
        /// </param>
        /// <param name="tokens">
        /// Upon return, receives the tokens of the added commands.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddCommands(
            Interpreter interpreter,   /* in */
            Assembly assembly,         /* in */
            IPlugin plugin,            /* in: OPTIONAL */
            IClientData clientData,    /* in: OPTIONAL */
            CommandFlags commandFlags, /* in */
            string includePattern,     /* in: OPTIONAL */
            string excludePattern,     /* in: OPTIONAL */
            bool stopOnError,          /* in */
            ref LongList tokens,       /* in, out */
            ref ResultList errors      /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            if (assembly == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid assembly");
                return ReturnCode.Error;
            }

            Type matchType = typeof(ICommand);
            string matchTypeName = matchType.FullName;

            try
            {
                Type[] types = assembly.GetTypes(); /* throw */

                foreach (Type type in types)
                {
                    if (type == null)
                        continue;

                    if (!type.IsClass)
                        continue;

                    if (type.GetInterface(
                            matchTypeName) == null)
                    {
                        continue;
                    }

                    CommandFlags typeFlags =
                        AttributeOps.GetCommandFlags(type);

                    if (FlagOps.HasFlags(
                            typeFlags, CommandFlags.Proxy, true))
                    {
                        continue;
                    }

                    string typeName = type.FullName;

                    if ((includePattern != null) && !StringOps.Match(
                            interpreter, MatchMode.Glob, typeName,
                            includePattern, false))
                    {
                        continue;
                    }

                    if ((excludePattern != null) && StringOps.Match(
                            interpreter, MatchMode.Glob, typeName,
                            excludePattern, false))
                    {
                        continue;
                    }

                    bool added = false;
                    object @object = null;

                    try
                    {
                        long token = 0;

                        ICommandData commandData = new CommandData(
                            ScriptOps.TypeNameToEntityName(type, false),
                            null, null, clientData, typeName, commandFlags,
                            plugin, token);

                        try
                        {
                            @object = Activator.CreateInstance(
                                type, commandData); /* throw */
                        }
                        catch (Exception e)
                        {
                            /* IGNORED */
                            RuntimeOps.MaybeGrabExceptions(
                                e, VerboseExceptions, ref errors);

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }

                        if (@object == null)
                        {
                            if (errors == null)
                                errors = new ResultList();

                            errors.Add(String.Format(
                                "expected to create {0} object of {1}",
                                MarshalOps.GetErrorTypeName(matchType),
                                MarshalOps.GetErrorTypeName(type)));

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }

                        ICommand command = @object as ICommand;

                        if (command == null)
                        {
                            if (errors == null)
                                errors = new ResultList();

                            errors.Add(String.Format(
                                "created object {0} not actually an {1}",
                                MarshalOps.GetErrorTypeName(type),
                                MarshalOps.GetErrorTypeName(matchType)));

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }

                        Result result = null;

                        if (interpreter.AddCommand(
                                command, clientData, ref token,
                                ref result) == ReturnCode.Ok)
                        {
                            added = true;

                            if (tokens == null)
                                tokens = new LongList();

                            tokens.Add(token);
                        }
                        else
                        {
                            if (result != null)
                            {
                                if (errors == null)
                                    errors = new ResultList();

                                errors.Add(result);
                            }

                            if (stopOnError)
                                return ReturnCode.Error;
                            else
                                continue;
                        }
                    }
                    finally
                    {
                        if (!added && (@object != null))
                        {
                            ObjectOps.TryDisposeOrComplain<object>(
                                interpreter, ref @object);

                            @object = null;
                        }
                    }
                }

                return ReturnCode.Ok;
            }
            catch (Exception e)
            {
                /* IGNORED */
                RuntimeOps.MaybeGrabExceptions(
                    e, VerboseExceptions, ref errors);

                return ReturnCode.Error;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method removes the commands identified by the specified tokens
        /// from the interpreter, updating the token list as commands are
        /// removed.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data to use when removing the commands, if any.
        /// </param>
        /// <param name="tokens">
        /// The list of command tokens to remove; upon return, the successfully
        /// removed tokens are removed from this list.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> if all commands were removed; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestRemoveCommands(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in: OPTIONAL */
            ref LongList tokens,     /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            if (tokens == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid token list");
                return ReturnCode.Error;
            }

            LongList localTokens = new LongList(tokens);

            foreach (long token in localTokens)
            {
                Result result = null;

                if (interpreter.RemoveCommand(
                        token, clientData,
                        ref result) == ReturnCode.Ok)
                {
                    if (!tokens.Remove(token))
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(String.Format(
                            "could not remove token: {0}",
                            token));
                    }
                }
                else
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(result);
                }
            }

            return (tokens.Count == 0) ?
                ReturnCode.Ok : ReturnCode.Error;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method removes the non-core commands, library procedures, and
        /// system variables of the specified kinds from the interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data to use when removing identifiers, if any.
        /// </param>
        /// <param name="kind">
        /// The kinds of identifiers to clean up.
        /// </param>
        /// <param name="count">
        /// Upon return, is incremented by the number of identifiers removed.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestCleanupIdentifiers(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in */
            IdentifierKind kind,     /* in */
            ref int count,           /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            int errorCount = 0;
            Result error; /* REUSED */

            if (FlagOps.HasFlags(kind, IdentifierKind.Command, true))
            {
                error = null;

                if (interpreter.RemoveCommands(
                        clientData, null, CommandFlags.Core, false,
                        false, ref count, ref error) != ReturnCode.Ok)
                {
                    if (error != null)
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(error);
                    }

                    errorCount++;
                }
            }

            if (FlagOps.HasFlags(kind, IdentifierKind.Procedure, true))
            {
                error = null;

                if (interpreter.RemoveProcedures(
                        clientData, null, ProcedureFlags.Library, false,
                        false, ref count, ref error) != ReturnCode.Ok)
                {
                    if (error != null)
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(error);
                    }

                    errorCount++;
                }
            }

            if (FlagOps.HasFlags(kind, IdentifierKind.Variable, true))
            {
                ICallFrame frame = interpreter.CurrentGlobalFrame;

                if (frame == null)
                    frame = interpreter.GlobalFrame;

                error = null;

                if (interpreter.RemoveVariables(
                        frame, null, VariableFlags.System, false, false,
                        true, ref count, ref error) != ReturnCode.Ok)
                {
                    if (error != null)
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(error);
                    }

                    errorCount++;
                }
            }

            return (errorCount > 0) ? ReturnCode.Error : ReturnCode.Ok;
        }
        #endregion

