        #region Methods for TraceFilterCallback
        /// <summary>
        /// This method retrieves the captured trace filter output as a string.
        /// </summary>
        /// <returns>
        /// The captured trace output, or null if it could not be retrieved.
        /// </returns>
        public static string TestTraceFilterGetOutput()
        {
            Result result = null;

            if (TestTraceFilterGetOutput(
                    true, true, ref result) == ReturnCode.Ok)
            {
                return result;
            }
            else
            {
                return null;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method retrieves the captured trace filter output, optionally
        /// treating null or empty output as an error.
        /// </summary>
        /// <param name="errorOnNull">
        /// Non-zero to treat null trace output as an error.
        /// </param>
        /// <param name="errorOnEmpty">
        /// Non-zero to treat empty trace output as an error.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the captured trace output; upon failure,
        /// receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestTraceFilterGetOutput(
            bool errorOnNull,
            bool errorOnEmpty,
            ref Result result
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (traceFilterOutput != null)
                {
                    if (errorOnEmpty &&
                        (traceFilterOutput.Length == 0))
                    {
                        result = "trace output is empty";
                        return ReturnCode.Error;
                    }
                    else
                    {
                        result = traceFilterOutput.ToString();
                        return ReturnCode.Ok;
                    }
                }
                else if (errorOnNull)
                {
                    result = "trace output is null";
                    return ReturnCode.Error;
                }
                else
                {
                    result = null;
                    return ReturnCode.Ok;
                }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method resets the captured trace filter output, discarding any
        /// accumulated text.
        /// </summary>
        public static void TestTraceFilterResetOutput()
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (traceFilterOutput != null)
                {
                    traceFilterOutput.Length = 0;
                    traceFilterOutput = null;
                }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method installs or removes one of the predefined trace filter
        /// callbacks, optionally configuring its match mode and pattern.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use, or null to operate on the global
        /// trace filter callback.
        /// </param>
        /// <param name="mode">
        /// The match mode to use for the trace filter, if any.
        /// </param>
        /// <param name="pattern">
        /// The pattern to use for the trace filter.
        /// </param>
        /// <param name="index">
        /// The index of the predefined trace filter callback to use, or -1 for
        /// no callback.
        /// </param>
        /// <param name="setup">
        /// Non-zero to install the trace filter callback; zero to remove it.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetTraceFilterCallback(
            Interpreter interpreter,
            MatchMode? mode,
            string pattern,
            int index,
            bool setup,
            ref Result error
            )
        {
            TraceFilterCallback callback;

            switch (index)
            {
                case -1:
                    {
                        callback = null;
                        break;
                    }
                case 0:
                    {
                        callback = new TraceFilterCallback(
                            TestTraceFilterStubCallback);

                        break;
                    }
                case 1:
                    {
                        callback = new TraceFilterCallback(
                            TestTraceFilterMessageCallback);

                        break;
                    }
                case 2:
                    {
                        callback = new TraceFilterCallback(
                            TestTraceFilterCategoryCallback);

                        break;
                    }
                case 3:
                    {
                        callback = new TraceFilterCallback(
                            TestTraceFilterCaptureCallback);

                        break;
                    }
                case 4:
                    {
                        callback = new TraceFilterCallback(
                            TestTraceFilterMessageSpyCallback);

                        break;
                    }
                case 5:
                    {
                        callback = new TraceFilterCallback(
                            TestTraceFilterCategorySpyCallback);

                        break;
                    }
                default:
                    {
                        error = "unknown trace filter callback index";
                        return ReturnCode.Error;
                    }
            }

            if (setup && (callback == null))
            {
                error = String.Format(
                    "unsupported trace filter callback #{0}",
                    index);

                return ReturnCode.Error;
            }

            if (mode != null)
            {
                lock (staticSyncRoot) /* TRANSACTIONAL */
                {
                    traceFilterMatchMode = (MatchMode)mode;
                    traceFilterPattern = pattern;
                }
            }

            if (interpreter != null)
            {
                if (setup)
                    interpreter.InternalTraceFilterCallback = callback;
                else
                    interpreter.InternalTraceFilterCallback = null;
            }
            else
            {
                if (setup)
                    TraceOps.SetTraceFilterCallback(callback);
                else
                    TraceOps.SetTraceFilterCallback(null);
            }

            return ReturnCode.Ok;
        }

