        #region Methods for ListOps.GetUniqueElements
        /// <summary>
        /// This method determines whether the specified script file name (or an
        /// equivalent variant of it) is already present in the supplied
        /// dictionary, for use as a uniqueness callback.
        /// </summary>
        /// <param name="collection">
        /// The collection of file names being processed.
        /// </param>
        /// <param name="dictionary">
        /// The dictionary of file names seen so far, if any.
        /// </param>
        /// <param name="keyItem">
        /// The candidate script file name to check.
        /// </param>
        /// <returns>
        /// True if the candidate file name is already present; null if no
        /// determination could be made.
        /// </returns>
        public static bool? TestHaveAnyScriptFileName(
            ICollection<string> collection,         /* in: NOT USED */
            IDictionary<string, string> dictionary, /* in: OPTIONAL */
            string keyItem                          /* in */
            ) /* CodeBrix.Platform.TclTk._Components.Public.Delegates.UniqueStringCallback<T> */
        {
            if ((dictionary != null) && (keyItem != null))
            {
                if (dictionary.ContainsKey(keyItem))
                    return true;

                if (!PathOps.IsRemoteUri(keyItem) && File.Exists(keyItem))
                {
                    bool encrypted = TestIsEncryptedFileName(keyItem);
                    string localKeyItem = keyItem;

                    /* NO RESULT */
                    TestMutateScriptFileName(!encrypted, ref localKeyItem);

                    if ((localKeyItem != null) &&
                        dictionary.ContainsKey(localKeyItem) &&
                        !PathOps.IsRemoteUri(localKeyItem) &&
                        File.Exists(localKeyItem) &&
                        !PathOps.IsSameFile(null, keyItem, localKeyItem))
                    {
                        return true;
                    }
                }
            }

            return null;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method returns the unique script file names from the specified
        /// list, treating file names that refer to the same file as duplicates.
        /// </summary>
        /// <param name="list">
        /// The list of script file names to filter for uniqueness.
        /// </param>
        /// <returns>
        /// A list containing only the unique script file names.
        /// </returns>
        public static StringList TestGetUniqueScriptFileNames(
            StringList list /* in */
            )
        {
            StringList result = ListOps.GetUniqueElements(list,
                new UniqueStringCallback<string>(TestHaveAnyScriptFileName));

            return result;
        }
