        /// </param>
        /// <param name="useFail">
        /// Non-zero to install a callback that fails when a complaint is raised;
        /// otherwise, a callback that breaks into the debugger.
        /// </param>
        public static void TestSetBreakOrFailOnComplain(
            Interpreter interpreter, /* NOT USED */
            bool setup,
            bool useFail
            )
