        /// <summary>
        /// This method installs or removes a test complaint callback on the
        /// interpreter that optionally throws when a complaint is raised.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="setup">
        /// Non-zero to install the test complaint callback; zero to remove it.
        /// </param>
        /// <param name="withThrow">
        /// Non-zero to install a callback that throws when a complaint is
        /// raised; otherwise, a callback that does not throw.
        /// </param>
        public static void TestSetComplainCallback(
            Interpreter interpreter, /* NOT USED */
            bool setup,
            bool withThrow
            )
        {
            if (setup)
            {
                Interpreter.ComplainCallback = withThrow ?
                    (ComplainCallback)TestComplainCallbackThrow :
                    TestComplainCallbackNoThrow;
            }
            else
            {
                Interpreter.ComplainCallback = null;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method installs or removes a script-based complaint callback on
        /// the interpreter that evaluates the specified script whenever a
        /// complaint is raised.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="text">
        /// The script to evaluate when a complaint is raised.
        /// </param>
        /// <param name="engineFlags">
        /// The engine flags to use when evaluating the complaint script.
        /// </param>
        /// <param name="setup">
        /// Non-zero to install the script-based complaint callback; zero to
        /// remove it.
        /// </param>
        public static void TestSetScriptOnComplain(
            Interpreter interpreter, /* NOT USED */
            string text,
            EngineFlags engineFlags,
            bool setup
            )
        {
            if (setup)
            {
                bool success = false;
                ScriptComplain scriptComplain = null;

                try
                {
                    scriptComplain = new ScriptComplain(
                        text, engineFlags);

                    ComplainCallback callback = new ComplainCallback(
                        scriptComplain.Complain);

                    Interpreter.ComplainCallback = callback;

                    success = true;
                }
                finally
                {
                    if (scriptComplain != null)
                    {
                        if (!success)
                        {
                            ObjectOps.DisposeOrTrace<ScriptComplain>(
                                interpreter, ref scriptComplain);
                        }

                        scriptComplain = null;
                    }
                }
            }
            else
            {
                try
                {
                    ComplainCallback callback = Interpreter.ComplainCallback;

                    if (callback != null)
                    {
                        ScriptComplain scriptComplain = callback.Target as ScriptComplain;

                        if (scriptComplain != null)
                        {
                            scriptComplain.Dispose(); /* throw */
                            scriptComplain = null;
                        }
                    }
                }
                catch (Exception e)
                {
                    TraceOps.DebugTrace(
                        e, typeof(Default).Name,
                        TracePriority.CleanupError);
                }
                finally
                {
                    Interpreter.ComplainCallback = null;
                }
            }
        }
        #endregion

