        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method serves as a test rule iteration callback, evaluating the
        /// configured rule callback script (if any) for the specified rule.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data supplied when the callback was registered, if any.
        /// </param>
        /// <param name="rule">
        /// The rule currently being iterated.
        /// </param>
        /// <param name="stopOnError">
        /// Upon return, may be modified to indicate whether iteration should
        /// stop on the first error.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestRuleIterationCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in */
            IRule rule,              /* in */
            ref bool stopOnError,    /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (!String.IsNullOrEmpty(ruleCallbackText))
            {
                ScriptBooleanValue stopOnErrorValue = new ScriptBooleanValue(
                    stopOnError);

                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("interpreter", interpreter);
                objects.Add("clientData", clientData);
                objects.Add("rule", rule);
                objects.Add("stopOnError", stopOnErrorValue);

                ReturnCode code;
                Result result = null;

                code = Helpers.EvaluateScript(
                    interpreter, ruleCallbackText, objects, ref result);

                stopOnErrorValue.MaybeGetValue(ref stopOnError);

                if (result != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(result);
                }

                return code;
            }
            else
            {
                return ReturnCode.Ok;
            }
        }
        #endregion

