        #region Methods for RuleMatchCallback
        /// <summary>
        /// This method creates a rule match callback delegate that wraps the
        /// test rule match callback method.
        /// </summary>
        /// <returns>
        /// The newly created rule match callback delegate.
        /// </returns>
        public static RuleMatchCallback TestGetRuleMatchCallback()
        {
