        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method serves as a test rule match callback, evaluating the
        /// configured rule callback script (if any) to determine whether the
        /// specified rule matches.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The extra data supplied when the callback was registered, if any.
        /// </param>
        /// <param name="kind">
        /// The kind of identifier being matched, if known.
        /// </param>
        /// <param name="mode">
        /// The matching mode to use.
        /// </param>
        /// <param name="text">
        /// The text being matched against the rule.
        /// </param>
        /// <param name="rule">
        /// The rule being evaluated for a match.
        /// </param>
        /// <param name="match">
        /// Upon return, may be modified to indicate whether the rule matched;
        /// null indicates an indeterminate result.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestRuleMatchCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in */
            IdentifierKind? kind,    /* in */
            MatchMode mode,          /* in */
            string text,             /* in */
            IRule rule,              /* in */
            ref bool? match,         /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (!String.IsNullOrEmpty(ruleCallbackText))
            {
                ScriptBooleanValue matchValue = new ScriptBooleanValue(
                    match);

                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("interpreter", interpreter);
                objects.Add("clientData", clientData);
                objects.Add("kind", kind);
                objects.Add("mode", mode);
                objects.Add("text", text);
                objects.Add("rule", rule);
                objects.Add("match", matchValue);

                ReturnCode code;
                Result result = null;

                code = Helpers.EvaluateScript(
                    interpreter, ruleCallbackText, objects, ref result);

                matchValue.MaybeGetNullableValue(ref match);

                if (result != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(result);
                }

                return code;
            }
            else
            {
                return ReturnCode.Ok;
            }
        }
        #endregion

