        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetupWebErrorCallback(
            Interpreter interpreter,
            bool setup,
            bool logOnly,
            bool noRestore,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            WebErrorCallback callback;

            if (setup)
            {
                callback = logOnly ?
                    new WebErrorCallback(TestLogWebErrorCallback) :
                    new WebErrorCallback(TestBestWebErrorCallback);
            }
            else
            {
                callback = null;
            }

            lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
            {
                interpreter.WebErrorCallback = callback;
            }

            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (!noRestore && !setup && (SavedSecurityProtocol != null))
                {
                    BestSecurityProtocol = SavedSecurityProtocol;
                    SavedSecurityProtocol = null;
                }
            }

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method formats the specified network security protocol value
        /// as a human-readable string.
        /// </summary>
        /// <param name="protocol">
        /// The security protocol value to format.
        /// </param>
        /// <param name="cultureInfo">
        /// The culture information to use for formatting.
        /// </param>
        /// <param name="system">
        /// Non-zero to format using the underlying system security protocol
        /// values.
        /// </param>
        /// <returns>
        /// The formatted string, or null on failure.
        /// </returns>
        public static string TestSecurityProtocolToString(
            SecurityProtocolType protocol,
            CultureInfo cultureInfo,
            bool system
            )
        {
            try
            {
                SecurityProtocolType[] values = Enum.GetValues(
                    typeof(SecurityProtocolType)) as SecurityProtocolType[];

                if (values == null)
                    return null;

                StringList list = new StringList();

                list.Separator = String.Format(
                    "{0}{1}", Characters.Comma, Characters.Space);

                System.Net.SecurityProtocolType altProtocol =
                    (System.Net.SecurityProtocolType)protocol;

                Int32ObjectDictionary protocols = new Int32ObjectDictionary();

                foreach (SecurityProtocolType value in values)
                {
                    if (value == (SecurityProtocolType)0)
                        continue;

                    if (protocols.ContainsKey((int)value))
                        continue;

                    string valueString = value.ToString().Replace(
                        "SystemDefault, ", String.Empty);

                    if (system)
                    {
                        System.Net.SecurityProtocolType altValue =
                            (System.Net.SecurityProtocolType)value;

                        if ((altProtocol & altValue) != 0)
                        {
                            string altString = altValue.ToString();
                            int altInteger = 0;

                            if (Value.GetInteger2(altString,
                                    ValueFlags.AnyInteger, cultureInfo,
                                    ref altInteger) == ReturnCode.Ok)
                            {
                                list.Add(StringList.MakeList(
                                    valueString, FormatOps.Hexadecimal(
                                    altInteger, true)));
                            }
                            else
                            {
                                list.Add(StringList.MakeList(
                                    altString, FormatOps.Hexadecimal(
                                    altValue, true)));
                            }
                        }
                    }
                    else if ((protocol & value) != 0)
                    {
                        list.Add(StringList.MakeList(
                            valueString, FormatOps.Hexadecimal(
                            value, true)));
                    }

                    protocols.Add((int)value, null);
                }

                return list.ToString();
            }
            catch (Exception e)
            {
                TraceOps.DebugTrace(
                    e, typeof(Default).Name,
                    TracePriority.NetworkError);

                return null;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method detects security protocols that are known to be broken
        /// on the current platform.
        /// </summary>
        /// <returns>
        /// The broken security protocols, or null if none are known to be
        /// broken.
        /// </returns>
        public static SecurityProtocolType? TestDetectBrokenSecurityProtocols()
        {
            //
            // HACK: Yes, Windows 11 seems to have a broken TLS 1.3
            //       when using the .NET Framework 4.x.  Hopefully,
            //       it will be fixed; however, this workaround may
            //       still last forever.
            //
            if (PlatformOps.IsWindows10OrHigher())
                return SecurityProtocolType.BrokenOnWindows10OrHigher;

            return null;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method masks off the obsolete and/or broken security protocols
        /// from the specified value.
        /// </summary>
        /// <param name="noObsolete">
        /// Non-zero to mask off obsolete security protocols.
        /// </param>
        /// <param name="protocols">
        /// On input, the security protocols to filter; on output, the filtered
        /// protocols.
        /// </param>
        public static void TestMaskOffSecurityProtocol(
            bool noObsolete,                   /* in */
            ref SecurityProtocolType protocols /* in, out */
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (!NoMaskOffSecurityProtocol)
                {
                    if (noObsolete)
                        protocols &= ~SecurityProtocolType.Obsolete;

                    if (MaskOffSecurityProtocol != null)
                    {
                        SecurityProtocolType maskProtocols =
                            (SecurityProtocolType)MaskOffSecurityProtocol;

                        protocols &= ~maskProtocols;
                    }
                    else if (!NoBrokenSecurityProtocol)
                    {
                        SecurityProtocolType? maskProtocols =
                            TestDetectBrokenSecurityProtocols();

                        if (maskProtocols != null)
                            protocols &= ~((SecurityProtocolType)maskProtocols);
                    }
                }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method probes for the set of network security protocols
        /// supported by the runtime.
        /// </summary>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// The set of supported security protocols, or null on failure.
        /// </returns>
        public static SecurityProtocolType? TestProbeSecurityProtocol(
            ref Result error /* out */
            )
        {
            try
            {
                SecurityProtocolType[] values = Enum.GetValues(
                    typeof(SecurityProtocolType)) as SecurityProtocolType[];

                if (values == null)
                {
                    error = String.Format(
                        "no enumeration values for {0}",
                        MarshalOps.GetErrorTypeName(
                            typeof(SecurityProtocolType)));

                    return null;
                }

                SecurityProtocolType result = SecurityProtocolType.None;

                SecurityProtocolType savedValue =
                    (SecurityProtocolType)ServicePointManager.SecurityProtocol;

                try
                {
                    foreach (SecurityProtocolType value in values)
                    {
                        if (value == (SecurityProtocolType)0)
                            continue;

                        try
                        {
                            //
                            // HACK: Check if this is a legal value by trying to
                            //       actually use it.  All known versions of the
                            //       .NET Framework will throw an exception if
                            //       this is not a legal value.
                            //
                            ServicePointManager.SecurityProtocol =
                                (System.Net.SecurityProtocolType)value; /* throw */

                            result |= value;
                        }
                        catch
                        {
                            // do nothing.
                        }
                    }
                }
                finally
                {
                    ServicePointManager.SecurityProtocol =
                        (System.Net.SecurityProtocolType)savedValue;
                }

                return result;
            }
            catch (Exception e)
            {
                error = e;
                return null;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method overrides the best network security protocol with the
        /// specified value.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="protocols">
        /// The security protocols to use as the best value.
        /// </param>
        /// <param name="force">
        /// Non-zero to override even when a value is already configured.
        /// </param>
        /// <param name="noSave">
        /// Non-zero to skip saving the previous value.
        /// </param>
        /// <param name="noObsolete">
        /// Non-zero to exclude obsolete security protocols.
        /// </param>
        /// <param name="results">
        /// Upon return, receives messages describing the operation.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestOverrideSecurityProtocol(
            Interpreter interpreter,        /* in */
            SecurityProtocolType protocols, /* in */
            bool force,                     /* in */
            bool noSave,                    /* in */
            bool noObsolete,                /* in */
            ref ResultList results          /* in, out */
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                Result localResult; /* REUSED */

                if (force || (BestSecurityProtocol == null))
                {
                    localResult = null;

                    if (!noSave && TestSaveBestSecurityProtocol(
                            interpreter, force, ref localResult) != ReturnCode.Ok)
                    {
                        if (localResult != null)
                        {
                            if (results == null)
                                results = new ResultList();

                            results.Add(localResult);
                        }

                        return ReturnCode.Error;
                    }

                    TestMaskOffSecurityProtocol(
                        noObsolete, ref protocols);

                    BestSecurityProtocol = protocols;

                    localResult = String.Format(
                        "best security protocol overridden to {0}",
                        FormatOps.WrapOrNull(BestSecurityProtocol));
                }
                else
                {
                    localResult = "best security protocol already setup";
                }

                if (localResult != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(localResult);
                }

                return ReturnCode.Ok;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method probes for and configures the best available network
        /// security protocol.
        /// </summary>
        /// <param name="force">
        /// Non-zero to reconfigure even when a value is already configured.
        /// </param>
        /// <param name="noObsolete">
        /// Non-zero to exclude obsolete security protocols.
        /// </param>
        /// <param name="results">
        /// Upon return, receives messages describing the operation.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetupSecurityProtocol(
            bool force,            /* in */
            bool noObsolete,       /* in */
            ref ResultList results /* in, out */
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                Result localResult; /* REUSED */

                if (force || (BestSecurityProtocol == null))
                {
                    SecurityProtocolType? probeProtocols;

                    localResult = null;

                    probeProtocols = TestProbeSecurityProtocol(
                        ref localResult);

                    if (probeProtocols == null)
                    {
                        if (localResult != null)
                        {
                            if (results == null)
                                results = new ResultList();

                            results.Add(localResult);
                        }

                        return ReturnCode.Error;
                    }

                    SecurityProtocolType allProtocols =
                        (SecurityProtocolType)probeProtocols;

                    TestMaskOffSecurityProtocol(
                        noObsolete, ref allProtocols);

                    BestSecurityProtocol = allProtocols;

                    localResult = String.Format(
                        "best security protocol set to {0}",
                        FormatOps.WrapOrNull(BestSecurityProtocol));
                }
                else
                {
                    localResult = "best security protocol already setup";
                }

                if (localResult != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(localResult);
                }

                return ReturnCode.Ok;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method clears the best network security protocol that has been
        /// configured.
        /// </summary>
        /// <param name="force">
        /// Non-zero to clear even when no value is configured.
        /// </param>
        /// <returns>
        /// True if the best security protocol was cleared; otherwise, false.
        /// </returns>
        public static bool TestResetSecurityProtocol(
            bool force /* in */
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (force || (BestSecurityProtocol != null))
                {
                    BestSecurityProtocol = null;
                    return true;
                }

                return false;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method gets the best network security protocol that has been
        /// configured.
        /// </summary>
        /// <param name="results">
        /// Upon return, receives the best security protocol, or an error
        /// message if none is available.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestGetSecurityProtocol(
            ref ResultList results /* in, out */
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                SecurityProtocolType? protocol = BestSecurityProtocol;

                if (results == null)
                    results = new ResultList();

                if (protocol != null)
                {
                    results.Add(protocol);
                    return ReturnCode.Ok;
                }
                else
                {
                    results.Add("best security protocol unavailable");
                    return ReturnCode.Error;
                }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method applies the best network security protocol to the
        /// service point manager.
        /// </summary>
        /// <param name="results">
        /// Upon return, receives messages describing the operation.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetSecurityProtocol(
            ref ResultList results /* in, out */
            )
        {
            try
            {
                lock (staticSyncRoot) /* TRANSACTIONAL */
                {
                    Result localResult; /* REUSED */
                    SecurityProtocolType? newProtocol = BestSecurityProtocol;

                    if (newProtocol != null)
                    {
                        SecurityProtocolType oldProtocol =
                            (SecurityProtocolType)ServicePointManager.SecurityProtocol;

                        if ((SecurityProtocolType)newProtocol != oldProtocol)
                        {
                            ServicePointManager.SecurityProtocol =
                                (System.Net.SecurityProtocolType)newProtocol;

                            localResult = String.Format(
                                "security protocol changed from {0} to {1} (set)",
                                FormatOps.WrapOrNull(oldProtocol),
                                FormatOps.WrapOrNull(newProtocol));
                        }
                        else
                        {
                            localResult = String.Format(
                                "security protocol unchanged from {0} (set)",
                                FormatOps.WrapOrNull(oldProtocol));
                        }
                    }
                    else
                    {
                        localResult = "cannot change security protocol (set)";
                    }

                    if (localResult != null)
                    {
                        if (results == null)
                            results = new ResultList();

                        results.Add(localResult);
                    }

                    return ReturnCode.Ok;
                }
            }
            catch (Exception e)
            {
                if (results == null)
                    results = new ResultList();

                results.Add(e);

                return ReturnCode.Error;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method saves the current network security protocol and applies
        /// the best one.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="result">
        /// Upon success, receives a message describing the change; upon
        /// failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestPushSecurityProtocol(
            Interpreter interpreter, /* in: NOT USED */
            ref Result result        /* out */
            )
        {
            try
            {
                lock (staticSyncRoot) /* TRANSACTIONAL */
                {
                    if (SavedSecurityProtocol != null)
                    {
                        result = "already have saved security protocol";
                        return ReturnCode.Error;
                    }

                    SecurityProtocolType oldProtocol =
                        (SecurityProtocolType)ServicePointManager.SecurityProtocol;

                    SecurityProtocolType? newProtocol = BestSecurityProtocol;

                    if (newProtocol != null)
                    {
                        //
                        // NOTE: Save existing network security protocol for
                        //       possible future use (e.g. restoration).
                        //
                        SavedSecurityProtocol = oldProtocol;

                        //
                        // HACK: For use of the TLS 1.2+ security protocol
                        //       because some web servers fail without it.
                        //
                        ServicePointManager.SecurityProtocol =
                            (System.Net.SecurityProtocolType)newProtocol;

                        //
                        // NOTE: If we get to this point, just assume success.
                        //
                        result = String.Format(
                            "security protocol changed from {0} to {1} (push)",
                            FormatOps.WrapOrNull(oldProtocol),
                            FormatOps.WrapOrNull(newProtocol));
                    }
                    else
                    {
                        result = String.Format(
                            "security protocol unchanged from {0} (push)",
                            FormatOps.WrapOrNull(oldProtocol));
                    }

                    return ReturnCode.Ok;
                }
            }
            catch (Exception e)
            {
                result = e;
                return ReturnCode.Error;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method restores the network security protocol from its
        /// previously saved value.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="result">
        /// Upon success, receives a message describing the change; upon
        /// failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestPopSecurityProtocol(
            Interpreter interpreter, /* in: NOT USED */
            ref Result result        /* out */
            )
        {
            try
            {
                lock (staticSyncRoot) /* TRANSACTIONAL */
                {
                    SecurityProtocolType? newProtocol = SavedSecurityProtocol;

                    if (newProtocol == null)
                    {
                        result = "missing saved security protocol";
                        return ReturnCode.Error;
                    }

                    SecurityProtocolType oldProtocol =
                        (SecurityProtocolType)ServicePointManager.SecurityProtocol;

                    ServicePointManager.SecurityProtocol =
                        (System.Net.SecurityProtocolType)newProtocol;

                    SavedSecurityProtocol = null;

                    result = String.Format(
                        "security protocol changed from {0} to {1} (pop)",
                        FormatOps.WrapOrNull(oldProtocol),
                        FormatOps.WrapOrNull(newProtocol));

                    return ReturnCode.Ok;
                }
            }
            catch (Exception e)
            {
                result = e;
                return ReturnCode.Error;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method saves the current best network security protocol for
        /// later restoration.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="force">
        /// Non-zero to overwrite any existing saved value.
        /// </param>
        /// <param name="result">
        /// Upon success, receives a message describing the operation; upon
        /// failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSaveBestSecurityProtocol(
            Interpreter interpreter, /* in: NOT USED */
            bool force,              /* in */
            ref Result result        /* out */
            )
        {
            try
            {
                lock (staticSyncRoot) /* TRANSACTIONAL */
                {
                    SecurityProtocolType? oldProtocol = SavedSecurityProtocol;

                    if (!force && (oldProtocol != null))
                    {
                        result = "already have saved security protocol";
                        return ReturnCode.Error;
                    }

                    SecurityProtocolType? newProtocol = BestSecurityProtocol;

                    if (oldProtocol != newProtocol)
                    {
                        //
                        // NOTE: Save existing best network security protocol
                        //       for possible future use (e.g. restoration).
                        //
                        SavedSecurityProtocol = newProtocol;

                        //
                        // NOTE: If we get to this point, just assume success.
                        //
                        result = String.Format(
                            "best security protocol saved from {0} to {1}",
                            FormatOps.WrapOrNull(oldProtocol),
                            FormatOps.WrapOrNull(newProtocol));
                    }
                    else
                    {
                        result = String.Format(
                            "best security protocol not saved from {0}",
                            FormatOps.WrapOrNull(oldProtocol));
                    }

                    return ReturnCode.Ok;
                }
            }
            catch (Exception e)
            {
                result = e;
                return ReturnCode.Error;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method restores the best network security protocol from its
        /// previously saved value.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="force">
        /// Non-zero to restore even when no saved value is present.
        /// </param>
        /// <param name="result">
        /// Upon success, receives a message describing the restoration; upon
        /// failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestRestoreBestSecurityProtocol(
            Interpreter interpreter, /* in: NOT USED */
            bool force,              /* in */
            ref Result result        /* out */
            )
        {
            try
            {
                lock (staticSyncRoot) /* TRANSACTIONAL */
                {
                    SecurityProtocolType? newProtocol = SavedSecurityProtocol;

                    if (!force && (newProtocol == null))
                    {
                        result = "missing saved security protocol";
                        return ReturnCode.Error;
                    }

                    SecurityProtocolType? oldProtocol = BestSecurityProtocol;

                    BestSecurityProtocol = newProtocol;
                    SavedSecurityProtocol = null;

                    result = String.Format(
                        "best security protocol restored from {0} to {1}",
                        FormatOps.WrapOrNull(oldProtocol),
                        FormatOps.WrapOrNull(newProtocol));

                    return ReturnCode.Ok;
                }
            }
            catch (Exception e)
            {
                result = e;
                return ReturnCode.Error;
            }
        }
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Methods for PreWaitCallback / PostWaitCallback
        /// <summary>
        /// This method is an event callback that enforces a maximum wait
        /// duration during testing.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the wait, possibly containing the
        /// requested wait duration.
        /// </param>
        /// <param name="result">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestWaitEventCallback(
            Interpreter interpreter,
            IClientData clientData,
            ref Result result
            )
        {
            ReturnCode code = ReturnCode.Ok;

            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (maximumWaitMicroseconds != null)
                {
                    long maximumMicroseconds = (long)maximumWaitMicroseconds;

                    if (maximumMicroseconds >= 0)
                    {
                        IAnyClientData anyClientData = clientData as IAnyClientData;

                        if (anyClientData != null)
                        {
                            foreach (string name in new string[] {
                                    "microseconds", "waitMicroseconds",
                                    "readyMicroseconds"
                                })
                            {
                                long microseconds;
                                Result error = null; /* NOT USED */

                                if (!anyClientData.TryGetWideInteger(
                                        name, false, out microseconds,
                                        ref error))
                                {
                                    continue;
                                }

                                if (microseconds < 0)
                                {
                                    result = String.Format(
                                        "infinite wait {0} disallowed",
                                        FormatOps.WrapOrNull(name));

                                    code = ReturnCode.Error;
                                    break;
                                }

                                if (microseconds > maximumMicroseconds)
                                {
                                    result = String.Format(
                                        "wait {0} cannot exceed {1}",
                                        FormatOps.WrapOrNull(name),
                                        maximumMicroseconds);

                                    code = ReturnCode.Error;
                                    break;
                                }
                            }
                        }
                    }
                }
            }

            TraceOps.DebugTrace(String.Format(
                "TestWaitEventCallback: interpreter = {0}, " +
                "clientData = {1}, code = {2}, result = {3}",
                FormatOps.InterpreterNoThrow(interpreter),
                FormatOps.WrapOrNull(clientData), code,
                FormatOps.WrapOrNull(true, false, result)),
                typeof(Default).Name, TracePriority.EventDebug2);

            return code;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method installs or removes the test pre-wait and post-wait
        /// event callbacks on the interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="setup">
        /// Non-zero to install the callbacks; zero to remove them.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetupWaitEventCallbacks(
            Interpreter interpreter,
            bool setup,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            EventCallback callback = setup ?
                new EventCallback(TestWaitEventCallback) : null;

            lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
            {
                interpreter.PreWaitCallback = callback;
                interpreter.PostWaitCallback = callback;
            }

            return ReturnCode.Ok;
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Methods for HealthCallback
#if THREADING
        /// <summary>
        /// This method is a health callback used to verify interpreter health
        /// during testing.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="status">
        /// On input, the health check status to check; may be modified.
        /// </param>
        /// <param name="errors">
        /// Upon return, receives any error messages produced by the health
        /// check.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestHealthCallback(
            Interpreter interpreter, /* in */
            ref CheckStatus status,  /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            ReturnCode code = ReturnCode.Ok;

            switch (status & CheckStatus.StatusMask)
            {
                case CheckStatus.Unknown:
                case CheckStatus.Success:
                case CheckStatus.Failure:
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(String.Format(
                            "test health callback invoked for {0}",
                            FormatOps.WrapOrNull(status)));

                        lock (staticSyncRoot) /* TRANSACTIONAL */
                        {
                            if (failHealthCallback)
                                code = ReturnCode.Error;
                        }

                        break;
                    }
                default:
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(String.Format(
                            "unrecognized health check status {0}",
                            FormatOps.WrapOrNull(status)));

                        code = ReturnCode.Error;
                        break;
                    }
            }

            TracePriority priority = code == ReturnCode.Ok ?
                TracePriority.EventDebug2 : TracePriority.EventError;

            TraceOps.DebugTrace(String.Format(
                "TestHealthCallback: interpreter = {0}, " +
                "status = {1}, code = {2}, errors = {3}",
                FormatOps.InterpreterNoThrow(interpreter),
                FormatOps.WrapOrNull(status), code,
                FormatOps.WrapOrNull(true, false, errors)),
                typeof(Default).Name, priority);

            return code;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method installs or removes the test health callback on the
        /// interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="setup">
        /// Non-zero to install the callback; zero to remove it.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetupHealthCallback(
            Interpreter interpreter,
            bool setup,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            HealthCallback callback = setup ?
                new HealthCallback(TestHealthCallback) : null;

            lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
            {
                interpreter.InternalHealthCallback = callback;
            }

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method gets and optionally sets whether the test health
        /// callback should report failure.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="fail">
        /// Non-zero to make the health callback report failure; zero to make
        /// it succeed; null to leave the setting unchanged.
        /// </param>
        /// <param name="result">
        /// Receives the current value of the setting.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetFailHealthCallback(
            Interpreter interpreter,
            bool? fail,
            ref Result result
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (fail != null)
                    failHealthCallback = (bool)fail;

                result = failHealthCallback;
                return ReturnCode.Ok;
            }
        }
#endif
