        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is a new web client callback that creates a web client,
        /// optionally backed by a script.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="argument">
        /// The argument associated with the web client request.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the request; may contain the
        /// backing script text.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// The newly created web client, or null if one could not be created.
        /// </returns>
        public static WebClient TestScriptNewWebClientCallback(
            Interpreter interpreter,
            string argument,
            IClientData clientData,
            ref Result error
            )
        {
            string text = null;

            if (clientData != null)
            {
                object data = null;

                /* IGNORED */
                clientData = ClientData.UnwrapOrReturn(
                    clientData, ref data);

                text = data as string;
            }

            if (text != null)
            {
                return ScriptWebClient.Create(
                    interpreter, text, argument, true,
                    ref error);
            }
            else
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return null;
                }

                NewWebClientCallback savedCallback =
                    interpreter.NewWebClientCallback;

                try
                {
                    //
                    // BUGFIX: Avoid infinite (mutual) recursion here by
                    //         making sure this method is NOT the current
                    //         new web client callback before attempting
                    //         to create a "default" WebClient instance.
                    //
                    interpreter.NewWebClientCallback = null;

                    return WebOps.CreateClient(
                        interpreter, argument, null, WebOps.GetTimeout(
                        interpreter, TimeoutType.Network), ref error);
                }
                finally
                {
                    interpreter.NewWebClientCallback = savedCallback;
                }
            }
        }

