        /// <summary>
        /// This method gets the currently configured value conversion error
        /// callbacks.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="errorDelegate">
        /// Upon success, receives the error callback delegate, if any.
        /// </param>
        /// <param name="errorListDelegate">
        /// Upon success, receives the error list callback delegate, if any.
        /// </param>
        /// <returns>
        /// True if the callbacks were obtained; otherwise, false.
        /// </returns>
        public static bool TestGetErrorCallbacks(
            Interpreter interpreter,       /* in: NOT USED */
            ref Delegate errorDelegate,    /* out: OPTIONAL */
            ref Delegate errorListDelegate /* out: OPTIONAL */
            )
        {
            errorDelegate = Value.GetErrorCallback();
            errorListDelegate = Value.GetErrorListCallback();

            return true;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method sets or clears the value conversion error callbacks.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="errorDelegate">
        /// The error callback delegate to set, if any.
        /// </param>
        /// <param name="errorListDelegate">
        /// The error list callback delegate to set, if any.
        /// </param>
        /// <param name="setup">
        /// Non-zero to set the default test callbacks when no delegates are
        /// supplied; zero to clear them.
        /// </param>
        /// <returns>
        /// True if the callbacks were set or cleared; otherwise, false.
        /// </returns>
        public static bool TestSetErrorCallbacks(
            Interpreter interpreter,    /* in: NOT USED */
            Delegate errorDelegate,     /* in: OPTIONAL */
            Delegate errorListDelegate, /* in: OPTIONAL */
            bool setup                  /* in */
            )
        {
            if ((errorDelegate == null) && (errorListDelegate == null))
            {
                if (setup)
                {
                    Value.SetErrorCallback(
                        new ErrorCallback(TestErrorCallback));

                    Value.SetErrorListCallback(
                        new ErrorListCallback(TestErrorListCallback));
                }
                else
                {
                    Value.SetErrorCallback(null);
                    Value.SetErrorListCallback(null);
                }

                return true;
            }

            if (errorDelegate != null)
            {
                ErrorCallback callback =
                    errorDelegate as ErrorCallback;

                if (callback != null)
                    Value.SetErrorCallback(callback);
                else
                    return false;
            }

            if (errorListDelegate != null)
            {
                ErrorListCallback callback =
                    errorListDelegate as ErrorListCallback;

                if (callback != null)
                    Value.SetErrorListCallback(callback);
                else
                    return false;
            }

            return true;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method enables or disables tracing of value conversion errors.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use; this parameter is not used.
        /// </param>
        /// <param name="enable">
        /// Non-zero to enable error tracing; zero to disable it.
        /// </param>
        /// <param name="pattern">
        /// The pattern used to match error messages to trace, if any.
        /// </param>
        /// <returns>
        /// True if the requested change took effect; otherwise, false.
        /// </returns>
        public static bool TestEnableErrorCallbacks(
            Interpreter interpreter, /* in: NOT USED */
            bool enable,             /* in */
            string pattern           /* in: OPTIONAL */
            )
        {
            Interlocked.Exchange(
                ref traceErrorPattern, pattern);

            if (enable)
            {
                return Interlocked.Increment(
                    ref shouldTraceError) > 0;
            }
            else
            {
                return Interlocked.Decrement(
                    ref shouldTraceError) <= 0;
            }
        }
        #endregion

