        #region Methods for AddExecuteCallback
        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is a test execute callback that evaluates its arguments
        /// as a script, starting after the command name.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The client data for the callback, if any.
        /// </param>
        /// <param name="arguments">
        /// The argument list passed to the callback.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the result of the evaluation; upon failure,
        /// receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestExecuteCallback1(
            Interpreter interpreter,
            IClientData clientData,
            ArgumentList arguments,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            if (arguments.Count < 2)
            {
                //
                // HACK: Just default the command name to "eval" here
                //       when there are zero arguments.
                //
                result = String.Format(
                    "wrong # args: should be \"{0} arg ?arg ...?\"",
                    (arguments.Count > 0) ? (string)arguments[0] : "command");

                return ReturnCode.Error;
            }

            return interpreter.EvaluateScript(arguments, 1, ref result);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is a test execute callback that evaluates its arguments
        /// as a script, starting after the command and sub-command names.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The client data for the callback, if any.
        /// </param>
        /// <param name="arguments">
        /// The argument list passed to the callback.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the result of the evaluation; upon failure,
        /// receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestExecuteCallback2(
            Interpreter interpreter,
            IClientData clientData,
            ArgumentList arguments,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            if (arguments.Count < 3)
            {
                result = String.Format(
                    "wrong # args: should be \"{0} {1} arg ?arg ...?\"",
                    (arguments.Count > 0) ? (string)arguments[0] : "command",
                    (arguments.Count > 1) ? (string)arguments[1] : "subcommand");

                return ReturnCode.Error;
            }

            return interpreter.EvaluateScript(arguments, 2, ref result);
        }

