        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method adds a set of test execute callbacks to the interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="name">
        /// The base name to use for the added callbacks.
        /// </param>
        /// <param name="clientData">
        /// The client data to associate with the operation, if any.
        /// </param>
        /// <param name="ignoreNull">
        /// Non-zero to ignore null entries in the collection.
        /// </param>
        /// <param name="stopOnError">
        /// Non-zero to stop after the first error.
        /// </param>
        /// <param name="collection">
        /// Upon success, receives the collection of execute callbacks that was
        /// added.
        /// </param>
        /// <param name="errorCount">
        /// Upon return, receives the number of errors that occurred.
        /// </param>
        /// <param name="result">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddExecuteCallbacks(
            Interpreter interpreter,
            string name,
            IClientData clientData,
            bool ignoreNull,
            bool stopOnError,
            ref IEnumerable<IExecuteCallbackData> collection,
            ref int errorCount,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            IPlugin plugin = TestGetPlugin(interpreter, ref result);

            if (plugin == null)
                return ReturnCode.Error;

            collection = new IExecuteCallbackData[] {
                new ExecuteCallbackData(
                    String.Format("{0}_one", name),
                    TestExecuteCallback1, null, 0
                ),
                null, /* NOTE: Purposely invalid. */
                new ExecuteCallbackData(
                    String.Format("{0}_two", name),
                    null, null, 1001 /* NOTE: Bad token. */
                ),
                new ExecuteCallbackData(
                    String.Format("{0}_two", name),
                    null, null, 0
                ),
                new ExecuteCallbackData(
                    String.Format("{0}_tri", name),
                    TestExecuteCallback2, null, 0
                )
            };

            return interpreter.AddExecuteCallbacks(
                collection, plugin, clientData, ignoreNull,
                stopOnError, ref errorCount, ref result);
        }

