        #region Methods for AddSubCommands
        /// <summary>
        /// This method is a callback that generates a unique delegate name for
        /// the specified method.
        /// </summary>
        /// <param name="delegates">
        /// The existing delegates, used to detect and avoid name collisions.
        /// </param>
        /// <param name="methodInfo">
        /// The method to generate a delegate name for.
        /// </param>
        /// <param name="clientData">
        /// The client data for the callback, if any.
        /// </param>
        /// <returns>
        /// The generated delegate name, or null if one could not be generated.
        /// </returns>
        public static string TestNewDelegateNameCallback(
            DelegateDictionary delegates,
            MethodInfo methodInfo,
            IClientData clientData
            ) /* NewDelegateNameCallback */
        {
            if (methodInfo == null)
                return null;

            string methodName = methodInfo.Name;
            StringBuilder builder = StringBuilderFactory.Create();

            builder.Append(methodName);

            if ((delegates != null) &&
                delegates.ContainsKey(builder.ToString()))
            {
                ParameterInfo[] parameterInfo =
                    methodInfo.GetParameters();

                if (parameterInfo != null)
                {
                    builder.AppendFormat("{0}{1}",
                        Characters.Underscore,
                        parameterInfo.Length);
                }
            }

            if ((delegates != null) &&
                delegates.ContainsKey(builder.ToString()))
            {
                byte[] hashValue = HashOps.HashString(
                    null, (string)null, methodInfo.ToString());

                if (hashValue != null)
                {
                    builder.AppendFormat("{0}{1}",
                        Characters.Underscore,
                        ArrayOps.ToHexadecimalString(hashValue));
                }
            }

            return StringBuilderCache.GetStringAndRelease(ref builder);
        }

