        /// <summary>
        /// This method adds all of the test commands to the specified
        /// interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The rule set client data to use, if any.
        /// </param>
        /// <param name="arguments">
        /// The argument list to use.
        /// </param>
        /// <param name="stopOnError">
        /// Non-zero to stop adding commands after the first error.
        /// </param>
        /// <param name="dynamic">
        /// Non-zero to add the commands dynamically.
        /// </param>
        /// <param name="tokens">
        /// Upon success, receives the list of command tokens that were added.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives the list of error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddAllCommands(
            Interpreter interpreter,
            RuleSetClientData clientData,
            ArgumentList arguments,
            bool stopOnError,
            bool dynamic,
            ref LongList tokens,
            ref ResultList errors
            )
        {
            ReturnCode code = ReturnCode.Ok;

            if (TestAddBuiltInExecuteCallbacks(
                    interpreter, clientData, stopOnError,
                    ref tokens, ref errors) != ReturnCode.Ok)
            {
                code = ReturnCode.Error;
            }

            Result result = null;

            if (TestAddPkgInstallLogCommand(
                    interpreter, ref result) != ReturnCode.Ok)
            {
                if (result != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(result);
                }

                code = ReturnCode.Error;
            }

            ResultList results = null;

            if (TestAddCommands(
                    interpreter, clientData,
                    ref results) == ReturnCode.Ok)
            {
                if (results != null)
                {
                    foreach (Result localResult in results)
                    {
                        if (localResult == null)
                            continue;

                        object value = localResult.Value;

                        if (value == null)
                            continue;

                        Type type = AppDomainOps.MaybeGetType(
                            value);

                        if (type == null)
                            continue;

                        if (type == typeof(int))
                        {
                            if (tokens == null)
                                tokens = new LongList();

                            tokens.Add((int)value);
                        }
                        else if (type == typeof(long))
                        {
                            if (tokens == null)
                                tokens = new LongList();

                            tokens.Add((long)value);
                        }
                    }
                }
            }
            else
            {
                if (results != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.AddRange(results);
                }

                code = ReturnCode.Error;
            }

            long token = 0;
            Result error = null;

            if (TestAddCalcCommand(
                    interpreter, clientData, ref token,
                    ref error) == ReturnCode.Ok)
            {
                if (tokens == null)
                    tokens = new LongList();

                tokens.Add(token);
            }
            else
            {
                if (error != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(error);
                }

                code = ReturnCode.Error;
            }

            if (clientData != null)
            {
                if (TestAddDefinitionCommands(
                        interpreter, clientData, ref tokens,
                        ref errors) != ReturnCode.Ok)
                {
                    code = ReturnCode.Error;
                }

                if (TestAddRuleSetCommands(
                        interpreter, clientData, ref tokens,
                        ref errors) != ReturnCode.Ok)
                {
                    code = ReturnCode.Error;
                }
            }

            return code;
        }
