        #region Methods for Reparse Points
        /// <summary>
        /// This method scans the specified reparse point data for an embedded
        /// file system path and extracts it.
        /// </summary>
        /// <param name="bytes">
        /// The raw reparse point data to process.
        /// </param>
        /// <param name="encoding">
        /// The character encoding to use; when null, Unicode is assumed.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the extracted path; upon failure, receives
        /// an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestProcessReparseData(
            byte[] bytes,
            Encoding encoding,
            ref Result result
            )
        {
            if (bytes == null)
            {
                result = "invalid bytes";
                return ReturnCode.Error;
            }

            int length = bytes.Length;

            if (length == 0)
            {
                result = "must have more than zero bytes";
                return ReturnCode.Error;
            }

            if ((length % 2) != 0)
            {
                result = "must have an even number of bytes";
                return ReturnCode.Error;
            }

            //
            // NOTE: Match with "\??\X:\some\path".
            //
            char[] scanCharacters1 = new char[] {
                Characters.Backslash,
                Characters.QuestionMark,
                Characters.QuestionMark,
                Characters.Backslash,
                Characters.X, /* NOTE: Any letter. */
                Characters.Colon,
                Characters.Backslash
            };

            //
            // NOTE: Match with "X:\some\path".
            //
            char[] scanCharacters2 = new char[] {
                Characters.X, /* NOTE: Any letter. */
                Characters.Colon,
                Characters.Backslash
            };

            bool found = false;
            int startIndex = 0;

            for (; startIndex < length; startIndex += 2)
            {
                if (TestScanForCharacters(
                        bytes, scanCharacters1, startIndex))
                {
                    found = true;
                    break;
                }

                if (TestScanForCharacters(
                        bytes, scanCharacters2, startIndex))
                {
                    found = true;
                    break;
                }
            }

            if (!found)
            {
                result = "no path found";
                return ReturnCode.Error;
            }

            if (encoding == null)
                encoding = Encoding.Unicode;

            try
            {
                string value = encoding.GetString(
                    bytes, startIndex, length - startIndex);

                if (!String.IsNullOrEmpty(value))
                {
                    int lastIndex = value.IndexOf(Characters.Null);

                    if (lastIndex != Index.Invalid)
                        value = value.Substring(0, lastIndex);
                }

                result = value;
                return ReturnCode.Ok;
            }
            catch (Exception e)
            {
                result = e;
            }

            return ReturnCode.Error;
        }
        #endregion

