        /// <summary>
        /// This method evaluates the specified script with the console input,
        /// output, and error streams redirected to the supplied values.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="script">
        /// The script to evaluate.
        /// </param>
        /// <param name="input">
        /// The text to use as redirected console input, if any.
        /// </param>
        /// <param name="output">
        /// Receives the redirected console output, if any.
        /// </param>
        /// <param name="error">
        /// Receives the redirected console error output, if any.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the result of the script; upon failure,
        /// receives an error message.
        /// </param>
        /// <param name="errorLine">
        /// Upon failure, receives the line number where the error occurred.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestEvaluateScriptWithConsoleRedirection(
            Interpreter interpreter, /* in */
            IScript script,          /* in */
            string input,            /* in: OPTIONAL */
            StringBuilder output,    /* in: OPTIONAL */
            StringBuilder error,     /* in: OPTIONAL */
            ref Result result,       /* out */
            ref int errorLine        /* out */
            )
        {
            TextReader inputReader = null;
            TextWriter outputWriter = null;
            TextWriter errorWriter = null;

            try
            {
                if (input != null)
                    inputReader = new StringReader(input);

                if (output != null)
                    outputWriter = new StringWriter(output);

                if (error != null)
                    errorWriter = new StringWriter(error);

                return Helpers.EvaluateScriptWithConsoleRedirection(
                    interpreter, script, inputReader, outputWriter,
                    errorWriter, ref result, ref errorLine);
            }
            finally
            {
                if (errorWriter != null)
                {
                    errorWriter.Close();
                    errorWriter = null;
                }

                if (outputWriter != null)
                {
                    outputWriter.Close();
                    outputWriter = null;
                }

                if (inputReader != null)
                {
                    inputReader.Close();
                    inputReader = null;
                }
            }
        }
