        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region XmlGetAttributeCallback Support Methods
        /// <summary>
        /// This method gets the script XML attribute getter callback associated
        /// with the specified name.
        /// </summary>
        /// <param name="name">
        /// The name of the XML attribute whose callback is retrieved.
        /// </param>
        /// <param name="delegate">
        /// Upon success, receives the callback delegate associated with the
        /// name.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestGetScriptXmlAttributeGetter(
            string name,            /* in */
            ref Delegate @delegate, /* out */
            ref Result error        /* out */
            )
        {
            lock (ScriptXmlOps.GetSyncRoot()) /* TRANSACTIONAL */
            {
                XmlGetAttributeDictionary attributeGetters =
                    ScriptXmlOps.GetAttributeGetters();

                if (attributeGetters == null)
                {
                    error = "xml attribute getters not available";
                    return ReturnCode.Error;
                }

                if (name == null)
                {
                    error = "invalid xml attribute name";
                    return ReturnCode.Error;
                }

                XmlGetAttributeCallback callback;

                if (!attributeGetters.TryGetValue(name, out callback))
                {
                    error = "xml attribute callback does not exist";
                    return ReturnCode.Error;
                }

                @delegate = callback;
                return ReturnCode.Ok;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method adds, replaces, or removes the script XML attribute
        /// getter callback associated with the specified name.
        /// </summary>
        /// <param name="name">
        /// The name of the XML attribute whose callback is changed.
        /// </param>
        /// <param name="delegate">
        /// The callback delegate to associate with the name, or null to remove
        /// the existing callback.
        /// </param>
        /// <param name="overwrite">
        /// Non-zero to overwrite an existing callback with the same name.
        /// </param>
        /// <param name="changed">
        /// Upon return, is incremented by the number of callbacks that were
        /// changed.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestChangeScriptXmlAttributeGetter(
            string name,        /* in */
            Delegate @delegate, /* in: OPTIONAL */
            bool overwrite,     /* in */
            ref int changed,    /* in, out */
            ref Result error    /* out */
            )
        {
            lock (ScriptXmlOps.GetSyncRoot()) /* TRANSACTIONAL */
            {
                XmlGetAttributeDictionary attributeGetters =
                    ScriptXmlOps.GetAttributeGetters();

                if (attributeGetters == null)
                {
                    error = "xml attribute getters not available";
                    return ReturnCode.Error;
                }

                if (name == null)
                {
                    error = "invalid xml attribute name";
                    return ReturnCode.Error;
                }

                if (@delegate != null)
                {
                    XmlGetAttributeCallback callback =
                        @delegate as XmlGetAttributeCallback;

                    if (callback == null)
                    {
                        error = "invalid xml attribute callback";
                        return ReturnCode.Error;
                    }

                    if (attributeGetters.ContainsKey(name))
                    {
                        if (overwrite)
                        {
                            changed++;
                        }
                        else
                        {
                            error = "xml attribute callback already exists";
                            return ReturnCode.Error;
                        }
                    }

                    attributeGetters[name] = callback;
                    changed++;
                }
                else if (attributeGetters.Remove(name))
                {
                    changed++;
                }
                else
                {
                    error = "xml attribute callback does not exist";
                    return ReturnCode.Error;
                }

                return ReturnCode.Ok;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method registers a script XML attribute getter callback that is
        /// appropriate for the specified value type.
        /// </summary>
        /// <param name="name">
        /// The name of the XML attribute to associate with the callback.
        /// </param>
        /// <param name="type">
        /// The value type used to select the appropriate getter callback, or
        /// null to select the callback for unset values.
        /// </param>
        /// <param name="overwrite">
        /// Non-zero to overwrite an existing callback with the same name.
        /// </param>
        /// <param name="changed">
        /// Upon return, is incremented by the number of callbacks that were
        /// changed.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddScriptXmlAttributeGetter(
            string name,     /* in */
            Type type,       /* in */
            bool overwrite,  /* in */
            ref int changed, /* in, out */
            ref Result error /* out */
            )
        {
            Delegate @delegate;

            if (type == null)
            {
                @delegate = new XmlGetAttributeCallback(
                    TestNullXmlGetAttributeCallback);
            }
            else if (type == typeof(bool))
            {
                @delegate = new XmlGetAttributeCallback(
                    TestBooleanXmlGetAttributeCallback);
            }
            else if (type == typeof(long))
            {
                @delegate = new XmlGetAttributeCallback(
                    TestInt64XmlGetAttributeCallback);
            }
            else if (type == typeof(string))
            {
                @delegate = new XmlGetAttributeCallback(
                    TestStringXmlGetAttributeCallback);
            }
            else if (type == typeof(byte[]))
            {
                @delegate = new XmlGetAttributeCallback(
                    TestByteArrayXmlGetAttributeCallback);
            }
            else if (type == typeof(StringList))
            {
                @delegate = new XmlGetAttributeCallback(
                    TestListXmlGetAttributeCallback);
            }
            else if (type == typeof(ScriptException))
            {
                @delegate = new XmlGetAttributeCallback(
                    TestErrorXmlGetAttributeCallback);
            }
            else
            {
                error = String.Format(
                    "unsupported type {0} for {1}",
                    MarshalOps.GetErrorTypeName(type),
                    MarshalOps.GetErrorTypeName(
                        typeof(XmlGetAttributeCallback)));

                return ReturnCode.Error;
            }

            return TestChangeScriptXmlAttributeGetter(
                name, @delegate, overwrite, ref changed, ref error);
        }
        #endregion

