        #region Methods for [pkgInstallLog]
        /// <summary>
        /// This method is an execute callback that logs package installation
        /// and uninstallation activity for the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="clientData">
        /// The opaque, application-specific data associated with the callback,
        /// if any.
        /// </param>
        /// <param name="arguments">
        /// The list of arguments that describe the package install activity.
        /// </param>
        /// <param name="result">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        public static ReturnCode TestPkgInstallLogCallback(
            Interpreter interpreter,
            IClientData clientData,
            ArgumentList arguments,
            ref Result result
            )
        {
            ReturnCode code = ReturnCode.Ok;

            try
            {
                bool? install;
                PkgInstallType? type;
                string name;
                string directory;

                code = TestValidatePkgInstallArguments(
                    interpreter, arguments, out install, out type,
                    out name, out directory, ref result);

                if (code != ReturnCode.Ok)
                    return code;

                string action = FormatOps.DisplayUnknown;

                if (install != null)
                    action = (bool)install ? "INSTALL" : "UNINSTALL";

                //
                // TODO: Maybe (?) send this package install information
                //       somewhere else as well, e.g. a SQLite database,
                //       etc.
                //
                TraceOps.DebugTrace(String.Format(
                    "{0}: {1} {2} AS {3} TO {4}",
                    PkgInstallLogCommandName, action,
                    FormatOps.WrapOrNull(name),
                    FormatOps.WrapOrNull(type),
                    FormatOps.WrapOrNull(directory)),
                    typeof(Default).Name,
                    TracePriority.PackageDebug5);
            }
            catch (Exception e)
            {
                result = e;
                code = ReturnCode.Error;
            }
            finally
            {
                TraceOps.DebugTrace(String.Format(
                    "TestPkgInstallLogCallback: interpreter = {0}, " +
                    "arguments = {1}, code = {2}, result = {3}",
                    FormatOps.InterpreterNoThrow(interpreter),
                    FormatOps.WrapOrNull(arguments), code,
                    FormatOps.WrapOrNull(result)),
                    typeof(Default).Name, TracePriority.PackageDebug4);
            }

            return code;
        }

