        #region Command Callback Methods
        /// <summary>
        /// This method adds a group of test commands to the specified
        /// interpreter, recording the token of each added command or any errors
        /// encountered.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to which the commands are added.
        /// </param>
        /// <param name="clientData">
        /// The opaque, application-specific data to associate with the commands,
        /// if any.
        /// </param>
        /// <param name="results">
        /// Upon return, receives the tokens of the added commands and any error
        /// messages; if null, a new list is created.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddCommands(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in */
            ref ResultList results   /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            if (interpreter.IsSafe())
            {
                if (results == null)
                    results = new ResultList();

                results.Add("permission denied: safe interpreter");
                return ReturnCode.Error;
            }

            int errorCount = 0;
            long token; /* REUSED */
            Result result; /* REUSED */

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("seti",
                    TestSetImmutableCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("writable",
                    TestWritableCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("exists",
                    TestExistsCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("vadd",
                    TestAddVariableCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("vusable",
                    TestUsableVariableCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("vislocked",
                    TestIsLockedVariableCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("vlock",
                    TestLockVariableCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback("vunlock",
                    TestUnlockVariableCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                if (token != 0)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(token);
                }
            }
            else
            {
                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                errorCount++;
            }

            return (errorCount > 0) ? ReturnCode.Error : ReturnCode.Ok;
        }
        #endregion

