        /// <summary>
        /// This method evaluates the specified script within the specified
        /// application domain, optionally emitting diagnostic trace output on
        /// failure.
        /// </summary>
        /// <param name="appDomain">
        /// The application domain in which to evaluate the script.
        /// </param>
        /// <param name="text">
        /// The script to evaluate.
        /// </param>
