        #region Methods for SimulateKeyboardString
#if NATIVE && WINDOWS
        /// <summary>
        /// This method starts a background worker that simulates keyboard input
        /// by playing the characters read from the specified text reader.
        /// </summary>
        /// <param name="milliseconds">
        /// The delay, in milliseconds, between simulated keystrokes, or null to
        /// use the default delay.
        /// </param>
        /// <param name="textReader">
        /// The text reader that supplies the characters to simulate.
        /// </param>
        /// <param name="stopEvent">
        /// The event that, when signaled, stops the simulation.
        /// </param>
        /// <param name="doneEvent">
        /// The event that is signaled when the simulation has completed.
        /// </param>
        /// <param name="flags">
        /// The flags that control how the keystrokes are simulated.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestStartKeyboardStream(
            int? milliseconds,         /* in */
            TextReader textReader,     /* in */
            EventWaitHandle stopEvent, /* in */
            EventWaitHandle doneEvent, /* in */
            SimulatedKeyFlags flags,   /* in */
            ref Result error           /* out */
            )
        {
            int localMilliseconds;

            if (milliseconds != null)
                localMilliseconds = (int)milliseconds;
            else
                localMilliseconds = PlayKeyboardMilliseconds;

            if (ThreadOps.QueueUserWorkItem(
                    new WaitCallback(
                        TestPlayKeyboardStreamThreadStart),
                    new NativeTriplet(
                        true, textReader, new EventTriplet(
                            stopEvent, doneEvent, flags),
                        localMilliseconds), false))
            {
                return ReturnCode.Ok;
            }
            else
            {
                error = "could not start stream";
                return ReturnCode.Error;
            }
        }

