        #region Methods for Fail-Safe
        /// <summary>
        /// This method performs a fail-safe abort of the current process,
        /// optionally emitting diagnostic trace output beforehand. This method
        /// does not return under normal circumstances.
        /// </summary>
        /// <param name="returnCode">
        /// The return code to include in the diagnostic output, if any.
        /// </param>
        /// <param name="result">
        /// The result to include in the diagnostic output, if any.
        /// </param>
        /// <param name="whatIf">
        /// Non-zero to simulate the abort without actually terminating the
        /// process.
        /// </param>
        /// <param name="withTrace">
        /// Non-zero to emit diagnostic trace output prior to aborting.
        /// </param>
        public static void TestFailSafeAbortWithTrace( /* NO-RETURN */
            ReturnCode? returnCode, /* in: OPTIONAL */
            Result result,          /* in: OPTIONAL */
            bool whatIf,            /* in */
            bool withTrace          /* in */
            )
        {
            Interlocked.Increment(ref FailSafeCount);

            ///////////////////////////////////////////////////////////////////////////////////////////

            string formatted = null;

            if (withTrace)
            {
                try
                {
                    string format;
                    string category;
                    TracePriority priority;

                    TestGetFailSafeTraceParameters(
                        out format, out category,
                        out priority);

                    if (!String.IsNullOrEmpty(format))
                    {
                        formatted = String.Format(
                            format, ResultOps.Format(
                            returnCode, result, true));

#if NATIVE
                        DebugOps.Output(formatted,
                            DebugPriority.FromFailSafe);
#endif

                        TraceOps.DebugTrace(
                            formatted, category,
                            priority); /* throw */
                    }

                    DebugOps.Flush();
                }
                catch
                {
                    // do nothing.
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            TestExitNow(FailSafeExitCode, formatted, whatIf);
            TestKillOrAbortSelfNow(whatIf);
        }
        #endregion

