        /// <summary>
        /// This method returns the recorded command line options, optionally
        /// filtered by a pattern.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context used when matching the pattern.
        /// </param>
        /// <param name="pattern">
        /// The glob pattern used to filter the option names, or null for no
        /// filtering.
        /// </param>
        /// <param name="nameOnly">
        /// Non-zero to include only the option names; zero to include both the
        /// names and their values.
        /// </param>
        /// <returns>
        /// A list of the matching command line options, or null if none have
        /// been recorded.
        /// </returns>
        public static StringList TestShellGetOptions(
            Interpreter interpreter,
            string pattern,
            bool nameOnly
            ) /* THREAD-SAFE */
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (commandLineOptions == null)
                    return null;

                StringList list = new StringList();

                foreach (CLOPair pair in commandLineOptions)
                {
                    if ((pattern != null) && !StringOps.Match(
                            interpreter, MatchMode.Glob,
                            pair.Key, pattern, false))
                    {
                        continue;
                    }

                    if (nameOnly)
                    {
                        list.Add(pair.Key);
                    }
                    else
                    {
                        list.Add(StringList.MakeList(
                            pair.Key, pair.Value));
                    }
                }

                return list;
            }
        }

