        /// <summary>
        /// This method formats the keys and values of the specified dictionary
        /// into a string list, using a default dictionary when none is
        /// supplied.
        /// </summary>
        /// <param name="dictionary">
        /// The dictionary whose keys and values are formatted, or null to use a
        /// default dictionary.
        /// </param>
        /// <param name="pairs">
        /// Non-zero to emit each key and value together as a pair.
        /// </param>
        /// <param name="keys">
        /// Non-zero to include the keys in the output.
        /// </param>
        /// <param name="values">
        /// Non-zero to include the values in the output.
        /// </param>
        /// <param name="mode">
        /// The matching mode used when applying the key and value patterns.
        /// </param>
        /// <param name="keyPattern">
        /// The pattern used to filter the keys, or null for no filtering.
        /// </param>
        /// <param name="valuePattern">
        /// The pattern used to filter the values, or null for no filtering.
        /// </param>
        /// <param name="keyFormat">
        /// The format string applied to each key, or null for none.
        /// </param>
        /// <param name="valueFormat">
        /// The format string applied to each value, or null for none.
        /// </param>
        /// <param name="formatProvider">
        /// The format provider used when formatting keys and values.
        /// </param>
        /// <param name="noCase">
        /// Non-zero to perform pattern matching without regard to case.
        /// </param>
        /// <returns>
        /// A string list containing the formatted keys and values.
        /// </returns>
        public static IStringList TestToStringFormat(
            IDictionary<long, double> dictionary,
            bool pairs,
            bool keys,
            bool values,
            MatchMode mode,
            string keyPattern,
            string valuePattern,
            string keyFormat,
            string valueFormat,
            IFormatProvider formatProvider,
            bool noCase
            )
        {
            if (dictionary == null)
            {
                dictionary = new Dictionary<long, double>();

                dictionary.Add(long.MinValue, double.MinValue);
                dictionary.Add(-1, -1.0);
                dictionary.Add(0, 0.0);
                dictionary.Add(1, 1.0);
                dictionary.Add(long.MaxValue, double.MaxValue);
            }

            return GenericOps<long, double>.KeysAndValues(
                dictionary, pairs, keys, values, mode,
                keyPattern, valuePattern, keyFormat,
                valueFormat, formatProvider, noCase);
        }

