        /// <summary>
        /// This method creates a variable that is missing from the specified
        /// call frame within the given interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context in which the variable is created.
        /// </param>
        /// <param name="variableFrame">
        /// The call frame in which the variable is created.
        /// </param>
        /// <param name="varName">
        /// The name of the variable to create.
        /// </param>
        /// <param name="varValue">
        /// The initial value of the variable.
        /// </param>
        /// <param name="traces">
        /// The list of traces to associate with the variable, if any.
        /// </param>
        /// <param name="dirty">
        /// Non-zero to mark the newly created variable as dirty.
        /// </param>
        /// <param name="variableFlags">
        /// Upon entry, the flags that control how the variable is created; upon
        /// return, the flags that were actually used.
        /// </param>
        /// <param name="variable">
        /// Upon success, receives the variable that was created.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestCreateMissingVariable(
            Interpreter interpreter,
            ICallFrame variableFrame,
            string varName,
            object varValue,
            TraceList traces,
            bool dirty,
            ref VariableFlags variableFlags,
            ref IVariable variable,
            ref Result error
            )
        {
            variableFlags &= ~VariableFlags.ErrorMask; // GetVariable

            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            IVariable localVariable;

            interpreter.CreateMissingVariable(
                variableFrame, varName, varValue, traces,
                dirty, ref variableFlags, out localVariable);

            variable = localVariable;
            return ReturnCode.Ok;
        }

