        /// <summary>
        /// This method creates a thread-local variable within the specified
        /// interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context in which the variable is created.
        /// </param>
        /// <param name="variableFlags">
        /// The flags that control how the variable is created.
        /// </param>
        /// <param name="name">
        /// The name of the variable to create.
        /// </param>
        /// <param name="variable">
        /// Upon success, receives the thread variable that was created.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestCreateThreadVariable(
            Interpreter interpreter,
            VariableFlags variableFlags,
            string name,
            ref object variable,
            ref Result error
            )
        {
            bool success = false;
            ThreadVariable threadVariable = null;

            try
            {
                threadVariable = ThreadVariable.Create();

                if (threadVariable == null)
                {
                    error = String.Format(
                        "could not create thread variable {0}",
                        FormatOps.ErrorVariableName(name));

                    return ReturnCode.Error;
                }

                if (threadVariable.AddVariable(
                        interpreter, variableFlags, name,
                        ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }

                variable = threadVariable;
                success = true;

                return ReturnCode.Ok;
            }
            catch (Exception e)
            {
                error = e;
                return ReturnCode.Error;
            }
            finally
            {
                if (!success && (threadVariable != null))
                {
                    threadVariable.Dispose();
                    threadVariable = null;
                }
            }
        }

