        /// <summary>
        /// This method changes the native callback delegate associated with the
        /// specified native callback type, optionally supplying a default
        /// delegate automatically.
        /// </summary>
        /// <param name="callbackType">
        /// The type of native callback to change.
        /// </param>
        /// <param name="automatic">
        /// Non-zero to automatically supply a default callback delegate when one
        /// is not provided.
        /// </param>
        /// <param name="delegate">
        /// Upon entry, the new callback delegate to install; upon return, the
        /// previous callback delegate.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestChangeNativeCallback(
            NativeCallbackType callbackType, /* in */
            bool automatic,                  /* in */
            ref Delegate @delegate,          /* in, out */
            ref Result error                 /* out */
            )
        {
            if (automatic && (@delegate == null))
            {
                switch (callbackType)
                {
                    case NativeCallbackType.IsMainThread:
                        {
                            @delegate = new NativeIsMainThreadCallback(
                                TestNativeIsMainThreadCallback);

                            break;
                        }
                    case NativeCallbackType.GetStackPointer:
                    case NativeCallbackType.GetStackAllocated:
                    case NativeCallbackType.GetStackMaximum:
                    case NativeCallbackType.UnixGetStackMaximum:
                        {
                            @delegate = new NativeStackCallback(
                                TestNativeStackCallback);

                            break;
                        }
                }
            }

            return NativeStack.ChangeCallback(
                callbackType, ref @delegate, ref error);
        }

