        /// <summary>
        /// This method installs, uninstalls, or queries the debug interactive
        /// loop callback for the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to modify or query.
        /// </param>
        /// <param name="setup">
        /// Non-zero to install the debug callback; zero to uninstall it; null
        /// to query whether it is currently installed.
        /// </param>
        /// <param name="quiet">
        /// Non-zero to suppress diagnostic trace output.
        /// </param>
        /// <returns>
        /// True if the callback was changed, or is currently installed when
        /// querying; otherwise, false.
        /// </returns>
        public static bool TestSetDebugInteractiveLoopCallback(
            Interpreter interpreter,
            bool? setup,
            bool quiet
            )
        {
            if (interpreter == null)
                return false;

            lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
            {
                if (Interpreter.IsDeletedOrDisposed(interpreter, false))
                    return false;

                bool result = false;

                if (setup != null)
                {
                    if ((bool)setup)
                    {
                        if (!TestIsDebugInteractiveLoopCallback(
                                interpreter.InteractiveLoopCallback))
                        {
                            TestEnableDebugInteractiveLoopCallback(
                                interpreter);

                            result = true;
                        }
                    }
                    else
                    {
                        if (!TestIsSavedInteractiveLoopCallback(
                                interpreter.InteractiveLoopCallback))
                        {
                            TestDisableDebugInteractiveLoopCallback(
                                interpreter);

                            result = true;
                        }
                    }

                    if (!quiet)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "TestSetDebugInteractiveLoopCallback: HOOK {0}{1}.",
                            result ? String.Empty : "already ", (bool)setup ?
                            "installed" : "uninstalled"), typeof(Default).Name,
                            TracePriority.ScriptDebug2);
                    }
                }
                else
                {
                    result = TestIsDebugInteractiveLoopCallback(
                        interpreter.InteractiveLoopCallback);
                }

                return result;
            }
        }

