        /// <summary>
        /// This method parses command line style options from the specified
        /// argument list using the identifier looked up by kind and name.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="kind">
        /// The kind of identifier to look up.
        /// </param>
        /// <param name="name">
        /// The name of the identifier to look up.
        /// </param>
        /// <param name="options">
        /// The options that are recognized during parsing, if any.
        /// </param>
        /// <param name="arguments">
        /// The list of arguments to parse.
        /// </param>
        /// <param name="lookupFlags">
        /// The flags that control how the identifier is looked up.
        /// </param>
        /// <param name="endOfOptions">
        /// Non-zero to add an explicit end-of-options marker to the recognized
        /// options.
        /// </param>
        /// <param name="argumentIndex">
        /// Upon return, receives the index of the next argument following the
        /// parsed options.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestGetOptions(
            Interpreter interpreter,
            IdentifierKind kind,
            string name,
            IEnumerable<IOption> options,
            ArgumentList arguments,
            LookupFlags lookupFlags,
            bool endOfOptions,
            ref int argumentIndex,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            IIdentifier identifier = null;

            if (interpreter.GetIdentifier(
                    kind, name, arguments, lookupFlags, ref identifier,
                    ref error) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            OptionDictionary localOptions = null;

            if (options != null)
                localOptions = new OptionDictionary(options);

            if (endOfOptions)
            {
                if (localOptions == null)
                    localOptions = new OptionDictionary();

                localOptions.Add(Option.CreateEndOfOptions());
            }

            return interpreter.GetOptions(
                identifier, localOptions, arguments, ref argumentIndex,
                ref error);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method parses command line style options from the specified
        /// argument list within the given index range.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="arguments">
        /// The list of arguments to parse.
        /// </param>
        /// <param name="options">
        /// The options that are recognized during parsing, if any.
        /// </param>
        /// <param name="listCount">
        /// The number of arguments in the list to consider.
        /// </param>
        /// <param name="startIndex">
        /// The index at which to begin parsing.
        /// </param>
        /// <param name="stopIndex">
        /// The index at which to stop parsing.
        /// </param>
        /// <param name="behaviorFlags">
        /// The flags that control how options are parsed.
        /// </param>
        /// <param name="endOfOptions">
        /// Non-zero to add an explicit end-of-options marker to the recognized
        /// options.
        /// </param>
        /// <param name="noCase">
        /// Non-zero to match option names without regard to case.
        /// </param>
        /// <param name="noValue">
        /// Non-zero to skip processing of option values.
        /// </param>
        /// <param name="noSet">
        /// Non-zero to avoid setting the parsed option values.
        /// </param>
        /// <param name="nextIndex">
        /// Upon return, receives the index of the next argument following the
        /// parsed options.
        /// </param>
        /// <param name="endIndex">
        /// Upon return, receives the index at which option parsing ended.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestGetOptions(
            Interpreter interpreter,
            ArgumentList arguments,
            IEnumerable<IOption> options,
            int listCount,
            int startIndex,
            int stopIndex,
            OptionBehaviorFlags behaviorFlags,
            bool endOfOptions,
            bool noCase,
            bool noValue,
            bool noSet,
            ref int nextIndex,
            ref int endIndex,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            OptionDictionary localOptions = null;

            if (options != null)
                localOptions = new OptionDictionary(options);

            if (endOfOptions)
            {
                if (localOptions == null)
                    localOptions = new OptionDictionary();

                localOptions.Add(Option.CreateEndOfOptions());
            }

            if (interpreter.GetOptions(
                    localOptions, arguments, listCount,
                    startIndex, stopIndex, behaviorFlags,
                    noCase, noValue, noSet, ref nextIndex,
                    ref endIndex, ref error) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            return ReturnCode.Ok;
        }

