        /// The "about" text for the core plugin, or null on failure.
        /// </returns>
        public static string TestCorePluginAbout(
            Interpreter interpreter,
            bool showCertificate,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return null;
            }

            IPlugin plugin = interpreter.GetCorePlugin(ref error);

            if (plugin == null)
                return null;

            Result localResult = null;

            if (HelpOps.GetPluginAbout(
                    interpreter, plugin, showCertificate,
                    ref localResult) != ReturnCode.Ok)
            {
                error = localResult;
                return null;
            }

            return localResult;
        }
