        /// <summary>
        /// This method retrieves a resource string from the host associated
        /// with the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context whose host is queried.
        /// </param>
        /// <param name="name">
        /// The name of the resource to retrieve.
        /// </param>
        /// <param name="scriptFlags">
        /// Upon entry, the script flags that control how the resource is
        /// located; upon return, the script flags that were actually used.
        /// </param>
        /// <param name="clientData">
        /// Upon return, receives any opaque, application-specific data that is
        /// associated with the resource.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// The resource string, or null if it could not be retrieved.
        /// </returns>
        public static string TestGetResourceString(
            Interpreter interpreter,
            string name,
            ref ScriptFlags scriptFlags,
            ref IClientData clientData,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return null;
            }

            if (name == null)
            {
                error = "invalid name";
                return null;
            }

            try
            {
                IFileSystemHost fileSystemHost = interpreter.InternalHost;

                if (fileSystemHost == null)
                {
                    error = "interpreter host not available";
                    return null;
                }

                scriptFlags |= ScriptFlags.CoreAssemblyOnly;

                ScriptOps.MaybeExactNameOnly(
                    interpreter, name, null, ref scriptFlags);

                Result result = null;

                if (fileSystemHost.GetData(
                        name, HostOps.CombineDataFlags(
                            interpreter, name, scriptFlags,
                            DataFlags.Script),
                        ref scriptFlags, ref clientData,
                        ref result) == ReturnCode.Ok)
                {
                    return result;
                }
                else
                {
                    error = result;
                }
            }
            catch (Exception e)
            {
                TraceOps.DebugTrace(
                    e, typeof(Default).Name,
                    TracePriority.HostError);

                error = e;
            }

            return null;
        }

