        {
#if ISOLATED_PLUGINS
            if (interpreter != null)
            {
                lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
                {
                    if (Interpreter.IsDeletedOrDisposed(interpreter, false))
                        return false;

                    return FlagOps.HasFlags(
                        interpreter.PluginFlags, PluginFlags.Isolated, true);
                }
            }
#endif

            return false;
        }

