        /// <summary>
        /// This method enables or disables the complaint host flag for the
        /// interactive host associated with the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context whose interactive host is modified.
        /// </param>
        /// <param name="complain">
        /// Non-zero to enable the complaint host flag; zero to disable it.
        /// </param>
        /// <returns>
        /// True if the host flag was changed successfully; otherwise, false.
        /// </returns>
        public static bool TestSetComplain(
            Interpreter interpreter,
            bool complain
            )
        {
            if (interpreter == null)
                return false;

            IInteractiveHost interactiveHost = interpreter.GetInteractiveHost();

            if (interactiveHost == null)
                return false;

            FieldInfo fieldInfo = interactiveHost.GetType().GetField(
                "hostFlags", ObjectOps.GetBindingFlags(
                    MetaBindingFlags.PrivateInstanceGetField, true));

            if (fieldInfo == null)
                return false;

            HostFlags hostFlags = (HostFlags)fieldInfo.GetValue(
                interactiveHost);

            if (complain)
                hostFlags |= HostFlags.Complain;
            else
                hostFlags &= ~HostFlags.Complain;

            fieldInfo.SetValue(interactiveHost, hostFlags);
            return true;
        }

