        /// <summary>
        /// This method disposes the specified interpreter, either synchronously
        /// or asynchronously via a queued work item, depending on the specified
        /// flags.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to dispose.
        /// </param>
        /// <param name="timeout">
        /// The number of milliseconds to wait when disposing the interpreter.
        /// </param>
        /// <param name="flags">
        /// The flags that control how the work item is queued.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestDisposeInterpreter(
            Interpreter interpreter,
            int timeout,
            QueueFlags flags,
            ref Result error
            )
        {
            if (FlagOps.HasFlags(flags, QueueFlags.Asynchronous, true))
            {
                if (Engine.QueueWorkItem(
                        new WaitCallback(TestDisposeInterpreterWaitCallback),
                        new AnyPair<int, Interpreter>(timeout, interpreter),
                        flags))
                {
                    return ReturnCode.Ok;
                }
                else
                {
                    error = "could not queue work item";
                }
            }
            else if (TestDisposeInterpreter(
                    timeout, ref interpreter, ref error))
            {
                return ReturnCode.Ok;
            }

            return ReturnCode.Error;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method creates an interpreter, optionally evaluates a script
        /// within it, releases all references to it, and then forces garbage
        /// collection in order to verify that the interpreter is disposed
        /// within the specified timeout.
        /// </summary>
        /// <param name="text">
        /// The script to evaluate within the created interpreter, or null for
        /// none.
        /// </param>
        /// <param name="timeout">
        /// The maximum number of milliseconds to wait for the interpreter to be
        /// disposed.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes the failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestDisposeInterpreterViaGc(
            string text,
            int timeout,
            ref Result error
            )
        {
            try
            {
                Interpreter interpreter;
                Result result = null; /* REUSED */

                interpreter = Interpreter.Create(ref result);

                if (interpreter == null)
                {
                    error = result;
                    return ReturnCode.Error;
                }

                if (text != null)
                {
                    ReturnCode code;

                    result = null;

                    code = interpreter.EvaluateScript(text, ref result);

                    if (code != ReturnCode.Ok)
                    {
                        error = result;
                        return code;
                    }
                }

                DateTime oldNow = TimeOps.GetUtcNow();
                DateTime stopNow = oldNow.AddMilliseconds(timeout);

                int oldCount = Interpreter.GlobalDisposeCount;

                interpreter.ClearReferences();
                interpreter = null; /* NOTE: No more references. */

                while (true) /* NOTE: Must timeout or dispose. */
                {
                    ObjectOps.CollectGarbage(); /* NOTE: Dispose now? */

                    int newCount = Interpreter.GlobalDisposeCount;

                    if (newCount > oldCount)
                        return ReturnCode.Ok;

                    DateTime newNow = TimeOps.GetUtcNow();

                    if (newNow >= stopNow)
                        break;
                }

                error = String.Format(
                    "interpreter was not disposed in {0} milliseconds",
                    timeout);

                return ReturnCode.Error;
            }
            catch (Exception e)
            {
                error = e;
                return ReturnCode.Error;
            }
        }

