        /// <summary>
        /// This method loads a plugin into the specified interpreter from the
        /// raw bytes of an assembly file (and its debugging symbols, if any),
        /// adding it to the interpreter upon success.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context into which the plugin is loaded.
        /// </param>
        /// <param name="assemblyFileName">
        /// The fully qualified file name of the assembly to load.
        /// </param>
        /// <param name="evidence">
        /// The Code Access Security evidence to use when loading the assembly.
        /// </param>
        /// <param name="typeName">
        /// The name of the plugin type to instantiate, or null to detect it
        /// automatically.
        /// </param>
        /// <param name="clientData">
        /// The opaque, application-specific data to associate with the plugin,
        /// if any.
        /// </param>
        /// <param name="pluginFlags">
        /// The flags that control how the plugin is loaded.
        /// </param>
        /// <param name="plugin">
        /// Upon success, receives the plugin that was loaded.
        /// </param>
        /// <param name="token">
        /// Upon success, receives the token that identifies the added plugin.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the result; upon failure, receives an error
        /// message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestLoadPluginViaBytes(
            Interpreter interpreter,
            string assemblyFileName,
#if CAS_POLICY
            Evidence evidence,
#endif
            string typeName,
            IClientData clientData,
            PluginFlags pluginFlags,
            ref IPlugin plugin,
            ref long token,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (String.IsNullOrEmpty(assemblyFileName))
            {
                result = "invalid assembly file name";
                return ReturnCode.Error;
            }

            if (!File.Exists(assemblyFileName))
            {
                result = String.Format(
                    "cannot load plugin: assembly file {0} does not exist",
                    FormatOps.WrapOrNull(assemblyFileName));

                return ReturnCode.Error;
            }

            if (plugin != null)
            {
                result = "cannot overwrite valid plugin";
                return ReturnCode.Error;
            }

            if (token != 0)
            {
                result = "cannot overwrite valid plugin token";
                return ReturnCode.Error;
            }

            ReturnCode code = ReturnCode.Ok;

            try
            {
                //
                // NOTE: Figure out what the debug symbols file for the
                //       assembly would be if it actually existed.
                //
                string symbolFileName = PathOps.GetNativePath(
                    PathOps.CombinePath(null, Path.GetDirectoryName(
                    assemblyFileName), Path.GetFileNameWithoutExtension(
                    assemblyFileName) + FileExtension.Symbols)); /* throw */

                byte[] assemblyBytes = File.ReadAllBytes(
                    assemblyFileName); /* throw */

                byte[] symbolBytes = File.Exists(symbolFileName) ?
                    File.ReadAllBytes(symbolFileName) : null; /* throw */

                code = interpreter.LoadPlugin(assemblyBytes, symbolBytes,
#if CAS_POLICY
                    evidence,
#endif
                    typeName, clientData, pluginFlags, ref plugin, ref result);

                if (code == ReturnCode.Ok)
                {
                    code = interpreter.AddPlugin(
                        plugin, clientData, ref token, ref result);
                }

                return code;
            }
            catch (Exception e)
            {
                result = e;
            }
            finally
            {
                if ((code != ReturnCode.Ok) && (plugin != null))
                {
                    ReturnCode unloadCode;
                    Result unloadResult = null;

                    unloadCode = interpreter.UnloadPlugin(
                        plugin, clientData, pluginFlags, ref unloadResult);

                    if (unloadCode != ReturnCode.Ok)
                        DebugOps.Complain(interpreter, unloadCode, unloadResult);
                }
            }

            return ReturnCode.Error;
        }

