        /// <summary>
        /// This method renames an existing namespace within the specified
        /// interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context that contains the namespace.
        /// </param>
        /// <param name="oldName">
        /// The name of the existing namespace to rename.
        /// </param>
        /// <param name="newName">
        /// The new, unqualified name for the namespace.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message that describes why the
        /// namespace could not be renamed.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestRenameNamespace(
            Interpreter interpreter,
            string oldName,
            string newName,
            ref Result error
            )
        {
            if (String.IsNullOrEmpty(newName))
            {
                error = "invalid or empty new namespace name";
                return ReturnCode.Error;
            }

            if (NamespaceOps.IsQualifiedName(newName))
            {
                error = "new namespace name must not be qualified";
                return ReturnCode.Error;
            }

            INamespace @namespace = NamespaceOps.Lookup(
                interpreter, oldName, false, false, ref error);

            if (@namespace == null)
                return ReturnCode.Error;

            try
            {
                @namespace.Name = newName;
                return ReturnCode.Ok;
            }
            catch (Exception e)
            {
                error = e;
                return ReturnCode.Error;
            }
        }

