        /// <summary>
        /// This method executes a fixed set of static delegate callbacks via
        /// the script engine, recording the return code and result produced by
        /// each one.
        /// </summary>
        /// <param name="arguments">
        /// The list of arguments to pass to each delegate.
        /// </param>
        /// <param name="returnCodes">
        /// Upon return, receives the return code produced by each delegate that
        /// was executed; if null, a new list is created.
        /// </param>
        /// <param name="results">
        /// Upon return, receives the result produced by each delegate that was
        /// executed; if null, a new list is created.
        /// </param>
        public static void TestExecuteStaticDelegates(
            ArgumentList arguments,         /* in */
            ref ReturnCodeList returnCodes, /* in, out */
            ref ResultList results          /* in, out */
            )
        {
            if (returnCodes == null)
                returnCodes = new ReturnCodeList();

            if (results == null)
                results = new ResultList();

            ReturnCode code;
            Result result = null;

            code = Engine.ExecuteDelegate(
                new VoidWithStringCallback(TestVoidMethod),
                arguments, ref result);

            returnCodes.Add(code);
            results.Add(result);

            code = Engine.ExecuteDelegate(
                new LongWithDateTimeCallback(TestLongMethod),
                arguments, ref result);

            returnCodes.Add(code);
            results.Add(result);

            code = Engine.ExecuteDelegate(
                new IEnumerableWithICommandCallback(TestIEnumerableMethod),
                arguments, ref result);

            returnCodes.Add(code);
            results.Add(result);
        }

