        /// <summary>
        /// This method is a test change-type callback that converts the
        /// specified text into an <see cref="IntPtr" /> value, optionally
        /// truncating a 64-bit pointer value to 32-bits.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context; this parameter is not used.
        /// </param>
        /// <param name="type">
        /// The target type; this parameter is not used.
        /// </param>
        /// <param name="text">
        /// The text to convert into a pointer value.
        /// </param>
        /// <param name="options">
        /// The options that may influence the conversion; this parameter is
        /// not used.
        /// </param>
        /// <param name="cultureInfo">
        /// The culture used when interpreting the text.
        /// </param>
        /// <param name="clientData">
        /// The optional client data; this parameter is not used.
        /// </param>
        /// <param name="marshalFlags">
        /// The marshalling flags; this parameter is not used.
        /// </param>
        /// <param name="value">
        /// Upon success, receives the resulting pointer value.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestToIntPtr(
            Interpreter interpreter, /* NOT USED */
            Type type, /* NOT USED */
            string text,
            OptionDictionary options, /* NOT USED */
            CultureInfo cultureInfo,
            IClientData clientData, /* NOT USED */
            ref MarshalFlags marshalFlags, /* NOT USED */
            ref object value,
            ref Result error
            )
        {
            long longValue = 0;

            if (Value.GetWideInteger2(
                    text, ValueFlags.AnyWideInteger, cultureInfo,
                    ref longValue, ref error) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            //
            // HACK: Maybe truncate 64-bit pointer value to 32-bit.
            //
            if (PlatformOps.Is64BitProcess())
                value = new IntPtr(longValue);
            else
                value = new IntPtr(ConversionOps.ToInt(longValue));

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method installs or removes the test change-type callback for
        /// the <see cref="IntPtr" /> type on the script binder of the
        /// specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose script binder will be modified.
        /// </param>
        /// <param name="install">
        /// Non-zero to install the callback; zero to remove it.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestIntPtrChangeTypeCallback(
            Interpreter interpreter,
            bool install,
            ref Result error
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            IScriptBinder scriptBinder = interpreter.InternalBinder as IScriptBinder;

            if (scriptBinder == null)
            {
                error = "invalid script binder";
                return ReturnCode.Error;
            }

            if (install)
            {
                if (scriptBinder.AddChangeTypeCallback(
                        typeof(IntPtr), TestToIntPtr,
                        ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }
            }
            else
            {
                if (scriptBinder.RemoveChangeTypeCallback(
                        typeof(IntPtr), ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }
            }

            return ReturnCode.Ok;
        }

