        /// <summary>
        /// This method invokes the specified callback delegate via dynamic
        /// invocation, accommodating a single object array parameter.
        /// </summary>
        /// <param name="callback">
        /// The callback delegate to invoke.
        /// </param>
        /// <param name="args">
        /// The arguments to pass to the callback.
        /// </param>
        /// <returns>
        /// The value returned by the callback.
        /// </returns>
        public static object TestCallStaticDynamicCallback0(
            Delegate callback,
            params object[] args
            )
        {
            if (callback == null)
                throw new ArgumentNullException("callback");

            if (TestHasOnlyObjectArrayParameter(callback))
                return callback.DynamicInvoke(new object[] { args });
            else
                return callback.DynamicInvoke(args);
        }

