        public static object TestCallStaticDynamicCallback1(
            DynamicInvokeCallback callback,
            params object[] args
            )
        {
            if (callback == null)
                throw new ArgumentNullException("callback");

            if (staticDynamicInvoke)
                return callback.DynamicInvoke(new object[] { args });
            else
