        /// <summary>
        /// This method invokes the specified three-argument callback, either
        /// directly or via dynamic invocation.
        /// </summary>
        /// <param name="callback">
        /// The callback delegate to invoke.
        /// </param>
        /// <param name="args">
        /// The arguments to pass to the callback.
        /// </param>
        /// <param name="value">
        /// The value to pass to the callback.
        /// </param>
        /// <param name="data">
        /// On input, a value to pass to the callback; upon return, receives
        /// the value produced by the callback.
        /// </param>
        public static void TestCallStaticDynamicCallback3(
            ThreeArgsDelegate callback,
            object[] args,
            int value,
            ref object data
            )
        {
            if (callback == null)
                throw new ArgumentNullException("callback");

            if (staticDynamicInvoke)
            {
                object[] newArgs = new object[] { args, value, data };

                callback.DynamicInvoke(newArgs);
                data = newArgs[newArgs.Length - 1];
            }
            else
            {
                callback(args, value, ref data);
            }
        }

