        /// <summary>
        /// This method returns a collection of delegates referring to the
        /// test static dynamic callbacks.
        /// </summary>
        /// <returns>
        /// A collection of delegates referring to the test static dynamic
        /// callbacks.
        /// </returns>
        public static IEnumerable<Delegate> TestGetStaticDynamicCallbacks()
