        /// <summary>
        /// This method sums the elements of the specified integer array,
        /// treating a null array as a special case.
        /// </summary>
        /// <param name="array">
        /// The integer array whose elements will be summed.
        /// </param>
        /// <returns>
        /// The sum of the array elements, or negative one if the array is
        /// null.
        /// </returns>
        public static int TestNullArray(
            int[] array
            )
        {
            if (array == null)
                return -1;

            int count = 0;

            foreach (int element in array)
                count += element;

            return count;
        }

