        /// </param>
        /// <param name="varName">
        /// The name of the variable to set.
        /// </param>
        /// <param name="varIndex">
        /// The array index of the variable to set, if any.
        /// </param>
        /// <param name="varValue">
        /// The value to assign to the variable.
        /// </param>
        /// <param name="create">
        /// Non-zero to populate the array; zero to leave it unchanged.
        /// </param>
        /// <param name="array">
        /// The string array to test; it may be populated.
        /// </param>
        /// <returns>
        /// Always returns true.
        /// </returns>
        public static bool TestByRefArray(
            Interpreter interpreter,
            VariableFlags variableFlags,
            string varName,
            string varIndex,
            object varValue,
            bool create,
            ref string[] array
            )
        {
            if ((interpreter != null) && (varName != null))
            {
                ReturnCode code;
                IVariable variable = null; /* NOT USED */
                Result error = null;

                code = interpreter.SetVariableValue2(
                    variableFlags, null, varName, varIndex,
                    varValue, null, ref variable, ref error);

                if (code != ReturnCode.Ok)
                    DebugOps.Complain(interpreter, code, error);
            }

            return TestByRefArray(create, ref array);
        }

