        /// <summary>
        /// This method installs or removes a test callback that controls the
        /// current date and time used by the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose date and time callback will be changed.
        /// </param>
        /// <param name="dateTime">
        /// The date and time value to use as the current time when the
        /// callback is enabled.
        /// </param>
        /// <param name="increment">
        /// The amount to advance the current time on each query.
        /// </param>
        /// <param name="enable">
        /// Non-zero to install the test callback; zero to restore the previous
        /// callback.
        /// </param>
        /// <returns>
        /// True if the callback was changed successfully; otherwise, false.
        /// </returns>
        public static bool TestSetDateTimeNowCallback(
            Interpreter interpreter,
            DateTime dateTime,
            long increment,
            bool enable
            )
        {
            if (interpreter == null)
                return false;

            IEventManager eventManager = interpreter.EventManager;

            if (!EventOps.ManagerIsOk(eventManager))
                return false;

            if (enable)
            {
                now = dateTime;
                nowCallback = eventManager.NowCallback; /* save */
                nowIncrement = increment;
                eventManager.NowCallback = TestDateTimeNow; /* set */
            }
            else
            {
                now = DateTime.MinValue;
                eventManager.NowCallback = nowCallback; /* restore */
                nowCallback = null; /* clear */
                nowIncrement = 0;
            }

            return true;
        }

