        /// <summary>
        /// This method enables or disables plugin isolation for the specified
        /// interpreter, complaining if the operation fails.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose plugin isolation will be changed.
        /// </param>
        /// <param name="enable">
        /// Non-zero to enable plugin isolation; zero to disable it.
        /// </param>
        public static void TestSetPluginIsolation(
            Interpreter interpreter,
            bool enable
            )
        {
            ReturnCode code;
            Result result = null;

            code = TestSetPluginIsolation(interpreter, enable, ref result);

            if (code != ReturnCode.Ok)
                DebugOps.Complain(interpreter, code, result);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method enables or disables plugin isolation for the specified
        /// interpreter, reporting the prior and current states.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose plugin isolation will be changed.
        /// </param>
        /// <param name="enable">
        /// Non-zero to enable plugin isolation; zero to disable it.
        /// </param>
        /// <param name="result">
        /// Upon success, receives a list describing the prior and current
        /// plugin isolation states; upon failure, receives information about
        /// the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestSetPluginIsolation(
            Interpreter interpreter,
            bool enable,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

#if ISOLATED_PLUGINS
            lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
            {
                if (Interpreter.IsDeletedOrDisposed(
                        interpreter, false, ref result))
                {
                    return ReturnCode.Error;
                }

                ResultList results = new ResultList();
                PluginFlags pluginFlags = interpreter.PluginFlags;

                results.Add(String.Format(
                    "plugin isolation was {0}", FlagOps.HasFlags(
                    pluginFlags, PluginFlags.Isolated, true) ?
                    "enabled" : "disabled"));

                if (enable)
                    interpreter.EnablePluginIsolation();
                else
                    interpreter.DisablePluginIsolation();

                pluginFlags = interpreter.PluginFlags;

                results.Add(String.Format(
                    "plugin isolation is {0}", FlagOps.HasFlags(
                    pluginFlags, PluginFlags.Isolated, true) ?
                    "enabled" : "disabled"));

                result = results;
                return ReturnCode.Ok;
            }
#else
            result = "plugin isolation is not implemented";
            return ReturnCode.Error;
#endif
        }

