        /// <summary>
        /// This method tests the string matching comparer by determining
        /// whether the specified value matches any entry in the specified
        /// list.
        /// </summary>
        /// <param name="mode">
        /// The matching mode to use.
        /// </param>
        /// <param name="noCase">
        /// Non-zero to perform a case-insensitive comparison.
        /// </param>
        /// <param name="regExOptions">
        /// The regular expression options to use when the matching mode
        /// involves regular expressions.
        /// </param>
        /// <param name="list">
        /// The list of values to match against.
        /// </param>
        /// <param name="value">
        /// The value to look for within the list.
        /// </param>
        /// <param name="match">
        /// Upon success, indicates whether the value matched an entry in the
        /// list.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestMatchComparer(
            MatchMode mode,
            bool noCase,
            RegexOptions regExOptions,
            StringList list,
            string value,
            ref bool match,
            ref Result error
            )
        {
            if (list != null)
            {
                if (value != null)
                {
                    try
                    {
                        PathDictionary<int> paths = new PathDictionary<int>(
                            new _Comparers.StringMatch(mode, noCase, regExOptions));

                        paths.Add(list);
                        match = paths.ContainsKey(value);

                        return ReturnCode.Ok;
                    }
                    catch (Exception e)
                    {
                        error = e;
                    }
                }
                else
                {
                    error = "invalid value";
                }
            }
            else
            {
                error = "invalid list";
            }

            return ReturnCode.Error;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method parses and evaluates the specified expression,
        /// returning the result both in a reused result object and as a
        /// separate output result.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter used to parse and evaluate the expression.
        /// </param>
        /// <param name="text">
        /// The text of the expression to evaluate.
        /// </param>
        /// <param name="usable">
        /// Upon return, indicates whether the evaluated value is usable.
        /// </param>
        /// <param name="exception">
        /// Upon return, indicates whether an exception occurred during
        /// evaluation.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the value of the evaluated expression; upon
        /// failure, receives information about the error.
        /// </param>
        /// <param name="result2">
        /// Upon success, receives the value of the evaluated expression; upon
        /// failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestExpr( /* LOCAL-ONLY */
            Interpreter interpreter,
            string text,
            ref bool usable,
            ref bool exception,
            ref Result result,
            out Result result2
            )
        {
            Result error; /* REUSED */

            if (interpreter == null)
            {
                error = "invalid interpreter";

                if (result == null)
                    result = String.Empty;

                result.Value = error;
                result2 = error;

                return ReturnCode.Error;
            }

            IParseState parseState = new ParseState(
                interpreter.EngineFlags, interpreter.SubstitutionFlags);

            error = null;

            if (ExpressionParser.ParseExpression(interpreter,
                    text, 0, (text != null) ? text.Length : 0,
                    parseState, true, ref error) != ReturnCode.Ok)
            {
                if (result == null)
                    result = String.Empty;

                result.Value = error;
                result2 = error;

                return ReturnCode.Error;
            }

            int savedExpressionLevels = 0;
            Argument value = null;

            interpreter.PushSubExpression(ref savedExpressionLevels);

            try
            {
                error = null;

                if (ExpressionEvaluator.EvaluateSubExpression(
                        interpreter, parseState, 0,
                        interpreter.EngineFlags,
                        interpreter.SubstitutionFlags,
                        interpreter.EngineEventFlags,
                        interpreter.ExpressionFlags,
#if RESULT_LIMITS
                        interpreter.ExecuteResultLimit,
                        interpreter.NestedResultLimit,
#endif
                        true, AppDomainOps.IsSame(interpreter),
#if DEBUGGER && DEBUGGER_BREAKPOINTS
                        Engine.HasArgumentLocation(interpreter),
#endif
                        ref usable, ref exception, ref value,
                        ref error) == ReturnCode.Ok)
                {
                    if (result == null)
                        result = String.Empty;

                    result.Value = value;
                    result2 = value;

                    return ReturnCode.Ok;
                }
                else
                {
                    if (result == null)
                        result = String.Empty;

                    result.Value = error;
                    result2 = error;

                    return ReturnCode.Error;
                }
            }
            finally
            {
                interpreter.PopSubExpression(ref savedExpressionLevels);
            }
        }

