        /// <summary>
        /// This method adds the <c>calc</c> test command to the specified
        /// interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter where the command will be added.
        /// </param>
        /// <param name="clientData">
        /// The optional client data to associate with the command.
        /// </param>
        /// <param name="token">
        /// Upon success, receives the token for the added command.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddCalcCommand(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in: OPTIONAL */
            ref long token,          /* in, out */
            ref Result error         /* in, out */
            )
        {
            Result result = null; /* REUSED */

            if (interpreter.AddExecuteCallback(
                    "calc", TestCalcCommandCallback, clientData,
                    ref token, ref result) == ReturnCode.Ok)
            {
                return ReturnCode.Ok;
            }
            else
            {
                error = result;
                return ReturnCode.Error;
            }
        }

