        /// <summary>
        /// This method parses an integer from the specified text and returns
        /// both the parsed value and the ending index.
        /// </summary>
        /// <param name="text">
        /// The text to parse the integer from.
        /// </param>
        /// <param name="startIndex">
        /// The index within the text where parsing should begin.
        /// </param>
        /// <param name="characters">
        /// The maximum number of characters to consider while parsing.
        /// </param>
        /// <param name="radix">
        /// The radix (i.e. number base) to use while parsing.
        /// </param>
        /// <param name="whiteSpace">
        /// Non-zero to allow surrounding white-space.
        /// </param>
        /// <param name="greedy">
        /// Non-zero to consume as many digits as possible.
        /// </param>
        /// <param name="unsigned">
        /// Non-zero to parse the value as unsigned.
        /// </param>
        /// <param name="legacyOctal">
        /// Non-zero to honor legacy octal parsing rules.
        /// </param>
        /// <returns>
        /// A list containing the parsed integer value and the ending index.
        /// </returns>
        public static StringList TestParseInteger(
            string text,
            int startIndex,
            int characters,
            byte radix,
            bool whiteSpace,
            bool greedy,
            bool unsigned,
            bool legacyOctal
            )
        {
            int endIndex = 0;

            int intValue = Parser.ParseInteger(
                text, startIndex, characters, radix,
                whiteSpace, greedy, unsigned, legacyOctal,
                ref endIndex);

            return new StringList(intValue.ToString(), endIndex.ToString());
        }

