        /// This method wraps the specified value as an opaque object handle
        /// and adds it to the specified interpreter, returning the resulting
        /// token.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter where the object will be added.
        /// </param>
        /// <param name="name">
        /// The optional name to use for the object handle.
        /// </param>
        /// <param name="value">
        /// The optional value to wrap as an opaque object handle.
        /// </param>
        /// <param name="clientData">
        /// The optional client data to associate with the object.
        /// </param>
        /// <param name="objectFlags">
        /// The optional object flags to use; if null, the default object
        /// flags are used.
        /// </param>
        /// <param name="referenceCount">
        /// The initial reference count for the object.
        /// </param>
        /// <param name="token">
        /// Upon success, receives the token for the added object.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the result; upon failure, receives
        /// information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise,
        /// <see cref="ReturnCode.Error" />.
        /// </returns>
        public static ReturnCode TestAddObject(
            Interpreter interpreter,  /* in */
            string name,              /* in: OPTIONAL */
            object value,             /* in: OPTIONAL */
            IClientData clientData,   /* in: OPTIONAL */
            ObjectFlags? objectFlags, /* in: OPTIONAL */
            int referenceCount,       /* in */
            ref long token,           /* out */
            ref Result result         /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (clientData == null)
                clientData = ClientData.Empty;

            if (objectFlags == null)
                objectFlags = ObjectOps.GetDefaultObjectFlags();

#if DEBUGGER && DEBUGGER_ARGUMENTS
            ArgumentList executeArguments =
                Engine.GetDebuggerExecuteArguments(
                    interpreter);

            if (executeArguments == null)
            {
                result = "invalid debugger execute arguments";
                return ReturnCode.Error;
            }
#endif

            return interpreter.AddObject(
                name, null, (ObjectFlags)objectFlags, clientData,
                referenceCount,
#if NATIVE && TCL
                null,
#endif
#if DEBUGGER && DEBUGGER_ARGUMENTS
                executeArguments,
#endif
                value, ref token, ref result);
        }

