        /// <summary>
        /// This method adds several test functions to the specified
        /// interpreter, collecting the resulting command tokens.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter where the test functions will be added.
        /// </param>
        /// <param name="clientData">
        /// The optional client data to associate with the added functions.
        /// </param>
        /// <param name="tokens">
        /// Upon success, contains the tokens of the functions that were
        /// added; the list is created if necessary.
        /// </param>
        /// <returns>
        /// A list of results describing the outcome of each function
        /// addition.
        /// </returns>
        public static ResultList TestAddFunctions(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in: OPTIONAL */
            ref LongList tokens      /* in, out */
            )
        {
            ResultList results = new ResultList();

            if (interpreter == null)
            {
                results.Add(ReturnCode.Error);
                results.Add("invalid interpreter");

                goto done;
            }

            IPlugin plugin;
            Result error = null;

            plugin = TestGetPlugin(interpreter, ref error);

            if (plugin == null)
            {
                results.Add(error);
                goto done;
            }

            if (tokens == null)
                tokens = new LongList();

            ReturnCode code; /* REUSED */
            long token; /* REUSED */
            Result result; /* REUSED */

            token = 0;
            result = null;

            code = interpreter.AddFunction(
                typeof(_Tests.Default), "foo", (int)Arity.Any, null,
                FunctionFlags.ForTestUse, plugin, clientData, true,
                ref token, ref result);

            if (code == ReturnCode.Ok)
            {
                results.Add(code);
                tokens.Add(token);
            }
            else
            {
                results.Add(code);
                results.Add(result);
            }

            token = 0;
            result = null;

            code = interpreter.AddFunction(
                typeof(_Functions.Min), "bar", (int)Arity.Any, null,
                FunctionFlags.ForTestUse, plugin, clientData, true,
                ref token, ref result);

            if (code == ReturnCode.Ok)
            {
                results.Add(code);
                tokens.Add(token);
            }
            else
            {
                results.Add(code);
                results.Add(result);
            }

            token = 0;
            result = null;

            code = interpreter.AddFunction(
                typeof(_Functions.Min), "eq", (int)Arity.Any, null,
                FunctionFlags.ForTestUse, plugin, clientData, true,
                ref token, ref result);

            if (code == ReturnCode.Ok)
            {
                results.Add(code);
                tokens.Add(token);
            }
            else
            {
                results.Add(code);
                results.Add(result);
            }

            token = 0;
            result = null;

            code = interpreter.AddFunction(
                typeof(_Functions.Min), "eqq", (int)Arity.Any, null,
                FunctionFlags.ForTestUse, plugin, clientData, true,
                ref token, ref result);

            if (code == ReturnCode.Ok)
            {
                results.Add(code);
                tokens.Add(token);
            }
            else
            {
                results.Add(code);
                results.Add(result);
            }

        done:

            return results;
        }

