        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method removes the functions identified by the specified tokens
        /// from the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter to remove the functions from.
        /// </param>
        /// <param name="clientData">
        /// The optional client data associated with the functions being
        /// removed.
        /// </param>
        /// <param name="tokens">
        /// On input, the list of function tokens to remove; upon return, any
        /// tokens that were successfully removed have been deleted from this
        /// list.
        /// </param>
        /// <param name="errors">
        /// Upon failure, receives one or more error messages describing the
        /// functions that could not be removed.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> if all functions were removed;
        /// otherwise, an error code.
        /// </returns>
        public static ReturnCode TestRemoveFunctions(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in: OPTIONAL */
            ref LongList tokens,     /* in, out */
            ref ResultList errors    /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            if (tokens == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid token list");
                return ReturnCode.Error;
            }

            LongList localTokens = new LongList(tokens);

            foreach (long token in localTokens)
            {
                Result result = null;

                if (interpreter.RemoveFunction(
                        token, clientData,
                        ref result) == ReturnCode.Ok)
                {
                    if (!tokens.Remove(token))
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(String.Format(
                            "could not remove token: {0}",
                            token));
                    }
                }
                else
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(result);
                }
            }

            return (tokens.Count == 0) ?
                ReturnCode.Ok : ReturnCode.Error;
        }

