            string name,
            IClientData clientData,
            Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            return interpreter.RemoveFunction(name, clientData, ref result);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method writes a box containing the specified value to the host
        /// of the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose host should be used to write the box.
        /// </param>
        /// <param name="value">
        /// The value to write inside the box.  When <paramref name="multiple" />
        /// is true, this value is treated as a list.
        /// </param>
        /// <param name="multiple">
        /// Non-zero if the value should be parsed as a list and written as
        /// multiple lines.
        /// </param>
        /// <param name="newLine">
        /// Non-zero to write a trailing line terminator after the box.
        /// </param>
        /// <param name="restore">
        /// Non-zero to restore the host cursor position after writing the box.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// True if the box was written successfully; otherwise, false.
        /// </returns>
        public static bool TestWriteBox(
            Interpreter interpreter,
            string value,
            bool multiple,
            bool newLine,
            bool restore,
            ref Result error
            )
        {
            if (interpreter != null)
            {
                IDisplayHost displayHost = interpreter.InternalHost;

                if (displayHost != null)
                {
                    try
                    {
                        bool positioning = FlagOps.HasFlags(
                            displayHost.GetHostFlags(), HostFlags.Positioning,
                            true);

                        int left = 0;
                        int top = 0;

                        if (!positioning ||
                            displayHost.GetPosition(ref left, ref top))
                        {
                            ConsoleColor foregroundColor = _ConsoleColor.None;
                            ConsoleColor backgroundColor = _ConsoleColor.None;

                            if (displayHost.GetColors(
                                    null, "TestInfo", true, true, ref foregroundColor,
                                    ref backgroundColor, ref error) == ReturnCode.Ok)
                            {
                                if (multiple)
                                {
                                    StringList list = null;

                                    if (ParserOps<string>.SplitList(
                                            interpreter, value, 0, Length.Invalid, true,
                                            ref list, ref error) == ReturnCode.Ok)
                                    {
                                        if (displayHost.WriteBox(
                                                null, new StringPairList(list), null,
                                                newLine, restore, ref left, ref top,
                                                foregroundColor, backgroundColor))
                                        {
                                            return true;
                                        }
                                        else
                                        {
                                            error = "could not write box to interpreter host";
                                        }
                                    }
                                }
                                else
                                {
                                    if (displayHost.WriteBox(
                                            null, value, null, newLine, restore,
                                            ref left, ref top, foregroundColor,
                                            backgroundColor))
                                    {
                                        return true;
                                    }
                                    else
                                    {
                                        error = "could not write box to interpreter host";
                                    }
                                }
                            }
                        }
                        else
                        {
                            error = "could not get interpreter host position";
                        }
                    }
                    catch (Exception e)
                    {
                        error = e;
                    }
                }
                else
                {
                    error = "interpreter host not available";
                }
            }
            else
            {
                error = "invalid interpreter";
            }

            return false;
        }

