        /// <summary>
        /// This method enables or disables the writing of custom test
        /// information for the specified interpreter and, when enabling,
        /// establishes the list of custom information to be displayed.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose host should display the custom information.
        /// </param>
        /// <param name="enable">
        /// Non-zero to enable custom information output; zero to disable it.
        /// </param>
        /// <param name="list">
        /// The list of custom name/value pairs to display; when this value is
        /// null and output is being enabled, a default list is used.
        /// </param>
        /// <returns>
        /// True if the custom information state was updated successfully;
        /// otherwise, false.
        /// </returns>
        public static bool EnableWriteCustomInfo(
            Interpreter interpreter,
            bool enable,
            StringPairList list
            )
        {
            if (interpreter == null)
                return false;

#if CONSOLE
            _Hosts.Console consoleHost =
                interpreter.InternalHost as _Hosts.Console;

            if (consoleHost == null)
                return false;

            consoleHost.EnableTests(enable);
#endif

            if (enable)
            {
                if (list != null)
                {
                    customInfoList = new StringPairList(list);
                }
                else
                {
                    customInfoList = new StringPairList(
                        new StringPair("Custom"), null,
                        new StringPair("name0", null),
                        new StringPair("name1", String.Empty),
                        new StringPair("name2", "value1"),
                        new StringPair("name3", FormatOps.Iso8601FullDateTime(TimeOps.GetUtcNow())),
                        new StringPair("name4", interpreter.GetRandomNumber().ToString("x16")));
                }
            }
            else
            {
                customInfoList = null;
            }

            return true;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method writes the previously configured custom test information
        /// to the host of the specified interpreter using its current output
        /// style.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose host should display the custom information.
        /// </param>
        /// <param name="detailFlags">
        /// The detail flags that control the level of detail to display.
        /// </param>
        /// <param name="newLine">
        /// Non-zero to write a trailing line terminator after the information.
        /// </param>
        /// <param name="foregroundColor">
        /// The foreground color to use when writing the information.
        /// </param>
        /// <param name="backgroundColor">
        /// The background color to use when writing the information.
        /// </param>
        /// <returns>
        /// True if the custom information was written successfully; otherwise,
        /// false.
        /// </returns>
        public static bool TestWriteCustomInfo(
            Interpreter interpreter,
            DetailFlags detailFlags,
            bool newLine,
            ConsoleColor foregroundColor,
            ConsoleColor backgroundColor
            )
        {
            if (interpreter == null)
                return false;

            _Hosts.Default defaultHost =
                interpreter.InternalHost as _Hosts.Default;

            if (defaultHost == null)
                return false;

            int hostLeft = 0;
            int hostTop = 0;

            if (!defaultHost.GetDefaultPosition(ref hostLeft, ref hostTop))
                return false;

            try
            {
                OutputStyle outputStyle = defaultHost.OutputStyle;
                StringPairList list = new StringPairList(customInfoList);

                if (defaultHost.IsBoxedOutputStyle(outputStyle))
                {
                    return defaultHost.WriteBox(
                        TestCustomInfoBoxName, list, null, false, true,
                        ref hostLeft, ref hostTop, foregroundColor,
                        backgroundColor);
                }
                else if (defaultHost.IsFormattedOutputStyle(outputStyle))
                {
                    return defaultHost.WriteFormat(
                        list, newLine, foregroundColor, backgroundColor);
                }
                else if (defaultHost.IsNoneOutputStyle(outputStyle))
                {
                    return true;
                }
                else
                {
                    return false;
                }
            }
            finally
            {
                defaultHost.SetDefaultPosition(hostLeft, hostTop);
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method copies the error code and error information from the
        /// specified interpreter when the supplied return code indicates an
        /// error, taking care not to block indefinitely on the interpreter
        /// lock.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter to copy the error information from.
        /// </param>
        /// <param name="code">
        /// The return code that determines whether error information should be
        /// copied.
        /// </param>
        /// <param name="strict">
        /// Non-zero to require that the error information be fully available.
        /// </param>
        /// <param name="errorCode">
        /// Upon success, receives the copied error code.
        /// </param>
        /// <param name="errorInfo">
        /// Upon success, receives the copied error information.
        /// </param>
        /// <returns>
        /// True if the error information was copied successfully; otherwise,
        /// false.
        /// </returns>
        public static bool TestCheckCopyErrorInformation(
            Interpreter interpreter,
            ReturnCode code,
            bool strict,
            ref Result errorCode,
            ref Result errorInfo
            )
        {
            if ((interpreter != null) && (code == ReturnCode.Error))
            {
                //
                // BUGFIX: Now, prevent blocking forever when copying the
                //         error information by using the TryLock method.
                //         If it succeeds, any internal locking performed
                //         by the CopyErrorInformation method is harmless
                //         -OR- if it fails, we just avoid blocking.
                //
                bool locked = false;

                try
                {
                    interpreter.InternalSoftTryLock(
                        ref locked); /* TRANSACTIONAL */

                    if (locked)
                    {
                        ResultList errors = null;

                        if (interpreter.InternalCopyErrorInformation(
                                VariableFlags.None, strict, ref errorCode,
                                ref errorInfo, ref errors) == ReturnCode.Ok)
                        {
                            return true;
                        }
                        else
                        {
                            TraceOps.DebugTrace(String.Format(
                                "Failed to copy error information: {0}",
                                errors), typeof(Default).Name,
                                TracePriority.EngineError2);
                        }
                    }
                    else
                    {
                        TraceOps.LockTrace(
                            "TestCheckCopyErrorInformation",
                            typeof(Default).Name, false,
                            TracePriority.LockError,
                            interpreter.MaybeWhoHasLock());
                    }
                }
                finally
                {
                    interpreter.InternalExitLock(ref locked);
                }
            }

            return false;
        }

