        /// <summary>
        /// This method verifies that the built-in commands provided by the core
        /// plugin match those discovered by populating the plugin entities.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose core plugin commands should be verified.
        /// </param>
        /// <param name="results">
        /// On input, an optional list of results to append to; upon return,
        /// contains any error messages or comparison details produced during
        /// verification.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> if the commands matched; otherwise, an
        /// error code.
        /// </returns>
        public static ReturnCode TestVerifyBuiltInCommands(
            Interpreter interpreter, /* in */
            ref ResultList results   /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            IPlugin plugin = interpreter.NewCorePlugin();

            if (plugin == null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add("could not create core plugin");
                return ReturnCode.Error;
            }

            Result error; /* REUSED */
            IRuleSet ruleSet = interpreter.GetRuleSet();
            CommandDataList list1 = new CommandDataList();

            plugin.Commands = list1;
            error = null;

            if (_RuntimeOps.PopulatePluginEntities(
                    interpreter, plugin, null, ruleSet, null,
                    null, false, false, true, Interpreter.IsVerbose(
                    interpreter), ref error) != ReturnCode.Ok)
            {
                if (error != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(error);
                }

                return ReturnCode.Error;
            }

            CommandDataList list2 = new CommandDataList();

            plugin.Commands = list2;
            error = null;

            if (_RuntimeOps.PopulatePluginEntities(
                    interpreter, plugin, null, ruleSet, null,
                    null, true, false, true, Interpreter.IsVerbose(
                    interpreter), ref error) != ReturnCode.Ok)
            {
                if (error != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(error);
                }

                return ReturnCode.Error;
            }

            return TestCompareCommandDataLists(list1, list2, ref results);
        }

