        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that creates a rule from its
        /// arguments and unconditionally adds it to the ruleset carried by the
        /// supplied client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the ruleset to add the rule to.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; the second argument is the
        /// rule definition.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the string representation of the added rule;
        /// upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestAlwaysAddRuleCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 2)
            {
                result = "wrong # args: should be \"rule definition\"";
                return ReturnCode.Error;
            }

            CultureInfo cultureInfo = interpreter.InternalCultureInfo;

            IRule rule = _Rule.Create(
                arguments[1], cultureInfo, ref result);

            if (rule == null)
                return ReturnCode.Error;

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            IRuleSet ruleSet = ruleSetClientData.RuleSet;

            if (ruleSet == null)
            {
                ruleSet = RuleSet.Create(ref result);

                if (ruleSet == null)
                    return ReturnCode.Error;

                ruleSetClientData.RuleSet = ruleSet;
            }

            if (!ruleSet.AddRule(rule, ref result))
                return ReturnCode.Error;

            result = rule.ToString();
            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that creates a rule from its
        /// arguments and adds it to the ruleset carried by the supplied client
        /// data only if a matching rule is not already present.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the ruleset to add the rule to.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; the second argument is the
        /// rule definition.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the string representation of the rule; upon
        /// failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestMaybeAddRuleCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 2)
            {
                result = "wrong # args: should be \"rule definition\"";
                return ReturnCode.Error;
            }

            CultureInfo cultureInfo = interpreter.InternalCultureInfo;

            IRule rule = _Rule.Create(
                arguments[1], cultureInfo, ref result);

            if (rule == null)
                return ReturnCode.Error;

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            IRuleSet ruleSet = ruleSetClientData.RuleSet;

            if (ruleSet == null)
            {
                ruleSet = RuleSet.Create(ref result);

                if (ruleSet == null)
                    return ReturnCode.Error;

                ruleSetClientData.RuleSet = ruleSet;
            }

            Result error = null; /* REUSED */

            if (ruleSet.FindRules(
                    rule, false, ref error) != null)
            {
                result = rule.ToString();
                return ReturnCode.Ok;
            }

            error = null;

            if (ruleSet.AddRule(rule, ref error))
            {
                result = rule.ToString();
                return ReturnCode.Ok;
            }

            result = error;
            return ReturnCode.Error;
        }

