        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that finds the rules matching the
        /// definition supplied in its arguments within the ruleset carried by
        /// the supplied client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the ruleset to search.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; the second argument is the
        /// rule definition used to match.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the list of matching rules; upon failure,
        /// receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestFindRulesCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 2)
            {
                result = "wrong # args: should be \"findRules definition\"";
                return ReturnCode.Error;
            }

            CultureInfo cultureInfo = interpreter.InternalCultureInfo;

            IRule rule = _Rule.Create(
                arguments[1], cultureInfo, ref result);

            if (rule == null)
                return ReturnCode.Error;

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            IRuleSet ruleSet = ruleSetClientData.RuleSet;

            if (ruleSet == null)
            {
                result = "invalid ruleset";
                return ReturnCode.Error;
            }

            IEnumerable<IRule> rules = ruleSet.FindRules(
                rule, false, ref result);

            if (rules == null)
                return ReturnCode.Error;

            result = new StringList(rules);
            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that clears all rules from the
        /// ruleset carried by the supplied client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the ruleset to clear.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; no additional arguments are
        /// expected.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the number of rules that were cleared; upon
        /// failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestClearRulesCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 1)
            {
                result = "wrong # args: should be \"noRules\"";
                return ReturnCode.Error;
            }

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            IRuleSet ruleSet = ruleSetClientData.RuleSet;

            if (ruleSet == null)
            {
                result = "invalid ruleset";
                return ReturnCode.Error;
            }

            result = ruleSet.CountRules();
            ruleSet.ClearRules();

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that discards the entire ruleset
        /// carried by the supplied client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, whose ruleset
        /// is discarded.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; no additional arguments are
        /// expected.
        /// </param>
        /// <param name="result">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestDiscardRulesCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 1)
            {
                result = "wrong # args: should be \"discardRules\"";
                return ReturnCode.Error;
            }

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            ruleSetClientData.RuleSet = null;
            return ReturnCode.Ok;
        }

