        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that evaluates a script while
        /// redirecting the rule-adding command so that rules are merged into the
        /// ruleset carried by the supplied client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the ruleset to merge rules into.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; the second argument is the
        /// script to evaluate.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the string representation of the resulting
        /// ruleset; upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestMergeRulesCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 2)
            {
                result = "wrong # args: should be \"mergeRules script\"";
                return ReturnCode.Error;
            }

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            string commandName = null;
            ICommand command = null;

            if (interpreter.GetCommand(
                    ruleSetClientData.AlwaysAddCommandToken,
                    LookupFlags.Default, ref commandName,
                    ref command, ref result) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            ExecuteCallback savedCallback = command.Callback;

            try
            {
                command.Callback = new ExecuteCallback(
                    TestMaybeAddRuleCommandCallback);

                Result localResult = null;

                if (interpreter.EvaluateScript(arguments[1],
                        ref localResult) != ReturnCode.Ok)
                {
                    result = localResult;
                    return ReturnCode.Error;
                }

                IRuleSet ruleSet = ruleSetClientData.RuleSet;

                result = (ruleSet != null) ?
                    ruleSet.ToString() : null;

                return ReturnCode.Ok;
            }
            finally
            {
                command.Callback = savedCallback;
            }
        }

