        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that loads a named ruleset from
        /// disk and includes its rules in the ruleset carried by the supplied
        /// client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the ruleset to include the loaded rules into.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; the second argument is the
        /// name of the ruleset to include.
        /// </param>
        /// <param name="result">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestIncludeRuleSetCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 2)
            {
                result = "wrong # args: should be \"includeRuleSet name\"";
                return ReturnCode.Error;
            }

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            IRuleSet ruleSet = ruleSetClientData.RuleSet;

            if (ruleSet == null)
            {
                ruleSet = RuleSet.Create(ref result);

                if (ruleSet == null)
                    return ReturnCode.Error;

                ruleSetClientData.RuleSet = ruleSet;
            }

            string name = arguments[1];

            if (!TestIsValidNameOnly(name, ref result))
                return ReturnCode.Error;

            string fileName = Path.Combine(
                ruleSetClientData.RuleSetDirectory, String.Format(
                "{0}{1}", name, FileExtension.RuleSet));

            IRuleSet loadRuleSet = null;

            if (TestLoadRuleSet(fileName,
                    ref loadRuleSet, ref result) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            int count = 0; /* NOT USED */

            if (!ruleSet.AddRules(
                    loadRuleSet, ruleSetClientData.StopOnError,
                    ruleSetClientData.MoveRules, ref count,
                    ref result))
            {
                return ReturnCode.Error;
            }

            return ReturnCode.Ok;
        }

