        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that defines a named rule or
        /// ruleset within the definition state carried by the supplied client
        /// data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the definition state.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; they specify the definition
        /// type, name, and value.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the string representation of the defined rule
        /// or ruleset; upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestDefineCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 4)
            {
                result = "wrong # args: should be \"define type name value\"";
                return ReturnCode.Error;
            }

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            RuleSetDictionary ruleSets = ruleSetClientData.RuleSets;
            RuleDictionary rules = ruleSetClientData.Rules;

            object enumValue = EnumOps.TryParse(
                typeof(DefinitionType), arguments[1], true, true, ref result);

            if (enumValue == null)
                return ReturnCode.Error;

            string nameOnly = arguments[2];

            if (String.IsNullOrEmpty(nameOnly))
                nameOnly = null;

            if (nameOnly == null)
            {
                result = "invalid definition name";
                return ReturnCode.Error;
            }

            if (!TestIsValidNameOnly(nameOnly, ref result))
                return ReturnCode.Error;

            IRuleSet oldRuleSet = ruleSetClientData.DefineRuleSet;
            DefinitionType definitionType = (DefinitionType)enumValue;

            definitionType = ruleSetClientData.TranslateDefinitionType(
                definitionType);

            switch (definitionType)
            {
                case DefinitionType.Rule:
                    {
                        if (rules == null)
                        {
                            result = "invalid rules";
                            return ReturnCode.Error;
                        }

                        IRule rule = _Rule.Create(
                            arguments[3], interpreter.InternalCultureInfo,
                            ref result);

                        if (rule == null)
                            return ReturnCode.Error;

                        if ((oldRuleSet != null) &&
                            !oldRuleSet.AddRule(rule, ref result))
                        {
                            return ReturnCode.Error;
                        }

                        rules[nameOnly] = rule;
                        result = rule.ToString();

                        return ReturnCode.Ok;
                    }
                case DefinitionType.RuleSet:
                    {
                        if (ruleSets == null)
                        {
                            result = "invalid rulesets";
                            return ReturnCode.Error;
                        }

                        IRuleSet newRuleSet = oldRuleSet;

                        if (TestDefineRuleSet(
                                null, arguments[3], ruleSetClientData,
                                ref newRuleSet, ref result) != ReturnCode.Ok)
                        {
                            return ReturnCode.Error;
                        }

                        ruleSets[nameOnly] = newRuleSet;

                        result = (newRuleSet != null) ?
                            newRuleSet.ToString() : String.Empty;

                        return ReturnCode.Ok;
                    }
                default:
                    {
                        result = String.Format(
                            "unsupported definition type {0}",
                            FormatOps.WrapOrNull(definitionType));

                        return ReturnCode.Error;
                    }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method is an execute callback that includes a previously defined
        /// named rule or ruleset into the definition ruleset carried by the
        /// supplied client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter that is invoking this callback.
        /// </param>
        /// <param name="clientData">
        /// The client data, which must be a ruleset client data, that carries
        /// the definition state.
        /// </param>
        /// <param name="arguments">
        /// The arguments supplied to the callback; they specify the definition
        /// type and name to include.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the string representation of the included rule
        /// or the file name of the included ruleset; upon failure, receives an
        /// error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestIncludeCommandCallback(
            Interpreter interpreter, /* in */
            IClientData clientData,  /* in, out */
            ArgumentList arguments,  /* in */
            ref Result result        /* out */
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            int argumentCount = arguments.Count;

            if (argumentCount != 3)
            {
                result = "wrong # args: should be \"include type name\"";
                return ReturnCode.Error;
            }

            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                result = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            RuleSetDictionary ruleSets = ruleSetClientData.RuleSets;

            if (ruleSets == null)
            {
                result = "invalid rulesets";
                return ReturnCode.Error;
            }

            RuleDictionary rules = ruleSetClientData.Rules;

            if (rules == null)
            {
                result = "invalid rules";
                return ReturnCode.Error;
            }

            object enumValue = EnumOps.TryParse(
                typeof(DefinitionType), arguments[1], true, true, ref result);

            if (enumValue == null)
                return ReturnCode.Error;

            string nameOnly = arguments[2];

            if (String.IsNullOrEmpty(nameOnly))
                nameOnly = null;

            if (nameOnly == null)
            {
                result = "invalid definition name";
                return ReturnCode.Error;
            }

            if (!TestIsValidName(nameOnly, ref result))
                return ReturnCode.Error;

            IRuleSet oldRuleSet = ruleSetClientData.DefineRuleSet;
            DefinitionType definitionType = (DefinitionType)enumValue;

            definitionType = ruleSetClientData.TranslateDefinitionType(
                definitionType);

            switch (definitionType)
            {
                case DefinitionType.Rule:
                    {
                        if (oldRuleSet == null)
                        {
                            result = "invalid definition ruleset";
                            return ReturnCode.Error;
                        }

                        IRule rule;

                        if (!rules.TryGetValue(nameOnly, out rule))
                        {
                            result = String.Format(
                                "named rule {0} is missing",
                                FormatOps.WrapOrNull(nameOnly));

                            return ReturnCode.Error;
                        }

                        if (!oldRuleSet.AddRule(rule, ref result))
                            return ReturnCode.Error;

                        result = (rule != null) ?
                            rule.ToString() : String.Empty;

                        return ReturnCode.Ok;
                    }
                case DefinitionType.RuleSet:
                    {
                        string fileName = ruleSetClientData.IncludeFileName(
                            nameOnly, ref result);

                        if (fileName == null)
                            return ReturnCode.Error;

                        IRuleSet newRuleSet = null;

                        if (TestDefineRuleSet(
                                fileName, null, ruleSetClientData,
                                ref newRuleSet, ref result) != ReturnCode.Ok)
                        {
                            return ReturnCode.Error;
                        }

                        if (oldRuleSet != null)
                        {
                            int count = 0; /* NOT USED */

                            if (!oldRuleSet.AddRules(
                                    newRuleSet, true, true, ref count,
                                    ref result))
                            {
                                return ReturnCode.Error;
                            }
                        }

                        ruleSets[nameOnly] = newRuleSet;

                        result = fileName;
                        return ReturnCode.Ok;
                    }
                default:
                    {
                        result = String.Format(
                            "unsupported definition type {0}",
                            FormatOps.WrapOrNull(definitionType));

                        return ReturnCode.Error;
                    }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method adds the definition commands (i.e. define and include) to
        /// the specified interpreter, associating them with the supplied ruleset
        /// client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter to add the definition commands to.
        /// </param>
        /// <param name="ruleSetClientData">
        /// The ruleset client data to associate with the added commands.
        /// </param>
        /// <param name="tokens">
        /// On input, an optional list of command tokens to append to; upon
        /// return, contains the tokens of any commands that were successfully
        /// added.
        /// </param>
        /// <param name="results">
        /// Upon return, contains any error messages or details produced while
        /// adding the commands.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> if all commands were added; otherwise,
        /// an error code.
        /// </returns>
        public static ReturnCode TestAddDefinitionCommands(
            Interpreter interpreter,             /* in */
            RuleSetClientData ruleSetClientData, /* in */
            ref LongList tokens,                 /* in, out */
            ref ResultList results               /* out */
            )
        {
            if (interpreter == null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            if (ruleSetClientData == null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add("invalid ruleset clientData");
                return ReturnCode.Error;
            }

            int errorCount = 0;
            long token; /* REUSED */
            Result result; /* REUSED */

            ///////////////////////////////////////////////////////////////////////////////////////////

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback(
                    "define", TestDefineCommandCallback,
                    ruleSetClientData, ref token,
                    ref result) == ReturnCode.Ok)
            {
                if (tokens == null)
                    tokens = new LongList();

                tokens.Add(token);
            }
            else
            {
                errorCount++;
            }

            if (result != null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add(result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            token = 0;
            result = null;

            if (interpreter.AddExecuteCallback(
                    "include", TestIncludeCommandCallback,
                    ruleSetClientData, ref token,
                    ref result) == ReturnCode.Ok)
            {
                if (tokens == null)
                    tokens = new LongList();

                tokens.Add(token);
            }
            else
            {
                errorCount++;
            }

            if (result != null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add(result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            ruleSetClientData.AddTokens(tokens);

            return (errorCount > 0) ?
                ReturnCode.Error : ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method removes the definition commands (i.e. define and include)
        /// from the specified interpreter, using the tokens recorded in the
        /// supplied ruleset client data when available.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter to remove the definition commands from.
        /// </param>
        /// <param name="ruleSetClientData">
        /// The ruleset client data that records the tokens of the commands to
        /// remove.
        /// </param>
        /// <param name="results">
        /// Upon return, contains any error messages or details produced while
        /// removing the commands.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> if all commands were removed; otherwise,
        /// an error code.
        /// </returns>
        public static ReturnCode TestRemoveDefinitionCommands(
            Interpreter interpreter,             /* in */
            RuleSetClientData ruleSetClientData, /* in */
            ref ResultList results               /* out */
            )
        {
            if (interpreter == null)
            {
                if (results == null)
                    results = new ResultList();

                results.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            LongList tokens = ruleSetClientData.Tokens;

            if (tokens != null)
            {
                StringList names = null; /* NOT USED */

                if (interpreter.RemoveCommands(
                        tokens, ruleSetClientData, false, true,
                        ref names, ref results) == ReturnCode.Ok)
                {
                    tokens.Clear();
                    return ReturnCode.Ok;
                }
                else
                {
                    return ReturnCode.Error;
                }
            }
            else
            {
                int errorCount = 0;
                Result result; /* REUSED */

                ///////////////////////////////////////////////////////////////////////////////////////

                result = null;

                if (interpreter.RemoveCommand(
                        "define", ruleSetClientData,
                        ref result) != ReturnCode.Ok)
                {
                    errorCount++;
                }

                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                result = null;

                if (interpreter.RemoveCommand(
                        "include", ruleSetClientData,
                        ref result) != ReturnCode.Ok)
                {
                    errorCount++;
                }

                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                return (errorCount > 0) ?
                    ReturnCode.Error : ReturnCode.Ok;
            }
        }

