                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                result = null;

                if (interpreter.RemoveCommand(
                        "includeRuleSet", ruleSetClientData,
                        ref result) != ReturnCode.Ok)
                {
                    errorCount++;
                }

                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                result = null;

                if (interpreter.RemoveCommand(
                        "saveRules", ruleSetClientData,
                        ref result) != ReturnCode.Ok)
                {
                    errorCount++;
                }

                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                result = null;

                if (interpreter.RemoveCommand(
                        "createWithRules", ruleSetClientData,
                        ref result) != ReturnCode.Ok)
                {
                    errorCount++;
                }

                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                result = null;

                if (interpreter.RemoveCommand(
                        "introspect", ruleSetClientData,
                        ref result) != ReturnCode.Ok)
                {
                    errorCount++;
                }

                if (result != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(result);
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                return (errorCount > 0) ?
                    ReturnCode.Error : ReturnCode.Ok;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method defines a ruleset from the supplied file or text, using
        /// the supplied ruleset client data to control how the ruleset is
        /// processed.
        /// </summary>
        /// <param name="fileName">
        /// The optional name of the file that contains the ruleset definition.
        /// </param>
        /// <param name="text">
        /// The optional text that contains the ruleset definition.
        /// </param>
        /// <param name="ruleSetClientData">
        /// The ruleset client data that controls how the ruleset is defined.
        /// </param>
        /// <param name="ruleSet">
        /// On input, an optional ruleset to add the defined rules to; upon
        /// return, contains the resulting ruleset.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestDefineRuleSet(
            string fileName,                     /* in: OPTIONAL */
            string text,                         /* in: OPTIONAL */
            RuleSetClientData ruleSetClientData, /* in */
            ref IRuleSet ruleSet,                /* in, out */
            ref Result error                     /* out */
            )
        {
            if (ruleSetClientData == null)
            {
                error = "invalid ruleset clientData";
                return ReturnCode.Error;
            }

            int levels = ruleSetClientData.EnterDefineLevel();

            try
            {
                IRuleSet newRuleSet = ruleSet;

                if (newRuleSet == null)
                {
                    newRuleSet = RuleSet.Create(ref error);

                    if (newRuleSet == null)
                        return ReturnCode.Error;
                }

                Result result; /* REUSED */

                CreateFlags createFlags = CreateFlags.RuleSetUse;
                HostCreateFlags hostCreateFlags = HostCreateFlags.Disable;

                result = null;

                using (Interpreter interpreter = Interpreter.Create(
                        null, createFlags, hostCreateFlags, ref result))
                {
                    if (interpreter == null)
                    {
                        error = result;
                        return ReturnCode.Error;
                    }

                    LongList tokens = null; /* NOT USED */
                    ResultList results = null;

                    if (TestAddDefinitionCommands(
                            interpreter, ruleSetClientData, ref tokens,
                            ref results) != ReturnCode.Ok)
                    {
                        error = results;
                        return ReturnCode.Error;
                    }

                    if (fileName == null)
                        fileName = ruleSetClientData.RuleSetFileName;

                    IRuleSet savedRuleSet = null;

                    ruleSetClientData.BeginDefineRuleSet(
                        newRuleSet, ref savedRuleSet);

                    try
                    {
                        string savedFileName = null;

                        ruleSetClientData.BeginRuleSetFile(
                            fileName, ref savedFileName);

                        try
                        {
                            if (text != null)
                            {
                                result = null;

                                if (interpreter.EvaluateScript(
                                        text, ref result) != ReturnCode.Ok)
                                {
                                    error = result;
                                    return ReturnCode.Error;
                                }
                            }
                            else
                            {
                                result = null;

                                if (interpreter.EvaluateFile(
                                        fileName, ref result) != ReturnCode.Ok)
                                {
                                    error = result;
                                    return ReturnCode.Error;
                                }
                            }
                        }
                        finally
                        {
                            ruleSetClientData.EndRuleSetFile(
                                ref savedFileName);
                        }
                    }
                    finally
                    {
                        ruleSetClientData.EndDefineRuleSet(
                            ref savedRuleSet);
                    }

                    ruleSet = newRuleSet;
                    return ReturnCode.Ok;
                }
            }
            finally
            {
                if (levels == 1)
                    ruleSetClientData.ResetForDefine();

                /* IGNORED */
                ruleSetClientData.ExitDefineLevel();
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This overload resolves the engine, substitution, event, and
        /// expression flags from the specified interpreter and then fetches the
        /// script associated with the specified file name, returning its text.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose flags are used and whose script-fetching
        /// infrastructure is consulted.  This parameter may not be null.
        /// </param>
        /// <param name="encoding">
        /// The optional text encoding to use when reading the script file.
        /// </param>
        /// <param name="fileName">
        /// The name of the script file to fetch.
        /// </param>
        /// <param name="scriptFlags">
        /// On input, the requested script flags (combined with those of the
        /// interpreter); upon return, the effective script flags that were used.
        /// </param>
        /// <param name="clientData">
        /// On input, optional client data; upon return, receives the client data
        /// produced while reading the script.
        /// </param>
        /// <param name="canRetry">
        /// Upon failure, receives non-zero when the operation may be retried.
        /// </param>
        /// <param name="text">
        /// Upon success, receives the text of the fetched script.
        /// </param>
        /// <param name="errors">
        /// On input, an optional error list to add to; upon failure, receives the
        /// accumulated error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestGetScriptFile(
            Interpreter interpreter,     /* in */
            Encoding encoding,           /* in */
            string fileName,             /* in */
            ref ScriptFlags scriptFlags, /* in, out */
            ref IClientData clientData,  /* in, out */
            ref bool canRetry,           /* out */
            ref string text,             /* out */
            ref ResultList errors        /* in, out */
            )
        {
            if (interpreter == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid interpreter");
                return ReturnCode.Error;
            }

            EngineFlags engineFlags;
            SubstitutionFlags substitutionFlags;
            EventFlags eventFlags;
            ExpressionFlags expressionFlags;

            lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
            {
                scriptFlags |= interpreter.ScriptFlagsNoLock;
                engineFlags = interpreter.EngineFlagsNoLock;
                substitutionFlags = interpreter.SubstitutionFlagsNoLock;
                eventFlags = interpreter.EngineEventFlagsNoLock;
                expressionFlags = interpreter.ExpressionFlagsNoLock;
            }

            return TestGetScriptFile(
                interpreter, encoding, fileName, ref scriptFlags,
                ref engineFlags, ref substitutionFlags, ref eventFlags,
                ref expressionFlags, ref clientData, ref canRetry,
                ref text, ref errors);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method fetches the script associated with the specified file
        /// name using the supplied interpreter, encoding, and flags, returning
        /// its text together with the client data used to read it.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the script being fetched.  This
        /// parameter may not be null.
        /// </param>
        /// <param name="encoding">
        /// The optional text encoding to use when reading the script file.
        /// </param>
        /// <param name="fileName">
        /// The name of the script file to fetch.
        /// </param>
        /// <param name="scriptFlags">
        /// On input, the script flags to use; upon return, the effective script
        /// flags that were used.
        /// </param>
        /// <param name="engineFlags">
        /// On input, the engine flags to use; upon return, the engine flags that
        /// were in effect.
        /// </param>
        /// <param name="substitutionFlags">
        /// On input, the substitution flags to use; upon return, the
        /// substitution flags that were in effect.
        /// </param>
        /// <param name="eventFlags">
        /// On input, the event flags to use; upon return, the event flags that
        /// were in effect.
        /// </param>
        /// <param name="expressionFlags">
        /// On input, the expression flags to use; upon return, the expression
        /// flags that were in effect.
        /// </param>
        /// <param name="clientData">
        /// On input, optional client data; upon return, receives the client data
        /// produced while reading the script.
        /// </param>
        /// <param name="canRetry">
        /// Upon failure, receives non-zero when the operation may be retried.
        /// </param>
        /// <param name="text">
        /// Upon success, receives the text of the fetched script.
        /// </param>
        /// <param name="errors">
        /// On input, an optional error list to add to; upon failure, receives the
        /// accumulated error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestGetScriptFile(
            Interpreter interpreter,                 /* in */
            Encoding encoding,                       /* in */
            string fileName,                         /* in */
            ref ScriptFlags scriptFlags,             /* in, out */
            ref EngineFlags engineFlags,             /* in, out */
            ref SubstitutionFlags substitutionFlags, /* in, out */
            ref EventFlags eventFlags,               /* in, out */
            ref ExpressionFlags expressionFlags,     /* in, out */
            ref IClientData clientData,              /* in, out */
            ref bool canRetry,                       /* out */
            ref string text,                         /* out */
            ref ResultList errors                    /* in, out */
            )
        {
            ScriptFlags localScriptFlags = scriptFlags;
            EngineFlags localEngineFlags = engineFlags;
            SubstitutionFlags localSubstitutionFlags = substitutionFlags;
            EventFlags localEventFlags = eventFlags;
            ExpressionFlags localExpressionFlags = expressionFlags;
            RSCD readScriptClientData = null;

            if (Engine.GetScriptFile(interpreter,
                    encoding, fileName, ref localScriptFlags,
                    ref localEngineFlags, ref localSubstitutionFlags,
                    ref localEventFlags, ref localExpressionFlags,
                    ref readScriptClientData, ref canRetry,
                    ref errors) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            scriptFlags = localScriptFlags;
            engineFlags = localEngineFlags;
            substitutionFlags = localSubstitutionFlags;
            eventFlags = localEventFlags;
            expressionFlags = localExpressionFlags;
            clientData = readScriptClientData;

            if (readScriptClientData != null)
                text = readScriptClientData.Text;

            return ReturnCode.Ok;
        }

