        /// <summary>
        /// This overload fetches a ruleset definition from the specified file
        /// (resolving the supplied interpreter's flags) and loads the resulting
        /// rules into a ruleset, evaluating the definition in a temporary
        /// interpreter created with the given creation flags.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter used to fetch the ruleset definition file.  This
        /// parameter may not be null.
        /// </param>
        /// <param name="encoding">
        /// The optional text encoding to use when reading the ruleset definition
        /// file.
