        /// The name of the file that contains the ruleset definition.
        /// </param>
        /// <param name="createFlags">
        /// The interpreter creation flags to use when evaluating the ruleset
        /// definition.
        /// </param>
        /// <param name="hostCreateFlags">
        /// The host creation flags to use when evaluating the ruleset
        /// definition.
        /// </param>
        /// <param name="scriptFlags">
        /// On input, the requested script flags (combined with those of the
        /// interpreter); upon return, the effective script flags that were used
        /// to fetch the file.
        /// </param>
        /// <param name="clientData">
        /// Upon return, receives the client data produced while reading the
        /// ruleset definition.
        /// </param>
        /// <param name="ruleSet">
        /// Upon return, contains the loaded ruleset.
        /// </param>
        /// <param name="canRetry">
        /// Upon failure, receives non-zero when the operation may be retried.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestLoadRuleSet(
            Interpreter interpreter,         /* in */
            Encoding encoding,               /* in */
            string fileName,                 /* in */
            CreateFlags createFlags,         /* in */
            HostCreateFlags hostCreateFlags, /* in */
            ref ScriptFlags scriptFlags,     /* in, out */
            ref IClientData clientData,      /* out */
            ref IRuleSet ruleSet,            /* out */
            ref bool canRetry,               /* out */
            ref Result error                 /* out */
            )
        {
            string text = null;
            ResultList errors = null;

            if (TestGetScriptFile(
                    interpreter, encoding, fileName,
                    ref scriptFlags, ref clientData,
                    ref canRetry, ref text,
                    ref errors) != ReturnCode.Ok)
            {
                error = errors;
                return ReturnCode.Error;
            }

            return TestLoadRuleSet(
                text, createFlags, hostCreateFlags, FlagOps.HasFlags(
                scriptFlags, ScriptFlags.File, true), ref ruleSet,
                ref error);
        }

