        /// The interpreter used to fetch the ruleset definition file.  This
        /// parameter may not be null.
        /// </param>
        /// <param name="encoding">
        /// The optional text encoding to use when reading the ruleset definition
        /// file.
        /// </param>
        /// <param name="fileName">
        /// The name of the file that contains the ruleset definition.
        /// </param>
        /// <param name="createFlags">
        /// The interpreter creation flags to use when evaluating the ruleset
        /// definition.
        /// </param>
        /// <param name="hostCreateFlags">
        /// The host creation flags to use when evaluating the ruleset
        /// definition.
        /// </param>
        /// <param name="scriptFlags">
        /// On input, the script flags to use; upon return, the effective script
        /// flags that were used to fetch the file.
        /// </param>
        /// <param name="engineFlags">
        /// On input, the engine flags to use; upon return, the engine flags that
        /// were in effect.
