        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestLoadRuleSet(
            Interpreter interpreter,                 /* in */
            Encoding encoding,                       /* in */
            string fileName,                         /* in */
            CreateFlags createFlags,                 /* in */
            HostCreateFlags hostCreateFlags,         /* in */
            ref ScriptFlags scriptFlags,             /* in, out */
            ref EngineFlags engineFlags,             /* in, out */
            ref SubstitutionFlags substitutionFlags, /* in, out */
            ref EventFlags eventFlags,               /* in, out */
            ref ExpressionFlags expressionFlags,     /* in, out */
            ref IClientData clientData,              /* in, out */
            ref IRuleSet ruleSet,                    /* in, out */
            ref bool canRetry,                       /* out */
            ref Result error                         /* out */
            )
        {
            string text = null;
            ResultList errors = null;

            if (TestGetScriptFile(
                    interpreter, encoding, fileName, ref scriptFlags,
                    ref engineFlags, ref substitutionFlags, ref eventFlags,
                    ref expressionFlags, ref clientData, ref canRetry,
                    ref text, ref errors) != ReturnCode.Ok)
            {
