        /// <summary>
        /// This overload loads a ruleset from the specified text -- or from the
        /// file it names when <paramref name="asFile" /> is non-zero -- using the
        /// default ruleset creation and host creation flags.
        /// </summary>
        /// <param name="text">
        /// The ruleset definition text, or the name of the file containing it
        /// when <paramref name="asFile" /> is non-zero.
        /// </param>
        /// <param name="asFile">
        /// Non-zero to treat <paramref name="text" /> as the name of a file to
        /// evaluate; zero to evaluate it directly as a script.
        /// </param>
        /// <param name="ruleSet">
        /// On input, an optional ruleset to add the loaded rules to; upon
        /// return, contains the loaded ruleset.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestLoadRuleSet(
            string text,          /* in */
            bool asFile,          /* in */
            ref IRuleSet ruleSet, /* in, out */
            ref Result error      /* out */
            )
        {
            return TestLoadRuleSet(
                text, CreateFlags.RuleSetUse, HostCreateFlags.Disable,
                asFile, ref ruleSet, ref error);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method loads a ruleset by creating a temporary interpreter
        /// (using the specified creation and host creation flags), registering
        /// the ruleset definition commands, and evaluating the supplied text --
        /// either as a file or directly as a script.
        /// </summary>
        /// <param name="text">
        /// The ruleset definition text, or the name of the file containing it
        /// when <paramref name="asFile" /> is non-zero.
        /// </param>
        /// <param name="createFlags">
        /// The interpreter creation flags to use for the temporary interpreter.
        /// </param>
        /// <param name="hostCreateFlags">
        /// The host creation flags to use for the temporary interpreter.
        /// </param>
        /// <param name="asFile">
        /// Non-zero to evaluate <paramref name="text" /> as the name of a file;
        /// zero to evaluate it directly as a script.
        /// </param>
        /// <param name="ruleSet">
        /// On input, an optional ruleset to add the loaded rules to; upon
        /// return, contains the loaded ruleset.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestLoadRuleSet(
            string text,                     /* in */
            CreateFlags createFlags,         /* in */
            HostCreateFlags hostCreateFlags, /* in */
            bool asFile,                     /* in */
            ref IRuleSet ruleSet,            /* in, out */
            ref Result error                 /* out */
            )
        {
            Result result = null; /* REUSED */

            using (Interpreter interpreter = Interpreter.Create(
                    null, createFlags, hostCreateFlags, ref result))
            {
                if (interpreter == null)
                {
                    error = result;
                    return ReturnCode.Error;
                }

                RuleSetClientData ruleSetClientData =
                    new RuleSetClientData(null, ruleSet);

                LongList tokens = null; /* NOT USED */
                ResultList results = null;

                if (TestAddRuleSetCommands(
                        interpreter, ruleSetClientData, ref tokens,
                        ref results) != ReturnCode.Ok)
                {
                    error = results;
                    return ReturnCode.Error;
                }

                result = null;

                if (asFile)
                {
                    string savedFileName = null;

                    ruleSetClientData.BeginRuleSetFile(
                        text, ref savedFileName);

                    try
                    {
                        result = null;

                        if (interpreter.EvaluateFile(
                                text, ref result) != ReturnCode.Ok)
                        {
                            error = result;
                            return ReturnCode.Error;
                        }
                    }
                    finally
                    {
                        ruleSetClientData.EndRuleSetFile(
                            ref savedFileName);
                    }
                }
                else
                {
                    if (interpreter.EvaluateScript(
                            text, ref result) != ReturnCode.Ok)
                    {
                        error = result;
                        return ReturnCode.Error;
                    }
                }

                ruleSet = ruleSetClientData.RuleSet;
                return ReturnCode.Ok;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method loads all rulesets found in the specified directory,
        /// adding each one to the supplied dictionary keyed by its name.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the rulesets being loaded.
        /// </param>
        /// <param name="directory">
        /// The optional directory to search for ruleset files; when null, a
        /// default directory is used.
        /// </param>
        /// <param name="recursive">
        /// Non-zero to search the directory recursively.
        /// </param>
        /// <param name="dictionary">
        /// On input, an optional dictionary to add the loaded rulesets to; upon
        /// return, contains the loaded rulesets keyed by name.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestLoadRuleSets(
            Interpreter interpreter,          /* in */
            string directory,                 /* in: OPTIONAL */
            bool recursive,                   /* in */
            ref RuleSetDictionary dictionary, /* in, out */
            ref Result error                  /* out */
            )
        {
            if (directory == null)
            {
                directory = CommonOps.Environment.GetVariable(
                    EnvVars.XdgRuleSetDir);
            }

            string[] fileNames;

            try
            {
                fileNames = Directory.GetFiles(
                    directory, String.Format("{0}{1}",
                    Characters.Asterisk, FileExtension.RuleSet),
                    recursive ? SearchOption.AllDirectories :
                    SearchOption.TopDirectoryOnly);
            }
            catch (Exception e)
            {
                error = e;
                return ReturnCode.Error;
            }

            if ((fileNames == null) || (fileNames.Length == 0))
            {
                error = "no file names were found";
                return ReturnCode.Error;
            }

            Array.Sort(fileNames); /* O(N) */

            if (dictionary == null)
                dictionary = new RuleSetDictionary();

            foreach (string fileName in fileNames)
            {
                IRuleSet ruleSet = null;

                if (TestLoadRuleSet(
                        fileName, ref ruleSet,
                        ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }

                dictionary[fileName] = ruleSet;
            }

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method saves the specified ruleset to the specified file, using
        /// the supplied ruleset client data to determine the target file when
        /// one is not provided.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the ruleset being saved.
        /// </param>
        /// <param name="fileName">
        /// The optional name of the file to save the ruleset to; when null, the
        /// file name is derived from the supplied ruleset client data.
        /// </param>
        /// <param name="ruleSet">
        /// The ruleset to save.
        /// </param>
        /// <param name="ruleSetClientData">
        /// On input, the ruleset client data that provides default save
        /// settings; upon return, it may be updated with details of the save
        /// operation.
        /// </param>
        /// <param name="result">
        /// Upon success, receives details about the saved ruleset; upon failure,
        /// receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestSaveRuleSet(
            Interpreter interpreter,                 /* in */
            string fileName,                         /* in: OPTIONAL */
            IRuleSet ruleSet,                        /* in */
            ref RuleSetClientData ruleSetClientData, /* in, out */
            ref Result result                        /* out */
            )
        {
            if (ruleSet == null)
            {
                result = "invalid ruleset";
                return ReturnCode.Error;
            }

            if (ruleSetClientData == null)
                ruleSetClientData = new RuleSetClientData();

            RuleIterationCallback callback = new RuleIterationCallback(
                TestSaveRuleIterationCallback);

            if (ruleSet.ForEachRule(
                    callback, interpreter, ruleSetClientData, null,
                    MatchMode.None, ref result) != ReturnCode.Ok)
            {
                return ReturnCode.Error;
            }

            string text = ruleSetClientData.GetStringAndRelease();

            if (!String.IsNullOrEmpty(fileName))
            {
                if (File.Exists(fileName))
                {
                    result = String.Format(
                        "cannot save rules: file {0} exists",
                        FormatOps.WrapOrNull(fileName));

                    return ReturnCode.Error;
                }

                try
                {
                    File.WriteAllText(fileName, text); /* throw */
                }
                catch (Exception e)
                {
                    result = e;
                    return ReturnCode.Error;
                }
            }
            else
            {
                result = text;
            }

            return ReturnCode.Ok;
        }
        #endregion

