        #region LockCallback Methods
        /// <summary>
        /// This method is a lock callback that is invoked while attempting to
        /// acquire a lock; by default it requests that the caller keep trying to
        /// acquire the lock.
        /// </summary>
        /// <param name="synchronizeAll">
        /// The synchronization object that the lock is being acquired on.
        /// </param>
        /// <param name="retry">
        /// The current retry count for the lock acquisition attempt.
        /// </param>
        /// <param name="timeout">
        /// The timeout, in milliseconds, for the lock acquisition attempt.
        /// </param>
        /// <param name="no">
        /// On input, indicates whether lock acquisition should be skipped; this
        /// callback may update its value.
        /// </param>
        /// <returns>
        /// True if the caller should stop attempting to acquire the lock;
        /// otherwise, false.
        /// </returns>
        public static bool TestLockCallback(
            ISynchronizeAll synchronizeAll, /* in */
            int retry,                      /* in */
            int timeout,                    /* in */
            ref bool no                     /* in, out */
            )
        {
            TraceOps.DebugTrace(String.Format(
                "TestLockCallback: synchronizeAll {0} ({1}) retry {2}, timeout {3}, no {4}",
                synchronizeAll, RuntimeOps.GetHashCode(synchronizeAll), retry, timeout, no),
                typeof(Default).Name, TracePriority.LockWarning);

            //
            // NOTE: By default, just keep trying for the lock.
            //
            return false;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method installs or removes the test lock callback on the
        /// specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose lock callback should be configured.
        /// </param>
        /// <param name="setup">
        /// Non-zero to install the test lock callback; zero to remove it.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives an error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestSetupLockCallback(
            Interpreter interpreter, /* in */
            bool setup,              /* in */
            ref Result error         /* out */
            )
        {
            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            interpreter.LockCallback = setup ?
                new LockCallback(TestLockCallback) : null;

            return ReturnCode.Ok;
        }
        #endregion

