        /// <summary>
        /// This method copies an input byte array to an output byte array,
        /// optionally exclusive-ORing each byte with a random value.  It is
        /// used by the test suite to verify the marshalling of multiple byte
        /// arrays.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the operation.
        /// </param>
        /// <param name="randomize">
        /// Non-zero to exclusive-OR each input byte with a random value.
        /// </param>
        /// <param name="inByteArray">
        /// The input byte array to copy.
        /// </param>
        /// <param name="outByteArray">
        /// Upon success, receives the resulting byte array.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        public ReturnCode TestTwoByteArrays(
            Interpreter interpreter,
            bool randomize,
            byte[] inByteArray,
            ref byte[] outByteArray,
            ref Result error
            )
        {
            CheckDisposed();

            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (inByteArray == null)
            {
                error = "invalid input byte array";
                return ReturnCode.Error;
            }

            if (randomize)
            {
                byte[] randomByteArray = new byte[inByteArray.Length];

                /* NO RESULT */
                interpreter.GetRandomBytes(ref randomByteArray);

                outByteArray = new byte[inByteArray.Length];

                for (int index = 0; index < outByteArray.Length; index++)
                {
                    outByteArray[index] = ConversionOps.ToByte(
                        inByteArray[index] ^ randomByteArray[index]);
                }
            }
            else
            {
                outByteArray = new byte[inByteArray.Length];

                for (int index = 0; index < outByteArray.Length; index++)
                    outByteArray[index] = inByteArray[index];
            }

            return ReturnCode.Ok;
        }

