        /// <summary>
        /// This method exercises a wide variety of parameter passing styles,
        /// including value, reference, and output parameters of several array
        /// types, and produces a new instance.  It is used by the test suite to
        /// verify complex method marshalling.
        /// </summary>
        /// <param name="w">
        /// A signed byte value.
        /// </param>
        /// <param name="x">
        /// An integer value.
        /// </param>
        /// <param name="y">
        /// A Boolean value.
        /// </param>
        /// <param name="z">
        /// A double-precision value.
        /// </param>
        /// <param name="t1">
        /// An integer array passed by reference.
        /// </param>
        /// <param name="t2">
        /// A two-dimensional integer array passed by reference.
        /// </param>
        /// <param name="t3">
        /// A string array passed by reference.
        /// </param>
        /// <param name="t4">
        /// Upon return, receives a formatted string value.
        /// </param>
        /// <param name="t5">
        /// Upon return, receives a string array.
        /// </param>
        /// <param name="t6">
        /// Upon return, receives a jagged integer array.
        /// </param>
        /// <returns>
        /// A new <see cref="Default" /> instance.
        /// </returns>
        public Default TestComplexMethod(
            sbyte w,
            int x,
            bool y,
            double z,
            ref int[] t1,
            ref int[,] t2,
            ref string[] t3,
            out string t4,
            out string[] t5,
            out int[][] t6
            )
        {
            CheckDisposed();

            if (y)
                t1[0]++;

            if (z > 1)
            {
#if !MONO_BUILD
                t2[-1, -2] += 20;
#endif

                t2[0, 0]++;
                t2[0, 1] *= 2;
                t2[1, 0]--;
                t2[1, 1] /= 2;
                t2[2, 1] += 21;
            }

            if (x > 0)
                //
                // BUGFIX: We do not want to complicate the test case to account
                //         for negative numbers here; therefore, just use the
                //         absolute value.
                //
                t3[0] = Math.Abs(PerformanceOps.GetTickCount()).ToString();

            //
            // BUGFIX: Cannot be locale-specific here.
            //
            t4 = FormatOps.Iso8601DateTime(TimeOps.GetUtcNow(), true);

            t5 = new string[] {
                w.ToString(), x.ToString(), y.ToString(), z.ToString()
            };

            t6 = new int[][] {
                new int[] { 0, 1, 2 }, new int[] { 2, 4, 6 }, new int[] { 8, 16, 32 }
            };

            return new Default(w);
        }

