#if !MONO_BUILD
        /// <summary>
        /// This method creates or modifies a two-dimensional integer array
        /// that uses non-zero lower bounds.  It is used by the test suite to
        /// verify the marshalling of multidimensional arrays with custom
        /// bounds.
        /// </summary>
        /// <param name="y">
        /// Non-zero to create a new array; otherwise, the existing array is
        /// modified in place.
        /// </param>
        /// <param name="t7">
        /// The two-dimensional integer array to create or modify, passed by
        /// reference.
        /// </param>
        /// <returns>
        /// The created or modified two-dimensional integer array.
        /// </returns>
        public int[,] TestMoreComplexMethod(
            bool y,
            ref int[,] t7
            )
        {
            CheckDisposed();

            if (y)
            {
                t7 = (int[,])Array.CreateInstance(
                    typeof(int), new int[] { 4, 5 }, new int[] { -6, 6 });
            }
            else
            {
                t7[-6, 6] += -6 * 6;
                t7[-6, 7] += -6 * 7;
                t7[-6, 8] += -6 * 8;
                t7[-6, 9] += -6 * 9;
                t7[-6, 10] += -6 * 10;

                t7[-5, 6] += -5 * 6;
                t7[-5, 7] += -5 * 7;
                t7[-5, 8] += -5 * 8;
                t7[-5, 9] += -5 * 9;
                t7[-5, 10] += -5 * 10;

                t7[-4, 6] += -4 * 6;
                t7[-4, 7] += -4 * 7;
                t7[-4, 8] += -4 * 8;
                t7[-4, 9] += -4 * 9;
                t7[-4, 10] += -4 * 10;

                t7[-3, 6] += -3 * 6;
                t7[-3, 7] += -3 * 7;
                t7[-3, 8] += -3 * 8;
                t7[-3, 9] += -3 * 9;
                t7[-3, 10] += -3 * 10;
            }

            return t7;
        }
#endif

