        /// <summary>
        /// This method populates the internal integer array field with a
        /// sequence of values, optionally in reverse order.  It is used by the
        /// test suite to prepare array state for subsequent operations.
        /// </summary>
        /// <param name="reverse">
        /// Non-zero to populate the array in descending order; otherwise, it is
        /// populated in ascending order.
        /// </param>
        public void TestSetupIntArray(
            bool reverse
            )
        {
            CheckDisposed();

            if (intArrayField == null)
                throw new InvalidOperationException();

            int length = intArrayField.Length;

            for (int index = 0; index < length; index++)
            {
                intArrayField[index] = reverse ?
                    ((length - 1) - index) : index;
            }
        }

