            )
        {
            CheckDisposed();

            if (interpreter != null)
            {
                BindingFlags bindingFlags; /* REUSED */

                bindingFlags = ObjectOps.GetBindingFlags(
                    MetaBindingFlags.PrivateInstanceGetField,
