        /// an instance of the specified type when no value is supplied.  It is
        /// used by the test suite to verify typed variable assignment.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter in which to set the variable.
        /// </param>
        /// <param name="flags">
        /// The flags used to control how the variable is set.
        /// </param>
        /// <param name="varName">
        /// The name of the variable to set.
        /// </param>
        /// <param name="varValue">
        /// The value to assign to the variable, or null to create an instance
        /// of <paramref name="type" />.
        /// </param>
        /// <param name="type">
        /// The type to instantiate when <paramref name="varValue" /> is null.
        /// </param>
        /// <param name="nonPublic">
        /// Non-zero to permit the use of non-public constructors when creating
        /// an instance.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        public ReturnCode TestSetVariableWithTypedValue(
            Interpreter interpreter,
            VariableFlags flags,
            string varName,
            object varValue,
            Type type,
            bool nonPublic,
            ref Result error
            )
        {
            CheckDisposed();

            if (interpreter == null)
            {
                error = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (varValue != null)
            {
                return interpreter.SetVariableValue2(
                    flags, varName, varValue, null,
                    ref error);
            }
            else if (type != null)
            {
                try
                {
                    varValue = TestCreateInstance(
                        type, nonPublic);

                    return interpreter.SetVariableValue2(
                        flags, varName, varValue, null,
                        ref error);
                }
                catch (Exception e)
                {
                    error = e;
                }
            }
            else
            {
                error = "must specify valid value or type";
            }

            return ReturnCode.Error;
        }

