        /// <summary>
        /// This method evaluates a script, optionally asynchronously, passing
        /// any supplied arguments as named objects.  It is used by the test
        /// suite to verify script evaluation helpers.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter in which to evaluate the script.
        /// </param>
        /// <param name="text">
        /// The script text to evaluate.
        /// </param>
        /// <param name="callback">
        /// The asynchronous completion callback, or null to evaluate
        /// synchronously.
        /// </param>
        /// <param name="clientData">
        /// The client data to associate with the evaluation.
        /// </param>
        /// <param name="objectFlags">
        /// The flags used when adding the supplied arguments as objects.
        /// </param>
        /// <param name="synchronous">
        /// Non-zero to perform the evaluation synchronously.
        /// </param>
        /// <param name="dispose">
        /// Non-zero to dispose of the added objects after the evaluation.
        /// </param>
        /// <param name="result">
        /// Upon failure, receives the error; upon success of an asynchronous
        /// evaluation, may receive the result.
        /// </param>
        /// <param name="args">
        /// The arguments to add as named objects prior to evaluation.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        public ReturnCode TestEvaluateHelper(
            Interpreter interpreter,
            string text,
            AsynchronousCallback callback,
            IClientData clientData,
            ObjectFlags objectFlags,
            bool synchronous,
            bool dispose,
            ref Result result,
            params object[] args
            )
        {
            CheckDisposed();

            ObjectDictionary objects = null;

            if (args != null)
            {
                int length = args.Length;

                objects = new ObjectDictionary(length);

                for (int index = 0; index < length; index++)
                {
                    objects.Add(String.Format(
                        "parameter{0}", index + 1), args[index]);
                }
            }

            if (callback != null) /* NOTE: Asynchronous? */
            {
                ReturnCode code;
                Result error = null;

                code = Helpers.EvaluateScript(
                    interpreter, text, callback, clientData,
                    objects, objectFlags, synchronous, dispose,
                    ref error);

                if (code != ReturnCode.Ok)
                    result = error;

                return code;
            }
            else
            {
                return Helpers.EvaluateScript(
                    interpreter, text, objects, objectFlags,
                    synchronous, dispose, ref result);
            }
        }

