            long preDisposeContextCount = 0;
            long postDisposeContextCount = 0;

            return TestEvaluateAsync(
                interpreter, text, engineFlags, substitutionFlags, eventFlags,
                expressionFlags, timeout, ref preDisposeContextCount,
                ref postDisposeContextCount, ref result);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method evaluates a script asynchronously, waiting up to the
        /// specified timeout for completion and reporting the dispose context
        /// counts.  It is used by the test suite to verify asynchronous script
        /// evaluation.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter in which to evaluate the script.
        /// </param>
        /// <param name="text">
        /// The script text to evaluate.
        /// </param>
        /// <param name="engineFlags">
        /// The engine flags used during evaluation.
        /// </param>
        /// <param name="substitutionFlags">
        /// The substitution flags used during evaluation.
        /// </param>
        /// <param name="eventFlags">
        /// The event flags used during evaluation.
        /// </param>
        /// <param name="expressionFlags">
        /// The expression flags used during evaluation.
        /// </param>
        /// <param name="timeout">
        /// The maximum number of milliseconds to wait for completion, or null
        /// to use the default timeout.
        /// </param>
        /// <param name="preDisposeContextCount">
        /// Upon success, receives the context count prior to disposal.
        /// </param>
        /// <param name="postDisposeContextCount">
        /// Upon success, receives the context count after disposal.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the result; upon failure, receives
        /// information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        public ReturnCode TestEvaluateAsync(
            Interpreter interpreter,
            string text,
            EngineFlags engineFlags,
            SubstitutionFlags substitutionFlags,
            EventFlags eventFlags,
            ExpressionFlags expressionFlags,
            int? timeout,
            ref long preDisposeContextCount,
            ref long postDisposeContextCount,
            ref Result result
            )
        {
            CheckDisposed();

            if (interpreter != null)
            {
                if (Engine.EvaluateScript(
                        interpreter, text, engineFlags, substitutionFlags,
                        eventFlags, expressionFlags, TestEvaluateAsyncCallback,
                        null, ref result) == ReturnCode.Ok)
                {
                    if (@event != null)
                    {
                        int localTimeout = ThreadOps.GetTimeout(
                            interpreter, timeout, TimeoutType.Script |
                            TimeoutType.MaybeFallback);

                        if (ThreadOps.WaitEvent(@event, localTimeout))
                        {
                            //
                            // HACK: Wait a bit for the EngineThreadStart
                            //       method to invoke MaybeDisposeThread
                            //       on the interpreter.  It should not be
                            //       too long as the callback has already
                            //       completed.
                            //
                            if (localTimeout > 0)
                            {
                                try
                                {
                                    HostOps.ThreadSleep(
                                        localTimeout); /* throw */
                                }
                                catch (ThreadAbortException e)
                                {
                                    Thread.ResetAbort();

                                    TraceOps.DebugTrace(
                                        e, typeof(Default).Name,
                                        TracePriority.ThreadError2);
                                }
                                catch (ThreadInterruptedException e)
                                {
                                    TraceOps.DebugTrace(
                                        e, typeof(Default).Name,
                                        TracePriority.ThreadError2);
                                }
                                catch (Exception e)
                                {
                                    TraceOps.DebugTrace(
                                        e, typeof(Default).Name,
                                        TracePriority.ThreadError);
                                }
                            }

#if THREADING
                            //
                            // NOTE: Return the context counts that should
                            //       have been last updated when the context
                            //       manager was purged from the thread-pool
                            //       thread.
                            //
                            interpreter.QueryDisposeContextCounts(
                                ref preDisposeContextCount,
                                ref postDisposeContextCount);
#endif

                            //
                            // NOTE: Return async result.
                            //
                            result = asyncResult;

                            return ReturnCode.Ok;
                        }
                        else
                        {
                            result = String.Format(
                                "waited {0} milliseconds for script to complete",
                                localTimeout);
                        }

                        //
                        // NOTE: Reset event for next time.
                        //
                        ThreadOps.ResetEvent(@event);
                    }
                    else
                    {
                        //
                        // NOTE: No event is setup, skip waiting.
                        //
                        return ReturnCode.Ok;
                    }
                }
            }
            else
            {
                result = "invalid interpreter";
            }

            return ReturnCode.Error;
        }

