        /// permutation, accumulating counters from each list it receives.
        /// </summary>
        /// <param name="list">
        /// The list to process, or null to stop the permutation.
        /// </param>
        /// <returns>
        /// True if the supplied list is null; otherwise, false.
        /// </returns>
        private bool TestListTransformCallback(
            IList<string> list
            )
        {
            // CheckDisposed();

            if (list == null)
                return true;

            string value = list.ToString();

            longField ^= value.GetHashCode();
            intField++;

            return false;
        }

