        /// <summary>
        /// This method is a complaint callback that optionally evaluates a
        /// configured script and optionally throws.  It is used by the test
        /// suite to verify complaint handling.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the complaint.
        /// </param>
        /// <param name="id">
        /// The unique identifier of the complaint.
        /// </param>
        /// <param name="code">
        /// The return code associated with the complaint.
        /// </param>
