        #region Methods for GetTempFileNameCallback
        /// <summary>
        /// This method is a callback that produces a temporary file name,
        /// honoring configured overrides for the path, prefix, and naming
        /// scheme, and optionally throwing on demand.  It is used by the test
        /// suite to verify temporary file name generation.
        /// </summary>
        /// <returns>
        /// The generated temporary file name.
        /// </returns>
        private string TestGetTempFileNameCallback()
        {
            // CheckDisposed();

            bool exception;

            lock (syncRoot)
            {
                exception = tempException;
            }

            if (exception)
            {
                throw new ScriptException(
                    "get temporary file name failure (requested)");
            }

            string result;
            string path;
            bool exists;

            lock (syncRoot)
            {
                path = tempPath;
            }

            if (path != null)
            {
                string format; /* NOTE: File name (only) format string. */
                long id; /* NOTE: The "unique" file identifier. */
                bool eightDotThree;

                lock (syncRoot)
                {
                    eightDotThree = tempEightDotThree;
                }

                if (eightDotThree) // COMPAT: TclTk beta.
                {
                    id = GlobalState.NextFileId();

                    if ((id < 0) || (id > 0xFFFF))
                    {
                        throw new ScriptException(String.Format(
                            "unique file identifier is out-of-range: {0}",
                            id));
                    }

                    format = "eltc{0:X4}.tmp"; /* TclTk Library Test Code */
                }
                else
                {
                    id = RuntimeOps.GetSignedRandomNumber();

                    StringBuilder builder = StringBuilderFactory.Create();
                    string prefix;

                    lock (syncRoot)
                    {
                        prefix = tempPrefix;
                    }

                    if (prefix != null)
                    {
                        /* ?????: Supplied via the end-user override. */
                        builder.Append(prefix);
                    }
                    else
                    {
                        /* TclTk NextGen Library Test Code */
                        builder.Append("enltc_");
                    }

                    builder.Append("{0:X16}.tmp");

                    format = StringBuilderCache.GetStringAndRelease(
                        ref builder);
                }

                result = Path.Combine(path, String.Format(format, id));
                exists = false; /* NOTE: File name must not exist. */
            }
            else
            {
                result = Path.GetTempFileName(); /* EXEMPT */
                exists = true; /* MSDN: File name must exist. */
            }

            if (PathOps.ShouldValidateTempFileName() &&
                !PathOps.ValidatePathAsFile(result, true, exists))
            {
                throw new ScriptException(String.Format(
                    "temporary file name failed validation (test): {0}",
                    FormatOps.WrapOrNull(result)));
            }

            return result;
        }
        #endregion

