        /// evaluating a configured script and resolving the resulting object to
        /// a command.  It is used by the test suite to verify the new command
        /// callback.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the callback.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the callback.
        /// </param>
        /// <param name="name">
        /// The name of the command being created.
        /// </param>
        /// <param name="plugin">
        /// The plugin associated with the command, if any.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// The created command, or null if no command could be produced.
        /// </returns>
        private ICommand TestNewCommandCallback(
            Interpreter interpreter,
            IClientData clientData,
            string name,
            IPlugin plugin,
            ref Result error
            )
        {
            // CheckDisposed();

            if ((callbackInterpreter != null) &&
                !String.IsNullOrEmpty(newCommandText))
            {
                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("interpreter", interpreter);
                objects.Add("clientData", clientData);
                objects.Add("name", name);
                objects.Add("plugin", plugin);

                ReturnCode code;
                Result result = null;

                code = Helpers.EvaluateScript(
                    callbackInterpreter, newCommandText,
                    objects, ref result);

                if (code == ReturnCode.Ok)
                {
                    string objectName = result;
                    IObject @object = null;

                    code = interpreter.GetObject(
                        objectName, LookupFlags.Default, ref @object,
                        ref result);

                    if (code == ReturnCode.Ok)
                    {
                        ICommand command = @object.Value as ICommand;

                        if (command == null)
                            error = "returned object is not a command";

                        return command;
                    }
                    else
                    {
                        error = result;
                    }
                }
                else
                {
                    error = result;
                }
            }

            return null;
        }
        #endregion

