        /// <param name="prefix">
        /// The prefix identifying the calling callback, or null to use a
        /// default prefix.
        /// </param>
        /// <param name="interpreter">
        /// The interpreter associated with the callback.
        /// </param>
        /// <param name="engineFlags">
        /// The engine flags associated with the callback.
        /// </param>
        /// <param name="name">
        /// The name of the unknown command.
        /// </param>
        /// <param name="oldArguments">
        /// The original argument list.
        /// </param>
        /// <param name="newArguments">
        /// The modified argument list, if any.
        /// </param>
        /// <param name="lookupFlags">
        /// The lookup flags associated with the callback.
        /// </param>
        /// <param name="ambiguous">
        /// Non-zero if the command name was ambiguous.
        /// </param>
        /// <param name="execute">
        /// The resolved executable entity, if any.
        /// </param>
        /// <param name="error">
        /// The error associated with the callback, if any.
        /// </param>
        /// <param name="code">
        /// The return code associated with the callback.
        /// </param>
        private void TraceForUnknownCallback(
            string prefix,
            Interpreter interpreter,
            EngineFlags engineFlags,
            string name,
            ArgumentList oldArguments,
            ArgumentList newArguments,
            LookupFlags lookupFlags,
            bool ambiguous,
            IExecute execute,
            Result error,
            ReturnCode code
            )
        {
            TraceOps.DebugTrace(String.Format(
                "{0}: interpreter = {1}, engineFlags = {2}, name = {3}, " +
                "oldArguments = {4}, newArguments = {5}, lookupFlags = {6}, " +
                "ambiguous = {7}, execute = {8}, error = {9}, code = {10}",
                (prefix != null) ? prefix : "TraceForUnknownCallback",
                FormatOps.InterpreterNoThrow(interpreter), FormatOps.WrapOrNull(
                engineFlags), FormatOps.WrapOrNull(name), FormatOps.WrapOrNull(
                oldArguments), FormatOps.WrapOrNull(newArguments),
                FormatOps.WrapOrNull(lookupFlags), FormatOps.WrapOrNull(
                ambiguous), FormatOps.WrapOrNull(execute), FormatOps.WrapOrNull(
                true, true, error), FormatOps.WrapOrNull(code)),
                typeof(Default).Name, TracePriority.Command);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is an unknown-command callback that evaluates a
        /// configured script and resolves the resulting object to an executable
        /// entity.  It is used by the test suite to verify unknown command
        /// handling.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the callback.
        /// </param>
        /// <param name="engineFlags">
        /// The engine flags associated with the callback.
        /// </param>
        /// <param name="name">
        /// The name of the unknown command.
        /// </param>
        /// <param name="arguments">
        /// The arguments associated with the unknown command.
        /// </param>
        /// <param name="lookupFlags">
        /// The lookup flags associated with the callback.
        /// </param>
        /// <param name="ambiguous">
        /// Upon return, indicates whether the command name was ambiguous.
        /// </param>
        /// <param name="execute">
        /// Upon success, receives the resolved executable entity.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private ReturnCode TestUnknownScriptObjectCallback(
            Interpreter interpreter,
            EngineFlags engineFlags,
            string name,
            ArgumentList arguments,
            LookupFlags lookupFlags,
            ref bool ambiguous,
            ref IExecute execute,
            ref Result error
            )
        {
            // CheckDisposed();

            ReturnCode code = ReturnCode.Ok;

            try
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    code = ReturnCode.Error;

                    return code;
                }

                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("methodName", "UnknownCallback");
                objects.Add("engineFlags", engineFlags);
                objects.Add("name", name);
                objects.Add("arguments", arguments);
                objects.Add("lookupFlags", lookupFlags);
                objects.Add("ambiguous", ambiguous);
                objects.Add("execute", execute);

                Result localResult = null; /* REUSED */

                code = Helpers.EvaluateScript(
                    interpreter, unknownCallbackText,
                    objects, ref localResult);

                if (!ResultOps.IsOkOrReturn(code))
                {
                    error = localResult;
                    return code;
                }

                string objectName = localResult;
                IObject @object = null;

                localResult = null;

                code = interpreter.GetObject(
                    objectName, LookupFlags.Default, ref @object,
                    ref localResult);

                if (code != ReturnCode.Ok)
                {
                    error = localResult;
                    return code;
                }

                IExecute localExecute = @object.Value as IExecute;

                if (localExecute == null)
                {
                    error = "returned object is not an execute";
                    code = ReturnCode.Error;

                    return code;
                }

                execute = localExecute;

                return code;
            }
            finally
            {
                TraceForUnknownCallback("TestUnknownScriptObjectCallback",
                    interpreter, engineFlags, name, arguments, null,
                    lookupFlags, ambiguous, execute, error, code);
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is an unknown-command callback that evaluates a
        /// configured script and resolves the resulting name to an executable
        /// entity via the interpreter's resolvers.  It is used by the test
        /// suite to verify unknown command handling.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the callback.
        /// </param>
        /// <param name="engineFlags">
        /// The engine flags associated with the callback.
        /// </param>
        /// <param name="name">
        /// The name of the unknown command.
        /// </param>
        /// <param name="arguments">
        /// The arguments associated with the unknown command.
        /// </param>
        /// <param name="lookupFlags">
        /// The lookup flags associated with the callback.
        /// </param>
        /// <param name="ambiguous">
        /// Upon return, indicates whether the command name was ambiguous.
        /// </param>
        /// <param name="execute">
        /// Upon success, receives the resolved executable entity.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private ReturnCode TestUnknownScriptCommandCallback(
            Interpreter interpreter,
            EngineFlags engineFlags,
            string name,
            ArgumentList arguments,
            LookupFlags lookupFlags,
            ref bool ambiguous,
            ref IExecute execute,
            ref Result error
            )
        {
            // CheckDisposed();

            ReturnCode code = ReturnCode.Ok;

            try
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    code = ReturnCode.Error;

                    return code;
                }

                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("methodName", "UnknownCallback");
                objects.Add("engineFlags", engineFlags);
                objects.Add("name", name);
                objects.Add("arguments", arguments);
                objects.Add("lookupFlags", lookupFlags);
                objects.Add("ambiguous", ambiguous);
                objects.Add("execute", execute);

                Result localResult = null; /* REUSED */

                code = Helpers.EvaluateScript(
                    interpreter, unknownCallbackText,
                    objects, ref localResult);

                if (!ResultOps.IsOkOrReturn(code))
                {
                    error = localResult;
                    return code;
                }

                string commandName = localResult;
                IExecute localExecute = null;

                localResult = null;

                code = interpreter.InternalGetIExecuteViaResolvers(
                    engineFlags, commandName, arguments, lookupFlags,
                    ref localExecute, ref localResult);

                if (code != ReturnCode.Ok)
                {
                    error = localResult;
                    return code;
                }

                execute = localExecute;
                return code;
            }
            finally
            {
                TraceForUnknownCallback("TestUnknownScriptCommandCallback",
                    interpreter, engineFlags, name, arguments, null,
                    lookupFlags, ambiguous, execute, error, code);
            }
        }

