        #region Methods for PackageCallback
        /// <summary>
        /// This method is a package fallback callback that evaluates a
        /// configured script and, when it succeeds, provides the requested
        /// package.  It is used by the test suite to verify package fallback
        /// handling.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter associated with the callback.
        /// </param>
        /// <param name="name">
        /// The name of the package being requested.
        /// </param>
        /// <param name="version">
        /// The version of the package being requested.
        /// </param>
        /// <param name="text">
        /// The text associated with the package request.
        /// </param>
        /// <param name="flags">
        /// The flags associated with the package request.
        /// </param>
        /// <param name="exact">
        /// Non-zero if an exact version match is required.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the result; upon failure, receives
        /// information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private ReturnCode TestPackageFallbackCallback(
            Interpreter interpreter,
            string name,
            Version version,
            string text,
            PackageFlags flags,
            bool exact,
            ref Result result
            )
        {
            // CheckDisposed();

            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (name == null)
            {
                result = "invalid package name";
                return ReturnCode.Error;
            }

            if (version == null)
            {
                result = "invalid package version";
                return ReturnCode.Error;
            }

            if (packageFallbackText != null)
            {
                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("methodName", "PackageFallback");
                objects.Add("name", name);
                objects.Add("version", version);
                objects.Add("text", text);
                objects.Add("flags", flags);
                objects.Add("exact", exact);

                Result localResult = null; /* REUSED */

                if (!ResultOps.IsOkOrReturn(Helpers.EvaluateScript(
                        interpreter, packageFallbackText, objects,
                        ref localResult)))
                {
                    result = localResult;
                    return ReturnCode.Error;
                }

                bool value = false;

                if (Helpers.ToBoolean(
                        interpreter, localResult, ref value,
                        ref localResult) != ReturnCode.Ok)
                {
                    result = localResult;
                    return ReturnCode.Error;
                }

                if (value)
                {
                    localResult = null;

                    if (interpreter.PkgProvide(
                            name, version, ClientData.Empty, flags,
                            ref localResult) == ReturnCode.Ok)
                    {
                        result = localResult;
                    }
                    else
                    {
                        result = localResult;
                        return ReturnCode.Error;
                    }
                }
                else
                {
                    result = String.Empty;
                }
            }
            else
            {
                result = String.Empty;
            }

            return ReturnCode.Ok;
        }
        #endregion
        #endregion

