        #region Private Static Methods
        #region Methods for StatusCallback
#if WINFORMS
        /// <summary>
        /// This method is a status callback whose behavior is controlled by a
        /// configurable setting, allowing it to succeed, return various
        /// non-success codes, or throw, for testing purposes.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the callback.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the callback.
        /// </param>
        /// <param name="text">
        /// The status text associated with the callback.
        /// </param>
        /// <param name="clear">
        /// Non-zero if the status should be cleared.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestStatusCallback(
            Interpreter interpreter,
            IClientData clientData,
            string text,
            bool clear,
            ref Result error
            )
        {
            int localShouldStatusCallback = Interlocked.CompareExchange(
                ref shouldStatusCallback, 0, 0);

            if (localShouldStatusCallback == 1)
            {
                error = "status callback error";
                return ReturnCode.Error;
            }

            if (localShouldStatusCallback == 2)
            {
                error = "status callback return";
                return ReturnCode.Return;
            }

            if (localShouldStatusCallback == 3)
            {
                error = "status callback break";
                return ReturnCode.Break;
            }

            if (localShouldStatusCallback == 4)
            {
                error = "status callback continue";
                return ReturnCode.Continue;
            }

            if (localShouldStatusCallback == 5)
                throw new ScriptException("status callback exception");

            return ReturnCode.Ok;
        }
#endif
        #endregion

