        #region Methods for Monitor
        /// <summary>
        /// This method attempts to acquire the static lock without blocking.
        /// </summary>
        /// <param name="locked">
        /// Upon return, this will be non-zero if the static lock was acquired.
        /// </param>
        private static void TryLock(
            ref bool locked /* out */
            )
        {
            if (staticSyncRoot == null)
                return;

            locked = Monitor.TryEnter(staticSyncRoot);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method releases the static lock if it is currently held by the
        /// caller.
        /// </summary>
        /// <param name="locked">
        /// On input, indicates whether the static lock is held; upon return,
        /// this will be set to false if the lock was released.
        /// </param>
        private static void ExitLock(
            ref bool locked /* in, out */
            )
        {
            if (staticSyncRoot == null)
                return;

            if (locked)
            {
                Monitor.Exit(staticSyncRoot);
                locked = false;
            }
        }
        #endregion

