        /// specified command, for use in ad-hoc command testing.
        /// </summary>
        /// <param name="command">
        /// The command whose sub-command names should be returned.
        /// </param>
        /// <returns>
        /// The sorted list of sub-command names, or null if there are none.
        /// </returns>
        private static IEnumerable TestIEnumerableMethod(
            ICommand command
            )
        {
            //
            // NOTE: Return the sub-commands for the command.
            //
            if (command != null)
            {
                EnsembleDictionary subCommands = PolicyOps.GetSubCommandsUnsafe(
                    command); /* TEST NAME LIST USE ONLY */

                if (subCommands != null)
                {
                    StringList result = new StringList(subCommands.Keys);

                    result.Sort(); /* O(N log N) */

                    return result;
                }
            }

            return null;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method determines whether the specified delegate has exactly
        /// one parameter and that parameter is of type array-of-object.
        /// </summary>
        /// <param name="callback">
        /// The delegate to examine.
        /// </param>
        /// <returns>
        /// True if the delegate has exactly one parameter of type
        /// array-of-object; otherwise, false.
        /// </returns>
        private static bool TestHasOnlyObjectArrayParameter(
            Delegate callback
            )
        {
            if (callback == null)
                return false;

            MethodInfo methodInfo = callback.Method;

            if (methodInfo == null)
                return false;

            ParameterInfo[] parameterInfo = methodInfo.GetParameters();

            if ((parameterInfo == null) || (parameterInfo.Length != 1))
                return false;

            ParameterInfo firstParameterInfo = parameterInfo[0];

            if (firstParameterInfo == null)
                return false;

            return (firstParameterInfo.ParameterType == typeof(object[]));
        }
