        #region Methods for ErrorCallback / ErrorListCallback
        /// <summary>
        /// This method is an error callback that optionally traces the supplied
        /// error (subject to a configurable pattern) and then returns it
        /// unchanged.
        /// </summary>
        /// <param name="error">
        /// The error being reported.
        /// </param>
        /// <returns>
        /// The supplied error, unchanged.
        /// </returns>
        private static Result TestErrorCallback(
            Result error
            )
        {
            if (Interlocked.CompareExchange(
                    ref shouldTraceError, 0, 0) > 0)
            {
                string pattern = Interlocked.CompareExchange(
                    ref traceErrorPattern, null, null);

                if ((pattern == null) || Parser.StringMatch(
                        null, error, 0, pattern, 0, true))
                {
                    TraceOps.DebugTrace(String.Format(
                        "TestErrorCallback: error = {0}",
                        FormatOps.WrapOrNull(true, false,
                        error)), typeof(Default).Name,
                        TracePriority.ConversionError);
                }
            }

            return error;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is an error list callback that optionally traces the
        /// supplied errors (subject to a configurable pattern) and then returns
        /// them unchanged.
        /// </summary>
        /// <param name="errors">
        /// The list of errors being reported.
        /// </param>
        /// <returns>
        /// The supplied list of errors, unchanged.
        /// </returns>
        private static ResultList TestErrorListCallback(
            ResultList errors
            )
        {
            if (Interlocked.CompareExchange(
                    ref shouldTraceError, 0, 0) > 0)
            {
                string pattern = Interlocked.CompareExchange(
                    ref traceErrorPattern, null, null);

                if ((pattern == null) || Parser.StringMatch(
                        null, (Result)errors, 0, pattern, 0, true))
                {
                    TraceOps.DebugTrace(String.Format(
                        "TestErrorListCallback: errors = {0}",
                        FormatOps.WrapOrNull(true, false,
                        errors)), typeof(Default).Name,
                        TracePriority.ConversionError);
                }
            }

            return errors;
        }
