        #region Methods for TraceFilterCallback
        /// <summary>
        /// This method is a stub trace filter callback whose behavior is
        /// controlled by a configurable setting, allowing it to filter, throw,
        /// trace, or do nothing.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the trace.
        /// </param>
        /// <param name="message">
        /// The trace message, which may be modified.
        /// </param>
        /// <param name="category">
        /// The trace category, which may be modified.
        /// </param>
        /// <param name="priority">
        /// The trace priority, which may be modified.
        /// </param>
        /// <returns>
        /// True if the trace should be filtered out; otherwise, false.
        /// </returns>
        private static bool TestTraceFilterStubCallback(
            Interpreter interpreter,
            ref string message,
            ref string category,
            ref TracePriority priority
            )
        {
            int localTraceFilterStubSetting = Interlocked.CompareExchange(
                ref traceFilterStubSetting, 0, 0);

            if (localTraceFilterStubSetting == 1)
                return true;

            if (localTraceFilterStubSetting == 2)
                throw new ScriptException("trace filter callback error");

            if (localTraceFilterStubSetting == 3)
            {
                TraceOps.DebugTrace(String.Format(
                    "TestTraceFilterStubCallback: traceFilterStubSetting = {0}",
                    localTraceFilterStubSetting), typeof(Default).Name,
                    TracePriority.TestError);
            }

            return false;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is a trace filter callback that filters out traces whose
        /// message does not match the configured pattern.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the trace.
        /// </param>
        /// <param name="message">
        /// The trace message, which may be modified.
        /// </param>
        /// <param name="category">
        /// The trace category, which may be modified.
        /// </param>
        /// <param name="priority">
        /// The trace priority, which may be modified.
        /// </param>
        /// <returns>
        /// True if the trace should be filtered out; otherwise, false.
        /// </returns>
        private static bool TestTraceFilterMessageCallback(
            Interpreter interpreter,
            ref string message,
            ref string category,
            ref TracePriority priority
            )
        {
            MatchMode mode;
            string pattern;

            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                mode = traceFilterMatchMode;
                pattern = traceFilterPattern;
            }

            if ((pattern != null) && !StringOps.Match(
                    interpreter, mode, message, pattern, false))
            {
                return true;
            }

            return false;
        }

