        /// <summary>
        /// This method is a trace filter callback that filters out traces whose
        /// category does not match the configured pattern.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the trace.
        /// </param>
        /// <param name="message">
        /// The trace message, which may be modified.
        /// </param>
        /// <param name="category">
        /// The trace category, which may be modified.
        /// </param>
        /// <param name="priority">
        /// The trace priority, which may be modified.
        /// </param>
        /// <returns>
        /// True if the trace should be filtered out; otherwise, false.
        /// </returns>
        private static bool TestTraceFilterCategoryCallback(
            Interpreter interpreter,
            ref string message,
            ref string category,
            ref TracePriority priority
            )
        {
            MatchMode mode;
            string pattern;

            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                mode = traceFilterMatchMode;
                pattern = traceFilterPattern;
            }

            if ((pattern != null) && !StringOps.Match(
                    interpreter, mode, category, pattern, false))
            {
                return true;
            }

            return false;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is a trace filter callback that appends the interpreter,
        /// category, message, and priority of each trace to the captured trace
        /// output.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the trace.
        /// </param>
        /// <param name="message">
        /// The trace message, which may be modified.
        /// </param>
        /// <param name="category">
        /// The trace category, which may be modified.
        /// </param>
        /// <param name="priority">
        /// The trace priority, which may be modified.
        /// </param>
        /// <returns>
        /// Always returns false so the trace is not filtered out.
        /// </returns>
        private static bool TestTraceFilterCaptureCallback(
            Interpreter interpreter,
            ref string message,
            ref string category,
            ref TracePriority priority
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (traceFilterOutput == null)
                    traceFilterOutput = StringBuilderFactory.CreateNoCache(); /* EXEMPT */

                traceFilterOutput.AppendLine(
                    FormatOps.InterpreterNoThrow(interpreter, false));

                traceFilterOutput.AppendLine(
                    FormatOps.DisplayString(category));

                traceFilterOutput.AppendLine(
                    FormatOps.DisplayString(message));

                traceFilterOutput.AppendLine(priority.ToString());
            }

            return false;
        }

