        #region Methods for StringOps.MatchCore
        /// <summary>
        /// This method is a string matching callback that either tries every
        /// simple match mode (when callback mode is requested) or performs a
        /// single match using the specified mode, honoring the case, comparer,
        /// and regular expression options carried by the client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the match.
        /// </param>
        /// <param name="mode">
        /// The match mode to use.
        /// </param>
        /// <param name="text">
        /// The text to match against the pattern.
        /// </param>
        /// <param name="pattern">
        /// The pattern to match.
        /// </param>
        /// <param name="clientData">
        /// The client data carrying the optional no-case flag, comparer, and
        /// regular expression options.
        /// </param>
        /// <param name="match">
        /// Upon success, this will be non-zero if the text matched the pattern.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestMatchCallback(
            Interpreter interpreter,
            MatchMode mode,
            string text,
            string pattern,
            IClientData clientData,
            ref bool match,
            ref Result error
            )
        {
            bool noCase = false;
            IComparer<string> comparer = null;
            RegexOptions regExOptions = RegexOptions.None;

            if (clientData != null)
            {
                ObjectList objectList = clientData.Data as ObjectList;

                if ((objectList != null) && (objectList.Count >= 3))
                {
                    if (objectList[0] is bool)
                        noCase = (bool)objectList[0];

                    if (objectList[1] is IComparer<string>)
                        comparer = (IComparer<string>)objectList[1];

                    if (objectList[2] is RegexOptions)
                        regExOptions = (RegexOptions)objectList[2];
                }
            }

            if (FlagOps.HasFlags(mode, MatchMode.Callback, true))
            {
                MatchMode[] modes = Enum.GetValues(
                    typeof(MatchMode)) as MatchMode[];

                if (modes != null)
                {
                    foreach (MatchMode localMode in modes)
                    {
                        if ((localMode == MatchMode.None) ||
                            (localMode == MatchMode.Invalid) ||
                            (localMode == MatchMode.Callback) ||
                            !FlagOps.HasFlags(localMode,
                                MatchMode.SimpleModeMask, false) ||
                            FlagOps.HasFlags(localMode,
                                MatchMode.SimpleModeMask, true))
                        {
                            continue;
                        }

                        ReturnCode code;
                        bool localMatch = false;
                        Result localError = null;

                        code = StringOps.Match(
                            interpreter, localMode, text,
                            pattern, noCase, comparer,
                            regExOptions, ref localMatch,
                            ref localError);

                        if (code != ReturnCode.Ok)
                        {
                            error = localError;
                            return code;
                        }

                        if (localMatch)
                        {
                            match = localMatch;
                            return ReturnCode.Ok;
                        }
                    }
                }

                match = false;
                return ReturnCode.Ok;
            }
            else
            {
                return StringOps.Match(
                    interpreter, mode, text, pattern,
                    noCase, comparer, regExOptions,
                    ref match, ref error);
            }
        }
        #endregion

