        #region Methods for ListOps.GetUniqueElements
        /// <summary>
        /// This method determines whether the specified file name has an
        /// extension associated with encrypted markup or encrypted scripts.
        /// </summary>
        /// <param name="fileName">
        /// The file name to examine.
        /// </param>
        /// <returns>
        /// True if the file name has an encrypted extension; otherwise, false.
        /// </returns>
        private static bool TestIsEncryptedFileName(
            string fileName /* in */
            )
        {
            if (String.IsNullOrEmpty(fileName))
                return false;

            string fileExtension = Path.GetExtension(fileName);

            if (PathOps.IsEqualParts(
                    fileExtension, FileExtension.EncryptedMarkup))
            {
                return true;
            }

            if (PathOps.IsEqualParts(
                    fileExtension, FileExtension.EncryptedScript))
            {
                return true;
            }

            return false;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method changes the extension of the specified script file name
        /// to either the encrypted-script extension or the plain-script
        /// extension, based on the specified flag.
        /// </summary>
        /// <param name="encrypted">
        /// Non-zero to use the encrypted-script extension; zero to use the
        /// plain-script extension.  If this parameter is null, no action is
        /// taken.
        /// </param>
        /// <param name="fileName">
        /// The script file name to modify, updated in place.
        /// </param>
        private static void TestMutateScriptFileName(
            bool? encrypted,    /* in: OPTIONAL */
            ref string fileName /* in, out */
            )
        {
            if (encrypted == null)
                return;

            if (String.IsNullOrEmpty(fileName))
                return;

            if ((bool)encrypted)
            {
                fileName = Path.Combine(Path.GetDirectoryName(
                    fileName), String.Format("{0}{1}",
                    Path.GetFileNameWithoutExtension(fileName),
                    FileExtension.EncryptedScript));
            }
            else
            {
                fileName = Path.Combine(Path.GetDirectoryName(
                    fileName), String.Format("{0}{1}",
                    Path.GetFileNameWithoutExtension(fileName),
                    FileExtension.Script));
            }
        }
        #endregion

