        /// <summary>
        /// This method records the details of a complaint into the named
        /// interpreter variable, for use by the complaint callbacks.
        /// </summary>
        /// <param name="varName">
        /// The name of the variable in which to record the complaint details.
        /// </param>
        /// <param name="interpreter">
        /// The interpreter in which to set the variable.
        /// </param>
        /// <param name="id">
        /// The unique identifier associated with the complaint.
        /// </param>
        /// <param name="code">
        /// The return code associated with the complaint.
        /// </param>
        /// <param name="result">
        /// The result associated with the complaint.
        /// </param>
        /// <param name="stackTrace">
        /// The stack trace associated with the complaint.
        /// </param>
        /// <param name="quiet">
        /// Non-zero if the complaint should be handled quietly.
        /// </param>
        /// <param name="retry">
        /// The retry count associated with the complaint.
        /// </param>
        /// <param name="levels">
        /// The nesting level associated with the complaint.
        /// </param>
        private static void TestComplainCallbackSetVariable(
            string varName,
            Interpreter interpreter,
            long id,
            ReturnCode code,
            Result result,
            string stackTrace,
            bool quiet,
            int retry,
            int levels
            )
        {
            if (interpreter != null)
            {
                ReturnCode setCode;
                Result setError = null;

                setCode = interpreter.SetVariableValue(
                    VariableFlags.None, varName, StringList.MakeList(
                    "retry", retry, "levels", levels, "formatted",
                    FormatOps.Complaint(id, code, result, stackTrace)),
                    ref setError);

                if ((setCode != ReturnCode.Ok) && (levels == 1))
                {
                    DebugOps.Complain(
                        interpreter, setCode, setError); /* RECURSIVE */
                }
            }
        }
