        /// <summary>
        /// This method implements a command callback that reports whether the
        /// named variable is currently usable.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the command.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the command.
        /// </param>
        /// <param name="arguments">
        /// The list of arguments supplied to the command.
        /// </param>
        /// <param name="result">
        /// Upon success, this will contain the command result; upon failure,
        /// this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestUsableVariableCommandCallback(
            Interpreter interpreter,
            IClientData clientData,
            ArgumentList arguments,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            if (arguments.Count != 2)
            {
                result = "wrong # args: should be \"vusable name\"";
                return ReturnCode.Error;
            }

            Result error; /* REUSED */
            VariableFlags variableFlags = VariableFlags.NoUsable;
            IVariable variable = null;

            error = null;

            if (interpreter.GetVariableViaResolversWithSplit(
                    arguments[1], ref variableFlags, ref variable,
                    ref error) != ReturnCode.Ok)
            {
                result = error;
                return ReturnCode.Error;
            }

            error = null;

            if (variable.IsUsable(ref error))
            {
                result = String.Empty;
                return ReturnCode.Ok;
            }
            else
            {
                result = error;
                return ReturnCode.Error;
            }
        }

