        /// <summary>
        /// This method implements a command callback that reports the
        /// identifier of the thread, if any, currently holding a lock on the
        /// named variable.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the command.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the command.
        /// </param>
        /// <param name="arguments">
        /// The list of arguments supplied to the command.
        /// </param>
        /// <param name="result">
        /// Upon success, this will contain the command result; upon failure,
        /// this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestIsLockedVariableCommandCallback(
            Interpreter interpreter,
            IClientData clientData,
            ArgumentList arguments,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            if (arguments.Count != 2)
            {
                result = "wrong # args: should be \"vislocked name\"";
                return ReturnCode.Error;
            }

            VariableFlags variableFlags = VariableFlags.NoUsable;
            IVariable variable = null;
            Result error = null;

            if (interpreter.GetVariableViaResolversWithSplit(
                    arguments[1], ref variableFlags, ref variable,
                    ref error) != ReturnCode.Ok)
            {
                result = error;
                return ReturnCode.Error;
            }

            Variable localVariable = variable as Variable;

            if (localVariable == null)
            {
                result = "unsupported variable type";
                return ReturnCode.Error;
            }

            long? threadId = null;

            /* IGNORED */
            localVariable.IsLockedByOtherThread(ref threadId);

            result = threadId;
            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
        /// <summary>
        /// This method implements a command callback that locks the named
        /// variable, optionally waiting up to the specified timeout.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the command.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the command.
        /// </param>
        /// <param name="arguments">
        /// The list of arguments supplied to the command.
        /// </param>
        /// <param name="result">
        /// Upon success, this will contain the command result; upon failure,
        /// this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestLockVariableCommandCallback(
            Interpreter interpreter,
            IClientData clientData,
            ArgumentList arguments,
            ref Result result
            )
        {
            if (interpreter == null)
            {
                result = "invalid interpreter";
                return ReturnCode.Error;
            }

            if (arguments == null)
            {
                result = "invalid argument list";
                return ReturnCode.Error;
            }

            if ((arguments.Count < 2) || (arguments.Count > 3))
            {
                result = "wrong # args: should be \"vlock name ?timeout?\"";
                return ReturnCode.Error;
            }

            int timeout = 0;

            if (arguments.Count == 3)
            {
                if (Value.GetInteger2(
                        (IGetValue)arguments[2], ValueFlags.AnyInteger,
                        interpreter.InternalCultureInfo, ref timeout,
                        ref result) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }
            }

            EventWaitFlags eventWaitFlags = interpreter.EventWaitFlags;
            VariableFlags variableFlags = interpreter.EventVariableFlags;

            ScriptOps.MaybeModifyEventWaitFlags(ref eventWaitFlags);

            return interpreter.LockVariable(
                eventWaitFlags, variableFlags, arguments[1], timeout, null,
                ref result);
        }

