        #region Methods for Reparse Points
        /// <summary>
        /// This method scans the specified Unicode byte data, starting at the
        /// specified index, for a sequence of characters matching the specified
        /// scan pattern, where an upper-case letter X in the pattern matches any
        /// letter.
        /// </summary>
        /// <param name="dataBytes">
        /// The byte data to scan, interpreted as a sequence of Unicode
        /// characters.
        /// </param>
        /// <param name="scanCharacters">
        /// The characters to scan for.
        /// </param>
        /// <param name="dataStartIndex">
        /// The zero-based byte index at which to begin scanning.  This must be
        /// even.
        /// </param>
        /// <returns>
        /// True if a matching sequence of characters was found; otherwise,
        /// false.
        /// </returns>
        private static bool TestScanForCharacters(
            byte[] dataBytes,
            char[] scanCharacters,
            int dataStartIndex
            )
        {
            if (dataBytes == null)
                return false;

            if (scanCharacters == null)
                return false;

            if (dataStartIndex < 0)
                return false;

            if ((dataStartIndex % 2) != 0)
                return false;

            int dataLength = dataBytes.Length;

            if (dataLength == 0)
                return false;

            if ((dataLength % 2) != 0)
                return false;

            int scanLength = scanCharacters.Length;

            if (scanLength == 0)
                return true; // NOTE: Match nothing?  Ok.

            int scanIndex = 0;

            for (int dataIndex = dataStartIndex;
                    dataIndex < dataLength; dataIndex += 2)
            {
                char dataCharacter = ConversionOps.ToChar(
                    dataBytes[dataIndex], dataBytes[dataIndex + 1]);

                char scanCharacter = scanCharacters[scanIndex];

                if (scanCharacter == Characters.X)
                {
                    if (Char.IsLetter(dataCharacter))
                    {
                        scanIndex++;

                        if (scanIndex >= scanLength)
                            return true;
                    }
                    else
                    {
                        return false;
                    }
                }
                else
                {
                    if (dataCharacter == scanCharacter)
                    {
                        scanIndex++;

                        if (scanIndex >= scanLength)
                            return true;
                    }
                    else
                    {
                        return false;
                    }
                }
            }

            return false;
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Methods for Interpreter Disposal
        /// <summary>
        /// This method disposes the specified interpreter, optionally after a
        /// delay, catching and reporting any exceptions that occur.
        /// </summary>
        /// <param name="timeout">
        /// The delay, in milliseconds, to wait before disposing the
        /// interpreter.  A value greater than zero enables the delay.
        /// </param>
        /// <param name="interpreter">
        /// The interpreter to dispose.  Upon success, this will be set to null.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// True if the interpreter was disposed successfully; otherwise, false.
        /// </returns>
        private static bool TestDisposeInterpreter(
            int timeout,                 /* in */
            ref Interpreter interpreter, /* in, out */
            ref Result error             /* out */
            )
        {
            try
            {
                if (timeout > 0)
                    HostOps.ThreadSleep(timeout); /* throw */

                if (interpreter != null)
                {
                    interpreter.Dispose(); /* throw */
                    interpreter = null;
                }

                return true;
            }
            catch (ThreadAbortException e)
            {
                Thread.ResetAbort();

                error = e;
                return false;
            }
            catch (ThreadInterruptedException e)
            {
                error = e;
                return false;
            }
            catch (Exception e)
            {
                error = e;
                return false;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is a thread pool work item callback that disposes the
        /// interpreter carried by the supplied state object after an optional
        /// delay.
        /// </summary>
        /// <param name="state">
        /// The state object for this callback, which must be a pair containing
        /// the delay and the interpreter to dispose.
        /// </param>
        private static void TestDisposeInterpreterWaitCallback(
            object state
            ) /* System.Threading.WaitCallback */
        {
            IAnyPair<int, Interpreter> anyPair =
                state as IAnyPair<int, Interpreter>;

            if (anyPair == null)
                return;

            int timeout = anyPair.X;
            Interpreter interpreter = anyPair.Y;
            Result error = null;

            if (!TestDisposeInterpreter(
                    timeout, ref interpreter, ref error))
            {
                TraceOps.DebugTrace(String.Format(
                    "TestDisposeInterpreterWaitCallback: error = {0}",
                    FormatOps.WrapOrNull(error)), typeof(Default).Name,
                    TracePriority.CleanupError);
            }
        }
        #endregion

