        #region Methods for SecurityProtocolType
#if NETWORK
        /// <summary>
        /// This method is a web error callback that, on the first attempt,
        /// saves the current best security protocol and switches to the
        /// fail-safe security protocol before allowing the transfer to
        /// continue.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the web transfer.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the web transfer.
        /// </param>
        /// <param name="uri">
        /// The URI involved in the web transfer.
        /// </param>
        /// <param name="webFlags">
        /// The flags that control the web transfer.
        /// </param>
        /// <param name="retries">
        /// The number of retries that have been attempted so far.
        /// </param>
        /// <param name="timeout">
        /// The timeout, in milliseconds, for the web transfer, or null if none.
        /// </param>
        /// <param name="maximumRetries">
        /// The maximum number of retries allowed, or null if none.
        /// </param>
        /// <param name="result">
        /// Upon return, this may contain the result of the web transfer.
        /// </param>
        /// <param name="errors">
        /// Upon failure, this will contain one or more error messages.
        /// </param>
        /// <returns>
        /// Always returns <see cref="ReturnCode.Continue" /> so that processing
        /// continues.
        /// </returns>
        private static ReturnCode TestBestWebErrorCallback(
            Interpreter interpreter,
            IClientData clientData,
            Uri uri,
            WebFlags webFlags,
            int retries,
            int? timeout,
            int? maximumRetries,
            ref object result,
            ref ResultList errors
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if ((retries == 0) && (SavedSecurityProtocol == null))
                {
                    SavedSecurityProtocol = BestSecurityProtocol;
                    BestSecurityProtocol = SecurityProtocolType.FailSafe;
                }
            }

            return ReturnCode.Continue; /* Do nothing and keep going. */
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is a web error callback that traces diagnostic
        /// information about a failed web transfer and then allows the transfer
        /// to continue.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the web transfer.
        /// </param>
        /// <param name="clientData">
        /// The client data associated with the web transfer.
        /// </param>
        /// <param name="uri">
        /// The URI involved in the web transfer.
        /// </param>
        /// <param name="webFlags">
        /// The flags that control the web transfer.
        /// </param>
        /// <param name="retries">
        /// The number of retries that have been attempted so far.
        /// </param>
        /// <param name="timeout">
        /// The timeout, in milliseconds, for the web transfer, or null if none.
        /// </param>
        /// <param name="maximumRetries">
        /// The maximum number of retries allowed, or null if none.
        /// </param>
        /// <param name="result">
        /// Upon return, this may contain the result of the web transfer.
        /// </param>
        /// <param name="errors">
        /// Upon failure, this will contain one or more error messages.
        /// </param>
        /// <returns>
        /// Always returns <see cref="ReturnCode.Continue" /> so that processing
        /// continues.
        /// </returns>
        private static ReturnCode TestLogWebErrorCallback(
            Interpreter interpreter,
            IClientData clientData,
            Uri uri,
            WebFlags webFlags,
            int retries,
            int? timeout,
            int? maximumRetries,
            ref object result,
            ref ResultList errors
            )
        {
            TraceOps.DebugTrace(
                "TestLogWebErrorCallback", null, typeof(Default).Name,
                TracePriority.NetworkError, false, "interpreter",
                interpreter, "clientData", clientData, "uri", uri,
                "webFlags", webFlags, "retries", retries, "timeout",
                timeout, "maximumRetries", maximumRetries, "result",
                result, "errors", errors);

            return ReturnCode.Continue; /* Do nothing and keep going. */
        }
#endif
