        #region Methods for [pkgInstallLog]
        /// <summary>
        /// This method validates the arguments supplied to the package install
        /// log command, extracting the install flag, install type, package
        /// name, and package directory.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the command.
        /// </param>
        /// <param name="arguments">
        /// The list of arguments to validate.
        /// </param>
        /// <param name="install">
        /// Upon success, this will be non-zero for an install action, zero for
        /// an uninstall action, or null if no action was specified.
        /// </param>
        /// <param name="type">
        /// Upon success, this will contain the package install type.
        /// </param>
        /// <param name="name">
        /// Upon success, this will contain the package name.
        /// </param>
        /// <param name="directory">
        /// Upon success, this will contain the package directory.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestValidatePkgInstallArguments(
            Interpreter interpreter,
            ArgumentList arguments,
            out bool? install,
            out PkgInstallType? type,
            out string name,
            out string directory,
            ref Result error
            )
        {
            install = null;
            type = null;
            name = null;
            directory = null;

            if (arguments == null)
            {
                error = "invalid argument list";
                return ReturnCode.Error;
            }

            if (arguments.Count < 4)
            {
                error = String.Format(
                    "wrong # args: should be \"{0} type name directory ?arg ...?\"",
                    PkgInstallLogCommandName);

                return ReturnCode.Error;
            }

            CultureInfo cultureInfo = null;

            if (interpreter != null)
                cultureInfo = interpreter.InternalCultureInfo;

            object enumValue = EnumOps.TryParseFlags(
                interpreter, typeof(PkgInstallType),
                PkgInstallType.Default.ToString(),
                arguments[1], cultureInfo, true, true,
                true, ref error);

            if (!(enumValue is PkgInstallType))
                return ReturnCode.Error;

            PkgInstallType localType = (PkgInstallType)enumValue;
            bool? localInstall = null;

            if (FlagOps.HasFlags(
                    localType, PkgInstallType.Install, true))
            {
                localInstall = true;
            }
            else if (FlagOps.HasFlags(
                    localType, PkgInstallType.Uninstall, true))
            {
                localInstall = false;
            }

            localType &= ~PkgInstallType.ActionMask;
            localType &= ~PkgInstallType.ForDefault;

            if ((localType != PkgInstallType.Temporary) &&
                (localType != PkgInstallType.Persistent))
            {
                error = String.Format(
                    "unsupported package install type, must be {0} or {1}",
                    PkgInstallType.Temporary, PkgInstallType.Persistent);

                return ReturnCode.Error;
            }

            string localName = arguments[2];

            if (!TestIsValidName(localName, ref error))
                return ReturnCode.Error;

            string localDirectory = arguments[3];

            if (String.IsNullOrEmpty(localDirectory) ||
                !Directory.Exists(localDirectory))
            {
                error = "bad package directory";
                return ReturnCode.Error;
            }

            install = localInstall;
            type = localType;
            name = localName;
            directory = localDirectory;

            return ReturnCode.Ok;
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Methods for CrossAppDomainHelper
#if !NET_STANDARD_20
        /// <summary>
        /// This method evaluates the specified script in the specified
        /// application domain using a cross-domain helper and the cross-domain
        /// callback mechanism.
        /// </summary>
        /// <param name="appDomain">
        /// The application domain in which to evaluate the script.
        /// </param>
        /// <param name="text">
        /// The script to evaluate.
        /// </param>
        /// <param name="result">
        /// Upon success, this will contain the result of evaluating the script;
        /// upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestEvaluateInAppDomainViaCross(
            AppDomain appDomain, /* in */
            string text,         /* in */
            ref Result result    /* out */
            )
        {
            if (appDomain == null)
            {
                result = "invalid application domain";
                return ReturnCode.Error;
            }

            TestCrossAppDomainHelper helper = null;

            try
            {
                helper = new TestCrossAppDomainHelper();
                helper.Text = text; /* in */

                //
                // TODO: Why can this call never succeed
                //       when the AppDomain cannot probe
                //       for the core library assembly,
                //       even if it is already loaded in
                //       that AppDomain?
                //
                appDomain.DoCallBack(helper.Evaluate); /* throw */

                result = helper.Result; /* out */
                return helper.ReturnCode; /* out */
            }
            catch (Exception e)
            {
                result = e;
                return ReturnCode.Error;
            }
            finally
            {
                ObjectOps.DisposeOrTrace<TestCrossAppDomainHelper>(
                    null, ref helper);

                helper = null;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method evaluates the specified script in the specified
        /// application domain by creating a cross-domain helper instance within
        /// that domain.
        /// </summary>
        /// <param name="appDomain">
        /// The application domain in which to evaluate the script.
        /// </param>
        /// <param name="text">
        /// The script to evaluate.
        /// </param>
        /// <param name="result">
        /// Upon success, this will contain the result of evaluating the script;
        /// upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestEvaluateInAppDomainViaCreate(
            AppDomain appDomain, /* in */
            string text,         /* in */
            ref Result result    /* out */
            )
        {
            if (appDomain == null)
            {
                result = "invalid application domain";
                return ReturnCode.Error;
            }

            string location = GlobalState.GetAssemblyLocation();

            if (String.IsNullOrEmpty(location))
            {
                result = "invalid assembly location";
                return ReturnCode.Error;
            }

            string typeName = TestCrossAppDomainHelper.GetTypeName();

            if (String.IsNullOrEmpty(typeName))
            {
                result = "invalid type name";
                return ReturnCode.Error;
            }

            TestCrossAppDomainHelper helper = null;

            try
            {
                helper = appDomain.CreateInstanceFromAndUnwrap(
                    location, typeName) as TestCrossAppDomainHelper;

                if (helper != null)
                {
                    helper.Text = text; /* in */

                    helper.Evaluate(); /* throw */

                    result = helper.Result; /* out */
                    return helper.ReturnCode; /* out */
                }
                else
                {
                    result = String.Format(
                        "could not create {0} from {1}",
                        FormatOps.WrapOrNull(typeName),
                        FormatOps.WrapOrNull(location));

                    return ReturnCode.Error;
                }
            }
            catch (Exception e)
            {
                result = e;
                return ReturnCode.Error;
            }
            finally
            {
                ObjectOps.DisposeOrTrace<TestCrossAppDomainHelper>(
                    null, ref helper);

                helper = null;
            }
        }
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Methods for SimulateKeyboardString
#if NATIVE && WINDOWS
        /// <summary>
        /// This method reads lines from the specified text reader and simulates
        /// the corresponding keyboard input, stopping when the stop event is
        /// signaled and setting the done event when finished.
        /// </summary>
        /// <param name="milliseconds">
        /// The delay, in milliseconds, between simulated keystrokes.
        /// </param>
        /// <param name="textReader">
        /// The text reader from which the keyboard input lines are read.
        /// </param>
        /// <param name="stopEvent">
        /// The event that, when signaled, causes playback to stop.
        /// </param>
        /// <param name="doneEvent">
        /// The event that will be signaled when playback is finished.
        /// </param>
        /// <param name="flags">
        /// The flags that control how the keyboard input is simulated.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestPlayKeyboardStream(
            int milliseconds,          /* in */
            TextReader textReader,     /* in */
            EventWaitHandle stopEvent, /* in */
            EventWaitHandle doneEvent, /* in */
            SimulatedKeyFlags flags,   /* in */
            ref Result error           /* out */
            )
        {
            if (textReader == null)
            {
                error = "invalid text reader";
                return ReturnCode.Error;
            }

            CheckCancelCallback cancelCallback = new CheckCancelCallback(
                TestCheckKeyboardCancelCallback);

            CheckStringCallback stringCallback = new CheckStringCallback(
                TestCheckKeyboardStringCallback);

            IClientData clientData = new ClientData(stopEvent);

            try
            {
                StringBuilder builder = null;

                try
                {
                    builder = StringBuilderFactory.Create();

                    while (true)
                    {
                        string line = textReader.ReadLine();

                        if (line == null)
                            return ReturnCode.Ok;

                        builder.Length = 0;
                        builder.Append(line);
                        builder.Append(Characters.CarriageReturn);

                        if (FlagOps.HasFlags(
                                flags, SimulatedKeyFlags.ConsoleOnly, true))
                        {
                            if (NativeConsole.SimulateKeyboardString(
                                    stringCallback, clientData,
                                    builder.ToString(), milliseconds,
                                    flags, ref error) != ReturnCode.Ok)
                            {
                                break;
                            }
                        }
                        else
                        {
                            if (NativeOps.SimulateKeyboardString(
                                    cancelCallback, stringCallback,
                                    clientData, builder.ToString(),
                                    milliseconds, flags,
                                    ref error) != ReturnCode.Ok)
                            {
                                break;
                            }
                        }
                    }
                }
                finally
                {
                    StringBuilderCache.Release(ref builder);
                }
            }
            catch (Exception e)
            {
                error = e;
            }
            finally
            {
                if (doneEvent != null)
                    ThreadOps.SetEvent(doneEvent);
            }

            return ReturnCode.Error;
        }

        ///////////////////////////////////////////////////////////////////////

        /* System.Threading.ParameterizedThreadStart */
        /// <summary>
        /// This method is a parameterized thread start routine that plays back
        /// a keyboard stream using the text reader and event handles carried by
        /// the supplied state object.
        /// </summary>
        /// <param name="obj">
        /// The state object for the thread, which must carry the keyboard
        /// playback parameters.
        /// </param>
        private static void TestPlayKeyboardStreamThreadStart(
            object obj /* in */
            )
        {
            TextReader textReader = null;

            try
            {
                NativeTriplet anyTriplet = obj as NativeTriplet;

                if (anyTriplet != null)
                {
                    EventTriplet anyTriplet2 = anyTriplet.Y as EventTriplet;

                    if (anyTriplet2 != null)
                    {
                        textReader = anyTriplet.X;
                        anyTriplet.X = null;

                        Result error = null;

                        if (TestPlayKeyboardStream(anyTriplet.Z,
                                textReader, anyTriplet2.X,
                                anyTriplet2.Y, anyTriplet2.Z,
                                ref error) != ReturnCode.Ok)
                        {
                            Utility.Complain(
                                null, ReturnCode.Error, error);
                        }
                    }
                }
            }
            finally
            {
                if (textReader != null)
                {
                    textReader.Close();
                    textReader = null;
                }
            }
        }

        ///////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.CheckCancelCallback */
        /// <summary>
        /// This method is a check-cancel callback used during simulated
        /// keyboard playback; it reports cancellation when the stop event
        /// carried by the client data has been signaled.
        /// </summary>
        /// <param name="clientData">
        /// The client data for the callback, which must carry the stop event.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// True to continue playback; otherwise, false.
        /// </returns>
        private static bool TestCheckKeyboardCancelCallback(
            IClientData clientData, /* in */
            ref Result error        /* out */
            )
        {
            if (clientData == null)
            {
                error = "invalid clientData";
                return false;
            }

            EventWaitHandle stopEvent = clientData.Data as EventWaitHandle;

            if (stopEvent == null)
            {
                error = "invalid stop event";
                return false;
            }

            if (ThreadOps.WaitEvent(stopEvent, 0))
            {
                error = "playback has been stopped";
                return false;
            }

            return true;
        }

        ///////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.CheckStringCallback */
        /// <summary>
        /// This method is a check-string callback used during simulated
        /// keyboard playback; it simply defers to the keyboard cancel callback.
        /// </summary>
        /// <param name="clientData">
        /// The client data for the callback, which must carry the stop event.
        /// </param>
        /// <param name="value">
        /// The string value being processed.  This parameter is not used.
        /// </param>
        /// <param name="index">
        /// The index associated with the string value.  This parameter is not
        /// used.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// True to continue playback; otherwise, false.
        /// </returns>
        private static bool TestCheckKeyboardStringCallback(
            IClientData clientData, /* in */
            string value,           /* in */
            int? index,             /* in */
            ref Result error        /* out */
            )
        {
            return TestCheckKeyboardCancelCallback(clientData, ref error);
        }
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Methods for Fail-Safe
        /// <summary>
        /// This method attempts to obtain the current process and the current
        /// thread, ignoring any exceptions that occur.
        /// </summary>
        /// <param name="process">
        /// Upon return, this will contain the current process, or null if it
        /// could not be obtained.
        /// </param>
        /// <param name="thread">
        /// Upon return, this will contain the current thread, or null if it
        /// could not be obtained.
        /// </param>
        private static void TestSafeGetProcessAndThread(
            out Process process, /* out */
            out Thread thread    /* out */
            )
        {
            process = null;

            try
            {
                process = Process.GetCurrentProcess();
            }
            catch
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            thread = null;

            try
            {
                thread = Thread.CurrentThread;
            }
            catch
            {
                // do nothing.
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method obtains the format string, category, and priority to use
        /// for fail-safe tracing, using the configured values when the static
        /// lock can be acquired and default values otherwise.
        /// </summary>
        /// <param name="format">
        /// Upon return, this will contain the fail-safe trace format string.
        /// </param>
        /// <param name="category">
        /// Upon return, this will contain the fail-safe trace category.
        /// </param>
        /// <param name="priority">
        /// Upon return, this will contain the fail-safe trace priority.
        /// </param>
        private static void TestGetFailSafeTraceParameters(
            out string format,         /* out */
            out string category,       /* out */
            out TracePriority priority /* out */
            )
        {
            bool locked = false;

            try
            {
                TryLock(ref locked);

                if (locked)
                {
                    format = FailSafeErrorFormat;
                    category = FailSafeCategory;
                    priority = FailSafePriority;
                }
                else
                {
                    format = DefaultFailSafeErrorFormat;
                    category = DefaultFailSafeCategory;
                    priority = DefaultFailSafePriority;
                }
            }
            finally
            {
                ExitLock(ref locked);
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method attempts to terminate the current process immediately,
        /// first via a normal exit and then via a fail-fast, optionally only
        /// reporting what it would do.
        /// </summary>
        /// <param name="exitCode">
        /// The exit code to use when terminating the process.
        /// </param>
        /// <param name="message">
        /// The message to associate with the termination.
        /// </param>
        /// <param name="whatIf">
        /// Non-zero to only trace the actions that would be taken, without
        /// actually performing them.
        /// </param>
        private static void TestExitNow(
            ExitCode exitCode, /* in */
            string message,    /* in */
            bool whatIf        /* in */
            )
        {
            try
            {
                if (whatIf)
                {
                    TraceOps.DebugTrace(String.Format(
                        "TestExitNow: EXIT {0}: {1}",
                        exitCode, FormatOps.MaybeNull(message)),
                        typeof(Default).Name,
                        TracePriority.ProcessDebug2);
                }
                else
                {
                    Environment.Exit((int)exitCode); /* throw */
                }
            }
            catch
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            try
            {
                if (whatIf)
                {
                    TraceOps.DebugTrace(String.Format(
                        "TestExitNow: FAIL-FAST {0}: {1}",
                        exitCode, FormatOps.MaybeNull(message)),
                        typeof(Default).Name,
                        TracePriority.ProcessDebug2);
                }
                else
                {
                    Environment.FailFast(message); /* throw */
                }
            }
            catch
            {
                // do nothing.
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method attempts to kill the current process and abort the
        /// current thread, optionally only reporting what it would do.
        /// </summary>
        /// <param name="whatIf">
        /// Non-zero to only trace the actions that would be taken, without
        /// actually performing them.
        /// </param>
        private static void TestKillOrAbortSelfNow(
            bool whatIf
            )
        {
            Process process;
            Thread thread;

            TestSafeGetProcessAndThread(out process, out thread);

            ///////////////////////////////////////////////////////////////////////////////////////////

            if (process != null)
            {
                try
                {
                    if (whatIf)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "TestKillOrAbortSelfNow: KILL {0}",
                            FormatOps.ProcessName(process, true)),
                            typeof(Default).Name,
                            TracePriority.ProcessDebug2);
                    }
                    else
                    {
                        process.Kill(); /* throw */
                    }
                }
                catch
                {
                    // do nothing.
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            if (thread != null)
            {
                try
                {
                    if (whatIf)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "TestKillOrAbortSelfNow: ABORT {0}",
                            FormatOps.ThreadName(thread, true)),
                            typeof(Default).Name,
                            TracePriority.ProcessDebug2);
                    }
                    else
                    {
                        thread.Abort(); /* throw */
                    }
                }
                catch
                {
                    // do nothing.
                }
            }
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Test Plugin Methods
        /// <summary>
        /// This method returns a plugin suitable for testing, preferring the
        /// test plugin (when available) and falling back to the core plugin.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter from which to obtain the plugin.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain one or more error messages.
        /// </param>
        /// <returns>
        /// The plugin instance, or null if no suitable plugin could be found.
        /// </returns>
        private static IPlugin TestGetPlugin(
            Interpreter interpreter,
            ref Result error
            )
        {
            ResultList errors = null;
            IPlugin plugin; /* REUSED */
            Result localError; /* REUSED */

#if TEST_PLUGIN || DEBUG
            localError = null;

            plugin = interpreter.GetTestPlugin(
                ref localError);

            if (plugin != null)
                return plugin;

            if (localError != null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add(localError);
            }
#endif

            localError = null;

            plugin = interpreter.GetCorePlugin(
                ref localError);

            if (plugin != null)
                return plugin;

            if (localError != null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add(localError);
            }

            error = errors;
            return null;
        }
        #endregion

