        /// <summary>
        /// This method returns a friendly name for a test-created interpreter,
        /// either as a literal unique name or as a matching pattern.
        /// </summary>
        /// <param name="asPattern">
        /// Non-zero to return a pattern that matches such names; zero to return
        /// a new unique name.
        /// </param>
        /// <returns>
        /// The friendly name or pattern.
        /// </returns>
        private static string TestGetFriendlyName(
            bool asPattern
            )
        {
            if (asPattern)
            {
                return String.Format(
                    "testCreateInterpreter{0}{1}",
                    Characters.NumberSign,
                    Characters.Asterisk);
            }
            else
            {
                return FormatOps.Id(
                    "testCreateInterpreter", null,
                    GlobalState.NextInterpreterId());
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /* CodeBrix.Platform.TclTk._Components.Public.Delegates.RuleIterationCallback */
        /// <summary>
        /// This method is a rule iteration callback that appends a textual
        /// representation of each visited rule to the string builder carried by
        /// the ruleset client data.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the rule iteration.
        /// </param>
        /// <param name="clientData">
        /// The client data for the rule iteration, which must be a ruleset
        /// client data object.
        /// </param>
        /// <param name="rule">
        /// The rule currently being visited.
        /// </param>
        /// <param name="stopOnError">
        /// Upon return, indicates whether rule iteration should stop when an
        /// error is encountered.
        /// </param>
        /// <param name="errors">
        /// Upon failure, this will contain one or more error messages.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestSaveRuleIterationCallback(
            Interpreter interpreter,
            IClientData clientData,
            IRule rule,
            ref bool stopOnError,
            ref ResultList errors
            )
        {
            RuleSetClientData ruleSetClientData =
                clientData as RuleSetClientData;

            if (ruleSetClientData == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid ruleset clientData");
                return ReturnCode.Error;
            }

            if (rule == null)
            {
                if (errors == null)
                    errors = new ResultList();

                errors.Add("invalid rule");
                return ReturnCode.Error;
            }

            rule.SetId(null);

            StringBuilder builder = ruleSetClientData.Builder;

            if (builder == null)
            {
                builder = StringBuilderFactory.Create();
                ruleSetClientData.Builder = builder;
            }

            builder.AppendLine();
            builder.AppendFormat("rule {0}", Characters.OpenBrace);
            builder.AppendLine();
            builder.AppendFormat("{0}{1}", Characters.Indent, rule);
            builder.AppendLine();
            builder.Append(Characters.CloseBrace);
            builder.AppendLine();

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method determines whether the specified name is considered
        /// valid, checking it against both the good-name and bad-name regular
        /// expressions.
        /// </summary>
        /// <param name="name">
        /// The name to validate.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// True if the name is valid; otherwise, false.
        /// </returns>
        private static bool TestIsValidName(
            string name,
            ref Result error
            )
        {
            if ((GoodNameRegEx != null) &&
                !GoodNameRegEx.Match(name).Success)
            {
                error = "this is not a good name";
                return false;
            }

            if ((BadNameRegEx != null) &&
                BadNameRegEx.Match(name).Success)
            {
                error = "this is a bad name";
                return false;
            }

            return true;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method determines whether the specified name (without any
        /// qualifying parts) is considered valid.
        /// </summary>
        /// <param name="nameOnly">
        /// The name to validate.
        /// </param>
        /// <param name="error">
        /// Upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// True if the name is valid; otherwise, false.
        /// </returns>
        private static bool TestIsValidNameOnly(
            string nameOnly,
            ref Result error
            )
        {
            if ((GoodNameOnlyRegEx != null) &&
                !GoodNameOnlyRegEx.Match(nameOnly).Success)
            {
                error = "this is not a good name";
                return false;
            }

            return true;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

#if SHELL
        /// <summary>
        /// This method initializes the table of supported command line options,
        /// along with their associated minimum and maximum argument counts, if
        /// it has not already been initialized.
        /// </summary>
        private static void TestShellInitializeOptions()
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (commandLineOptions == null)
                {
                    commandLineOptions = new CLODictionary(
                        new _Comparers.StringCustom(StringComparison.OrdinalIgnoreCase));

                    commandLineOptions.Add(CommandLineOption.About, new CLOAnyPair(0, 0));
                    commandLineOptions.Add(CommandLineOption.AnyFile, new CLOAnyPair(1, 1));

#if !ENTERPRISE_LOCKDOWN
                    commandLineOptions.Add(CommandLineOption.AnyInitialize, new CLOAnyPair(1, 1));
