        /// <summary>
        /// This method looks up the minimum and maximum argument counts
        /// associated with the specified command line option.
        /// </summary>
        /// <param name="optionName">
        /// The name of the command line option to look up.
        /// </param>
        /// <param name="minimumCount">
        /// Upon return, this will contain the minimum number of arguments for
        /// the option, or null if it could not be determined.
        /// </param>
        /// <param name="maximumCount">
        /// Upon return, this will contain the maximum number of arguments for
        /// the option, or null if it could not be determined.
        /// </param>
        private static void TestShellGetOptionArgumentCounts(
            string optionName,
            out int? minimumCount,
            out int? maximumCount
            ) /* THREAD-SAFE */
        {
            minimumCount = null;
            maximumCount = null;

            if (optionName != null)
            {
                int prefixCount = 0;

                optionName = StringOps.TrimSwitchChars(
                    optionName, ref prefixCount);

                if (prefixCount > 0)
                {
                    lock (staticSyncRoot) /* TRANSACTIONAL */
                    {
                        if (commandLineOptions != null)
                        {
                            CLOAnyPair anyPair;

                            if (commandLineOptions.TryGetValue(
                                    optionName, out anyPair))
                            {
                                minimumCount = anyPair.X;
                                maximumCount = anyPair.Y;
                            }
                            else
                            {
                                foreach (CLOPair pair in commandLineOptions)
                                {
                                    anyPair = pair.Value;

                                    if (anyPair == null)
                                        continue;

                                    if (StringOps.MatchSwitch(
                                            optionName, pair.Key))
                                    {
                                        minimumCount = anyPair.X;
                                        maximumCount = anyPair.Y;
                                        break;
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
#endif

