        /// <summary>
        /// This method sets or clears the quiet-related interpreter flags on
        /// the specified interpreter.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose flags should be modified.  If this parameter
        /// is null, no action is taken.
        /// </param>
        /// <param name="quiet">
        /// Non-zero to enable the quiet interpreter flags; zero to disable
        /// them.
        /// </param>
        /// <returns>
        /// The previous interpreter flags, or null if the interpreter is null.
        /// </returns>
        private static InterpreterFlags? TestSetQuietMask(
            Interpreter interpreter,
            bool quiet
            )
        {
            if (interpreter == null)
                return null;

            lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
            {
                InterpreterFlags oldFlags = interpreter.InterpreterFlagsNoLock;
                InterpreterFlags unsetFlags = InterpreterFlags.QuietUnsetMask;
                InterpreterFlags setFlags = InterpreterFlags.QuietSetMask;

                if (quiet)
                {
                    interpreter.InterpreterFlagsNoLock &= ~unsetFlags;
                    interpreter.InterpreterFlagsNoLock |= setFlags;
                }
                else
                {
                    interpreter.InterpreterFlagsNoLock &= ~setFlags;
                    interpreter.InterpreterFlagsNoLock |= unsetFlags;
                }

                return oldFlags;
            }
        }

