        /// does nothing.
        /// </summary>
        /// <param name="state">
        /// The state object for this callback.  This parameter is not used.
        /// </param>
        private static void TestNopWaitCallback(
            object state
            ) /* System.Threading.WaitCallback */
        {
            // do nothing.
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is a thread pool work item callback that evaluates the
        /// debugger emergency and break scripts against the interpreter passed
        /// via the supplied state object.
        /// </summary>
        /// <param name="state">
        /// The state object for this callback, which must be the interpreter to
        /// use.
        /// </param>
        private static void TestDebugEmergencyBreakWaitCallback(
            object state
            ) /* System.Threading.WaitCallback */
        {
            Interpreter interpreter = null;
            ReturnCode code = ReturnCode.Error; /* REDUNDANT */
            Result result = null;

            try
            {
                interpreter = state as Interpreter;

                if (interpreter != null)
                {
                    code = interpreter.EvaluateScript(
                        DebugEmergencyScript, ref result);

                    if (code == ReturnCode.Ok)
                    {
                        code = interpreter.EvaluateScript(
                            DebugBreakScript, ref result);
                    }
                }
                else
                {
                    result = "invalid interpreter";
                    code = ReturnCode.Error;
                }
            }
            catch (Exception e)
            {
                result = e;
                code = ReturnCode.Error;
            }
            finally
            {
                if (code != ReturnCode.Ok)
                    DebugOps.Complain(interpreter, code, result);
            }
        }

