        /// <summary>
        /// This method determines whether the specified interactive loop
        /// callback is the one previously saved by this class.
        /// </summary>
        /// <param name="interactiveLoopCallback">
        /// The interactive loop callback to check.
        /// </param>
        /// <returns>
        /// True if the specified callback is the saved interactive loop
        /// callback; otherwise, false.
        /// </returns>
        private static bool TestIsSavedInteractiveLoopCallback(
            InteractiveLoopCallback interactiveLoopCallback
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                return interactiveLoopCallback == savedInteractiveLoopCallback;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method saves the current interactive loop callback of the
        /// specified interpreter and then installs the debug interactive loop
        /// callback in its place.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose interactive loop callback should be replaced.
        /// If this parameter is null, no action is taken.
        /// </param>
        private static void TestEnableDebugInteractiveLoopCallback(
            Interpreter interpreter
            )
        {
            if (interpreter == null)
                return;

            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                savedInteractiveLoopCallback = interpreter.InteractiveLoopCallback;
                interpreter.InteractiveLoopCallback = TestDebugInteractiveLoopCallback;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method restores the previously saved interactive loop callback
        /// on the specified interpreter, undoing the effect of a prior call to
        /// enable the debug interactive loop callback.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter whose interactive loop callback should be restored.
        /// If this parameter is null, no action is taken.
        /// </param>
        private static void TestDisableDebugInteractiveLoopCallback(
            Interpreter interpreter
            )
        {
            if (interpreter == null)
                return;

            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                interpreter.InteractiveLoopCallback = savedInteractiveLoopCallback;
                savedInteractiveLoopCallback = null;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method implements an interactive loop callback used for
        /// testing the script debugger.  When using the console host, it
        /// ensures the native console window is open and ready before
        /// delegating to the previously saved interactive loop callback (or
        /// the built-in interactive loop).
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the interactive loop.
        /// </param>
        /// <param name="loopData">
        /// The data associated with this invocation of the interactive loop.
        /// </param>
        /// <param name="result">
        /// Upon success, this may contain the result of the interactive loop;
        /// upon failure, this will contain an appropriate error message.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestDebugInteractiveLoopCallback(
            Interpreter interpreter,
            IInteractiveLoopData loopData,
            ref Result result
            )
        {
#if CONSOLE
            //
            // NOTE: If the interpreter is not disposed and is using the
            //       console host, make sure the native console window
            //       is open and ready for use by the interactive use.
            //
            if (interpreter != null)
            {
                bool locked = false;

                try
                {
                    interpreter.InternalHardTryLock(ref locked);

                    if (locked)
                    {
                        if (!interpreter.InternalDisposed)
                        {
                            //
                            // HACK: Check for an actual System.Console based host.
                            //
                            _Hosts.Console consoleHost = interpreter.GetInteractiveHost(
                                typeof(_Hosts.Console)) as _Hosts.Console;

                            if (consoleHost != null)
                            {
                                HostCreateFlags hostCreateFlags = TestMaskFlags(
                                    interpreter.HostCreateFlags);

                                HostOps.SetupNativeConsole(interpreter, hostCreateFlags);

                                if (!HostOps.IsNativeConsoleOpen(interpreter, false))
                                {
                                    TraceOps.DebugTrace(
                                        "TestDebugInteractiveLoopCallback: native console is not open.",
                                        typeof(Default).Name, TracePriority.ScriptError2);
                                }
                            }
                            else
                            {
                                TraceOps.DebugTrace(String.Format(
                                    "TestDebugInteractiveLoopCallback: interpreter {0} host type mismatch.",
                                    FormatOps.InterpreterNoThrow(interpreter)),
                                    typeof(Default).Name, TracePriority.ScriptDebug2);
                            }
                        }
                        else
                        {
                            TraceOps.DebugTrace(String.Format(
                                "TestDebugInteractiveLoopCallback: interpreter {0} is disposed.",
                                FormatOps.InterpreterNoThrow(interpreter)),
                                typeof(Default).Name, TracePriority.ScriptError2);
                        }
                    }
                    else
                    {
                        TraceOps.DebugTrace(String.Format(
                            "TestDebugInteractiveLoopCallback: interpreter {0} already locked.",
                            FormatOps.InterpreterNoThrow(interpreter)),
                            typeof(Default).Name, TracePriority.LockWarning);
                    }
                }
                finally
                {
                    interpreter.InternalExitLock(ref locked);
                }
            }
            else
            {
                TraceOps.DebugTrace(
                    "TestDebugInteractiveLoopCallback: interpreter is invalid.",
                    typeof(Default).Name, TracePriority.ScriptError2);
            }
#endif

            ///////////////////////////////////////////////////////////////////////////////////////////

            InteractiveLoopCallback interactiveLoopCallback;

            lock (staticSyncRoot)
            {
                interactiveLoopCallback = savedInteractiveLoopCallback;
            }

            if (interactiveLoopCallback != null)
            {
                return interactiveLoopCallback(
                    interpreter, loopData, ref result);
            }
            else
            {
#if SHELL
                return Interpreter.InteractiveLoop(
                    interpreter, loopData, ref result);
#else
                result = "interactive loop is not implemented";
                return ReturnCode.Error;
#endif
            }
        }
#endif

