        /// purposes.
        /// </summary>
        /// <param name="type">
        /// The type to create an instance of.  This parameter may not be null.
        /// </param>
        /// <param name="nonPublic">
        /// Non-zero to permit use of a non-public constructor when creating the
        /// instance.
        /// </param>
        /// <returns>
        /// The newly created instance of the specified type.
        /// </returns>
        private static object TestCreateInstance(
            Type type,     /* in */
            bool nonPublic /* in */
            )
        {
            if (type == null)
                throw new ArgumentNullException("type");

            if (type == typeof(string))
            {
                return Activator.CreateInstance(
                    type, Guid.NewGuid().ToString().ToCharArray());
            }
            else
            {
                return Activator.CreateInstance(type, nonPublic);
            }
        }

