        /// string for testing purposes.
        /// </summary>
        /// <param name="args">
        /// The array of arguments to format.  This parameter may be null.
        /// </param>
        /// <returns>
        /// The formatted string representation of the supplied arguments.
        /// </returns>
        private static string TestFormatArgs(
            object[] args /* in: OPTIONAL */
            )
        {
            return TestFormatArgs(false, args);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method formats an array of arguments into a human-readable
        /// string for testing purposes.
        /// </summary>
        /// <param name="toString">
        /// Non-zero to include the string representation of each argument in
        /// the formatted result.
        /// </param>
        /// <param name="args">
        /// The array of arguments to format.  This parameter may be null.
        /// </param>
        /// <returns>
        /// The formatted string representation of the supplied arguments.
        /// </returns>
        public static string TestFormatArgs(
            bool toString, /* in */
            object[] args  /* in: OPTIONAL */
            )
        {
            if (args == null)
                return FormatOps.DisplayNull;

            int length = args.Length;

            if (length == 0)
                return FormatOps.DisplayEmpty;

            StringBuilder builder = StringBuilderFactory.Create();

            builder.AppendFormat("object[{0}]", length);

            if (toString)
            {
                for (int index = 0; index < length; index++)
                {
                    if (index == 0)
                    {
                        builder.Append(
                            "{0}{1}{0}", Characters.Space,
                            Characters.EqualSign);
                    }

                    object arg = args[index];

                    builder.AppendFormat("{0}{1}{2}",
                        Characters.Comma, Characters.Space,
                        FormatOps.WrapOrNull(
                            StringOps.GetStringFromObject(arg)));
                }
            }

            return StringBuilderCache.GetStringAndRelease(ref builder);
        }

