        /// <summary>
        /// This method is a test callback that handles unknown command-line
        /// arguments encountered by the shell.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the shell.
        /// </param>
        /// <param name="interactiveHost">
        /// The interactive host associated with the shell, if any.
        /// </param>
        /// <param name="clientData">
        /// The extra data supplied to the callback, if any.
        /// </param>
        /// <param name="switchCount">
        /// The number of switch-style arguments processed so far.
        /// </param>
        /// <param name="arg">
        /// The unknown argument being handled.
        /// </param>
        /// <param name="whatIf">
        /// Non-zero to evaluate the argument without taking any real action.
        /// </param>
        /// <param name="argv">
        /// Upon return, this parameter receives the remaining arguments after
        /// any consumed by this callback have been removed.
        /// </param>
        /// <param name="result">
        /// Upon return, this parameter receives a message describing how the
        /// argument was handled, or an error message on failure.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> if the argument was handled
        /// successfully; otherwise, <see cref="ReturnCode.Error" />.
        /// </returns>
        private static ReturnCode TestShellUnknownArgumentCallback(
            Interpreter interpreter,          /* in */
            IInteractiveHost interactiveHost, /* in */
            IClientData clientData,           /* in */
            int switchCount,                  /* in */
            string arg,                       /* in */
            bool whatIf,                      /* in */
            ref IList<string> argv,           /* in, out */
            ref Result result                 /* out */
            )
        {
            int argc = (argv != null) ? argv.Count : 0;

            if ((switchCount > 0) &&
                StringOps.MatchSwitch(arg, "one"))
            {
                GenericOps<string>.PopFirstArgument(ref argv);

                result += String.Format(
                    "argument one OK{0}",
                    Characters.Pipe);

                return ReturnCode.Ok;
            }
            else if ((switchCount > 0) &&
                StringOps.MatchSwitch(arg, "two"))
            {
                if (argc >= 2)
                {
                    string value = argv[1];

                    GenericOps<string>.PopFirstArgument(ref argv);
                    GenericOps<string>.PopFirstArgument(ref argv);

                    result += String.Format(
                        "argument two {0} OK{1}",
                        FormatOps.WrapOrNull(value),
                        Characters.Pipe);

                    return ReturnCode.Ok;
                }
                else
                {
                    result += String.Format(
                        "wrong # args: should be \"-two <value>\"{0}",
                        Characters.Pipe);
                }
            }
            else if ((switchCount > 0) &&
                StringOps.MatchSwitch(arg, "three"))
            {
                GenericOps<string>.PopFirstArgument(ref argv);

                result += String.Format(
                    "argument three ERROR{0}",
                    Characters.Pipe);
            }
            else
            {
                result += String.Format(
                    "invalid test argument {0}{1}",
                    FormatOps.WrapOrNull(arg),
                    Characters.Pipe);
            }

            return ReturnCode.Error;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method is a test callback that evaluates a shell script,
        /// emitting prompts before and after the evaluation.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter in which to evaluate the script.
        /// </param>
        /// <param name="text">
        /// The script text to evaluate.
        /// </param>
        /// <param name="result">
        /// Upon success, this parameter receives the result of evaluating the
        /// script.  Upon failure, this parameter receives an error message.
        /// </param>
        /// <param name="errorLine">
        /// Upon failure, this parameter receives the line number where the
        /// error occurred.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestShellEvaluateScriptCallback(
            Interpreter interpreter, /* in */
            string text,             /* in */
            ref Result result,       /* out */
            ref int errorLine        /* out */
            )
        {
            IInteractiveHost interactiveHost = (interpreter != null) ?
                interpreter.GetInteractiveHost() : null;

            ShellOps.WritePrompt(interactiveHost, String.Format(
                "Begin evaluation of shell script {0}{1}{2}...",
                Characters.OpenBrace, Parser.Quote(text),
                Characters.CloseBrace));

            try
            {
                if (interpreter != null)
                {
                    return interpreter.EvaluateScript(
                        text, ref result, ref errorLine);
                }
                else
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }
            }
            finally
            {
                ShellOps.WritePrompt(interactiveHost, String.Format(
                    "End evaluation of shell script {0}{1}{2}.",
                    Characters.OpenBrace, Parser.Quote(text),
                    Characters.CloseBrace));
            }
        }

