#if DEBUGGER
        /// <summary>
        /// This method is a test callback that enters the interactive loop on
        /// behalf of the shell.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context for the interactive loop.
        /// </param>
        /// <param name="loopData">
        /// The data describing how the interactive loop should be configured.
        /// </param>
        /// <param name="result">
        /// Upon failure, this parameter receives an error message describing
        /// why the interactive loop could not be entered or completed.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
        /// error code.
        /// </returns>
        private static ReturnCode TestShellInteractiveLoopCallback(
            Interpreter interpreter,       /* in */
            IInteractiveLoopData loopData, /* in */
            ref Result result              /* out */
            )
        {
            IInteractiveHost interactiveHost = (interpreter != null) ?
                interpreter.GetInteractiveHost() : null;

            ShellOps.WritePrompt(
                interactiveHost, "Entering the interactive loop...");

            try
            {
                return Interpreter.InteractiveLoop(
                    interpreter, loopData, ref result);
            }
            finally
            {
                ShellOps.WritePrompt(
                    interactiveHost, "Exiting the interactive loop...");
            }
        }
#endif
#endif

