        /// <summary>
        /// This method builds a dictionary that maps command names to their
        /// command data, using the supplied list of commands.
        /// </summary>
        /// <param name="commands">
        /// The list of command data to index by name.
        /// </param>
        /// <returns>
        /// The dictionary of command data keyed by name, or null if the
        /// supplied list is null.
        /// </returns>
        private static CommandDataDictionary TestMakeCommandDictionary(
            CommandDataList commands /* in */
            )
        {
            if (commands == null)
                return null;

            CommandDataDictionary result = new CommandDataDictionary();

            foreach (ICommandData command in commands)
            {
                if (command == null)
                    continue;

                string name = command.Name;

                if (name == null)
                    continue;

                result[name] = command;
            }

            return result;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method builds a dictionary that maps function names to their
        /// function data, using the supplied collection of functions.
        /// </summary>
        /// <param name="functions">
        /// The collection of function data to index by name.
        /// </param>
        /// <returns>
        /// The dictionary of function data keyed by name, or null if the
        /// supplied collection is null.
        /// </returns>
        private static FunctionDataDictionary TestMakeFunctionDictionary(
            IEnumerable<IFunctionData> functions /* in */
            )
        {
            if (functions == null)
                return null;

            FunctionDataDictionary result = new FunctionDataDictionary();

            foreach (IFunctionData function in functions)
            {
                if (function == null)
                    continue;

                string name = function.Name;

                if (name == null)
                    continue;

                result[name] = function;
            }

            return result;
        }

