        #region ResultList Command Result Helper Class
        /// <summary>
        /// This class implements a command that returns its arguments as a
        /// result list, for testing purposes.
        /// </summary>
        [ObjectId("f9c4c632-726d-4600-9c6e-58b9d48be208")]
        public sealed class ReturnAsList : IExecute
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public ReturnAsList()
            {
                // do nothing.
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method adds this command to the specified interpreter.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to add this command to.
            /// </param>
            /// <param name="name">
            /// The name to use for the added command.
            /// </param>
            /// <param name="clientData">
            /// The extra data to associate with the added command, if any.
            /// </param>
            /// <param name="token">
            /// Upon success, this parameter receives the token that identifies
            /// the added command.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter receives an error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public ReturnCode AddToInterpreter(
                Interpreter interpreter,
                string name,
                IClientData clientData,
                ref long token,
                ref Result error
                )
            {
                return Helpers.AddToInterpreter(
                    interpreter, name, this, clientData, ref token,
                    ref error);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecute Members
            /// <summary>
            /// This method executes the command, building a result list from
            /// the supplied arguments using the requested result flags.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which this command is being executed.
            /// </param>
            /// <param name="clientData">
            /// The extra data supplied when this command was created, if any.
            /// </param>
            /// <param name="arguments">
            /// The list of arguments supplied to this command.
            /// </param>
            /// <param name="result">
            /// Upon success, this parameter receives the result list built from
            /// the supplied arguments.  Upon failure, this parameter receives
            /// an error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
            public ReturnCode Execute(
                Interpreter interpreter,
                IClientData clientData,
                ArgumentList arguments,
                ref Result result
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (arguments == null)
                {
                    result = "invalid argument list";
                    return ReturnCode.Error;
                }

                int argumentCount = arguments.Count;

                if (argumentCount < 2)
                {
                    result = String.Format(
                        "wrong # args: should be \"{0} flags ?arg ...?\"",
                        null);

                    return ReturnCode.Error;
                }

                string value = arguments[1];
                ResultFlags flags = ResultFlags.DefaultListMask;

                if (!String.IsNullOrEmpty(value))
                {
                    object enumValue = EnumOps.TryParseFlags(
                        interpreter, typeof(ResultFlags), flags.ToString(),
                        value, interpreter.InternalCultureInfo, true, true,
                        true, ref result);

                    if (!(enumValue is ResultFlags))
                        return ReturnCode.Error;

                    flags = (ResultFlags)enumValue;
                }

                ResultList results = new ResultList(flags);

                for (int index = 2; index < argumentCount; index++)
                    results.Add(arguments[index]);

                result = results;
                return ReturnCode.Ok;
            }
            #endregion
        }
        #endregion

