        #region CrossAppDomainHelper Helper Class
#if !NET_STANDARD_20
        /// <summary>
        /// This class provides a helper used to evaluate a script in another
        /// application domain and convey the results back to the caller.
        /// </summary>
        [ObjectId("40db6d0e-c718-4fe6-9b1f-9fb108e8be68")]
        public sealed class TestCrossAppDomainHelper :
#if ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
            ScriptMarshalByRefObject,
#endif
            IDisposable
        {
            #region Private Data
            /// <summary>
            /// The object used to synchronize access to the data of this
            /// instance.
            /// </summary>
            private readonly object syncRoot = new object();
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Static Methods
            /// <summary>
            /// This method returns the fully qualified name of this type.
            /// </summary>
            /// <returns>
            /// The fully qualified name of this type.
            /// </returns>
            public static string GetTypeName()
            {
                return typeof(TestCrossAppDomainHelper).FullName;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public TestCrossAppDomainHelper()
            {
                // do nothing.
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// The script text to be evaluated.
            /// </summary>
            private string text;
            /// <summary>
            /// Gets or sets the script text to be evaluated.
            /// </summary>
            public string Text /* in */
            {
                get { CheckDisposed(); lock (syncRoot) { return text; } }
                set { CheckDisposed(); lock (syncRoot) { text = value; } }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The return code produced by evaluating the script text.
            /// </summary>
            private ReturnCode returnCode;
            /// <summary>
            /// Gets or sets the return code produced by evaluating the script
            /// text.
            /// </summary>
            public ReturnCode ReturnCode /* out */
            {
                get { CheckDisposed(); lock (syncRoot) { return returnCode; } }
                set { CheckDisposed(); lock (syncRoot) { returnCode = value; } }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The result produced by evaluating the script text.
            /// </summary>
            private Result result;
            /// <summary>
            /// Gets or sets the result produced by evaluating the script text.
            /// </summary>
            public Result Result /* out */
            {
                get { CheckDisposed(); lock (syncRoot) { return result; } }
                set { CheckDisposed(); lock (syncRoot) { result = value; } }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method evaluates the configured script text within an
            /// interpreter, storing the resulting return code and result for
            /// later retrieval.  It conforms to the
            /// <c>System.CrossAppDomainDelegate</c> signature.
            /// </summary>
            public void Evaluate() /* System.CrossAppDomainDelegate */
            {
                CheckDisposed();

                string localText;

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    localText = text;
                }

                ReturnCode localCode = ReturnCode.Ok; /* REUSED */
                Result localResult = null; /* REUSED */

                try
                {
                    Interpreter interpreter = Interpreter.GetFirst();

                    if (interpreter != null)
                    {
                        localResult = null;

                        localCode = interpreter.EvaluateScript(
                            localText, ref localResult);
                    }
                    else
                    {
                        localResult = null;

                        using (interpreter = Interpreter.Create(
                                ref localResult))
                        {
                            if (interpreter != null)
                            {
                                localResult = null;

                                localCode = interpreter.EvaluateScript(
                                    localText, ref localResult);
                            }
                            else
                            {
                                localCode = ReturnCode.Error;
                            }
                        }
                    }
                }
                catch (Exception e)
                {
                    localResult = e;
                    localCode = ReturnCode.Error;
                }
                finally
                {
                    lock (syncRoot) /* TRANSACTIONAL */
                    {
                        result = localResult;
                        returnCode = localCode;
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method disposes of the resources used by this instance.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if
            /// this instance has already been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(TestCrossAppDomainHelper).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method disposes of the resources used by this instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="Dispose()" /> method; otherwise, it is being called
            /// from the finalizer.
            /// </param>
            private /* protected virtual */ void Dispose(
                bool disposing /* in */
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            text = null;
                            returnCode = ReturnCode.Ok;
                            result = null;
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////

                        disposed = true;
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class, releasing any resources
            /// that were not explicitly disposed.
            /// </summary>
            ~TestCrossAppDomainHelper()
            {
                Dispose(false);
            }
            #endregion
        }
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Static Helpers Class
        /// <summary>
        /// This class provides static helper methods and nested helper types
        /// used to support the test infrastructure.
        /// </summary>
        [ObjectId("0ea7f7bb-bf64-4a11-b11c-20ff8be94024")]
        public static class Helpers
        {
            #region AsynchronousCallbackClientData Helper Class
            /// <summary>
            /// This class holds the client data used to dispatch an
            /// asynchronous callback for testing purposes.
            /// </summary>
            [ObjectId("e93df7af-ad99-4fc5-b3f5-f38b12c6115b")]
            public sealed class AsynchronousCallbackClientData : ClientData, IGetClientData
            {
                #region Private Constructors
                /// <summary>
                /// Constructs an instance of this class used to convey the
                /// state needed to dispatch an asynchronous callback.
                /// </summary>
                /// <param name="callback">
                /// The asynchronous callback to be invoked.
                /// </param>
                /// <param name="clientData">
                /// The extra data to pass to the callback, if any.
                /// </param>
                /// <param name="objectNames">
                /// The list of object names associated with the callback, if
                /// any.
                /// </param>
                /// <param name="instanceId">
                /// The unique instance identifier for this callback.
                /// </param>
                /// <param name="synchronous">
                /// Non-zero if the callback should be invoked synchronously.
                /// </param>
                /// <param name="dispose">
                /// Non-zero if associated resources should be disposed after
                /// the callback is invoked.
                /// </param>
                internal AsynchronousCallbackClientData(
                    AsynchronousCallback callback, /* in */
                    IClientData clientData,        /* in */
                    StringList objectNames,        /* in */
                    long instanceId,               /* in */
                    bool synchronous,              /* in */
                    bool dispose                   /* in */
                    )
                    : base(null, true)
                {
                    this.callback = callback;
                    this.clientData = clientData;
                    this.objectNames = objectNames;
                    this.instanceId = instanceId;
                    this.synchronous = synchronous;
                    this.dispose = dispose;
                }
                #endregion

                ///////////////////////////////////////////////////////////////////////////////////////

                #region IGetClientData Members
                /// <summary>
                /// The client data associated with this asynchronous callback
                /// instance.
                /// </summary>
                private IClientData clientData;
                /// <summary>
                /// Gets the client data associated with this asynchronous
                /// callback instance.
                /// </summary>
                public IClientData ClientData
                {
                    get { return clientData; }
                }
                #endregion

                ///////////////////////////////////////////////////////////////////////////////////////

                #region Public Properties
                /// <summary>
                /// The asynchronous callback to invoke when the evaluation
                /// completes.
                /// </summary>
                private AsynchronousCallback callback;
                /// <summary>
                /// Gets the asynchronous callback to invoke when the evaluation
                /// completes.
                /// </summary>
                public AsynchronousCallback Callback
                {
                    get { return callback; }
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                /// <summary>
                /// The names of the objects to remove when the evaluation
                /// completes.
                /// </summary>
                private StringList objectNames;
                /// <summary>
                /// Gets the names of the objects to remove when the evaluation
                /// completes.
                /// </summary>
                public StringList ObjectNames
                {
                    get { return objectNames; }
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                /// <summary>
                /// The instance identifier used to construct the saved object
                /// names.
                /// </summary>
                private long instanceId;
                /// <summary>
                /// Gets the instance identifier used to construct the saved
                /// object names.
                /// </summary>
                public long InstanceId
                {
                    get { return instanceId; }
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                /// <summary>
                /// Non-zero if the objects should be removed synchronously when
                /// the evaluation completes.
                /// </summary>
                private bool synchronous;
                /// <summary>
                /// Gets a value indicating whether the objects should be removed
                /// synchronously when the evaluation completes.
                /// </summary>
                public bool Synchronous
                {
                    get { return synchronous; }
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                /// <summary>
                /// Non-zero if the objects should be disposed when they are
                /// removed.
                /// </summary>
                private bool dispose;
                /// <summary>
                /// Gets a value indicating whether the objects should be
                /// disposed when they are removed.
                /// </summary>
                public bool Dispose
                {
                    get { return dispose; }
                }
                #endregion
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constants
            //
            // NOTE: The object flags to use when calling FixupReturnValue on the
            //       various method parameters passed required by the script being
            //       evaluated to handle formal interface methods.
            //
            /// <summary>
            /// The object flags to use when fixing up the parameter values
            /// passed to formal interface methods handled by an evaluated
            /// script.
            /// </summary>
            private static readonly ObjectFlags DefaultObjectFlags =
                ObjectFlags.Default | ObjectFlags.NoBinder |
                ObjectFlags.NoDispose | ObjectFlags.AddReference;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The object option type to use when calling FixupReturnValue
            //       on the various method parameters passed required by the
            //       script being evaluated to handle formal interface methods.
            //
            /// <summary>
            /// The object option type to use when fixing up the parameter values
            /// passed to formal interface methods handled by an evaluated
            /// script.
            /// </summary>
            private static readonly ObjectOptionType DefaultObjectOptionType =
                ObjectOptionType.Default;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method renames the named objects out of the way, or restores
            /// them, by appending the instance identifier to each name.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter containing the objects.
            /// </param>
            /// <param name="objectNames">
            /// The base names of the objects to save or restore.
            /// </param>
            /// <param name="instanceId">
            /// The instance identifier appended to each name to form the saved
            /// name.
            /// </param>
            /// <param name="restore">
            /// Non-zero to restore the objects to their base names; zero to
            /// rename them to their saved names.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            private static ReturnCode SaveOrRestoreObjects(
                Interpreter interpreter, /* in */
                StringList objectNames,  /* in */
                long instanceId,         /* in */
                bool restore,            /* in */
                ref Result error         /* out */
                )
            {
                int count = 0;

                return SaveOrRestoreObjects(
                    interpreter, objectNames, instanceId, restore,
                    ref count, ref error);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method renames the named objects out of the way, or restores
            /// them, by appending the instance identifier to each name.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter containing the objects.
            /// </param>
            /// <param name="objectNames">
            /// The base names of the objects to save or restore.
            /// </param>
            /// <param name="instanceId">
            /// The instance identifier appended to each name to form the saved
            /// name.
            /// </param>
            /// <param name="restore">
            /// Non-zero to restore the objects to their base names; zero to
            /// rename them to their saved names.
            /// </param>
            /// <param name="count">
            /// Upon return, is incremented by the number of objects that were
            /// renamed.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            private static ReturnCode SaveOrRestoreObjects(
                Interpreter interpreter, /* in */
                StringList objectNames,  /* in */
                long instanceId,         /* in */
                bool restore,            /* in */
                ref int count,           /* out */
                ref Result error         /* out */
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (objectNames == null)
                {
                    error = "invalid object names";
                    return ReturnCode.Error;
                }

                int localCount = 0;

                foreach (string oldName in objectNames)
                {
                    if (oldName == null)
                        continue;

                    string newName = String.Format(
                        "{0}_{1}", oldName, instanceId);

                    Result localResult = null;

                    if (restore)
                    {
                        if (interpreter.DoesObjectExist(
                                newName) != ReturnCode.Ok)
                        {
                            continue;
                        }

                        if (interpreter.RenameObject(
                                newName, oldName, false, false, false,
                                ref localResult) != ReturnCode.Ok)
                        {
                            error = localResult;
                            return ReturnCode.Error;
                        }

                        localCount++;
                    }
                    else
                    {
                        if (interpreter.DoesObjectExist(
                                oldName) != ReturnCode.Ok)
                        {
                            continue;
                        }

                        if (interpreter.RenameObject(
                                oldName, newName, false, false, false,
                                ref localResult) != ReturnCode.Ok)
                        {
                            error = localResult;
                            return ReturnCode.Error;
                        }

                        localCount++;
                    }
                }

                count += localCount;
                return ReturnCode.Ok;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method wraps the specified value as an opaque object handle
            /// within the interpreter, using the default object flags.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to add the object to.
            /// </param>
            /// <param name="objectName">
            /// The name to give the object, or null to automatically generate
            /// one.
            /// </param>
            /// <param name="value">
            /// The value to wrap.  This parameter may be null.
            /// </param>
            /// <param name="objectFlags">
            /// The object flags to use when wrapping the value.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the name of the wrapped object; upon
            /// failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            internal static ReturnCode FixupReturnValue(
                Interpreter interpreter, /* in */
                string objectName,       /* in */
                object value,            /* in */
                ObjectFlags objectFlags, /* in */
                ref Result result        /* out */
                )
            {
                return FixupReturnValue(
                    interpreter, objectName, value, objectFlags, false,
                    ref result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method removes the named opaque object handle from the
            /// interpreter.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to remove the object from.
            /// </param>
            /// <param name="objectName">
            /// The name of the object to remove.
            /// </param>
            /// <param name="synchronous">
            /// Non-zero to remove the object synchronously.
            /// </param>
            /// <param name="dispose">
            /// Non-zero to dispose the object when it is removed.
            /// </param>
            /// <param name="result">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            private static ReturnCode RemoveObject(
                Interpreter interpreter, /* in */
                string objectName,       /* in */
                bool synchronous,        /* in */
                bool dispose,            /* in */
                ref Result result        /* out */
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                return interpreter.RemoveObject(
                    objectName, _Public.ClientData.Empty, synchronous,
                    ref dispose, ref result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a copy of the specified asynchronous context,
            /// substituting the specified callback and client data.
            /// </summary>
            /// <param name="context">
            /// The asynchronous context to copy.  This parameter may be null.
            /// </param>
            /// <param name="callback">
            /// The callback to use in the copied context.
            /// </param>
            /// <param name="clientData">
            /// The client data to use in the copied context.  This parameter may
            /// be null.
            /// </param>
            /// <returns>
            /// The copied asynchronous context, or null if the specified context
            /// was null.
            /// </returns>
            private static IAsynchronousContext CopyAsynchronousContext(
                IAsynchronousContext context,  /* in */
                AsynchronousCallback callback, /* in */
                IClientData clientData         /* in */
                )
            {
                if (context == null)
                    return null;

                return new AsynchronousContext(
                    context.ThreadId, context.EngineMode,
                    context.Interpreter, context.Text,
                    context.EngineFlags, context.SubstitutionFlags,
                    context.EventFlags, context.ExpressionFlags,
                    callback, clientData);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method begins redirecting the interpreter standard channels
            /// to the specified streams, using a temporary stream host.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter whose channels are being redirected.
            /// </param>
            /// <param name="inputStream">
            /// The stream to use as the standard input channel.  This parameter
            /// may be null, in which case the input channel is not redirected.
            /// </param>
            /// <param name="outputStream">
            /// The stream to use as the standard output channel.  This parameter
            /// may be null, in which case the output channel is not redirected.
            /// </param>
            /// <param name="errorStream">
            /// The stream to use as the standard error channel.  This parameter
            /// may be null, in which case the error channel is not redirected.
            /// </param>
            /// <param name="hostFlags">
            /// The host flags to use for the temporary stream host.
            /// </param>
            /// <param name="channelType">
            /// On entry, the channel type flags indicating which channels to
            /// redirect; upon success, receives the channel type flags actually
            /// used.
            /// </param>
            /// <param name="streamHost">
            /// Upon success, receives the temporary stream host created for the
            /// redirection.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            private static ReturnCode BeginChannelRedirection(
                Interpreter interpreter,     /* in */
                Stream inputStream,          /* in: OPTIONAL */
                Stream outputStream,         /* in: OPTIONAL */
                Stream errorStream,          /* in: OPTIONAL */
                HostFlags hostFlags,         /* in */
                ref ChannelType channelType, /* in, out */
                ref IStreamHost streamHost,  /* out */
                ref Result error             /* out */
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                IStreamHost newStreamHost = new ScriptStreamHost(
                    inputStream, outputStream, errorStream, null,
                    null, null, Defaults.HostCreateFlags, hostFlags);

                ChannelType newChannelType = channelType;

                newChannelType &= ~ChannelType.StandardChannels;

                if (inputStream != null)
                    newChannelType |= ChannelType.Input;

                if (outputStream != null)
                    newChannelType |= ChannelType.Output;

                if (errorStream != null)
                    newChannelType |= ChannelType.Error;

                if (!FlagOps.HasFlags(
                        newChannelType, ChannelType.StandardChannels,
                        false))
                {
                    error = "no channels selected for redirection";
                    return ReturnCode.Error;
                }

                newChannelType &= ~ChannelType.EndContext;
                newChannelType &= ~ChannelType.UseHost;
                newChannelType |= ChannelType.ErrorOnNull;
                newChannelType |= ChannelType.BeginContext;
                newChannelType |= ChannelType.AllowExist;

                if (interpreter.ModifyStandardChannels(
                        newStreamHost, null, newChannelType,
                        ref error) == ReturnCode.Ok)
                {
                    channelType = newChannelType;
                    streamHost = newStreamHost;

                    return ReturnCode.Ok;
                }

                return ReturnCode.Error;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method ends the redirection of the interpreter standard
            /// channels that was previously begun, restoring the prior channels.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter whose channels are being restored.
            /// </param>
            /// <param name="channelType">
            /// The channel type flags describing the channels that were
            /// redirected.
            /// </param>
            /// <param name="streamHost">
            /// The temporary stream host that was used for the redirection.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            private static ReturnCode EndChannelRedirection(
                Interpreter interpreter, /* in */
                ChannelType channelType, /* in */
                IStreamHost streamHost,  /* in */
                ref Result error         /* out */
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                ChannelType newChannelType = channelType;

                newChannelType &= ~ChannelType.BeginContext;
                newChannelType &= ~ChannelType.UseHost;
                newChannelType |= ChannelType.AllowExist;
                newChannelType |= ChannelType.EndContext;
                newChannelType |= ChannelType.SkipGetStream;

                return interpreter.ModifyStandardChannels(
                    streamHost, null, newChannelType, ref error);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region CodeBrix.Platform.TclTk._Components.Public.Delegates.AsynchronousCallback
            /// <summary>
            /// This method is the internal callback used to invoke a
            /// user-supplied asynchronous callback and to remove any objects
            /// associated with the asynchronous evaluation when it completes.
            /// </summary>
            /// <param name="context">
            /// The context describing the completed asynchronous evaluation.
            /// This parameter may be null.
            /// </param>
            private static void AsynchronousCallbackWrapper(
                IAsynchronousContext context /* in */
                )
            {
                if (context == null)
                    return;

                AsynchronousCallbackClientData clientData =
                    context.ClientData as AsynchronousCallbackClientData;

                if (clientData == null)
                    return;

                try
                {
                    AsynchronousCallback callback = clientData.Callback;

                    if (callback != null)
                    {
                        callback(CopyAsynchronousContext(
                            context, clientData.Callback,
                            clientData.ClientData));
                    }
                }
                finally
                {
                    /* NO RESULT */
                    RemoveObjects(
                        context.Interpreter, clientData.ObjectNames,
                        clientData.InstanceId, clientData.Synchronous,
                        clientData.Dispose);
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method adds an executable entity to the interpreter under
            /// the specified name.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to add the entity to.
            /// </param>
            /// <param name="name">
            /// The name to give the entity.
            /// </param>
            /// <param name="execute">
            /// The executable entity to add.
            /// </param>
            /// <param name="clientData">
            /// The client data to associate with the entity.  This parameter may
            /// be null.
            /// </param>
            /// <param name="token">
            /// Upon success, receives the token of the added entity.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode AddToInterpreter(
                Interpreter interpreter,
                string name,
                IExecute execute,
                IClientData clientData,
                ref long token,
                ref Result error
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                Result result = null;

                if (interpreter.AddIExecute(
                        name, execute, clientData, ref token,
                        ref result) != ReturnCode.Ok)
                {
                    error = result;
                    return ReturnCode.Error;
                }

                return ReturnCode.Ok;
            }

