                    case IdentifierKind.AnyIExecute:
                    case IdentifierKind.Ensemble:
                    case IdentifierKind.Lambda:
                    case IdentifierKind.Operator:
                    case IdentifierKind.Variable:
                    case IdentifierKind.CallFrame:
                    case IdentifierKind.Host:
                    case IdentifierKind.Callback:
                    case IdentifierKind.Resolve:
                    case IdentifierKind.Namespace:
                    case IdentifierKind.SubCommand:
                    case IdentifierKind.InteractiveLoopData:
                    case IdentifierKind.ShellCallbackData:
                    case IdentifierKind.UpdateData:
                    case IdentifierKind.Certificate:
                    case IdentifierKind.KeyPair:
                    case IdentifierKind.KeyRing:
                    case IdentifierKind.Channel:
                    case IdentifierKind.None:
                    case IdentifierKind.PolicyData:
                    case IdentifierKind.TraceData:
                    case IdentifierKind.CommandData:
                    case IdentifierKind.SubCommandData:
                    case IdentifierKind.ProcedureData:
                    case IdentifierKind.LambdaData:
                    case IdentifierKind.OperatorData:
                    case IdentifierKind.FunctionData:
                    case IdentifierKind.EnsembleData:
                    case IdentifierKind.PackageData:
                    case IdentifierKind.PluginData:
                    case IdentifierKind.ObjectData:
                    case IdentifierKind.ObjectTypeData:
                    case IdentifierKind.ObjectType:
                    case IdentifierKind.Option:
                    case IdentifierKind.Module:
                    case IdentifierKind.HostData:
                    case IdentifierKind.AliasData:
                    case IdentifierKind.DelegateData:
                    case IdentifierKind.Delegate:
                    case IdentifierKind.SubDelegate:
                    case IdentifierKind.Automatic:
                    case IdentifierKind.ResolveData:
                    case IdentifierKind.ClockData:
                    case IdentifierKind.Clock:
                    case IdentifierKind.Script:
                    case IdentifierKind.ScriptBuilder:
                    case IdentifierKind.NamespaceData:
                    case IdentifierKind.InteractiveLoop:
                    case IdentifierKind.ShellCallback:
                    case IdentifierKind.Update:
                    case IdentifierKind.Path:
                    case IdentifierKind.Uri:
                    case IdentifierKind.Type:
                    case IdentifierKind.Hash:
                    case IdentifierKind.TrustedPath:
                    case IdentifierKind.TrustedUri:
                    case IdentifierKind.TrustedType:
                    case IdentifierKind.TrustedHash:
                        {
                            error = "identifier kind not supported";
                            return ReturnCode.Error;
                        }
                    default:
                        {
                            error = "unknown identifier kind";
                            return ReturnCode.Error;
                        }
                }

                return ReturnCode.Ok;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a new interpreter and adds the specified
            /// commands to it.
            /// </summary>
            /// <param name="interpreterSettings">
            /// The settings used to create the interpreter.  This parameter may
            /// be null.
            /// </param>
            /// <param name="commands">
            /// The commands to add to the interpreter, each described by a name,
            /// type, and token triplet.  This parameter may be null.
            /// </param>
            /// <param name="clientData">
            /// The client data to associate with each added command.  This
            /// parameter may be null.
            /// </param>
            /// <param name="plugin">
            /// The plugin to associate with each added command.  This parameter
            /// may be null.
            /// </param>
            /// <param name="commandFlags">
            /// The command flags to use when adding each command.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// The newly created interpreter, or null if it could not be
            /// created.
            /// </returns>
            public static Interpreter CreateInterpreterWithCommands(
                IInterpreterSettings interpreterSettings, /* in: OPTIONAL */
                IEnumerable<CommandTriplet> commands,     /* in: OPTIONAL */
                IClientData clientData,                   /* in: OPTIONAL */
                IPlugin plugin,                           /* in: OPTIONAL */
                CommandFlags commandFlags,                /* in */
                ref Result error                          /* out */
                )
            {
                Interpreter interpreter;
                Result result = null; /* REUSED */

                interpreter = Interpreter.Create(
                    interpreterSettings, false, ref result);

                if (interpreter == null)
                {
                    error = result;
                    return null;
                }

                if (commands != null)
                {
                    foreach (CommandTriplet anyTriplet in commands)
                    {
                        if (anyTriplet == null)
                            continue;

                        Type type = anyTriplet.Y;

                        if (type == null)
                            continue;

                        string name = anyTriplet.X;

                        if (name == null)
                            name = type.Name;

                        ICommandData commandData = new CommandData(
                            name, null, null, clientData, type.FullName,
                            commandFlags, plugin, 0);

                        try
                        {
                            ICommand command = Activator.CreateInstance(
                                type, commandData) as ICommand; /* throw */

                            if (command == null)
                            {
                                interpreter.Dispose(); /* throw */
                                interpreter = null;

                                error = String.Format(
                                    "cannot create instance of type {0}",
                                    MarshalOps.GetErrorTypeName(type));

                                break;
                            }

                            long token = 0;

                            result = null;

                            if (interpreter.AddCommand(
                                    command, null, ref token,
                                    ref result) == ReturnCode.Ok)
                            {
                                //
                                // NOTE: Save new command token to its
                                //       associated command descriptor
                                //       for use by the caller.  This
                                //       can be done if the triplet is
                                //       actually mutable.
                                //
                                if (anyTriplet.Mutable)
                                    anyTriplet.Z = token;
                            }
                            else
                            {
                                interpreter.Dispose(); /* throw */
                                interpreter = null;

                                error = result;
                                break;
                            }
                        }
                        catch (Exception e)
                        {
                            try
                            {
                                if (interpreter != null)
                                {
                                    interpreter.Dispose(); /* throw */
                                    interpreter = null;
                                }
                            }
                            catch (Exception ex)
                            {
                                TraceOps.DebugTrace(
                                    ex, typeof(Helpers).Name,
                                    TracePriority.CleanupError);
                            }

                            error = e;
                            break;
                        }
                    }
                }

                return interpreter;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method wraps the specified value as an opaque object handle
            /// within the interpreter.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to add the object to.
            /// </param>
            /// <param name="objectName">
            /// The name to give the object, or null to automatically generate
            /// one.
            /// </param>
            /// <param name="value">
            /// The value to wrap.  This parameter may be null.
            /// </param>
            /// <param name="objectFlags">
            /// The object flags to use when wrapping the value.
            /// </param>
            /// <param name="noDefaultObjectFlags">
            /// Non-zero to omit the default object flags that are otherwise
            /// added.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the name of the wrapped object; upon
            /// failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode FixupReturnValue(
                Interpreter interpreter,   /* in */
                string objectName,         /* in */
                object value,              /* in */
                ObjectFlags objectFlags,   /* in */
                bool noDefaultObjectFlags, /* in */
                ref Result result          /* out */
                )
            {
                ObjectFlags localObjectFlags = objectFlags;

                if (!noDefaultObjectFlags)
                    localObjectFlags |= DefaultObjectFlags;

                return MarshalOps.FixupReturnValue(
                    interpreter, null, localObjectFlags, null,
                    null, DefaultObjectOptionType, objectName,
                    value, true, true, false, ref result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method fixes up each of the specified objects into the
            /// interpreter, renaming any conflicting existing objects out of the
            /// way, and collects the resulting object names.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to add the objects to.
            /// </param>
            /// <param name="objects">
            /// The objects to fix up into the interpreter.  This parameter may
            /// be null.
            /// </param>
            /// <param name="objectFlags">
            /// The object flags to use when fixing up the objects.
            /// </param>
            /// <param name="instanceId">
            /// The instance identifier used to construct the saved object names.
            /// </param>
            /// <param name="objectNames">
            /// Upon return, receives the names of the objects that were added to
            /// the interpreter.  This parameter may be null on entry.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode FixupReturnValues(
                Interpreter interpreter,    /* in */
                ObjectDictionary objects,   /* in */
                ObjectFlags objectFlags,    /* in */
                long instanceId,            /* in */
                ref StringList objectNames, /* in, out */
                ref Result error            /* out */
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (objects != null)
                {
                    lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
                    {
                        if (Interpreter.IsDeletedOrDisposed(
                                interpreter, false, ref error))
                        {
                            return ReturnCode.Error;
                        }

                        StringList localObjectNames = new StringList(objects.Keys);

                        if (SaveOrRestoreObjects(
                                interpreter, localObjectNames, instanceId, false,
                                ref error) != ReturnCode.Ok)
                        {
                            return ReturnCode.Error;
                        }

                        foreach (ObjectPair pair in objects)
                        {
                            string objectName = pair.Key;

                            if (String.IsNullOrEmpty(objectName))
                                objectName = null; /* AUTOMATIC */

                            Result localResult = null;

                            if (FixupReturnValue(interpreter,
                                    objectName, pair.Value, objectFlags,
                                    ref localResult) != ReturnCode.Ok)
                            {
                                error = localResult;
                                return ReturnCode.Error;
                            }

                            if (localResult != null)
                            {
                                if (objectNames == null)
                                    objectNames = new StringList();

                                objectNames.Add(localResult);
                            }
                        }
                    }
                }

                return ReturnCode.Ok;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method removes the named objects from the interpreter and
            /// then restores any objects that were previously renamed out of the
            /// way.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to remove the objects from.  This parameter may
            /// be null.
            /// </param>
            /// <param name="objectNames">
            /// The names of the objects to remove.  This parameter may be null.
            /// </param>
            /// <param name="instanceId">
            /// The instance identifier used to construct the saved object names.
            /// </param>
            /// <param name="synchronous">
            /// Non-zero to remove the objects synchronously.
            /// </param>
            /// <param name="dispose">
            /// Non-zero to dispose the objects when they are removed.
            /// </param>
            public static void RemoveObjects(
                Interpreter interpreter, /* in */
                StringList objectNames,  /* in */
                long instanceId,         /* in */
                bool synchronous,        /* in */
                bool dispose             /* in */
                )
            {
                if ((interpreter != null) && (objectNames != null))
                {
                    lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
                    {
                        if (Interpreter.IsDeletedOrDisposed(interpreter, false))
                            return;

                        foreach (string objectName in objectNames)
                        {
                            if (objectName == null)
                                continue;

                            ReturnCode removeCode;
                            Result removeResult = null;

                            removeCode = RemoveObject(
                                interpreter, objectName, synchronous,
                                dispose, ref removeResult);

                            if (removeCode != ReturnCode.Ok)
                            {
                                DebugOps.Complain(
                                    interpreter, removeCode, removeResult);
                            }
                        }

                        ReturnCode restoreCode;
                        Result restoreError = null;

                        restoreCode = SaveOrRestoreObjects(
                            interpreter, objectNames, instanceId, true,
                            ref restoreError);

                        if (restoreCode != ReturnCode.Ok)
                        {
                            DebugOps.Complain(
                                interpreter, restoreCode, restoreError);
                        }
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method evaluates the specified script, fixing up the
            /// specified objects beforehand and removing them when the script
            /// completes, using default object and removal options.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used to evaluate the script.
            /// </param>
            /// <param name="text">
            /// The script text to evaluate.
            /// </param>
            /// <param name="objects">
            /// The objects to make available to the script.  This parameter may
            /// be null.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the result of the script; upon failure,
            /// receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode EvaluateScript(
                Interpreter interpreter,  /* in */
                string text,              /* in */
                ObjectDictionary objects, /* in */
                ref Result result         /* out */
                )
            {
                return EvaluateScript(
                    interpreter, text, objects, ObjectFlags.None,
                    ObjectOps.GetDefaultSynchronous(),
                    ObjectOps.GetDefaultDispose(), ref result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method evaluates the specified script, fixing up the
            /// specified objects beforehand and removing them when the script
            /// completes.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used to evaluate the script.
            /// </param>
            /// <param name="text">
            /// The script text to evaluate.
            /// </param>
            /// <param name="objects">
            /// The objects to make available to the script.  This parameter may
            /// be null.
            /// </param>
            /// <param name="objectFlags">
            /// The object flags to use when fixing up the objects.
            /// </param>
            /// <param name="synchronous">
            /// Non-zero to remove the objects synchronously when the script
            /// completes.
            /// </param>
            /// <param name="dispose">
            /// Non-zero to dispose the objects when they are removed.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the result of the script; upon failure,
            /// receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode EvaluateScript(
                Interpreter interpreter,  /* in */
                string text,              /* in */
                ObjectDictionary objects, /* in */
                ObjectFlags objectFlags,  /* in */
                bool synchronous,         /* in */
                bool dispose,             /* in */
                ref Result result         /* out */
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                long instanceId = interpreter.NextId();
                StringList objectNames = null;

                try
                {
                    Result error = null;

                    if (FixupReturnValues(
                            interpreter, objects, objectFlags,
                            instanceId, ref objectNames,
                            ref error) != ReturnCode.Ok)
                    {
                        result = error;
                        return ReturnCode.Error;
                    }

                    return interpreter.EvaluateScript(
                        text, ref result);
                }
                finally
                {
                    /* NO RESULT */
                    RemoveObjects(
                        interpreter, objectNames, instanceId,
                        synchronous, dispose);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method evaluates the specified script asynchronously,
            /// fixing up the specified objects beforehand and removing them when
            /// the script completes.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used to evaluate the script.
            /// </param>
            /// <param name="text">
            /// The script text to evaluate.
            /// </param>
            /// <param name="callback">
            /// The callback to invoke when the asynchronous evaluation
            /// completes.
            /// </param>
            /// <param name="clientData">
            /// The client data to pass to the callback.  This parameter may be
            /// null.
            /// </param>
            /// <param name="objects">
            /// The objects to make available to the script.  This parameter may
            /// be null.
            /// </param>
            /// <param name="objectFlags">
            /// The object flags to use when fixing up the objects.
            /// </param>
            /// <param name="synchronous">
            /// Non-zero to remove the objects synchronously when the script
            /// completes.
            /// </param>
            /// <param name="dispose">
            /// Non-zero to dispose the objects when they are removed.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode EvaluateScript(
                Interpreter interpreter,       /* in */
                string text,                   /* in */
                AsynchronousCallback callback, /* in */
                IClientData clientData,        /* in */
                ObjectDictionary objects,      /* in */
                ObjectFlags objectFlags,       /* in */
                bool synchronous,              /* in */
                bool dispose,                  /* in */
                ref Result error               /* out */
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                long instanceId = interpreter.NextId();
                StringList objectNames = null;

                if (FixupReturnValues(
                        interpreter, objects, objectFlags,
                        instanceId, ref objectNames,
                        ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }

                return interpreter.EvaluateScript(
                    text, AsynchronousCallbackWrapper,
                    new AsynchronousCallbackClientData(
                        callback, clientData, objectNames,
                        instanceId, synchronous, dispose),
                    ref error);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method evaluates the specified script while temporarily
            /// redirecting the interpreter standard channels to the specified
            /// streams.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used to evaluate the script.
            /// </param>
            /// <param name="script">
            /// The script to evaluate.
            /// </param>
            /// <param name="inputStream">
            /// The stream to use as the standard input channel.  This parameter
            /// may be null, in which case the input channel is not redirected.
            /// </param>
            /// <param name="outputStream">
            /// The stream to use as the standard output channel.  This parameter
            /// may be null, in which case the output channel is not redirected.
            /// </param>
            /// <param name="errorStream">
            /// The stream to use as the standard error channel.  This parameter
            /// may be null, in which case the error channel is not redirected.
            /// </param>
            /// <param name="hostFlags">
            /// The host flags to use for the temporary stream host.
            /// </param>
            /// <param name="channelType">
            /// The channel type flags indicating which channels to redirect.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the result of the script; upon failure,
            /// receives information about the error.
            /// </param>
            /// <param name="errorLine">
            /// Upon failure, receives the script line number where the error
            /// occurred.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode EvaluateScriptWithChannelRedirection(
                Interpreter interpreter, /* in */
                IScript script,          /* in */
                Stream inputStream,      /* in: OPTIONAL */
                Stream outputStream,     /* in: OPTIONAL */
                Stream errorStream,      /* in: OPTIONAL */
                HostFlags hostFlags,     /* in */
                ChannelType channelType, /* in */
                ref Result result,       /* out */
                ref int errorLine        /* out */
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                ChannelType newChannelType = channelType;
                IStreamHost streamHost = null;
                Result error; /* REUSED */

                error = null;

                if (BeginChannelRedirection(
                        interpreter, inputStream, outputStream,
                        errorStream, hostFlags, ref newChannelType,
                        ref streamHost, ref error) != ReturnCode.Ok)
                {
                    result = error;
                    return ReturnCode.Error;
                }

                try
                {
                    return interpreter.EvaluateScript(
                        script, ref result, ref errorLine);
                }
                finally
                {
                    error = null;

                    if (EndChannelRedirection(
                            interpreter, newChannelType, streamHost,
                            ref error) != ReturnCode.Ok)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "EvaluateScriptWithChannelRedirection: " +
                            "EndChannelRedirection, error = {0}",
                            FormatOps.WrapOrNull(error)),
                            typeof(Helpers).Name,
                            TracePriority.CleanupError);
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

#if CONSOLE
            /// <summary>
            /// This method redirects the system console input, output, and
            /// error to the specified readers and writer, saving the previous
            /// values so they can be restored later.
            /// </summary>
            /// <param name="inputReader">
            /// The reader to use as the console input.  This parameter may be
            /// null, in which case the console input is not redirected.
            /// </param>
            /// <param name="outputReader">
            /// The writer to use as the console output.  This parameter may be
            /// null, in which case the console output is not redirected.
            /// </param>
            /// <param name="errorReader">
            /// The writer to use as the console error.  This parameter may be
            /// null, in which case the console error is not redirected.
            /// </param>
            /// <param name="savedInputReader">
            /// Receives the previously active console input reader, or null if
            /// the console input is not being redirected.
            /// </param>
            /// <param name="savedOutputReader">
            /// Receives the previously active console output writer, or null if
            /// the console output is not being redirected.
            /// </param>
            /// <param name="savedErrorReader">
            /// Receives the previously active console error writer, or null if
            /// the console error is not being redirected.
            /// </param>
            public static void BeginConsoleRedirection(
                TextReader inputReader,           /* in: OPTIONAL */
                TextWriter outputReader,          /* in: OPTIONAL */
                TextWriter errorReader,           /* in: OPTIONAL */
                out TextReader savedInputReader,  /* out */
                out TextWriter savedOutputReader, /* out */
                out TextWriter savedErrorReader   /* out */
                )
            {
                savedInputReader = (inputReader != null) ?
                    Console.In : null;

                savedOutputReader = (outputReader != null) ?
                    Console.Out : null;

                savedErrorReader = (errorReader != null) ?
                    Console.Error : null;

                if (inputReader != null)
                    Console.SetIn(inputReader);

                if (outputReader != null)
                    Console.SetOut(outputReader);

                if (errorReader != null)
                    Console.SetError(errorReader);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method restores the system console input, output, and error
            /// from the previously saved readers and writer.
            /// </summary>
            /// <param name="savedInputReader">
            /// The previously saved console input reader to restore, if any.
            /// Upon return, this is set to null.  This parameter may be null.
            /// </param>
            /// <param name="savedOutputReader">
            /// The previously saved console output writer to restore, if any.
            /// Upon return, this is set to null.  This parameter may be null.
            /// </param>
            /// <param name="savedErrorReader">
            /// The previously saved console error writer to restore, if any.
            /// Upon return, this is set to null.  This parameter may be null.
            /// </param>
            public static void EndConsoleRedirection(
                ref TextReader savedInputReader,  /* in, out: OPTIONAL */
                ref TextWriter savedOutputReader, /* in, out: OPTIONAL */
                ref TextWriter savedErrorReader   /* in, out: OPTIONAL */
                )
            {
                if (savedInputReader != null)
                {
                    Console.SetIn(savedInputReader);
                    savedInputReader = null;
                }

                if (savedOutputReader != null)
                {
                    Console.SetOut(savedOutputReader);
                    savedOutputReader = null;
                }

                if (savedErrorReader != null)
                {
                    Console.SetError(savedErrorReader);
                    savedErrorReader = null;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method evaluates the specified script while temporarily
            /// redirecting the system console input, output, and error to the
            /// specified readers and writer.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used to evaluate the script.
            /// </param>
            /// <param name="script">
            /// The script to evaluate.
            /// </param>
            /// <param name="inputReader">
            /// The reader to use as the console input.  This parameter may be
            /// null, in which case the console input is not redirected.
            /// </param>
            /// <param name="outputReader">
            /// The writer to use as the console output.  This parameter may be
            /// null, in which case the console output is not redirected.
            /// </param>
            /// <param name="errorReader">
            /// The writer to use as the console error.  This parameter may be
            /// null, in which case the console error is not redirected.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the result of the script; upon failure,
            /// receives information about the error.
            /// </param>
            /// <param name="errorLine">
            /// Upon failure, receives the script line number where the error
            /// occurred.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode EvaluateScriptWithConsoleRedirection(
                Interpreter interpreter, /* in */
                IScript script,          /* in */
                TextReader inputReader,  /* in: OPTIONAL */
                TextWriter outputReader, /* in: OPTIONAL */
                TextWriter errorReader,  /* in: OPTIONAL */
                ref Result result,       /* out */
                ref int errorLine        /* out */
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                TextReader savedInputReader;
                TextWriter savedOutputReader;
                TextWriter savedErrorReader;

                BeginConsoleRedirection(
                    inputReader, outputReader, errorReader,
                    out savedInputReader, out savedOutputReader,
                    out savedErrorReader);

                try
                {
                    return interpreter.EvaluateScript(
                        script, ref result, ref errorLine);
                }
                finally
                {
                    EndConsoleRedirection(
                        ref savedInputReader, ref savedOutputReader,
                        ref savedErrorReader);
                }
            }
#endif

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes the specified string to a stream using the
            /// specified encoding, optionally appending a newline and flushing
            /// the stream.
            /// </summary>
            /// <param name="stream">
            /// The stream to write to.  This parameter may not be null.
            /// </param>
            /// <param name="encoding">
            /// The encoding to use.  If this parameter is null, the UTF-8
            /// encoding is used.
            /// </param>
            /// <param name="value">
            /// The string to write.  This parameter may not be null.
            /// </param>
            /// <param name="newLine">
            /// Non-zero to append a newline after the string.
            /// </param>
            /// <param name="flush">
            /// Non-zero to flush the stream after writing.
            /// </param>
            public static void WriteString(
                Stream stream,     /* in */
                Encoding encoding, /* in */
                string value,      /* in */
                bool newLine,      /* in */
                bool flush         /* in */
                )
            {
                if (stream == null)
                    throw new ArgumentNullException("stream");

                if (value == null)
                    throw new ArgumentNullException("value");

                Encoding localEncoding = (encoding != null) ?
                    encoding : Encoding.UTF8;

                byte[] bytes; /* REUSED */

                bytes = localEncoding.GetBytes(value);

                if (bytes == null)
                    throw new InvalidOperationException();

                stream.Write(bytes, 0, bytes.Length);

                if (newLine)
                {
                    bytes = localEncoding.GetBytes(Characters.DosNewLine);

                    if (bytes == null)
                        throw new InvalidOperationException();

                    stream.Write(bytes, 0, bytes.Length);
                }

                if (flush)
                    stream.Flush();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method converts the specified result into a boolean value.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used for the conversion.
            /// </param>
            /// <param name="result">
            /// The result to convert into a boolean value.
            /// </param>
            /// <param name="value">
            /// Upon success, receives the converted boolean value.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode ToBoolean(
                Interpreter interpreter, /* in */
                Result result,           /* in */
                ref bool value,          /* out */
                ref Result error         /* out */
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                return Value.GetBoolean3(
                    result, ValueFlags.AnyBoolean, interpreter.InternalCultureInfo,
                    ref value, ref error);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method parses the specified string as a dictionary and
            /// reconstructs a result from its "returnCode", "result", and
            /// "errorLine" elements.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to use for parsing.  This parameter may be null.
            /// </param>
            /// <param name="value">
            /// The string, in dictionary form, to parse.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the reconstructed result; upon failure,
            /// receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public static ReturnCode GetResultFromDictionary(
                Interpreter interpreter, /* in: OPTIONAL */
                string value,            /* in */
                ref Result result        /* out */
                )
            {
                StringList list = null;

                if (ParserOps<string>.SplitList(
                        interpreter, value, 0, Length.Invalid, true,
                        ref list, ref result) == ReturnCode.Ok)
                {
                    try
                    {
                        StringDictionary dictionary = new StringDictionary(
                            list, true, true); /* throw */

                        string element; /* REUSED */
                        ReturnCode? returnCode = null;

                        if (dictionary.TryGetValue("returnCode", out element))
                        {
                            object enumValue = EnumOps.TryParse(
                                typeof(ReturnCode), element, true, true,
                                ref result);

                            if (enumValue == null)
                                return ReturnCode.Error;

                            returnCode = (ReturnCode)enumValue;
                        }

                        string stringValue = null;

                        if (dictionary.TryGetValue("result", out element))
                            stringValue = element;

                        int? errorLine = null;

                        if (dictionary.TryGetValue("errorLine", out element))
                        {
                            CultureInfo cultureInfo = null;

                            if (interpreter != null)
                                cultureInfo = interpreter.InternalCultureInfo;

                            int intValue = 0;

                            if (Value.GetInteger2(
                                    element, ValueFlags.AnyInteger, cultureInfo,
                                    ref intValue, ref result) != ReturnCode.Ok)
                            {
                                return ReturnCode.Error;
                            }

                            errorLine = intValue;
                        }

                        result = (stringValue != null) ?
                            stringValue : String.Empty;

                        if (returnCode != null)
                            result.ReturnCode = (ReturnCode)returnCode;

                        if (errorLine != null)
                            result.ErrorLine = (int)errorLine;

                        return ReturnCode.Ok;
                    }
                    catch (Exception e)
                    {
                        result = e;
                    }
                }

                return ReturnCode.Error;
            }
            #endregion
        }
        #endregion

