        #region ScriptStreamHost Test Class
        /// <summary>
        /// This class implements a test host that exposes the specified streams
        /// as the standard input, output, and error channels, for use when
        /// redirecting channels during script evaluation.
        /// </summary>
        [ObjectId("fadcc915-e31e-4004-aeb4-4218392c9fff")]
        public class ScriptStreamHost : _Hosts.Fake
        {
            #region Private Constants
            /// <summary>
            /// The simple type name of this class, used when creating host
