        #region ScriptClient Test Class
#if NET_35 || NET_40 || NET_STANDARD_20
        /// <summary>
        /// This class implements a simple test client that connects to a
        /// <see cref="ScriptServer" /> over a named pipe, sends a script for
        /// evaluation, and returns the result produced by the server.
        /// </summary>
        [ObjectId("d7624c68-da17-478d-9fc7-9efd94bdc6b8")]
        public class ScriptClient : IDisposable
        {
            #region Private Constants
            /// <summary>
            /// The server name that refers to the local host.
            /// </summary>
            internal static readonly string LocalHost = Characters.Period.ToString();
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The object used to synchronize access to the data in this
            /// instance.
            /// </summary>
            private readonly object syncRoot = new object();

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The interpreter used to interpret results received from the
            /// server.
            /// </summary>
            private Interpreter interpreter;
            /// <summary>
            /// The name of the server hosting the named pipe.
            /// </summary>
            private string serverName;
            /// <summary>
            /// The name of the named pipe to connect to.
            /// </summary>
            private string pipeName;
            /// <summary>
            /// Non-zero if diagnostic trace messages should be emitted.
            /// </summary>
            private bool trace;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs a new instance of this class.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used to interpret results received from the
            /// server.
            /// </param>
            /// <param name="serverName">
            /// The name of the server hosting the named pipe.
            /// </param>
            /// <param name="pipeName">
            /// The name of the named pipe to connect to.
            /// </param>
            /// <param name="trace">
            /// Non-zero to emit diagnostic trace messages.
            /// </param>
            public ScriptClient(
                Interpreter interpreter,
                string serverName,
                string pipeName,
                bool trace
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    this.interpreter = interpreter;
                    this.serverName = serverName;
                    this.pipeName = pipeName;
                    this.trace = trace;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method connects to the configured named pipe server, sends
            /// the specified script text, and receives the resulting return
            /// code, result, and error line.
            /// </summary>
            /// <param name="text">
            /// The script text to send to the server.  If this parameter is
            /// null, the server is contacted but no script is sent.
            /// </param>
            /// <param name="timeout">
            /// The maximum number of milliseconds to wait when connecting to
            /// the server.
            /// </param>
            /// <param name="result">
            /// Upon success, receives the result returned by the server; upon
            /// failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public virtual ReturnCode Send(
                string text,
                int timeout,
                ref Result result
                )
            {
                CheckDisposed();

                Interpreter localInterpreter;
                string localServerName;
                string localPipeName;
                bool localTrace;

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    localInterpreter = interpreter;
                    localServerName = serverName;
                    localPipeName = pipeName;
                    localTrace = trace;
                }

                if (localInterpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (localServerName == null)
                {
                    result = "invalid server name";
                    return ReturnCode.Error;
                }

                if (localPipeName == null)
                {
                    result = "invalid pipe name";
                    return ReturnCode.Error;
                }

                using (NamedPipeClientStream stream = new NamedPipeClientStream(
                        localServerName, localPipeName))
                {
                    if (localTrace)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "Send: connecting, server {0}, pipe {1}",
                            FormatOps.WrapOrNull(localServerName),
                            FormatOps.WrapOrNull(localPipeName)),
                            typeof(ScriptClient).Name,
                            TracePriority.NetworkDebug);
                    }

                    stream.Connect(timeout);

                    if (localTrace)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "Send: connected, server {0}, pipe {1}",
                            FormatOps.WrapOrNull(localServerName),
                            FormatOps.WrapOrNull(localPipeName)),
                            typeof(ScriptClient).Name,
                            TracePriority.NetworkDebug);
                    }

                    if (text != null)
                    {
                        using (StreamReader streamReader = new StreamReader(
                                stream))
                        {
                            Helpers.WriteString(
                                stream, null, text, true, true);

                            Helpers.WriteString(
                                stream, null, ScriptServer.EndOfData, true,
                                true);

                            if (localTrace)
                            {
                                TraceOps.DebugTrace(String.Format(
                                    "Send: sent script/end-of-data: {0}",
                                    FormatOps.ScriptForLog(true, false, text)),
                                    typeof(ScriptClient).Name,
                                    TracePriority.NetworkDebug2);
                            }

                            if (Helpers.GetResultFromDictionary(
                                    localInterpreter, streamReader.ReadToEnd(),
                                    ref result) == ReturnCode.Ok)
                            {
                                if (localTrace)
                                {
                                    TraceOps.DebugTrace(String.Format(
                                        "Send: received/extracted result: {0}",
                                        FormatOps.ScriptForLog(true, false, result)),
                                        typeof(ScriptClient).Name,
                                        TracePriority.NetworkDebug2);
                                }

                                return ReturnCode.Ok;
                            }
                            else
                            {
                                if (localTrace)
                                {
                                    TraceOps.DebugTrace(String.Format(
                                        "Send: failed to extract result {0}",
                                        FormatOps.WrapOrNull(result)),
                                        typeof(ScriptClient).Name,
                                        TracePriority.NetworkDebug2);
                                }

                                return ReturnCode.Error;
                            }
                        }
                    }
                    else
                    {
                        return ReturnCode.Ok;
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources used by this instance.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this instance has been
            /// disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptClient).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="Dispose()" /> method; zero if it is being called from
            /// the finalizer.
            /// </param>
            protected virtual void Dispose(
                bool disposing
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (trace)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "Dispose: called, disposing = {0}, disposed = {1}",
                            disposing, disposed), typeof(ScriptClient).Name,
                            TracePriority.CleanupDebug);
                    }

                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            interpreter = null; /* NOT OWNED */
                            serverName = null;
                            pipeName = null;
                            trace = false;
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////

                        disposed = true;
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~ScriptClient()
            {
                Dispose(false);
            }
            #endregion
        }
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ScriptServer Test Class
#if NET_35 || NET_40 || NET_STANDARD_20
        /// <summary>
        /// This class implements a simple test server that listens on a named
        /// pipe, evaluates each script it receives using an interpreter, and
        /// sends back the resulting return code, result, and error line.
        /// </summary>
        [ObjectId("ff4501a0-dce2-4f48-80ec-7f07f24cceb6")]
        public class ScriptServer : IDisposable
        {
            #region Private Constants
            /// <summary>
            /// The marker sent on its own line to indicate the end of the
            /// script data within the named pipe protocol.
            /// </summary>
            internal const string EndOfData = "### END-OF-DATA ###";
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The object used to synchronize access to the data in this
            /// instance.
            /// </summary>
            private readonly object syncRoot = new object();

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The interpreter used to evaluate scripts received by this
            /// server.
            /// </summary>
            private Interpreter interpreter;
            /// <summary>
            /// The name of the named pipe this server listens on.
            /// </summary>
            private string pipeName;

#if MONO_BUILD
#pragma warning disable 414
#endif
            /// <summary>
            /// Non-zero if this server should be stopped automatically when its
            /// associated interpreter is about to be disposed.
            /// </summary>
            private bool autoStop;
#if MONO_BUILD
#pragma warning restore 414
#endif

            /// <summary>
            /// Non-zero if diagnostic trace messages should be emitted.
            /// </summary>
            private bool trace;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The pre-dispose callback hooked into the associated interpreter
            /// to support automatic stopping, or null if not hooked.
            /// </summary>
            private DisposeCallback preDisposeCallback;
            /// <summary>
            /// The number of active calls to the server start method.
            /// </summary>
            private int startCount;
            /// <summary>
            /// The number of pending requests to stop the server.
            /// </summary>
            private int stopCount;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs a new instance of this class.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter used to evaluate scripts received by this
            /// server.
            /// </param>
            /// <param name="pipeName">
            /// The name of the named pipe this server listens on.
            /// </param>
            /// <param name="autoStop">
            /// Non-zero to automatically stop this server when its associated
            /// interpreter is about to be disposed.
            /// </param>
            /// <param name="trace">
            /// Non-zero to emit diagnostic trace messages.
            /// </param>
            public ScriptServer(
                Interpreter interpreter,
                string pipeName,
                bool autoStop,
                bool trace
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    this.interpreter = interpreter;
                    this.pipeName = pipeName;
                    this.autoStop = autoStop;
                    this.trace = trace;
                }

                if (autoStop)
                    SetupAutoStop();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method starts the server loop, listening on the configured
            /// named pipe and evaluating each received script until the server
            /// is stopped.
            /// </summary>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public virtual ReturnCode Start(
                ref Result error
                )
            {
                CheckDisposed();

                Interpreter localInterpreter;
                string localPipeName;
                bool localTrace;

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    localInterpreter = interpreter;
                    localPipeName = pipeName;
                    localTrace = trace;
                }

                if (localInterpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (localPipeName == null)
                {
                    error = "invalid pipe name";
                    return ReturnCode.Error;
                }

                int localStartCount = Interlocked.Increment(ref startCount);

                try
                {
                    if (localStartCount == 1)
                    {
                        using (NamedPipeServerStream stream = new NamedPipeServerStream(
                                localPipeName))
                        {
                            using (StreamReader streamReader = new StreamReader(stream))
                            {
                                /* IGNORED */
                                Interlocked.Exchange(ref stopCount, 0);

                                while (true)
                                {
                                    if (Interlocked.CompareExchange(ref stopCount, 0, 0) > 0)
                                    {
                                        if (localTrace)
                                        {
                                            TraceOps.DebugTrace(
                                                "Start: stopped (1)", typeof(ScriptServer).Name,
                                                TracePriority.NetworkDebug);
                                        }

                                        break;
                                    }

                                    try
                                    {
                                        if (localTrace)
                                        {
                                            TraceOps.DebugTrace(String.Format(
                                                "Start: waiting, interpreter {0}, pipe {1}",
                                                FormatOps.InterpreterNoThrow(localInterpreter),
                                                FormatOps.WrapOrNull(localPipeName)),
                                                typeof(ScriptServer).Name,
                                                TracePriority.NetworkDebug);
                                        }

                                        stream.WaitForConnection();

                                        if (localTrace)
                                        {
                                            TraceOps.DebugTrace(String.Format(
                                                "Start: connected, interpreter {0}, pipe {1}",
                                                FormatOps.InterpreterNoThrow(localInterpreter),
                                                FormatOps.WrapOrNull(localPipeName)),
                                                typeof(ScriptServer).Name,
                                                TracePriority.NetworkDebug);
                                        }

                                        if (Interlocked.CompareExchange(ref stopCount, 0, 0) > 0)
                                        {
                                            if (localTrace)
                                            {
                                                TraceOps.DebugTrace(
                                                    "Start: stopped (2)", typeof(ScriptServer).Name,
                                                    TracePriority.NetworkDebug);
                                            }

                                            break;
                                        }

                                        StringBuilder builder = StringBuilderFactory.Create();

                                        while (true)
                                        {
                                            string line = streamReader.ReadLine();

                                            if (line == null)
                                                break;

                                            if (SharedStringOps.SystemEquals(line, EndOfData))
                                                break;

                                            builder.AppendLine(line);
                                        }

                                        string text = StringBuilderCache.GetStringAndRelease(ref builder);

                                        if (localTrace)
                                        {
                                            TraceOps.DebugTrace(String.Format(
                                                "Start: received script: {0}",
                                                FormatOps.ScriptForLog(true, false, text)),
                                                typeof(ScriptServer).Name,
                                                TracePriority.NetworkDebug2);
                                        }

                                        ReturnCode code;
                                        Result result = null;
                                        int errorLine = 0;

                                        code = localInterpreter.EvaluateScript(
                                            text, ref result, ref errorLine);

                                        text = StringList.MakeList(
                                            "returnCode", code, "result", result,
                                            "errorLine", errorLine);

                                        Helpers.WriteString(
                                            stream, null, text, false, true);

                                        if (localTrace)
                                        {
                                            TraceOps.DebugTrace(String.Format(
                                                "Start: sent response: {0}",
                                                FormatOps.ScriptForLog(true, false, text)),
                                                typeof(ScriptServer).Name,
                                                TracePriority.NetworkDebug2);
                                        }
                                    }
                                    finally
                                    {
                                        if (stream != null)
                                        {
                                            try
                                            {
                                                stream.WaitForPipeDrain();
                                            }
                                            catch (Exception e)
                                            {
                                                if (localTrace)
                                                {
                                                    TraceOps.DebugTrace(
                                                        e, typeof(ScriptServer).Name,
                                                        TracePriority.NetworkError);
                                                }
                                            }

                                            try
                                            {
                                                stream.Disconnect();
                                            }
                                            catch (Exception e)
                                            {
                                                if (localTrace)
                                                {
                                                    TraceOps.DebugTrace(
                                                        e, typeof(ScriptServer).Name,
                                                        TracePriority.NetworkError);
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        return ReturnCode.Ok;
                    }
                    else
                    {
                        error = "server already started";
                        return ReturnCode.Error;
                    }
                }
                finally
                {
                    Interlocked.Decrement(ref startCount);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method requests that the running server loop stop.
            /// </summary>
            /// <param name="force">
            /// Non-zero to forcibly connect to the server in order to wake it
            /// from a blocking wait so that it can observe the stop request.
            /// </param>
            /// <param name="error">
            /// Upon failure, receives information about the error.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public virtual ReturnCode Stop(
                bool force,
                ref Result error
                )
            {
                CheckDisposed();

                Interpreter localInterpreter;
                string localPipeName;
                bool localTrace;

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    localInterpreter = interpreter;
                    localPipeName = pipeName;
                    localTrace = trace;
                }

                if (Interlocked.Increment(ref stopCount) > 0)
                {
                    if (force &&
                        (Interlocked.CompareExchange(ref startCount, 0, 0) > 0))
                    {
                        using (ScriptClient scriptClient = new ScriptClient(
                                localInterpreter, ScriptClient.LocalHost,
                                localPipeName, localTrace))
                        {
                            int timeout = ThreadOps.GetTimeout(
                                localInterpreter, null, TimeoutType.Join);

                            return scriptClient.Send(null, timeout, ref error);
                        }
                    }
                    else
                    {
                        return ReturnCode.Ok;
                    }
                }
                else
                {
                    error = "unable to make stop counter positive";
                    return ReturnCode.Error;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method is the pre-dispose callback for the associated
            /// interpreter; it stops this server before the interpreter is
            /// disposed.
            /// </summary>
            /// <param name="object">
            /// The object being disposed, which is expected to be the
            /// associated interpreter.  This parameter may be null.
            /// </param>
            private void PreInterpreterDisposed(
                object @object
                ) /* CodeBrix.Platform.TclTk._Components.Public.Delegates.DisposeCallback */
            {
                Interpreter localInterpreter = @object as Interpreter;

                try
                {
                    ReturnCode stopCode;
                    Result stopError = null;

                    stopCode = Stop(true, ref stopError);

                    if (stopCode != ReturnCode.Ok)
                    {
                        DebugOps.Complain(
                            localInterpreter, stopCode, stopError);
                    }
                }
                catch (Exception e)
                {
                    DebugOps.Complain(
                        localInterpreter, ReturnCode.Error, e);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method arranges for this server to be stopped
            /// automatically when its associated interpreter is about to be
            /// disposed, by hooking the interpreter pre-dispose callback.
            /// </summary>
            private void SetupAutoStop()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (interpreter == null)
                        return;

                    if (preDisposeCallback != null)
                        return;

                    DisposeCallback localPreDisposeCallback = new DisposeCallback(
                        PreInterpreterDisposed);

                    interpreter.PreInterpreterDisposed += localPreDisposeCallback;
                    preDisposeCallback = localPreDisposeCallback;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources held by this object and
            /// suppresses finalization.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Stores a value indicating whether this object has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this object has already been
            /// disposed.  It is called at the start of most members to guard
            /// against use after disposal.
            /// </summary>
            /// <exception cref="ObjectDisposedException">
            /// Thrown when this object has been disposed and the engine is
            /// configured to throw on use of a disposed object.
            /// </exception>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptServer).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the resources held by this object.  It
            /// implements the standard dispose pattern.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from
            /// <see cref="Dispose()" /> (i.e. deterministically); zero if it is
            /// being called from the finalizer.  When non-zero, managed
            /// resources are released.
            /// </param>
            protected virtual void Dispose(
                bool disposing
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (trace)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "Dispose: called, disposing = {0}, disposed = {1}",
                            disposing, disposed), typeof(ScriptServer).Name,
                            TracePriority.CleanupDebug);
                    }

                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            interpreter = null; /* NOT OWNED */
                            pipeName = null;
                            autoStop = false;
                            trace = false;
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////

                        disposed = true;
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes this object, releasing any resources that were not
            /// released by an explicit call to <see cref="Dispose()" />.
            /// </summary>
            ~ScriptServer()
            {
                Dispose(false);
            }
            #endregion
        }
#endif
        #endregion

