        #region TestStreamHost Test Class
        /// <summary>
        /// This class implements a host whose input, output, and error streams
        /// are supplied on demand by a callback, primarily for use by the TclTk
        /// test suite.
        /// </summary>
        [ObjectId("599f24b4-d297-4e3d-a7a9-ca9d32d0ffd3")]
        public class TestStreamHost : _Hosts.Fake
        {
            #region Private Data
            /// <summary>
            /// The interpreter this host is associated with, if any.
            /// </summary>
            private Interpreter interpreter;
            /// <summary>
            /// The callback used to refresh the streams backing the input,
            /// output, and error channels.
            /// </summary>
            private RefreshStreamsCallback callback;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class using the specified host
            /// data and stream-refresh callback.
            /// </summary>
            /// <param name="hostData">
            /// The host data used to initialize this host, including the
            /// interpreter it is associated with, if any.
            /// </param>
            /// <param name="callback">
            /// The callback used to refresh the streams backing the input,
            /// output, and error channels.
            /// </param>
            public TestStreamHost(
                IHostData hostData,
                RefreshStreamsCallback callback
                )
                : base(hostData)
            {
                if (hostData != null)
                {
                    //
                    // NOTE: Keep track of the interpreter that we are
                    //       provided, if any.
                    //
                    interpreter = hostData.Interpreter;
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                this.callback = callback;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method invokes the configured callback to refresh the
            /// streams backing the input, output, and error channels.
            /// </summary>
            /// <param name="channelType">
            /// The type of channel whose backing stream should be refreshed.
            /// </param>
            /// <param name="force">
            /// Non-zero to force the streams to be refreshed even when they
            /// already appear to be present.
            /// </param>
            private void RefreshStreams(
                ChannelType channelType,
                bool force
                )
            {
                ReturnCode refreshCode;
                Result refreshError = null;

                try
                {
                    refreshCode = callback(
                        interpreter, channelType, force, false,
                        ref input, ref output, ref error,
                        ref refreshError); /* throw */
                }
                catch (Exception e)
                {
                    refreshError = e;
                    refreshCode = ReturnCode.Error;
                }

                if (refreshCode != ReturnCode.Ok)
                {
                    TraceOps.DebugTrace(String.Format(
                        "RefreshStreams: error = {0}",
                        FormatOps.WrapOrNull(refreshError)),
                        typeof(TestStreamHost).Name,
                        TracePriority.IoError);
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IInteractiveHost Members
            /// <summary>
            /// This method determines whether the input stream is redirected.
            /// </summary>
            /// <returns>
            /// True if the input stream is redirected; otherwise, false.
            /// </returns>
            public override bool IsInputRedirected()
            {
                CheckDisposed();

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether this host is currently open.
            /// </summary>
            /// <returns>
            /// True if any of the input, output, or error streams are present;
            /// otherwise, false.
            /// </returns>
            public override bool IsOpen()
            {
                CheckDisposed();

                return (input != null) || (output != null) || (error != null);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the flags describing the capabilities of
            /// this host.
            /// </summary>
            /// <returns>
            /// The flags describing the capabilities of this host.
            /// </returns>
            public override HostFlags GetHostFlags()
            {
                CheckDisposed();

                return HostFlags.Stream;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IStreamHost Members
            /// <summary>
            /// Gets the default stream used for the input channel, refreshing
            /// the backing streams as necessary.
            /// </summary>
            public override Stream DefaultIn
            {
                get
                {
                    CheckDisposed();

                    RefreshStreams(ChannelType.Input, false);
                    return input;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the default stream used for the output channel, refreshing
            /// the backing streams as necessary.
            /// </summary>
            public override Stream DefaultOut
            {
                get
                {
                    CheckDisposed();

                    RefreshStreams(ChannelType.Output, false);
                    return output;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the default stream used for the error channel, refreshing
            /// the backing streams as necessary.
            /// </summary>
            public override Stream DefaultError
            {
                get
                {
                    CheckDisposed();

                    RefreshStreams(ChannelType.Error, false);
                    return error;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The stream currently backing the input channel.
            /// </summary>
            private Stream input;
            /// <summary>
            /// Gets the stream backing the input channel; Setting this property
            /// is not supported and always throws a
            /// <see cref="NotSupportedException" />.
            /// </summary>
            public override Stream In
            {
                get { CheckDisposed(); return input; }
                set { CheckDisposed(); throw new NotSupportedException(); }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The stream currently backing the output channel.
            /// </summary>
            private Stream output;
            /// <summary>
            /// Gets the stream backing the output channel; Setting this property
            /// is not supported and always throws a
            /// <see cref="NotSupportedException" />.
            /// </summary>
            public override Stream Out
            {
                get { CheckDisposed(); return output; }
                set { CheckDisposed(); throw new NotSupportedException(); }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The stream currently backing the error channel.
            /// </summary>
            private Stream error;
            /// <summary>
            /// Gets the stream backing the error channel; Setting this property
            /// is not supported and always throws a
            /// <see cref="NotSupportedException" />.
            /// </summary>
            public override Stream Error
            {
                get { CheckDisposed(); return error; }
                set { CheckDisposed(); throw new NotSupportedException(); }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the encoding used for the input stream; Setting this
            /// property is not supported and always throws a
            /// <see cref="NotSupportedException" />.
            /// </summary>
            public override Encoding InputEncoding
            {
                get { CheckDisposed(); return Encoding.Unicode; }
                set { CheckDisposed(); throw new NotSupportedException(); }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the encoding used for the output stream; Setting this
            /// property is not supported and always throws a
            /// <see cref="NotSupportedException" />.
            /// </summary>
            public override Encoding OutputEncoding
            {
                get { CheckDisposed(); return Encoding.Unicode; }
                set { CheckDisposed(); throw new NotSupportedException(); }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the encoding used for the error stream; Setting this
            /// property is not supported and always throws a
            /// <see cref="NotSupportedException" />.
            /// </summary>
            public override Encoding ErrorEncoding
            {
                get { CheckDisposed(); return Encoding.Unicode; }
                set { CheckDisposed(); throw new NotSupportedException(); }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the input stream to its default state.
            /// </summary>
            /// <returns>
            /// True if the input stream is available after the reset; otherwise,
            /// false.
            /// </returns>
            public override bool ResetIn()
            {
                CheckDisposed();

                RefreshStreams(ChannelType.Input, true);
                return (input != null);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the output stream to its default state.
            /// </summary>
            /// <returns>
            /// True if the output stream is available after the reset;
            /// otherwise, false.
            /// </returns>
            public override bool ResetOut()
            {
                CheckDisposed();

                RefreshStreams(ChannelType.Output, true);
                return (output != null);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the error stream to its default state.
            /// </summary>
            /// <returns>
            /// True if the error stream is available after the reset; otherwise,
            /// false.
            /// </returns>
            public override bool ResetError()
            {
                CheckDisposed();

                RefreshStreams(ChannelType.Error, true);
                return (error != null);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether the output stream is redirected.
            /// </summary>
            /// <returns>
            /// True if the output stream is redirected; otherwise, false.
            /// </returns>
            public override bool IsOutputRedirected()
            {
                CheckDisposed();

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether the error stream is redirected.
            /// </summary>
            /// <returns>
            /// True if the error stream is redirected; otherwise, false.
            /// </returns>
            public override bool IsErrorRedirected()
            {
                CheckDisposed();

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets up the standard channels for this host.
            /// </summary>
            /// <returns>
            /// True if the channels were set up successfully; otherwise, false.
            /// </returns>
            public override bool SetupChannels()
            {
                CheckDisposed();

                return false; /* NOT IMPLEMENTED */
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Stores a value indicating whether this object has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this object has already been
            /// disposed.  It is called at the start of most members to guard
            /// against use after disposal.
            /// </summary>
            /// <exception cref="InterpreterDisposedException">
            /// Thrown when this object has been disposed and the engine is
            /// configured to throw on use of a disposed object.
            /// </exception>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(interpreter, null))
                    throw new InterpreterDisposedException(typeof(TestStreamHost));
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the resources held by this object.  It
            /// implements the standard dispose pattern.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from
            /// <c>Dispose()</c> (i.e. deterministically); zero if it is
            /// being called from the finalizer.  When non-zero, managed
            /// resources are released.
            /// </param>
            protected override void Dispose(bool disposing)
            {
                try
                {
                    if (!disposed)
                    {
                        //if (disposing)
                        //{
                        //    ////////////////////////////////////
                        //    // dispose managed resources here...
                        //    ////////////////////////////////////
                        //}

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////

                        interpreter = null; /* NOT OWNED, DO NOT DISPOSE. */
                    }
                }
                finally
                {
                    base.Dispose(disposing);

                    disposed = true;
                }
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ListStream Test Class
        /// <summary>
        /// This class implements a <see cref="Stream" /> backed by a list of
        /// byte blocks, primarily for use by the TclTk test suite.
        /// </summary>
        [ObjectId("03f88240-9bfb-4e29-a0a6-f9c970df8c15")]
        public class ListStream : Stream
        {
            #region Private Constants
            //
            // HACK: This is purposely not marked as read-only.
            //
            /// <summary>
            /// The encoding used when no specific encoding has been configured
            /// for an instance of this class.
            /// </summary>
            private static Encoding DefaultEncoding = Encoding.UTF8;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The encoding used to convert between strings and bytes.
            /// </summary>
            private Encoding encoding;
            /// <summary>
            /// The list of byte blocks available to be read as input.
            /// </summary>
            private IList<byte[]> input;
            /// <summary>
            /// The list of byte blocks that have been written as output.
            /// </summary>
            private IList<byte[]> output;
            /// <summary>
            /// The index of the current block within the input list.
            /// </summary>
            private int inputIndex;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
            /// <summary>
            /// Constructs an instance of this class using the specified
            /// encoding and stream capabilities.
            /// </summary>
            /// <param name="encoding">
            /// The encoding used to convert between strings and bytes.
            /// </param>
            /// <param name="canRead">
            /// Non-zero if the stream should support reading.
            /// </param>
            /// <param name="canSeek">
            /// Non-zero if the stream should support seeking.
            /// </param>
            /// <param name="canWrite">
            /// Non-zero if the stream should support writing.
            /// </param>
            private ListStream(
                Encoding encoding, /* in */
                bool canRead,      /* in */
                bool canSeek,      /* in */
                bool canWrite      /* in */
                )
            {
                this.encoding = encoding;
                this.canRead = canRead;
                this.canSeek = canSeek;
                this.canWrite = canWrite;

                ResetInput();
                ResetOutput();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class using the specified
            /// encoding and initial collection of input strings.
            /// </summary>
            /// <param name="encoding">
            /// The encoding used to convert between strings and bytes.
            /// </param>
            /// <param name="collection">
            /// The initial collection of strings to add to the input list.
            /// </param>
            /// <param name="canRead">
            /// Non-zero if the stream should support reading.
            /// </param>
            /// <param name="canSeek">
            /// Non-zero if the stream should support seeking.
            /// </param>
            /// <param name="canWrite">
            /// Non-zero if the stream should support writing.
            /// </param>
            public ListStream(
                Encoding encoding,              /* in */
                IEnumerable<string> collection, /* in */
                bool canRead,                   /* in */
                bool canSeek,                   /* in */
                bool canWrite                   /* in */
                )
                : this(encoding, canRead, canSeek, canWrite)
            {
                AddInput(collection);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method returns the encoding used by this stream, falling
            /// back to the default encoding when none has been configured.
            /// </summary>
            /// <returns>
            /// The encoding used by this stream.
            /// </returns>
            private Encoding GetEncoding()
            {
                Encoding encoding = this.encoding;

                if (encoding == null)
                    encoding = DefaultEncoding;

                return encoding;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the bytes of the current input block.
            /// </summary>
            /// <returns>
            /// The bytes of the current input block, or null if there is no
            /// current input block.
            /// </returns>
            private byte[] GetInputBytes()
            {
                if (input == null)
                    return null;

                int index = GetInput();

                if ((index < 0) || (index >= input.Count))
                    return null;

                return input[index];
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method replaces the bytes of the current input block.
            /// </summary>
            /// <param name="bytes">
            /// The replacement bytes for the current input block.
            /// </param>
            /// <returns>
            /// True if the current input block was replaced; otherwise, false.
            /// </returns>
            private bool SetInputBytes(
                byte[] bytes /* in */
                )
            {
                if (bytes == null)
                    return false;

                int index = GetInput();

                if ((index < 0) || (index >= input.Count))
                    return false;

                input[index] = bytes;
                return true;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the next non-empty block of input bytes,
            /// advancing the input position as necessary.
            /// </summary>
            /// <returns>
            /// The next non-empty block of input bytes, or null if no more
            /// input is available.
            /// </returns>
            private byte[] NextInputBytes()
            {
                while (true)
                {
                    byte[] bytes = GetInputBytes();

                    if ((bytes != null) && (bytes.Length > 0))
                        return bytes;

                    if (!NextInput())
                        return null;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method calculates the total number of bytes available in
            /// the input list.
            /// </summary>
            /// <returns>
            /// The total number of bytes contained in the input list.
            /// </returns>
            private long GetLength()
            {
                int length = 0;

                if (input != null)
                {
                    foreach (byte[] bytes in input)
                    {
                        if (bytes == null)
                            continue;

                        length += bytes.Length;
                    }
                }

                return length;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method calculates a synthetic position within the stream.
            /// </summary>
            /// <returns>
            /// Zero if the stream currently contains any data; otherwise, one.
            /// </returns>
            private long GetPosition()
            {
                long length = GetLength();

                return (length > 0) ? 0 : 1;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method adds the specified bytes to the input list.
            /// </summary>
            /// <param name="bytes">
            /// The bytes to add to the input list.
            /// </param>
            private void AddInput(
                byte[] bytes /* in */
                )
            {
                if (bytes == null)
                    throw new ArgumentNullException("bytes");

                if (input == null)
                    throw new InvalidOperationException("invalid input");

                input.Add(bytes);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method adds the specified bytes to the output list.
            /// </summary>
            /// <param name="bytes">
            /// The bytes to add to the output list.
            /// </param>
            private void AddOutput(
                byte[] bytes /* in */
                )
            {
                if (bytes == null)
                    throw new ArgumentNullException("bytes");

                if (output == null)
                    throw new InvalidOperationException("invalid output");

                output.Add(bytes);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method adds the encoded bytes for each string in the
            /// specified collection to the input list.
            /// </summary>
            /// <param name="collection">
            /// The collection of strings to encode and add to the input list.
            /// </param>
            /// <returns>
            /// The number of strings added to the input list.
            /// </returns>
            private int AddInput(
                IEnumerable<string> collection /* in */
                )
            {
                if (collection == null)
                    throw new ArgumentNullException("collection");

                Encoding encoding = GetEncoding();

                if (encoding == null)
                    throw new InvalidOperationException("invalid encoding");

                int count = 0;

                foreach (string item in collection)
                {
                    AddInput(encoding.GetBytes(item));
                    count++;
                }

                return count;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the current input block index, initializing
            /// the input position first if necessary.
            /// </summary>
            /// <returns>
            /// The current input block index.
            /// </returns>
            private int GetInput()
            {
                MaybeFirstInput();
                return inputIndex;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the input list to an empty state and marks
            /// the input position as invalid.
            /// </summary>
            private void ResetInput()
            {
                input = new List<byte[]>();
                inputIndex = Index.Invalid;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the output list to an empty state.
            /// </summary>
            private void ResetOutput()
            {
                output = new List<byte[]>();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method positions the input at the first block, if it has
            /// not yet been positioned.
            /// </summary>
            /// <returns>
            /// True if the input position was advanced to the first block;
            /// otherwise, false.
            /// </returns>
            private bool MaybeFirstInput()
            {
                if (inputIndex == Index.Invalid)
                {
                    inputIndex = 0;
                    return true;
                }

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method advances the input position to the next available
            /// block of input bytes.
            /// </summary>
            /// <returns>
            /// True if another block of input is now available; otherwise,
            /// false.
            /// </returns>
            private bool NextInput()
            {
                if (input == null)
                    return false;

                int count = input.Count;

                if (count == 0)
                    return false;

                if (inputIndex < 0)
                    return MaybeFirstInput();

                if ((inputIndex + 1) >= count)
                {
                    input.Clear();
                    return false;
                }

                inputIndex++;
                return true;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Stream Members
            /// <summary>
            /// Non-zero if this stream supports reading.
            /// </summary>
            private bool canRead;
            /// <summary>
            /// Gets a value indicating whether the current stream supports
            /// reading.
            /// </summary>
            public override bool CanRead
            {
                get { CheckDisposed(); return canRead; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // HACK: This should always return false; however, we
            //       cannot do that because we want the "Length"
            //       property to be functional, e.g. for use by
            //       the ChannelStream class.
            //
            /// <summary>
            /// Non-zero if this stream supports seeking.
            /// </summary>
            private bool canSeek;
            /// <summary>
            /// Gets a value indicating whether the current stream supports
            /// seeking.
            /// </summary>
            public override bool CanSeek
            {
                get { CheckDisposed(); return canSeek; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Non-zero if this stream supports writing.
            /// </summary>
            private bool canWrite;
            /// <summary>
            /// Gets a value indicating whether the current stream supports
            /// writing.
            /// </summary>
            public override bool CanWrite
            {
                get { CheckDisposed(); return canWrite; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method clears all buffers for this stream and causes any
            /// buffered data to be written to the underlying device.
            /// </summary>
            public override void Flush()
            {
                CheckDisposed();

                if (!canWrite)
                    throw new IOException("stream is read-only");

                if (output == null)
                    throw new IOException("invalid output list");
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the length, in bytes, of the stream.
            /// </summary>
            public override long Length
            {
                get
                {
                    CheckDisposed();

                    if (!canSeek)
                        throw new NotSupportedException();

                    return GetLength();
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets or sets the position within the current stream.
            /// </summary>
            public override long Position
            {
                get
                {
                    CheckDisposed();

                    if (!canSeek)
                        throw new NotSupportedException();

                    return GetPosition();
                }
                set
                {
                    CheckDisposed();

                    /* IGNORED */
                    Seek(value, SeekOrigin.Begin);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reads a sequence of bytes from the current stream
            /// and advances the position within the stream by the number of
            /// bytes read.
            /// </summary>
            /// <param name="buffer">
            /// The buffer into which the bytes read from the stream are copied.
            /// </param>
            /// <param name="offset">
            /// The zero-based byte offset in <paramref name="buffer" /> at which
            /// to begin storing the bytes read.
            /// </param>
            /// <param name="count">
            /// The maximum number of bytes to read from the stream.
            /// </param>
            /// <returns>
            /// The total number of bytes read into the buffer, or zero if the
            /// end of the available input has been reached.
            /// </returns>
            public override int Read(
                byte[] buffer, /* in */
                int offset,    /* in */
                int count      /* in */
                )
            {
                CheckDisposed();

                if (!canRead)
                    throw new NotSupportedException();

                if (buffer == null)
                    throw new ArgumentNullException("buffer");

                if ((offset < 0) || (count < 0))
                    throw new ArgumentOutOfRangeException();

                int bufferLength = buffer.Length;

                if ((offset + count) > bufferLength)
                    throw new ArgumentException();

                byte[] bytes = NextInputBytes();

                if (bytes == null)
                    return 0;

                int bytesLength = bytes.Length;

                if (count > bytesLength)
                    count = bytesLength;

                /* NO RESULT */
                Array.Copy(bytes, 0, buffer, offset, count);

                if (ArrayOps.Consume<byte>(ref bytes, count))
                {
                    /* IGNORED */
                    SetInputBytes(bytes);
                }

                return count;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets the position within the current stream.  It is
            /// not supported by this class and always throws a
            /// <see cref="NotSupportedException" />.
            /// </summary>
            /// <param name="offset">
            /// A byte offset relative to the <paramref name="origin" />
            /// parameter.
            /// </param>
            /// <param name="origin">
            /// A value indicating the reference point used to obtain the new
            /// position.
            /// </param>
            /// <returns>
            /// The new position within the current stream; however, this method
            /// always throws instead of returning.
            /// </returns>
            public override long Seek(
                long offset,      /* in */
                SeekOrigin origin /* in */
                )
            {
                CheckDisposed();

                throw new NotSupportedException();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets the length of this stream.
            /// </summary>
            /// <param name="value">
            /// The desired length, in bytes, of this stream.
            /// </param>
            public override void SetLength(
                long value /* in */
                )
            {
                CheckDisposed();

                throw new NotSupportedException();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes a sequence of bytes to this stream.
            /// </summary>
            /// <param name="buffer">
            /// The buffer containing the bytes to write.
            /// </param>
            /// <param name="offset">
            /// The offset within the buffer at which to begin reading the bytes.
            /// </param>
            /// <param name="count">
            /// The number of bytes to write.
            /// </param>
            public override void Write(
                byte[] buffer, /* in */
                int offset,    /* in */
                int count      /* in */
                )
            {
                CheckDisposed();

                if (!canWrite)
                    throw new NotSupportedException();

                if (buffer == null)
                    throw new ArgumentNullException("buffer");

                if ((offset < 0) || (count < 0))
                    throw new ArgumentOutOfRangeException();

                int bufferLength = buffer.Length;

                if ((offset + count) > bufferLength)
                    throw new ArgumentException();

                byte[] bytes = new byte[count];

                /* NO RESULT */
                Array.Copy(buffer, offset, bytes, 0, count);

                /* NO RESULT */
                AddOutput(bytes);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed of.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this object instance has been
            /// disposed of.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                    throw new ObjectDisposedException(typeof(ListStream).Name);
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources held by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <c>Dispose()</c> method.
            /// </param>
            protected override void Dispose(
                bool disposing /* in */
                )
            {
                try
                {
                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            if (input != null)
                            {
                                input.Clear();
                                input = null;
                            }

                            if (output != null)
                            {
                                output.Clear();
                                output = null;
                            }
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////
                    }
                }
                finally
                {
                    base.Dispose(disposing);

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes this object instance.
            /// </summary>
            ~ListStream()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region TextBoxStream Test Class
#if WINFORMS
        /// <summary>
        /// This class implements a stream that reads from and/or writes to the
        /// text of a Windows Forms text box control.
        /// </summary>
        [ObjectId("81f27390-0ffa-4cd8-9e38-35fff48a623e")]
        public class TextBoxStream : Stream
        {
            #region Private Data
            /// <summary>
            /// The text box control that this stream reads from and/or writes
            /// to.
            /// </summary>
            private TextBox textBox;
            /// <summary>
            /// Non-zero if the most recently obtained text was selected, or null
            /// if no text has been obtained yet.
            /// </summary>
            private bool? wasSelected;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs a new instance of this class.
            /// </summary>
            /// <param name="textBox">
            /// The text box control that this stream reads from and/or writes
            /// to.
            /// </param>
            /// <param name="canRead">
            /// Non-zero if this stream supports reading.
            /// </param>
            /// <param name="canWrite">
            /// Non-zero if this stream supports writing.
            /// </param>
            public TextBoxStream(TextBox textBox, bool canRead, bool canWrite)
            {
                this.textBox = textBox;
                this.canRead = canRead;
                this.canWrite = canWrite;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method obtains the current text of the associated text box
            /// control.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The current text of the associated text box control, or null on
            /// failure.
            /// </returns>
            private string GetText(out Result error)
            {
                error = null;

                if (textBox == null)
                {
                    error = "invalid text box";
                    return null;
                }

                string text;
                bool selected;

                text = FormOps.GetText(textBox, out selected);

                if (text == null)
                {
                    error = "could not get text";
                    return null;
                }

                wasSelected = selected;
                return text;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets the text of the associated text box control.
            /// </summary>
            /// <param name="text">
            /// The text to set on the associated text box control.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the text was set successfully; otherwise, false.
            /// </returns>
            private bool SetText(string text, out Result error)
            {
                error = null;

                if (textBox == null)
                {
                    error = "invalid text box";
                    return false;
                }

                if (wasSelected == null)
                {
                    error = "selection flag not set";
                    return false;
                }

                if (!FormOps.SetText(textBox, text, (bool)wasSelected, false))
                {
                    error = "could not set text";
                    return false;
                }

                return true;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Stream Members
            /// <summary>
            /// Non-zero if this stream supports reading.
            /// </summary>
            private bool canRead;
            /// <summary>
            /// Gets a value indicating whether this stream supports reading.
            /// </summary>
            public override bool CanRead
            {
                get { CheckDisposed(); return canRead; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether this stream supports seeking.
            /// </summary>
            public override bool CanSeek
            {
                get { CheckDisposed(); return canRead; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Non-zero if this stream supports writing.
            /// </summary>
            private bool canWrite;
            /// <summary>
            /// Gets a value indicating whether this stream supports writing.
            /// </summary>
            public override bool CanWrite
            {
                get { CheckDisposed(); return canWrite; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method ensures that this stream is in a valid state for
            /// writing.
            /// </summary>
            public override void Flush()
            {
                CheckDisposed();

                if (!canWrite)
                    throw new IOException("stream is read-only");

                if (textBox == null)
                    throw new IOException("invalid text box");

                if (wasSelected == null)
                    throw new IOException("selection flag not set");
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the length, in bytes, of this stream.
            /// </summary>
            public override long Length
            {
                get
                {
                    CheckDisposed();

                    if (!canRead)
                        throw new NotSupportedException();

                    string text;
                    Result error;

                    text = GetText(out error);

                    if (text == null)
                        throw new InvalidOperationException(error);

                    return text.Length;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The current position within this stream.
            /// </summary>
            private int position = _Position.Invalid;
            /// <summary>
            /// Gets or sets the current position within this stream.
            /// </summary>
            public override long Position
            {
                get
                {
                    CheckDisposed();

                    if (!canRead)
                        throw new NotSupportedException();

                    return position;
                }
                set
                {
                    CheckDisposed();

                    if (!canRead)
                        throw new NotSupportedException();

                    if ((value < int.MinValue) || (value > int.MaxValue))
                        throw new IOException();

                    position = (int)value;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reads a sequence of bytes from this stream.
            /// </summary>
            /// <param name="buffer">
            /// The buffer into which the bytes will be read.
            /// </param>
            /// <param name="offset">
            /// The offset within the buffer at which to begin storing the bytes.
            /// </param>
            /// <param name="count">
            /// The maximum number of bytes to read.
            /// </param>
            /// <returns>
            /// The total number of bytes read into the buffer.
            /// </returns>
            public override int Read(byte[] buffer, int offset, int count)
            {
                CheckDisposed();

                if (!canRead)
                    throw new NotSupportedException();

                if (buffer == null)
                    throw new ArgumentNullException();

                if ((offset < 0) || (count < 0))
                    throw new ArgumentOutOfRangeException();

                int length = buffer.Length;

                if ((offset + count) > length)
                    throw new ArgumentException();

                string text;
                Result error;

                text = GetText(out error);

                if (text == null)
                    throw new InvalidOperationException(error);

                if (position < 0)
                    position = 0;

                int index;

                for (index = offset; count > 0; index++, count--)
                {
                    if (position >= text.Length)
                        break;

                    buffer[index] = (byte)(text[position++] & (char)byte.MaxValue);
                }

                return (index - offset);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets the position within this stream.
            /// </summary>
            /// <param name="offset">
            /// The offset, relative to the specified origin, to seek to.
            /// </param>
            /// <param name="origin">
            /// The reference point used to obtain the new position.
            /// </param>
            /// <returns>
            /// The new position within this stream.
            /// </returns>
            public override long Seek(long offset, SeekOrigin origin)
            {
                CheckDisposed();

                if (!canRead)
                    throw new NotSupportedException();

                string text;
                Result error;

                text = GetText(out error);

                if (text == null)
                    throw new InvalidOperationException(error);

                //
                // HACK: Only allow seeking to the start of the stream.
                //
                if ((offset != 0) || (origin != SeekOrigin.Begin))
                    throw new IOException();

                position = _Position.Invalid;

                return position;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets the length of this stream.
            /// </summary>
            /// <param name="value">
            /// The desired length, in bytes, of this stream.
            /// </param>
            public override void SetLength(long value)
            {
                CheckDisposed();

                throw new NotSupportedException();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes a sequence of bytes to this stream.
            /// </summary>
            /// <param name="buffer">
            /// The buffer containing the bytes to write.
            /// </param>
            /// <param name="offset">
            /// The offset within the buffer at which to begin reading the bytes.
            /// </param>
            /// <param name="count">
            /// The number of bytes to write.
            /// </param>
            public override void Write(byte[] buffer, int offset, int count)
            {
                CheckDisposed();

                if (!canWrite)
                    throw new NotSupportedException();

                if (buffer == null)
                    throw new ArgumentNullException();

                if ((offset < 0) || (count < 0))
                    throw new ArgumentOutOfRangeException();

                int length = buffer.Length;

                if ((offset + count) > length)
                    throw new ArgumentException();

                string text;
                Result error;

                text = GetText(out error);

                if (text == null)
                    throw new InvalidOperationException(error);

                StringBuilder builder = StringBuilderFactory.Create(text);

                for (int index = offset; count > 0; index++, count--)
                    builder.Append((char)buffer[index]);

                if (!SetText(StringBuilderCache.GetStringAndRelease(
                        ref builder), out error))
                {
                    throw new IOException(error);
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed of.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this object instance has been
            /// disposed of.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                    throw new ObjectDisposedException(typeof(TextBoxStream).Name);
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources held by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="Stream.Dispose()" /> method.
            /// </param>
            protected override void Dispose(bool disposing)
            {
                try
                {
                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            textBox = null; /* NOT OWNED */
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////
                    }
                }
                finally
                {
                    base.Dispose(disposing);

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes this object instance.
            /// </summary>
            ~TextBoxStream()
            {
                Dispose(false);
            }
            #endregion
        }
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ScriptComplain Test Class
        /// <summary>
        /// This class implements a test object that evaluates a script in
        /// response to complaints raised by the engine.
        /// </summary>
        [ObjectId("6b919457-a9c8-4008-bd97-a2986f57d857")]
        public class ScriptComplain : IDisposable
        {
            #region Private Data
            /// <summary>
            /// The number of nested complaint operations that are currently in
            /// progress on this object instance.
            /// </summary>
            private int complainLevels = 0;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Internal Constructors
            /// <summary>
            /// Constructs a new instance of this class.
            /// </summary>
            /// <param name="text">
            /// The script to evaluate in response to a complaint.
            /// </param>
            /// <param name="engineFlags">
            /// The extra per-thread engine flags to use while evaluating the
            /// configured script.
            /// </param>
            internal ScriptComplain(
                string text,
                EngineFlags engineFlags
                )
            {
                this.text = text;
                this.engineFlags = engineFlags;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// The script to evaluate in response to a complaint.
            /// </summary>
            private string text;
            /// <summary>
            /// Gets or sets the script to evaluate in response to a complaint.
            /// </summary>
            public virtual string Text
            {
                get { CheckDisposed(); return text; }
                set { CheckDisposed(); text = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The extra per-thread engine flags used while evaluating the
            /// configured script.
            /// </summary>
            private EngineFlags engineFlags;
            /// <summary>
            /// Gets or sets the extra per-thread engine flags used while
            /// evaluating the configured script.
            /// </summary>
            public virtual EngineFlags EngineFlags
            {
                get { CheckDisposed(); return engineFlags; }
                set { CheckDisposed(); engineFlags = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method evaluates the configured script in response to a
            /// complaint being raised by the engine.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context that the script will be evaluated in.
            /// </param>
            /// <param name="id">
            /// The unique identifier associated with the complaint.
            /// </param>
            /// <param name="code">
            /// The return code associated with the complaint.
            /// </param>
            /// <param name="result">
            /// The result associated with the complaint.
            /// </param>
            /// <param name="stackTrace">
            /// The stack trace associated with the complaint, if any.
            /// </param>
            /// <param name="quiet">
            /// Non-zero if the complaint should be handled quietly.
            /// </param>
            /// <param name="retry">
            /// The number of times handling of the complaint has been retried.
            /// </param>
            /// <param name="levels">
            /// The number of nested complaint levels currently active.
            /// </param>
            public virtual void Complain(
                Interpreter interpreter,
                long id,
                ReturnCode code,
                Result result,
                string stackTrace,
                bool quiet,
                int retry,
                int levels
                )
            {
                CheckDisposed();

                int localLevels = Interlocked.Increment(ref complainLevels);

                try
                {
                    ReturnCode localCode;
                    Result localResult = null;

                    if (interpreter != null)
                    {
                        if (localLevels == 1)
                        {
                            EngineFlags engineFlags = this.EngineFlags;
                            string text = this.Text;
                            ObjectDictionary objects = new ObjectDictionary();

                            objects.Add("engineFlags", engineFlags);
                            objects.Add("methodName", "Complain");
                            objects.Add("interpreter", interpreter);
                            objects.Add("id", id);
                            objects.Add("code", code);
                            objects.Add("result", result);
                            objects.Add("stackTrace", stackTrace);
                            objects.Add("quiet", quiet);
                            objects.Add("retry", retry);
                            objects.Add("levels", levels);

                            EngineFlags savedEngineFlags = interpreter.ContextEngineFlags;
                            interpreter.ContextEngineFlags |= engineFlags;

                            try
                            {
                                localCode = Helpers.EvaluateScript(
                                    interpreter, text, objects, ref localResult);
                            }
                            finally
                            {
                                interpreter.ContextEngineFlags = savedEngineFlags;
                                savedEngineFlags = EngineFlags.None;
                            }
                        }
                        else
                        {
                            localResult = "cannot handle complaint, already pending";
                            localCode = ReturnCode.Error;
                        }
                    }
                    else
                    {
                        localResult = "invalid interpreter";
                        localCode = ReturnCode.Error;
                    }

                    if (localCode != ReturnCode.Ok)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "complain script failed: {0}",
                            ResultOps.Format(localCode, localResult)),
                            typeof(ScriptComplain).Name,
                            TracePriority.ComplainError);
                    }
                }
                finally
                {
                    Interlocked.Decrement(ref complainLevels);
                }
            }
            #endregion

