                )
            {
                //
                // HACK: Cleanup the script plugin token in the interpreter
                //       state because this is the only place where we can
                //       be 100% sure it will get done.
                //
                if (interpreter == null)
                    return;

                interpreter.InternalScriptNotifyPluginToken = 0;
            }
