                        ////////////////////////////////////

                        text = null;
                        notifyTypes = NotifyType.None;
                        notifyFlags = NotifyFlags.None;
                        engineFlags = EngineFlags.None;
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
