            /// </summary>
            private bool? throwOnError;
            /// <summary>
            /// Gets or sets a value indicating whether a
            /// <see cref="ScriptException" /> is thrown when a script evaluation
            /// returns an error, or null to defer to the interpreter.
            /// </summary>
            public virtual bool? ThrowOnError
            {
                get { CheckDisposed(); return throwOnError; }
                set { CheckDisposed(); throwOnError = value; }
            }
