            public virtual Interpreter Interpreter
            {
                get { CheckDisposed(); return interpreter; }
                set { CheckDisposed(); interpreter = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method determines whether an exception should be thrown when
            /// a script evaluation returns an error.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context to consult when no explicit preference
            /// has been configured.
            /// </param>
            /// <returns>
            /// True if an exception should be thrown on error; otherwise, false.
            /// </returns>
            private bool ShouldThrowOnError(
                Interpreter interpreter /* in: OPTIONAL */
                )
            {
                if (throwOnError != null)
                {
                    return (bool)throwOnError;
                }
                else if (interpreter != null)
                {
                    return interpreter.ThrowOnErrorForScriptWebClient();
                }
                else
                {
                    return DefaultThrowOnError;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Protected Methods
            /// <summary>
            /// This method reports an error, either by throwing a
            /// <see cref="ScriptException" /> or by logging it, depending on the
            /// configured behavior.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context associated with the error, if any.
            /// </param>
            /// <param name="code">
            /// The return code associated with the error.
            /// </param>
            /// <param name="result">
            /// The result or error message associated with the error.
            /// </param>
            protected virtual void Complain(
                Interpreter interpreter, /* in: OPTIONAL */
                ReturnCode code,         /* in */
                Result result            /* in */
                )
            {
                if (ShouldThrowOnError(interpreter))
                    throw new ScriptException(code, result);

                /* NO RESULT */
                DebugOps.Complain(interpreter, code, result);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Net.WebClient Overrides
            /// <summary>
            /// This method returns the web request for the specified address,
            /// evaluating the configured script in response.
            /// </summary>
            /// <param name="address">
            /// The address to obtain the web request for.
            /// </param>
            /// <returns>
            /// The web request for the specified address.
            /// </returns>
            protected override WebRequest GetWebRequest(
                Uri address /* in */
                )
            {
                WebRequest webRequest = base.GetWebRequest(address);

                Interpreter interpreter = this.Interpreter;
                string text = this.Text;

                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("argument", this.Argument);
                objects.Add("methodName", "GetWebRequest");
                objects.Add("address", address);
                objects.Add("webRequest", webRequest);

                ReturnCode localCode;
                Result localResult = null;

                localCode = Helpers.EvaluateScript(
                    interpreter, text, objects, ref localResult);

                if (localCode != ReturnCode.Ok)
                    Complain(this.Interpreter, localCode, localResult);

                return webRequest;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the web response for the specified request,
            /// evaluating the configured script in response.
            /// </summary>
            /// <param name="request">
            /// The web request to obtain the response for.
            /// </param>
            /// <returns>
            /// The web response for the specified request.
            /// </returns>
            protected override WebResponse GetWebResponse(
                WebRequest request /* in */
                )
            {
                WebResponse webResponse = base.GetWebResponse(request);

                Interpreter interpreter = this.Interpreter;
                string text = this.Text;

                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("argument", this.Argument);
                objects.Add("methodName", "GetWebResponse");
                objects.Add("webRequest", request);
                objects.Add("webResponse", webResponse);

                ReturnCode localCode;
                Result localResult = null;

                localCode = Helpers.EvaluateScript(
                    interpreter, text, objects, ref localResult);

                if (localCode != ReturnCode.Ok)
                    Complain(this.Interpreter, localCode, localResult);

                return webResponse;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the web response for the specified request
            /// and asynchronous result, evaluating the configured script in
            /// response.
            /// </summary>
            /// <param name="request">
            /// The web request to obtain the response for.
            /// </param>
            /// <param name="result">
            /// The asynchronous result associated with the request.
            /// </param>
            /// <returns>
            /// The web response for the specified request.
            /// </returns>
            protected override WebResponse GetWebResponse(
                WebRequest request, /* in */
                IAsyncResult result /* in */
                )
            {
                WebResponse webResponse = base.GetWebResponse(request);

                Interpreter interpreter = this.Interpreter;
                string text = this.Text;

                ObjectDictionary objects = new ObjectDictionary();

                objects.Add("argument", this.Argument);
                objects.Add("methodName", "GetWebResponse");
                objects.Add("webRequest", request);
                objects.Add("asyncResult", result);
                objects.Add("webResponse", webResponse);

                ReturnCode localCode;
                Result localResult = null;

                localCode = Helpers.EvaluateScript(
                    interpreter, text, objects, ref localResult);

                if (localCode != ReturnCode.Ok)
                    Complain(this.Interpreter, localCode, localResult);

                return webResponse;
            }
            #endregion

