            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method installs this limiter into the specified interpreter,
            /// saving the previously installed readiness callback.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to install this limiter into.
            /// </param>
            /// <param name="waitForLock">
            /// Non-zero to wait for the interpreter lock to be acquired.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public ReturnCode Install(
                Interpreter interpreter,
                bool waitForLock,
                ref Result error
                )
            {
                CheckDisposed();

                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                bool locked1 = false;

                try
                {
                    if (waitForLock)
                    {
                        interpreter.InternalHardTryLock(
                            ref locked1); /* TRANSACTIONAL */
                    }
                    else
                    {
                        interpreter.InternalSoftTryLock(
                            ref locked1); /* TRANSACTIONAL */
                    }

                    if (locked1)
                    {
                        bool locked2 = false;

                        try
                        {
                            PrivateTryLock(ref locked2); /* TRANSACTIONAL */

                            if (locked2)
                            {
                                savedReadyCallback = interpreter.InternalReadyCallback;
                                interpreter.InternalReadyCallback = ReadyCallback;

                                return ReturnCode.Ok;
                            }
                            else
                            {
                                error = "unable to acquire lock";
                                return ReturnCode.Error;
                            }
                        }
                        finally
                        {
                            PrivateExitLock(ref locked2); /* TRANSACTIONAL */
                        }
                    }
                    else
                    {
                        error = String.Format(
                            "unable to acquire interpreter {0} lock",
                            FormatOps.InterpreterNoThrow(interpreter));

                        return ReturnCode.Error;
                    }
                }
                finally
                {
                    interpreter.InternalExitLock(ref locked1); /* TRANSACTIONAL */
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method removes this limiter from the specified interpreter,
            /// restoring the previously installed readiness callback.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to remove this limiter from.
            /// </param>
            /// <param name="waitForLock">
            /// Non-zero to wait for the interpreter lock to be acquired.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            public ReturnCode Uninstall(
                Interpreter interpreter,
                bool waitForLock,
                ref Result error
                )
            {
                CheckDisposed();

                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                bool locked1 = false;

                try
                {
                    if (waitForLock)
                    {
                        interpreter.InternalHardTryLock(
                            ref locked1); /* TRANSACTIONAL */
                    }
                    else
                    {
                        interpreter.InternalSoftTryLock(
                            ref locked1); /* TRANSACTIONAL */
                    }

                    if (locked1)
                    {
                        bool locked2 = false;

                        try
                        {
                            PrivateTryLock(ref locked2); /* TRANSACTIONAL */

                            if (locked2)
                            {
                                interpreter.InternalReadyCallback = savedReadyCallback;
                                savedReadyCallback = null;

                                return ReturnCode.Ok;
                            }
                            else
                            {
                                error = "unable to acquire lock";
                                return ReturnCode.Error;
                            }
                        }
                        finally
                        {
                            PrivateExitLock(ref locked2); /* TRANSACTIONAL */
                        }
                    }
                    else
                    {
                        error = String.Format(
                            "unable to acquire interpreter {0} lock",
                            FormatOps.InterpreterNoThrow(interpreter));

                        return ReturnCode.Error;
                    }
                }
                finally
                {
                    interpreter.InternalExitLock(ref locked1); /* TRANSACTIONAL */
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method resets all of the configured limits and accounting
            /// state to their default values.
            /// </summary>
            private void Reset()
            {
                savedReadyCallback = null;
                disabled = false;
                commandLimit = Unlimited;
                operationLimit = Unlimited;
                timeLimit = null;
                started = null;
                stopped = null;
                autoReset = false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method attempts to acquire the lock on this object.
            /// </summary>
            /// <param name="locked">
            /// Upon success, this parameter will be set to non-zero if the lock
            /// was acquired.
            /// </param>
            private void PrivateTryLock(
                ref bool locked
                )
            {
                if (syncRoot == null)
                    return;

                locked = Monitor.TryEnter(syncRoot);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the lock on this object, if it was
            /// previously acquired.
            /// </summary>
            /// <param name="locked">
            /// Upon entry, non-zero if the lock was previously acquired; upon
            /// exit, this parameter will be set to false.
            /// </param>
            private void PrivateExitLock(
                ref bool locked
                )
            {
                if (syncRoot == null)
                    return;

                if (locked)
                {
                    Monitor.Exit(syncRoot);
                    locked = false;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region CodeBrix.Platform.TclTk._Components.Public.Delegates.ReadyCallback
            /// <summary>
            /// This method is the readiness callback used to enforce the
            /// configured command, operation, and time limits, also chaining to
            /// any previously installed readiness callback.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context being checked for readiness.
            /// </param>
            /// <param name="clientData">
            /// The client data supplied when the readiness check was requested.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, associated with the readiness
            /// check.
            /// </param>
            /// <param name="flags">
            /// The flags that control how the readiness check is performed.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success;
            /// <see cref="ReturnCode.Error" /> on failure.
            /// </returns>
            private ReturnCode ReadyCallback(
                Interpreter interpreter,
                IClientData clientData,
                int timeout,
                ReadyFlags flags,
                ref Result error
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                bool locked = false;

                try
                {
                    PrivateTryLock(ref locked); /* TRANSACTIONAL */

                    if (locked)
                    {
                        //
                        // NOTE: If readiness checking for this instance is
                        //       disabled, skip all of our readiness checks;
                        //       however, the saved readiness callback will
                        //       still be called, if it exists (and it does
                        //       not refer back to this instance).
                        //
                        if (disabled)
                            goto skip;

                        //
                        // NOTE: First, check the command count against our
                        //       limit, if it is set.  Upon exceeding this
                        //       limit, process the auto-reset flag and then
                        //       return an error.  This is a fairly accurate
                        //       count and should be favored over operation
                        //       count in almost all cases.
                        //
                        if (commandLimit != Unlimited)
                        {
                            long commandCount = interpreter.CommandCountNoLock;

                            if (commandCount >= commandLimit)
                            {
                                if (autoReset)
                                    interpreter.CommandCountNoLock = 0;

                                error = String.Format(
                                    "command limit exceeded: {0} versus {1}",
                                    commandCount, commandLimit);

                                return ReturnCode.Error;
                            }
                        }

                        //
                        // NOTE: Next, check the operation count against our
                        //       limit, if it is set.  Upon exceeding this
                        //       limit, process the auto-reset flag and then
                        //       return an error.  The operation count is not
                        //       quite as accurate (or useful) as the command
                        //       count and it should not normally be used.
                        //
                        if (operationLimit != Unlimited)
                        {
                            long operationCount = interpreter.OperationCountNoLock;

                            if (operationCount >= operationLimit)
                            {
                                if (autoReset)
                                    interpreter.OperationCountNoLock = 0;

                                error = String.Format(
                                    "operation limit exceeded: {0} versus {1}",
                                    operationCount, operationLimit);

                                return ReturnCode.Error;
                            }
                        }

                        //
                        // NOTE: Next, check the time limit against our time
                        //       limit and start date, if they are set.  Upon
                        //       exceeding this limit, process the auto-reset
                        //       flag and then return an error.  This differs
                        //       significantly from the other two limit checks
                        //       because it is entirely synthetic (i.e. the
                        //       interpreter itself does not track the start
                        //       date, we do).  This relies upon this method
                        //       being called often and at regular intervals.
                        //       When the auto-reset flag is processed, the
                        //       start date is simply reset to "now".  When
                        //       the limit is exceeded, the stopped date is
                        //       set to "now", for accounting purposes.
                        //
                        if (timeLimit != null)
                        {
                            DateTime now = TimeOps.GetUtcNow();

                            if (started != null)
                            {
                                TimeSpan elapsed = now.Subtract(
                                    (DateTime)started);

                                if (elapsed > timeLimit)
                                {
                                    if (autoReset)
                                        started = now;

                                    stopped = now;

                                    error = String.Format(
                                        "time limit exceeded: {0} versus {1}",
                                        elapsed, timeLimit);

                                    return ReturnCode.Error;
                                }
                            }
                            else
                            {
                                started = now;
                            }

                            stopped = null;
                        }

                    skip:

                        //
                        // NOTE: If there is a saved readiness checking
                        //       callback (and it does not refer to this
                        //       instanced callback), attempt to call it
                        //       now.  This allows readiness checking to
                        //       be chained.
                        //
                        if ((savedReadyCallback != null) &&
                            (savedReadyCallback != ReadyCallback))
                        {
                            ReturnCode savedCode;
                            Result savedError = null;

                            savedCode = savedReadyCallback(
                                interpreter, clientData, timeout, flags,
                                ref savedError);

                            if (savedCode != ReturnCode.Ok)
                            {
                                error = savedError;
                                return savedCode;
                            }
                        }

                        return ReturnCode.Ok;
                    }
                    else
                    {
                        error = "unable to acquire lock";
                        return ReturnCode.Error;
                    }
                }
                finally
                {
                    PrivateExitLock(ref locked); /* TRANSACTIONAL */
                }
            }
            #endregion
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources held by this object.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this object has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptLimiter).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases all resources held by this object.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="Dispose()" /> method; otherwise, it is being called
            /// from the finalizer.
            /// </param>
            private /* protected virtual */ void Dispose(
                bool disposing
                )
            {
                TraceOps.DebugTrace(String.Format(
                    "Dispose: called, disposing = {0}, disposed = {1}",
                    disposing, disposed), typeof(ScriptLimiter).Name,
                    TracePriority.CleanupDebug);

                if (!disposed)
                {
                    if (disposing)
                    {
                        ////////////////////////////////////
                        // dispose managed resources here...
                        ////////////////////////////////////

                        Reset();
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class, releasing any resources that
            /// were not explicitly disposed.
            /// </summary>
            ~ScriptLimiter()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ScriptEventState Test Class
        /// <summary>
        /// This class is used by the test suite to evaluate a script on a
        /// separate thread, coordinating the request and result via event wait
        /// handles, optionally subject to a timeout.
        /// </summary>
        [ObjectId("aea45f5e-1a29-48eb-ab8f-66bb56cbf32f")]
        public sealed class ScriptEventState : IGetInterpreter, IDisposable
        {
            #region Private Constants
            /// <summary>
            /// The minimum number of milliseconds to sleep while waiting for the
            /// script to be evaluated.
            /// </summary>
            private static int MinimumSleepTime = EventManager.MinimumSleepTime;
            /// <summary>
            /// When non-zero, the thread pool is used to enforce the script
            /// evaluation timeout.
            /// </summary>
            private static bool UseThreadPoolForTimeout = true;
            /// <summary>
            /// When non-zero, the script event thread will not be configured to
            /// use the single-threaded apartment state.
            /// </summary>
            private static bool NoStaThread = false;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The object used to synchronize access to this object across
            /// threads.
            /// </summary>
            private static readonly object syncRoot = new object();

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The script to be evaluated.
            /// </summary>
            private string text;
            /// <summary>
            /// The return code produced by evaluating the script.
            /// </summary>
            private ReturnCode returnCode;
            /// <summary>
            /// The result value produced by evaluating the script.
            /// </summary>
            private Result result;
            /// <summary>
            /// The line number where an error occurred while evaluating the
            /// script, or zero if there was no error.
            /// </summary>
            private int errorLine;
            /// <summary>
            /// The error code captured from the interpreter after evaluating the
            /// script.
            /// </summary>
            private Result errorCode;
            /// <summary>
            /// The error information captured from the interpreter after
            /// evaluating the script.
            /// </summary>
            private Result errorInfo;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The event that is signaled when script evaluation has completed.
            /// </summary>
            private EventWaitHandle doneEvent;   /* index = 0 */
            /// <summary>
            /// The event that is signaled to request that a script be evaluated.
            /// </summary>
            private EventWaitHandle scriptEvent; /* index = 1 */
            /// <summary>
            /// The event that is signaled when the script result is available.
            /// </summary>
            private EventWaitHandle resultEvent; /* index = 2 */
            /// <summary>
            /// The event that is signaled to request that the script event
            /// thread exit.
            /// </summary>
            private EventWaitHandle exitEvent;   /* index = 3 */

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The array of event wait handles that the script event thread
            /// waits upon.
            /// </summary>
            private EventWaitHandle[] waitHandles;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
            /// <summary>
            /// Constructs a new instance of this class.
            /// </summary>
            private ScriptEventState()
            {
                InitializeEvents();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs a new instance of this class and prepares it to
            /// evaluate the specified script.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context that the script will be evaluated in.
            /// </param>
            /// <param name="text">
            /// The script to be evaluated.
            /// </param>
            /// <param name="timeout">
            /// The maximum number of milliseconds to wait for the script to be
            /// evaluated, or null for no timeout.
            /// </param>
            /// <param name="useTimeout">
            /// Non-zero to enforce the specified timeout when waiting.
            /// </param>
            private ScriptEventState(
                Interpreter interpreter,
                string text,
                int? timeout,
                bool useTimeout
                )
                : this()
            {
                PrepareForEvent(interpreter, text, timeout, useTimeout);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Static "Factory" Methods
            /// <summary>
            /// This method creates a new instance of this class.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context that the script will be evaluated in.
            /// </param>
            /// <param name="text">
            /// The script to be evaluated.
            /// </param>
            /// <param name="timeout">
            /// The maximum number of milliseconds to wait for the script to be
            /// evaluated, or null for no timeout.
            /// </param>
            /// <param name="useTimeout">
            /// Non-zero to enforce the specified timeout when waiting.
            /// </param>
            /// <returns>
            /// The newly created instance of this class.
            /// </returns>
            public static ScriptEventState Create(
                Interpreter interpreter,
                string text,
                int? timeout,
                bool useTimeout
                )
            {
                return new ScriptEventState(
                    interpreter, text, timeout, useTimeout);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method creates the event wait handles used to coordinate the
            /// script evaluation thread, if they have not already been created.
            /// </summary>
            private void InitializeEvents()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (doneEvent == null)
                        doneEvent = ThreadOps.CreateEvent(false);

                    if (scriptEvent == null)
                        scriptEvent = ThreadOps.CreateEvent(false);

                    if (resultEvent == null)
                        resultEvent = ThreadOps.CreateEvent(false);

                    if (exitEvent == null)
                        exitEvent = ThreadOps.CreateEvent(false);

                    if (waitHandles == null)
                    {
                        //
                        // NOTE: The result event does not actually go into
                        //       this array, since the script event thread
                        //       never waits on it.
                        //
                        waitHandles = new EventWaitHandle[] {
                            doneEvent, scriptEvent
                        };
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the stored return code, result value, and
            /// error line to their default values.
            /// </summary>
            private void PrivateClearResult()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    returnCode = ReturnCode.Ok;
                    result = null;
                    errorLine = 0;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method stores the return code, result value, and error line
            /// for an evaluated script.
            /// </summary>
            /// <param name="returnCode">
            /// The return code produced by evaluating the script.
            /// </param>
            /// <param name="result">
            /// The result value produced by evaluating the script.
            /// </param>
            /// <param name="errorLine">
            /// The line number where an error occurred, or zero if there was no
            /// error.
            /// </param>
            private void PrivateSetResult(
                ReturnCode returnCode,
                Result result,
                int errorLine
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    this.returnCode = returnCode;
                    this.result = result;
                    this.errorLine = errorLine;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method stores the return code, result value, and error line
            /// for an evaluated script, optionally also populating the error
            /// information.
            /// </summary>
            /// <param name="returnCode">
            /// The return code produced by evaluating the script.
            /// </param>
            /// <param name="result">
            /// The result value produced by evaluating the script.
            /// </param>
            /// <param name="errorLine">
            /// The line number where an error occurred, or zero if there was no
            /// error.
            /// </param>
            /// <param name="errorInfo">
            /// Non-zero to also populate the stored error code and error
            /// information from the interpreter.
            /// </param>
            private void PrivateSetResult(
                ReturnCode returnCode,
                Result result,
                int errorLine,
                bool errorInfo
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    PrivateSetResult(returnCode, result, errorLine);

                    if (errorInfo)
                    {
                        /* IGNORED */
                        PrivateCheckPopulateErrorInformation();
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method clears the stored error code and error information.
            /// </summary>
            private void PrivateClearErrorInformation()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    errorCode = null;
                    errorInfo = null;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method copies the error code and error information from the
            /// interpreter into this object, based on the most recently recorded
            /// return code.
            /// </summary>
            /// <returns>
            /// True if the error information was successfully populated;
            /// otherwise, false.
            /// </returns>
            private bool PrivateCheckPopulateErrorInformation()
            {
                Interpreter localInterpreter;
                ReturnCode localReturnCode;

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    localInterpreter = interpreter;
                    localReturnCode = returnCode;
                }

                Result localErrorCode = null;
                Result localErrorInfo = null;

                bool result = TestCheckCopyErrorInformation(
                    localInterpreter, localReturnCode, true,
                    ref localErrorCode, ref localErrorInfo);

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    errorCode = localErrorCode;
                    errorInfo = localErrorInfo;
                }

                return result;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the event used to request that a script be
            /// evaluated, clearing its signaled state.
            /// </summary>
            private void PrivateUnSignalScript()
            {
                EventWaitHandle localScriptEvent;

                lock (syncRoot)
                {
                    localScriptEvent = scriptEvent;
                }

                ThreadOps.ResetEvent(localScriptEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the event used to indicate that a script result
            /// is available, clearing its signaled state.
            /// </summary>
            private void PrivateUnSignalResult()
            {
                EventWaitHandle localResultEvent;

                lock (syncRoot)
                {
                    localResultEvent = resultEvent;
                }

                ThreadOps.ResetEvent(localResultEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method signals the event used to indicate that the associated
            /// event thread should exit.
            /// </summary>
            private void PrivateSignalDone()
            {
                EventWaitHandle localDoneEvent;

                lock (syncRoot)
                {
                    localDoneEvent = doneEvent;
                }

                ThreadOps.SetEvent(localDoneEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method signals the event used to request that a script be
            /// evaluated.
            /// </summary>
            private void PrivateSignalScript()
            {
                EventWaitHandle localScriptEvent;

                lock (syncRoot)
                {
                    localScriptEvent = scriptEvent;
                }

                ThreadOps.SetEvent(localScriptEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method signals the event used to indicate that a script result
            /// is available.
            /// </summary>
            private void PrivateSignalResult()
            {
                EventWaitHandle localResultEvent;

                lock (syncRoot)
                {
                    localResultEvent = resultEvent;
                }

                ThreadOps.SetEvent(localResultEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method signals the event used to indicate that the associated
            /// thread should exit.
            /// </summary>
            private void PrivateSignalExit()
            {
                EventWaitHandle localExitEvent;

                lock (syncRoot)
                {
                    localExitEvent = exitEvent;
                }

                ThreadOps.SetEvent(localExitEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method clears the current result and error information and then
            /// signals that a result is available.
            /// </summary>
            private void ClearAndSignalResult()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    PrivateClearResult();
                    PrivateClearErrorInformation();
                    PrivateSignalResult();
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method waits for the associated event thread to exit, using the
            /// default timeout for disposal.
            /// </summary>
            /// <returns>
            /// True if the thread exited within the timeout; otherwise, false.
            /// </returns>
            private bool WaitExitForDispose()
            {
                Interpreter localInterpreter;

                lock (syncRoot)
                {
                    localInterpreter = interpreter;
                }

                return WaitExit(ThreadOps.GetDefaultTimeout(
                    localInterpreter, TimeoutType.Dispose));
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IGetInterpreter Members
            /// <summary>
            /// The interpreter associated with this script event state.
            /// </summary>
            private Interpreter interpreter;
            /// <summary>
            /// Gets the interpreter associated with this script event state.
            /// </summary>
            public Interpreter Interpreter
            {
                get { CheckDisposed(); lock (syncRoot) { return interpreter; } }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// The timeout, in milliseconds, to use when waiting for a script to be
            /// evaluated, or null for none.
            /// </summary>
            private int? timeout;
            /// <summary>
            /// Gets the timeout, in milliseconds, to use when waiting for a script
            /// to be evaluated, or null for none.
            /// </summary>
            public int? Timeout
            {
                get { CheckDisposed(); lock (syncRoot) { return timeout; } }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// When non-zero, the configured timeout is used when waiting for a
            /// script to be evaluated.
            /// </summary>
            private bool useTimeout;
            /// <summary>
            /// Gets a value indicating whether the configured timeout is used when
            /// waiting for a script to be evaluated.
            /// </summary>
            public bool UseTimeout
            {
                get { CheckDisposed(); lock (syncRoot) { return useTimeout; } }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method configures this script event state in preparation for
            /// evaluating a script on another thread.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to associate with this script event state.
            /// </param>
            /// <param name="text">
            /// The text of the script to be evaluated.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, to use when waiting, or null for none.
            /// </param>
            /// <param name="useTimeout">
            /// Non-zero to use the specified timeout when waiting.
            /// </param>
            public void PrepareForEvent(
                Interpreter interpreter,
                string text,
                int? timeout,
                bool useTimeout
                )
            {
                CheckDisposed();

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    this.interpreter = interpreter;
                    this.text = text;
                    this.timeout = timeout;
                    this.useTimeout = useTimeout;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets any pending script cancellation for the
            /// associated interpreter.
            /// </summary>
            /// <returns>
            /// True if the cancellation was reset successfully; otherwise, false.
            /// </returns>
            public bool ResetCancel()
            {
                CheckDisposed();

                Interpreter interpreter;

                lock (syncRoot)
                {
                    interpreter = this.interpreter;
                }

                return (Engine.ResetCancel(interpreter,
                    CancelFlags.ScriptEvent) == ReturnCode.Ok);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method queries the minimum amount of time, in milliseconds,
            /// that should be spent sleeping while waiting for a script.
            /// </summary>
            /// <returns>
            /// The minimum sleep time, in milliseconds.
            /// </returns>
            public int GetMinimumSleepTime()
            {
                CheckDisposed();

                Interpreter localInterpreter;

                lock (syncRoot)
                {
                    localInterpreter = interpreter;
                }

                if (localInterpreter == null)
                    return MinimumSleepTime;

                IEventManager eventManager;

                lock (localInterpreter.InternalSyncRoot) /* TRANSACTIONAL */
                {
                    if (localInterpreter.Disposed)
                        return MinimumSleepTime;

                    eventManager = localInterpreter.EventManager;

                    if (eventManager == null)
                        return MinimumSleepTime;
                }

                lock (eventManager.SyncRoot) /* TRANSACTIONAL */
                {
                    if (!EventOps.ManagerIsOk(eventManager))
                        return MinimumSleepTime;

                    return eventManager.GetMinimumSleepTime(
                        SleepType.Script);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method waits for either a script request or a done signal,
            /// using the minimum sleep time as the timeout.
            /// </summary>
            /// <returns>
            /// The zero-based index of the event that was signaled, or a value
            /// indicating that the wait timed out.
            /// </returns>
            public int WaitScriptOrDone()
            {
                CheckDisposed();

                return WaitScriptOrDone(GetMinimumSleepTime());
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method waits for either a script request or a done signal,
            /// using the specified timeout.
            /// </summary>
            /// <param name="timeout">
            /// The maximum amount of time, in milliseconds, to wait.
            /// </param>
            /// <returns>
            /// The zero-based index of the event that was signaled, or a value
            /// indicating that the wait timed out.
            /// </returns>
            public int WaitScriptOrDone(
                int timeout
                )
            {
                CheckDisposed();

                EventWaitHandle[] localWaitHandles;

                lock (syncRoot)
                {
                    localWaitHandles = waitHandles;
                }

                return ThreadOps.WaitAnyEvent(localWaitHandles, timeout);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method waits for a script result to become available.
            /// </summary>
            /// <returns>
            /// True if the result event was signaled; otherwise, false.
            /// </returns>
            public bool WaitResult()
            {
                CheckDisposed();

                EventWaitHandle localResultEvent;

                lock (syncRoot)
                {
                    localResultEvent = resultEvent;
                }

                return ThreadOps.WaitEvent(localResultEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method waits for a script result to become available, using the
            /// specified timeout.
            /// </summary>
            /// <param name="timeout">
            /// The maximum amount of time, in milliseconds, to wait.
            /// </param>
            /// <returns>
            /// True if the result event was signaled; otherwise, false.
            /// </returns>
            public bool WaitResult(
                int timeout
                )
            {
                CheckDisposed();

                EventWaitHandle localResultEvent;

                lock (syncRoot)
                {
                    localResultEvent = resultEvent;
                }

                return ThreadOps.WaitEvent(localResultEvent, timeout);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method waits for the associated thread to exit.
