            public bool WaitExit()
            {
                CheckDisposed();

                EventWaitHandle localExitEvent;

                lock (syncRoot)
                {
                    localExitEvent = exitEvent;
                }

                return ThreadOps.WaitEvent(localExitEvent);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method waits for the associated thread to exit, using the
