            {
                CheckDisposed();

                EventWaitHandle localExitEvent;

                lock (syncRoot)
                {
                    localExitEvent = exitEvent;
                }

                return ThreadOps.WaitEvent(localExitEvent, timeout);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets both the script request event and the result
            /// event, clearing their signaled states.
            /// </summary>
            /// <returns>
            /// True if both events were reset successfully; otherwise, false.
            /// </returns>
            public bool UnSignalScriptAndResult()
            {
                CheckDisposed();

                EventWaitHandle localScriptEvent;
                EventWaitHandle localResultEvent;

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    localScriptEvent = scriptEvent;
                    localResultEvent = resultEvent;
                }

                bool result = true;

                if (!ThreadOps.ResetEvent(localScriptEvent))
                    result = false;

                if (!ThreadOps.ResetEvent(localResultEvent))
                    result = false;

                return result;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method signals the script request event and then waits for the
