            /// </summary>
            /// <param name="scriptTimeoutThread">
            /// Upon return, receives the created script timeout thread, if any.
            /// </param>
            public void StartTimeout(
                ref ScriptTimeoutThread scriptTimeoutThread
                )
            {
                ScriptThreadClientData scriptThreadClientData =
                    ScriptThreadClientData.Create(
                        null, UseThreadPoolForTimeout);

                StartTimeout(
                    scriptThreadClientData, ref scriptTimeoutThread);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method starts a script timeout thread using the specified
            /// client data.
            /// </summary>
            /// <param name="scriptThreadClientData">
            /// The client data to use when creating the script timeout thread.
            /// </param>
            /// <param name="scriptTimeoutThread">
            /// Upon return, receives the created script timeout thread, if any.
            /// </param>
            public void StartTimeout(
                ScriptThreadClientData scriptThreadClientData,
                ref ScriptTimeoutThread scriptTimeoutThread
                )
            {
                CheckDisposed();

                Interpreter localInterpreter;
                int? localTimeout;
                bool localUseTimeout;

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    localInterpreter = interpreter;
                    localTimeout = timeout;
                    localUseTimeout = useTimeout;
                }

                if (localUseTimeout)
                {
                    scriptTimeoutThread = ScriptTimeoutThread.Create(
                        localInterpreter, localTimeout,
                        scriptThreadClientData);
                }
            }
            #endregion

