            #region IDisposable Members
            /// <summary>
            /// This method releases all resources used by this script event state.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(interpreter, null))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptEventState).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the resources used by this script event state.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="Dispose()" /> method; zero if it is being called from the
            /// finalizer.
            /// </param>
            private /* protected virtual */ void Dispose(
                bool disposing
                )
            {
                TraceOps.DebugTrace(String.Format(
                    "Dispose: called, disposing = {0}, disposed = {1}",
                    disposing, disposed), typeof(ScriptEventState).Name,
                    TracePriority.CleanupDebug);

                if (!disposed)
                {
                    if (disposing)
                    {
                        ////////////////////////////////////
                        // dispose managed resources here...
                        ////////////////////////////////////

                        //
                        // NOTE: First, attempt to unblock any threads that may
                        //       be waiting.
                        //
                        PrivateSignalDone(); /* trigger event thread to exit... */
                        ClearAndSignalResult(); /* trigger other thread to unblock... */
                        WaitExitForDispose(); /* wait for event thread to exit... */

                        //
                        // NOTE: Next, dispose of the event wait handle objects.
                        //
                        lock (syncRoot) /* TRANSACTIONAL */
                        {
                            /* NO RESULT */
                            ThreadOps.CloseEvent(ref doneEvent);

                            /* NO RESULT */
                            ThreadOps.CloseEvent(ref scriptEvent);

                            /* NO RESULT */
                            ThreadOps.CloseEvent(ref resultEvent);

                            /* NO RESULT */
                            ThreadOps.CloseEvent(ref exitEvent);

                            interpreter = null; /* NOT OWNED, DO NOT DISPOSE. */
                        }
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes this script event state, releasing any resources that were
            /// not explicitly disposed.
            /// </summary>
            ~ScriptEventState()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

