            /// active call stack.
            /// </summary>
            private static bool DefaultUseActiveStack = true;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The default value indicating whether the script thread is started
            /// automatically.
            /// </summary>
            private static bool DefaultAutoStart = true;

            ///////////////////////////////////////////////////////////////////////////////////////////

