            #region Private Static Methods
            /// <summary>
            /// This method obtains the thread startup parameters from the
            /// specified client data, falling back to the default values when no
            /// client data is supplied.
            /// </summary>
            /// <param name="scriptThreadClientData">
            /// The client data to obtain the startup parameters from.  This
            /// parameter may be null.
            /// </param>
            /// <param name="useThreadPool">
            /// Upon return, non-zero if a thread pool thread should be used.
            /// </param>
            /// <param name="maxStackSize">
            /// Upon return, the maximum stack size, in bytes, for the thread.
            /// </param>
            /// <param name="userInterface">
            /// Upon return, non-zero if the thread requires user interface
            /// support.
            /// </param>
            /// <param name="isBackground">
            /// Upon return, non-zero if the thread should be a background thread.
            /// </param>
            /// <param name="useActiveStack">
            /// Upon return, non-zero if the active stack should be used for the
            /// thread.
            /// </param>
            internal static void GetStartParameters(
                ScriptThreadClientData scriptThreadClientData,
                out bool useThreadPool,
                out int maxStackSize,
                out bool userInterface,
                out bool isBackground,
                out bool useActiveStack
                )
            {
                if (scriptThreadClientData != null)
                {
                    useThreadPool = scriptThreadClientData.useThreadPool;
                    maxStackSize = scriptThreadClientData.maxStackSize;
                    userInterface = scriptThreadClientData.userInterface;
                    isBackground = scriptThreadClientData.isBackground;
                    useActiveStack = scriptThreadClientData.useActiveStack;
                }
                else
                {
                    useThreadPool = DefaultUseThreadPool;
                    maxStackSize = DefaultMaxStackSize;
                    userInterface = DefaultUserInterface;
                    isBackground = DefaultIsBackground;
                    useActiveStack = DefaultUseActiveStack;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method obtains the thread shutdown parameters from the
            /// specified client data, falling back to the default values when no
            /// client data is supplied.
            /// </summary>
            /// <param name="scriptThreadClientData">
            /// The client data to obtain the shutdown parameters from.  This
            /// parameter may be null.
            /// </param>
            /// <param name="waitOnStop">
            /// Upon return, non-zero if stopping the thread should wait for it to
            /// exit before returning.
            /// </param>
            /// <param name="waitOnInterrupt">
            /// Upon return, non-zero if stopping the thread should wait for it to
            /// exit after interrupting it.
            /// </param>
            /// <param name="noAbort">
            /// Upon return, non-zero if the thread should not be aborted when it
            /// is stopped.
            /// </param>
            internal static void GetStopParameters(
                ScriptThreadClientData scriptThreadClientData,
                out bool waitOnStop,
                out bool waitOnInterrupt,
                out bool noAbort
                )
            {
                if (scriptThreadClientData != null)
                {
                    waitOnStop = scriptThreadClientData.WaitOnStop;
                    waitOnInterrupt = scriptThreadClientData.WaitOnInterrupt;
                    noAbort = scriptThreadClientData.NoAbort;
                }
                else
                {
                    waitOnStop = DefaultWaitOnStop;
                    waitOnInterrupt = DefaultWaitOnInterrupt;
                    noAbort = DefaultNoAbort;
                }
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ScriptEventThread Test Class
        /// <summary>
        /// This class implements a thread that evaluates scripts on behalf of an
        /// interpreter in response to signaled events, communicating the results
        /// back to the thread that requested the evaluation.
        /// </summary>
        [ObjectId("791aa07b-7c96-409c-8d8e-7205f07bb7c7")]
        public sealed class ScriptEventThread : IGetInterpreter, IDisposable
        {
            #region Private Data
            /// <summary>
            /// The object used to synchronize access to the data in this class.
            /// </summary>
            private static readonly object syncRoot = new object();

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The script event state used to communicate with the thread that
            /// requested script evaluation.
            /// </summary>
            private ScriptEventState scriptEventState;
            /// <summary>
            /// The client data used to configure this script event thread.
            /// </summary>
            private ScriptThreadClientData scriptThreadClientData;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The managed thread used to evaluate scripts.
            /// </summary>
            private Thread thread;
            /// <summary>
            /// The identifier of the thread used to evaluate scripts.
            /// </summary>
            private long threadId;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
            /// <summary>
            /// Constructs a script event thread using the specified script event
            /// state and client data.
            /// </summary>
            /// <param name="scriptEventState">
            /// The script event state used to communicate with this script event
            /// thread.
            /// </param>
            /// <param name="scriptThreadClientData">
            /// The client data used to configure this script event thread.  This
            /// parameter may be null.
            /// </param>
            private ScriptEventThread(
                ScriptEventState scriptEventState,
                ScriptThreadClientData scriptThreadClientData
                )
            {
                this.scriptEventState = scriptEventState;
                this.scriptThreadClientData = scriptThreadClientData;

                ///////////////////////////////////////////////////////////////////////////////////////

                MaybeAutoStart();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Static "Factory" Methods
            /// <summary>
            /// This method creates a new script event thread instance.
            /// </summary>
            /// <param name="scriptEventState">
            /// The script event state used to communicate with the new script
            /// event thread.
            /// </param>
            /// <param name="scriptThreadClientData">
            /// The client data used to configure the new script event thread.
            /// This parameter may be null.
            /// </param>
            /// <returns>
            /// The newly created script event thread instance.
            /// </returns>
            public static ScriptEventThread Create(
                ScriptEventState scriptEventState,
                ScriptThreadClientData scriptThreadClientData
                )
            {
                return new ScriptEventThread(
                    scriptEventState, scriptThreadClientData);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            //
            // NOTE: This method assumes the lock is already held -OR-
            //       is being called from a context where locks should
            //       not generally be obtained.
            //
            /// <summary>
            /// This method returns the interpreter associated with this script
            /// event thread.  It assumes any required lock is already held.
            /// </summary>
            /// <returns>
            /// The interpreter associated with this script event thread, or null
            /// if none is available.
            /// </returns>
            private Interpreter GetInterpreter()
            {
                return (scriptEventState != null) ?
                    scriptEventState.Interpreter : null;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether automatic startup has been
            /// requested for this thread.
            /// </summary>
            /// <returns>
            /// True if automatic startup is enabled; otherwise, false.
            /// </returns>
            private bool IsAutoStart()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (scriptThreadClientData == null)
                        return false;

                    return scriptThreadClientData.AutoStart;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method starts the thread when automatic startup has been
            /// requested.
            /// </summary>
            private void MaybeAutoStart()
            {
                if (IsAutoStart())
                    Start();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method evaluates the script contained within the specified
            /// script event state, applying any configured timeout and storing
            /// the result back into the script event state.
            /// </summary>
            /// <param name="scriptEventState">
            /// The script event state containing the script to evaluate and used
            /// to communicate the result.  If this parameter is null, this method
            /// does nothing.
            /// </param>
            private void EvaluateScript(
                ScriptEventState scriptEventState
                )
            {
                if (scriptEventState == null)
                    return;

                ScriptTimeoutThread scriptTimeoutThread = null;

                try
                {
                    Interpreter interpreter;

                    lock (syncRoot)
                    {
                        interpreter = GetInterpreter();
                    }

                    if (interpreter == null)
                        return;

                    string text = scriptEventState.TakeText();

                    if (text == null)
                        return;

                    scriptEventState.StartTimeout(
                        ref scriptTimeoutThread);

                    ReturnCode code;
                    Result result = null;
                    int errorLine = 0;

                    code = interpreter.EvaluateScript(
                        text, ref result, ref errorLine);

                    scriptEventState.SetResult(
                        code, result, errorLine, true);
                }
                finally
                {
                    scriptEventState.SignalResult();

                    if (scriptTimeoutThread != null)
                    {
                        scriptTimeoutThread.Stop();
                        scriptTimeoutThread = null;
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region ThreadStart Method
            /// <summary>
            /// This method is the thread procedure for the script event thread.
            /// It repeatedly waits for a script to be queued for evaluation, or
            /// for a signal that the thread should exit, and evaluates each
            /// script as it is received.
            /// </summary>
            /// <param name="obj">
            /// The thread parameter.  This parameter is not used.
            /// </param>
            private void ThreadStart(
                object obj /* NOT USED */
                ) /* System.Threading.ParameterizedThreadStart */
            {
                ScriptEventState localScriptEventState = null;

                try
                {
                    lock (syncRoot) /* TRANSACTIONAL */
                    {
                        //
                        // NOTE: Set the thread Id for this instance to the
                        //       current thread we are executing on (which
                        //       may be from the thread pool).  This can be
                        //       used by our owner to figure out what our
                        //       actual thread is.  It's not used elsewhere
                        //       in this class.
                        //
                        threadId = GlobalState.GetCurrentSystemThreadId();

                        //
                        // NOTE: Grab the script event state instance, which
                        //       is used to communicate with our creator.
                        //
                        localScriptEventState = scriptEventState;
                    }

                    if (localScriptEventState == null)
                        return;

                    while (true)
                    {
                        //
                        // NOTE: Wait for something to happen.  Either we will
                        //       exit our loop, evaluate a script, or maybe do
                        //       nothing (wait timeout).
                        //
                        int index = localScriptEventState.WaitScriptOrDone();

                        //
                        // NOTE: Check the result of the wait operation, using
                        //       roughly an order of priority.
                        //
                        if (index == WaitHandle.WaitTimeout)
                        {
                            //
                            // NOTE: This is the normal case, there is nothing
                            //       to do yet.  Keep waiting.
                            //
                            continue;
                        }
                        else if (ThreadOps.WasAnyWaitFailed(index))
                        {
                            //
                            // NOTE: There was some kind of error (invalid wait
                            //       handle, etc?) during the wait operation.
                            //       Normally, there is not much point in doing
                            //       any more waiting, since there is no way it
                            //       could succeed unless the wait handles were
                            //       somehow magically made valid again.
                            //
                            // TODO: In the future, perhaps this should be more
                            //       flexible, e.g. by adding a property to the
                            //       ScriptEventState class.
                            //
                            break;
                        }
                        else if (index == 0)
                        {
                            //
                            // NOTE: The "done" event was signaled, bail out
                            //       now.
                            //
                            break;
                        }
                        else if (index == 1)
                        {
                            //
                            // NOTE: Make sure that the script related event
                            //       is no longer signaled.
                            //
                            localScriptEventState.UnSignalScript();

                            //
                            // NOTE: The "script" event was signaled; so do
                            //       the evaluation now.  The script text to
                            //       evaluate should be contained within the
                            //       mutable script triplet passed when this
                            //       thread was created.  The triplet itself
                            //       will be updated before the script event
                            //       is signaled.  The interpreter will also
                            //       be refreshed before being used.
                            //
                            EvaluateScript(localScriptEventState);
                        }
                        else
                        {
                            //
                            // NOTE: Something odd happened, log it?
                            //
                            TraceOps.DebugTrace(String.Format(
                                "unhandled event wait result: {0}",
                                index), typeof(ScriptEventThread).Name,
                                TracePriority.ThreadError);
                        }
                    }
                }
                catch (ThreadAbortException)
                {
                    Thread.ResetAbort();
                }
                catch (ThreadInterruptedException)
                {
                    // do nothing.
                }
                catch (InterpreterDisposedException)
                {
                    // do nothing.
                }
                catch (Exception e)
                {
                    //
                    // NOTE: Since a user-defined script is being evaluated,
                    //       we catch and log all types of exceptions.
                    //
                    TraceOps.DebugTrace(
                        e, typeof(ScriptEventThread).Name,
                        TracePriority.ThreadError);
                }
                finally
                {
                    //
                    // NOTE: Indicate to any waiting thread that this thread
                    //       is now exiting.
                    //
                    if (localScriptEventState != null)
                    {
                        try
                        {
                            localScriptEventState.SignalExit();
                        }
                        catch (Exception e)
                        {
                            TraceOps.DebugTrace(
                                e, typeof(ScriptEventThread).Name,
                                TracePriority.ThreadError);
                        }

                        localScriptEventState = null;
                    }
                }
            }
            #endregion
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IGetInterpreter Members
            /// <summary>
            /// Gets the interpreter associated with this script event thread.
            /// </summary>
            public Interpreter Interpreter
            {
                get
                {
                    CheckDisposed();

                    lock (syncRoot)
                    {
                        return GetInterpreter();
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method starts the script event thread.  It throws an
            /// exception if the thread has already been started.
            /// </summary>
            public void Start() /* throw */
            {
                CheckDisposed();

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (thread != null)
                    {
                        throw new InvalidOperationException(
                            "script thread already started");
                    }

                    bool useThreadPool;
                    int maxStackSize;
                    bool userInterface;
                    bool isBackground;
                    bool useActiveStack;

                    ScriptThreadClientData.GetStartParameters(
                        scriptThreadClientData, out useThreadPool,
                        out maxStackSize, out userInterface,
                        out isBackground, out useActiveStack);

                    Interpreter localInterpreter = GetInterpreter();

                    ThreadOps.CreateAndOrStart(
                        localInterpreter, "scriptEvent", ThreadStart,
                        null, useThreadPool, maxStackSize, userInterface,
                        isBackground, useActiveStack, ref thread);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method stops the script event thread, optionally waiting for
            /// it to exit before and after interrupting it.
            /// </summary>
            public void Stop() /* throw */
            {
                CheckDisposed();

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    bool waitOnStop;
                    bool waitOnInterrupt;
                    bool noAbort;

                    ScriptThreadClientData.GetStopParameters(
                        scriptThreadClientData, out waitOnStop,
                        out waitOnInterrupt, out noAbort);

                    Interpreter localInterpreter = GetInterpreter();

                    ShutdownFlags shutdownFlags = ShutdownFlags.ScriptEvent;

                    if (waitOnStop)
                        shutdownFlags |= ShutdownFlags.WaitBefore;

                    if (waitOnInterrupt)
                        shutdownFlags |= ShutdownFlags.WaitAfter;

                    if (noAbort)
                        shutdownFlags |= ShutdownFlags.NoAbort;

                    ThreadOps.MaybeShutdown(
                        localInterpreter, null, shutdownFlags, ref thread);
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Object Overrides
            /// <summary>
            /// This method returns a string representation of this object
            /// instance.
            /// </summary>
            /// <returns>
            /// The identifier of the thread associated with this object
            /// instance, formatted as a string.
            /// </returns>
            public override string ToString()
            {
                CheckDisposed();

                long localThreadId;

                lock (syncRoot)
                {
                    localThreadId = threadId;
                }

                return localThreadId.ToString();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources held by this object instance.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed and the associated interpreter
            /// is configured to throw on disposed object access.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                Interpreter localInterpreter;

                lock (syncRoot)
                {
                    localInterpreter = GetInterpreter();
                }

                if (disposed &&
                    Engine.IsThrowOnDisposed(localInterpreter, null))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptEventThread).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="Dispose()" /> method; zero if it is being called from
            /// the finalizer.
            /// </param>
            private /* protected virtual */ void Dispose(
                bool disposing
                )
            {
                TraceOps.DebugTrace(String.Format(
                    "Dispose: called, disposing = {0}, disposed = {1}",
                    disposing, disposed), typeof(ScriptEventThread).Name,
                    TracePriority.CleanupDebug);

                if (!disposed)
                {
                    if (disposing)
                    {
                        ////////////////////////////////////
                        // dispose managed resources here...
                        ////////////////////////////////////

                        lock (syncRoot) /* TRANSACTIONAL */
                        {
                            if (scriptEventState != null)
                            {
                                scriptEventState.Dispose();
                                scriptEventState = null;
                            }
                        }
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of the <see cref="ScriptEventThread" />
            /// class, releasing any resources it holds.
            /// </summary>
            ~ScriptEventThread()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ScriptTimeoutThread Test Class
        /// <summary>
        /// This class implements a thread that cancels the script currently
        /// being evaluated in an interpreter after a configurable timeout has
        /// elapsed.
        /// </summary>
        [ObjectId("02cf4a67-9859-4f08-99b8-6285dcb57620")]
        public sealed class ScriptTimeoutThread : IGetInterpreter, IDisposable
        {
            #region Private Constants
            /// <summary>
            /// The name of the interpreter runtime option used to store the
            /// request identifier associated with a script timeout thread.
            /// </summary>
            private static readonly string RequestIdRuntimeOption =
                typeof(ScriptTimeoutThread).Name + "RequestId";
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Static Data
            /// <summary>
            /// The request identifier most recently allocated; used to generate
            /// unique request identifiers.
            /// </summary>
            private static long nextRequestId;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The object used to synchronize access to the data in this class.
            /// </summary>
            private static readonly object syncRoot = new object();

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The event used to interrupt the timeout wait, allowing the thread
            /// to exit early.
            /// </summary>
            EventWaitHandle timeoutEvent;
            /// <summary>
            /// The timeout, in milliseconds, after which the script being
            /// evaluated is canceled.  This value may be null.
            /// </summary>
            private int? timeout;
            /// <summary>
            /// The request identifier associated with this script timeout
            /// thread.
            /// </summary>
            private long requestId;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The client data used to configure this script timeout thread.
            /// </summary>
            private ScriptThreadClientData scriptThreadClientData;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The managed thread used to enforce the script timeout.
            /// </summary>
            private Thread thread;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
            /// <summary>
            /// Constructs a script timeout thread, allocating a new request
            /// identifier.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter associated with this script timeout thread.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, after which the script being
            /// evaluated should be canceled.  This parameter may be null.
            /// </param>
            /// <param name="scriptThreadClientData">
            /// The client data used to configure this script timeout thread.
            /// This parameter may be null.
            /// </param>
            private ScriptTimeoutThread(
                Interpreter interpreter,
                int? timeout,
                ScriptThreadClientData scriptThreadClientData
                )
                : this(interpreter, timeout, GetRequestId(),
                       scriptThreadClientData)
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs a script timeout thread using the fully specified set
            /// of interpreter, timeout, request identifier, and client data
            /// parameters.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter associated with this script timeout thread.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, after which the script being
            /// evaluated should be canceled.  This parameter may be null.
            /// </param>
            /// <param name="requestId">
            /// The request identifier to associate with this script timeout
            /// thread.
            /// </param>
            /// <param name="scriptThreadClientData">
            /// The client data used to configure this script timeout thread.
            /// This parameter may be null.
            /// </param>
            private ScriptTimeoutThread(
                Interpreter interpreter,
                int? timeout,
                long requestId,
                ScriptThreadClientData scriptThreadClientData
                )
            {
                this.interpreter = interpreter;
                this.timeoutEvent = null;
                this.timeout = timeout;
                this.requestId = requestId;
                this.scriptThreadClientData = scriptThreadClientData;

                ///////////////////////////////////////////////////////////////////////////////////////

                MaybeAutoStart();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Static "Factory" Methods
            /// <summary>
            /// This method creates a new script timeout thread instance,
            /// allocating a new request identifier.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter associated with the new script timeout thread.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, after which the script being
            /// evaluated should be canceled.  This parameter may be null.
            /// </param>
            /// <param name="scriptThreadClientData">
            /// The client data used to configure the new script timeout thread.
            /// This parameter may be null.
            /// </param>
            /// <returns>
            /// The newly created script timeout thread instance.
            /// </returns>
            public static ScriptTimeoutThread Create(
                Interpreter interpreter,
                int? timeout,
                ScriptThreadClientData scriptThreadClientData
                )
            {
                return new ScriptTimeoutThread(
                    interpreter, timeout, scriptThreadClientData);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a new script timeout thread instance using
            /// the specified request identifier.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter associated with the new script timeout thread.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, after which the script being
            /// evaluated should be canceled.  This parameter may be null.
            /// </param>
            /// <param name="requestId">
            /// The request identifier to associate with the new script timeout
            /// thread.
            /// </param>
            /// <param name="scriptThreadClientData">
            /// The client data used to configure the new script timeout thread.
            /// This parameter may be null.
            /// </param>
            /// <returns>
            /// The newly created script timeout thread instance.
            /// </returns>
            public static ScriptTimeoutThread Create(
                Interpreter interpreter,
                int? timeout,
                long requestId,
                ScriptThreadClientData scriptThreadClientData
                )
            {
                return new ScriptTimeoutThread(
                    interpreter, timeout, requestId,
                    scriptThreadClientData);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method closes the timeout event if it has been created.
            /// </summary>
            private void MaybeCloseEvent()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (timeoutEvent == null)
                        return;

                    ThreadOps.CloseEvent(ref timeoutEvent);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates the timeout event if it has not already been
            /// created.
            /// </summary>
            private void MaybeCreateEvent()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (timeoutEvent != null)
                        return;

                    timeoutEvent = ThreadOps.CreateEvent(false);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method signals the timeout event when it has been created.
            /// </summary>
            private void MaybeSignalEvent()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (timeoutEvent == null)
                        return;

                    ThreadOps.SetEvent(timeoutEvent);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether automatic startup has been
            /// requested for this thread.
            /// </summary>
            /// <returns>
            /// True if automatic startup is enabled; otherwise, false.
            /// </returns>
            private bool IsAutoStart()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (scriptThreadClientData == null)
                        return false;

                    return scriptThreadClientData.AutoStart;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method starts the thread when automatic startup has been
            /// requested.
            /// </summary>
            private void MaybeAutoStart()
            {
                if (IsAutoStart())
                    Start();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Static Methods
            /// <summary>
            /// This method returns the next available request identifier,
            /// incrementing the shared counter.
            /// </summary>
            /// <returns>
            /// The newly allocated request identifier.
            /// </returns>
            private static long GetRequestId()
            {
                return Interlocked.Increment(ref nextRequestId);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the request identifier previously associated
            /// with the specified interpreter via its runtime options.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter whose associated request identifier should be
            /// returned.  This parameter may be null.
            /// </param>
            /// <returns>
            /// The request identifier associated with the interpreter, or zero
            /// if none is available.
            /// </returns>
            private static long GetRequestId(
                Interpreter interpreter
                )
            {
                if (interpreter != null)
                {
                    try
                    {
                        IClientData clientData = null;

                        if (interpreter.InternalGetRuntimeOption(
                                RequestIdRuntimeOption,
                                ref clientData))
                        {
                            if (clientData != null)
                            {
                                object data = clientData.Data;

                                if (data is long)
                                    return (long)data;
                            }
                        }
                    }
                    catch
                    {
                        // do nothing.
                    }
                }

                return 0;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method associates the specified request identifier with the
            /// interpreter, storing it within the interpreter's runtime options.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter whose associated request identifier should be set.
            /// This parameter may be null.
            /// </param>
            /// <param name="requestId">
            /// The request identifier to associate with the interpreter.
            /// </param>
            /// <returns>
            /// True if the request identifier was set successfully; otherwise,
            /// false.
            /// </returns>
            private static bool SetRequestId(
                Interpreter interpreter,
                long requestId
                )
            {
                if (interpreter != null)
                {
                    try
                    {
                        if (interpreter.InternalSetRuntimeOption(
                                RequestIdRuntimeOption, new ClientData(
                                requestId), true, true))
                        {
                            return true;
                        }
                    }
                    catch
                    {
                        // do nothing.
                    }
                }

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region ParameterizedThreadStart Method
            /// <summary>
            /// This method is the thread procedure for the script timeout thread.
            /// It waits for the configured timeout to elapse and then cancels any
            /// script currently being evaluated in the associated interpreter.
            /// </summary>
            /// <param name="obj">
            /// The thread parameter, which is expected to be a <c>TimeoutTriplet</c>
            /// instance.  If it is not, this method does nothing.
            /// </param>
            private static void ThreadStart(
                object obj
                ) /* System.Threading.ParameterizedThreadStart */
            {
                try
                {
                    //
                    // NOTE: If this thread was not passed the correct type of
                    //       object(s), just do nothing and then return.
                    //
                    TimeoutTriplet anyTriplet = obj as TimeoutTriplet;

                    if (anyTriplet == null)
                        return;

                    ScriptTimeoutClientData scriptTimeoutClientData = anyTriplet.X;

                    if (scriptTimeoutClientData == null)
                        return;

                    //
                    // NOTE: If the interpreter or timeout is not valid, just
                    //       do nothing and then return.  It should be noted
                    //       that the EventWaitHandle here is optional.  When
                    //       missing, a simple sleep will be used instead.
                    //
                    Interpreter interpreter = scriptTimeoutClientData.Interpreter;
                    int timeout = scriptTimeoutClientData.Timeout;

                    if ((interpreter == null) || (timeout <= 0))
                        return;

                    //
                    // HACK: Cannot use the wrapper methods here because they
                    //       catch ThreadInterruptedException, et al.
                    //
                    EventWaitHandle timeoutEvent = anyTriplet.Y;

                    if (timeoutEvent != null)
                    {
#if !MONO && !MONO_HACKS && (NET_20_SP2 || NET_40 || NET_STANDARD_20)
                        timeoutEvent.WaitOne(timeout); /* throw */
#else
                        timeoutEvent.WaitOne(timeout, false); /* throw */
#endif
                    }
                    else
                    {
                        HostOps.ThreadSleep(timeout); /* throw */
                    }

                    //
                    // HACK: If the interpreter is now disposed, there is not
                    //       much else we can do now except log that fact.
                    //
                    long oldRequestId = anyTriplet.Z;

                    if (interpreter.InternalDisposed)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "skipping script timeout handling for " +
                            "interpreter {0} old request {1}: disposed " +
                            "after approximately {2} milliseconds",
                            FormatOps.InterpreterNoThrow(interpreter),
                            oldRequestId, timeout),
                            typeof(ScriptTimeoutThread).Name,
                            TracePriority.ScriptError);

                        return;
                    }

                    //
                    // NOTE: If another timeout thread has been started for
                    //       this interpreter since we started waiting, do
                    //       nothing.
                    //
                    if (oldRequestId != 0)
                    {
                        long newRequestId = GetRequestId(interpreter);

                        if ((newRequestId != 0) &&
                            (newRequestId != oldRequestId))
                        {
                            TraceOps.DebugTrace(String.Format(
                                "skipping script timeout handling for " +
                                "interpreter {0}, new request {1} does " +
                                "not match old request {2} after " +
                                "approximately {3} milliseconds",
                                FormatOps.InterpreterNoThrow(interpreter),
                                newRequestId, oldRequestId, timeout),
                                typeof(ScriptTimeoutThread).Name,
                                TracePriority.ThreadDebug5);

                            return;
                        }
                    }

                    //
                    // NOTE: If the interpreter is not busy (on any thread),
                    //       don't bother to do anything else.  In this case,
                    //       the script may have simply run to completion,
                    //       which means there is nothing to cancel.
                    //
                    if (!interpreter.InternalIsGlobalBusy)
                        return;

                    //
                    // NOTE: Create a result for the error message to be used
                    //       when the script is canceled.
                    //
                    Result cancelResult = String.Format(
                        Interpreter.timeoutCancelResultFormat, timeout);

                    //
                    // NOTE: Cancel any scripts in progress now.  This may
                    //       impact more than one user since the interpreter
                    //       is shared; however, that is seen as a necessary
                    //       evil.
                    //
                    // NOTE: Actually, this should now cancel the script on
                    //       the original (parent) thread only, i.e. if the
                    //       engine context is correctly set.
                    //
                    ReturnCode code;
                    Result error = null;

                    code = interpreter.InternalCancelAnyEvaluate(
#if THREADING
                        scriptTimeoutClientData.EngineContext,
#endif
                        cancelResult, CancelFlags.ScriptTimeout,
                        ref error);

                    if (code != ReturnCode.Ok)
                    {
                        TraceOps.DebugTrace(String.Format(
                            "script cancellation for interpreter {0} " +
                            "failed: {1}", FormatOps.InterpreterNoThrow(
                            interpreter), ResultOps.Format(code, error)),
                            typeof(ScriptTimeoutThread).Name,
                            TracePriority.EngineError);
                    }
                }
                catch (ThreadAbortException)
                {
                    Thread.ResetAbort();
                }
                catch (ThreadInterruptedException)
                {
                    // do nothing.
                }
                catch (InterpreterDisposedException)
                {
                    // do nothing.
                }
            }
            #endregion
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IGetInterpreter Members
            /// <summary>
            /// The interpreter associated with this script timeout thread.
            /// </summary>
            private Interpreter interpreter;
            /// <summary>
            /// Gets the interpreter associated with this script timeout thread.
            /// </summary>
            public Interpreter Interpreter
            {
                get { CheckDisposed(); lock (syncRoot) { return interpreter; } }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method starts the script timeout thread.
            /// </summary>
            public void Start() /* throw */
            {
                CheckDisposed();

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (thread != null)
                    {
                        throw new InvalidOperationException(
                            "timeout thread already started");
                    }

                    int localTimeout = ThreadOps.GetTimeout(
                        interpreter, timeout, TimeoutType.Script |
                        TimeoutType.MaybeFallback);

                    if (localTimeout > 0)
                    {
                        if ((requestId == 0) ||
                            SetRequestId(interpreter, requestId))
                        {
                            bool useThreadPool;
                            int maxStackSize;
                            bool userInterface;
                            bool isBackground;
                            bool useActiveStack;

                            ScriptThreadClientData.GetStartParameters(
                                scriptThreadClientData, out useThreadPool,
                                out maxStackSize, out userInterface,
                                out isBackground, out useActiveStack);

                            MaybeSignalEvent();
                            MaybeCloseEvent();
                            MaybeCreateEvent();

                            ScriptTimeoutClientData scriptTimeoutClientData =
                                interpreter.CreateScriptTimeoutClientData(
                                    null, TimeoutFlags.Timeout, null,
                                    localTimeout);

                            ThreadOps.CreateAndOrStart(
                                interpreter, "scriptTimeout", ThreadStart,
                                new TimeoutTriplet(
                                    scriptTimeoutClientData, timeoutEvent,
                                    requestId),
                                useThreadPool, maxStackSize, userInterface,
                                isBackground, useActiveStack, ref thread);
                        }
                        else
                        {
                            throw new ScriptException(
                                "failed to set timeout request Id");
                        }
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method stops the script timeout thread.
            /// </summary>
            public void Stop() /* throw */
            {
                CheckDisposed();

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    //
                    // HACK: If there is no thread instance, we must have used
                    //       a thread-pool thread and the MaybeShutdown method
                    //       is totally useless.  Therefore, signal associated
                    //       interrupt event instead.
                    //
                    if (thread != null)
                    {
                        bool waitOnStop;
                        bool waitOnInterrupt;
                        bool noAbort;

                        ScriptThreadClientData.GetStopParameters(
                            scriptThreadClientData, out waitOnStop,
                            out waitOnInterrupt, out noAbort);

                        ShutdownFlags shutdownFlags = ShutdownFlags.ScriptEvent;

                        if (waitOnStop)
                            shutdownFlags |= ShutdownFlags.WaitBefore;

                        if (waitOnInterrupt)
                            shutdownFlags |= ShutdownFlags.WaitAfter;

                        if (noAbort)
                            shutdownFlags |= ShutdownFlags.NoAbort;

                        ThreadOps.MaybeShutdown(
                            interpreter, null, shutdownFlags, ref thread);
                    }
                    else
                    {
                        //
                        // NOTE: Attempt to wake up thread-pool thread from
                        //       its script timeout wait state.
                        //
                        MaybeSignalEvent();
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources held by this object instance and
            /// suppresses finalization.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(interpreter, null))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptTimeoutThread).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            private /* protected virtual */ void Dispose(
                bool disposing
                )
            {
                TraceOps.DebugTrace(String.Format(
                    "Dispose: called, disposing = {0}, disposed = {1}",
                    disposing, disposed), typeof(ScriptTimeoutThread).Name,
                    TracePriority.CleanupDebug);

                if (!disposed)
                {
                    if (disposing)
                    {
                        ////////////////////////////////////
                        // dispose managed resources here...
                        ////////////////////////////////////

                        lock (syncRoot) /* TRANSACTIONAL */
                        {
                            if (thread != null)
                            {
                                try
                                {
                                    Stop(); /* throw */
                                }
                                catch (Exception e)
                                {
                                    TraceOps.DebugTrace(
                                        e, typeof(ScriptTimeoutThread).Name,
                                        TracePriority.CleanupError);
                                }

                                thread = null;
                            }

                            ////////////////////////////////

                            MaybeCloseEvent();

                            ////////////////////////////////

                            interpreter = null; /* NOT OWNED, DO NOT DISPOSE. */
                        }
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~ScriptTimeoutThread()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ScriptMutableValue Test Class
        /// <summary>
        /// This class implements a mutable container that holds a single object
        /// value, optionally taking ownership of that value so it can be
        /// disposed.  It is used during testing.
        /// </summary>
        [ObjectId("4f837494-d654-4c08-ba84-e00057772972")]
        public class ScriptMutableValue : IDisposable
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="value">
            /// The object value to be contained by this object instance.
            /// </param>
            /// <param name="owned">
            /// Non-zero if the contained value is owned by this object instance and
            /// should be disposed when this object instance is disposed.
            /// </param>
            public ScriptMutableValue(
                object value, /* in */
                bool owned    /* in */
                )
            {
                this.value = value;
                this.owned = owned;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// The object value contained by this object instance.
            /// </summary>
            private object value;
            /// <summary>
            /// Gets or sets the object value contained by this object instance.
            /// </summary>
            public virtual object Value
            {
                get { CheckDisposed(); return this.value; }
                set { CheckDisposed(); this.value = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Non-zero if the contained value is owned by this object instance and
            /// should be disposed when this object instance is disposed.
            /// </summary>
            private bool owned;
            /// <summary>
            /// Gets or sets a value indicating whether the contained value is owned
            /// by this object instance.
            /// </summary>
            public virtual bool Owned
            {
                get { CheckDisposed(); return this.owned; }
                set { CheckDisposed(); this.owned = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Object Overrides
            /// <summary>
            /// This method returns a string representation of this object instance.
            /// </summary>
            /// <returns>
            /// The string representation of this object instance.
            /// </returns>
            public override string ToString()
            {
                CheckDisposed();

                return StringList.MakeList(
                    FormatOps.WrapOrNull(this.Value), this.Owned);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources held by this object instance and
            /// suppresses finalization.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptMutableValue).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected virtual void Dispose(
                bool disposing /* in */
                )
            {
                TraceOps.DebugTrace(String.Format(
                    "Dispose: called, disposing = {0}, disposed = {1}",
                    disposing, disposed), typeof(ScriptMutableValue).Name,
                    TracePriority.CleanupDebug);

                if (!disposed)
                {
                    if (disposing)
                    {
                        ////////////////////////////////////
                        // dispose managed resources here...
                        ////////////////////////////////////

                        if (owned)
                        {
                            ObjectOps.TryDisposeOrComplain<object>(
                                null, ref value);

                            value = null;
                            owned = false;
                        }
                        else
                        {
                            value = null; /* NOT OWNED */
                        }
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~ScriptMutableValue()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ScriptBooleanValue Test Class
        /// <summary>
        /// This class implements a mutable container that holds a nullable
        /// boolean value.  It is used during testing.
        /// </summary>
        [ObjectId("73601e17-4e60-41fd-92dd-7ee2d9f875a7")]
        public sealed class ScriptBooleanValue : ScriptMutableValue
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="value">
            /// The nullable boolean value to be contained by this object instance.
            /// </param>
            public ScriptBooleanValue(
                bool? value /* in */
                )
                : base(value, false)
            {
                // do nothing.
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method retrieves the contained value as a boolean, if it is a
            /// boolean.
            /// </summary>
            /// <param name="value">
            /// Upon success, this parameter will be modified to contain the boolean
            /// value contained by this object instance; otherwise, it is left
            /// unchanged.
            /// </param>
            public void MaybeGetValue(
                ref bool value /* in, out */
                )
            {
                CheckDisposed();

                object localValue = base.Value;

                if (localValue is bool)
                    value = (bool)localValue;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method retrieves the contained value as a nullable boolean, if
            /// it is a nullable boolean.
            /// </summary>
            /// <param name="value">
            /// Upon success, this parameter will be modified to contain the nullable
            /// boolean value contained by this object instance; otherwise, it is
            /// left unchanged.
            /// </param>
            public void MaybeGetNullableValue(
                ref bool? value /* in, out */
                )
            {
                CheckDisposed();

                object localValue = base.Value;

                if (localValue is bool?)
                    value = (bool?)localValue;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(ScriptBooleanValue).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected override void Dispose(
                bool disposing /* in */
                )
            {
                try
                {
                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////
                    }
                }
                finally
                {
                    base.Dispose(disposing);

                    disposed = true;
                }
            }
            #endregion
        }
        #endregion

