        #region StringComparer Test Class
        /// <summary>
        /// This class implements a simple comparer for strings, used during
        /// testing.
        /// </summary>
        [ObjectId("80a09504-c74c-4104-a2bd-ea1c419d0e50")]
        public sealed class StringComparer : IComparer<string>
        {
            #region Private Data
            /// <summary>
            /// The underlying string comparer used to perform comparisons.
            /// </summary>
            private IComparer<string> comparer = null;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public StringComparer()
            {
                comparer = Comparer<string>.Default;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// Gets or sets the underlying string comparer used to perform
            /// comparisons.
            /// </summary>
            public IComparer<string> Comparer
            {
                get { return comparer; }
                set { comparer = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IComparer<string> Members
            /// <summary>
            /// This method compares two strings and returns an indication of their
            /// relative order.
            /// </summary>
            /// <param name="x">
            /// The first string to compare.
            /// </param>
            /// <param name="y">
            /// The second string to compare.
            /// </param>
            /// <returns>
            /// A signed integer that is less than zero, zero, or greater than zero,
            /// indicating whether the first string is less than, equal to, or
            /// greater than the second string.
            /// </returns>
            public int Compare(
                string x,
                string y
                )
            {
                if (comparer == null)
                    throw new ScriptException("invalid string comparer");

                return comparer.Compare(x, y);
            }
            #endregion
        }
        #endregion

