        #region IResolve Test Class
        /// <summary>
        /// This class implements a script-based <see cref="IResolve" /> that
        /// delegates the resolution of variable frames, namespaces, commands,
        /// and variables to a configured script.  It is used during testing.
        /// </summary>
        [ObjectId("c420fccf-69f8-463a-b97b-629d7f7fcd9f")]
        public sealed class Resolve :
#if ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
            ScriptMarshalByRefObject,
#endif
            IResolve
        {
            #region Private Data
            //
            // NOTE: The interpreter where the script should be evaluated in.
            //
            /// <summary>
            /// The interpreter where the script should be evaluated.
            /// </summary>
            private Interpreter sourceInterpreter;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The interpreter where the variable frame, current namespace,
            //           execute, or variable is being resolved.
            //
            /// <summary>
            /// The interpreter where the variable frame, current namespace,
            /// executable entity, or variable is being resolved.
            /// </summary>
            private Interpreter targetInterpreter;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The script to evaluate when this resolver instance is called.
            //
            /// <summary>
            /// The script to evaluate when this resolver instance is called.
            /// </summary>
            private string text;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The call frame to return from the GetVariableFrame method
            //       if the script returns non-zero.
            //
            /// <summary>
            /// The call frame to return from the <c>GetVariableFrame</c> method if
            /// the script returns non-zero.
            /// </summary>
            private ICallFrame frame;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The namespace to return from the GetCurrentNamespace method
            //       if the script returns non-zero.
            //
            /// <summary>
            /// The namespace to return from the <c>GetCurrentNamespace</c> method if
            /// the script returns non-zero.
            /// </summary>
            private INamespace @namespace;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The command to return from the GetIExecute method if the
            //       script returns non-zero.
            //
            /// <summary>
            /// The command to return from the <c>GetIExecute</c> method if the
            /// script returns non-zero.
            /// </summary>
            private IExecute execute;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The variable to return from the GetVariable method if the
            //       script returns non-zero.
            //
            /// <summary>
            /// The variable to return from the <c>GetVariable</c> method if the
            /// script returns non-zero.
            /// </summary>
            private IVariable variable;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: These are flags that control the behavior of the various
            //       IResolve methods of this class.
            //
            /// <summary>
            /// The flags that control the behavior of the various
            /// <see cref="IResolve" /> methods of this class.
            /// </summary>
            private TestResolveFlags testResolveFlags;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: Keeps track of the number of times each IResolve method
            //       has been called.
            //
            /// <summary>
            /// The number of times each <see cref="IResolve" /> method has been
            /// called, indexed by method.
            /// </summary>
            private readonly int[] methodInvokeCounts = {
                0, /* GetVariableFrame */
                0, /* GetCurrentNamespace */
                0, /* GetIExecute */
                0  /* GetVariable */
            };
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="sourceInterpreter">
            /// The interpreter where the script should be evaluated.
            /// </param>
            /// <param name="targetInterpreter">
            /// The interpreter where the entity is being resolved.
            /// </param>
            /// <param name="text">
            /// The script to evaluate when this resolver instance is called.
            /// </param>
            /// <param name="frame">
            /// The call frame to return when resolving a variable frame.
            /// </param>
            /// <param name="namespace">
            /// The namespace to return when resolving the current namespace.
            /// </param>
            /// <param name="execute">
            /// The command to return when resolving an executable entity.
            /// </param>
            /// <param name="variable">
            /// The variable to return when resolving a variable.
            /// </param>
            /// <param name="testResolveFlags">
            /// The flags that control the behavior of the various
            /// <see cref="IResolve" /> methods of this class.
            /// </param>
            public Resolve(
                Interpreter sourceInterpreter,
                Interpreter targetInterpreter,
                string text,
                ICallFrame frame,
                INamespace @namespace,
                IExecute execute,
                IVariable variable,
                TestResolveFlags testResolveFlags
                )
            {
                this.sourceInterpreter = sourceInterpreter;
                this.targetInterpreter = targetInterpreter;
                this.text = text;
                this.frame = frame;
                this.@namespace = @namespace;
                this.execute = execute;
                this.variable = variable;
                this.testResolveFlags = testResolveFlags;
            }
            #endregion

