            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method returns the configured call frame to use when resolving a
            /// variable frame, taking the namespace frame options into account.
            /// </summary>
            /// <returns>
            /// The configured call frame, or null if none is available.
            /// </returns>
            private ICallFrame GetVariableFrame()
            {
                if (frame != null)
                    return frame;

                if (FlagOps.HasFlags(
                        testResolveFlags, TestResolveFlags.AlwaysUseNamespaceFrame,
                        true))
                {
                    if (@namespace != null)
                        return @namespace.VariableFrame;
                }
                else if (FlagOps.HasFlags(
                        testResolveFlags, TestResolveFlags.NextUseNamespaceFrame,
                        true))
                {
                    /* ONE SHOT */
                    testResolveFlags &= ~TestResolveFlags.NextUseNamespaceFrame;

                    if (@namespace != null)
                        return @namespace.VariableFrame;
                }

                return null;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: For use by the IResolve.GetCurrentNamespace method only.
            //
            /// <summary>
            /// This method returns the configured namespace to use when resolving
            /// the current namespace.
            /// </summary>
            /// <returns>
            /// The configured namespace, or null if none is available.
            /// </returns>
            private INamespace GetCurrentNamespace()
            {
                testResolveFlags &= ~TestResolveFlags.NextUseNamespaceFrame;

                return @namespace;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Object Overrides
            /// <summary>
            /// This method returns a string representation of this object instance.
            /// </summary>
            /// <returns>
            /// The string representation of this object instance.
            /// </returns>
            public override string ToString()
            {
                StringList list = new StringList();

                for (int index = 0; index < methodInvokeCounts.Length; index++)
                    list.Add(methodInvokeCounts[index].ToString());

                return list.ToString();
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Automatic Commands Test Class
        /// <summary>
        /// This class implements an object exposing a variety of static and
        /// instance members, each marked with differing command flags, used to
        /// exercise automatic object command creation and member access during
        /// testing.
        /// </summary>
        [ObjectId("d47ad977-fd77-488a-91f7-d28650172c12")]
        public sealed class Automatic :
#if ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
            ScriptMarshalByRefObject,
#endif
            IMaybeDisposed, IDisposable
        {
            #region Private Constants
            /// <summary>
            /// The value flags used when converting a string argument to an integer.
            /// </summary>
            private const ValueFlags IntegerValueFlags =
                ValueFlags.AnyInteger | ValueFlags.WidenToUnsigned;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Static Data
            /// <summary>
            /// The number of times an instance of this class has been created.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long createCount;

            /// <summary>
            /// The number of times an instance member of this class has been
            /// accessed.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long instanceCount;

            /// <summary>
            /// The number of times a static member of this class has been accessed.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long staticCount;

            /// <summary>
            /// The number of times the <see cref="Dispose()" /> method has been
            /// called.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long dispose0Count;

            /// <summary>
            /// The number of times managed resources have been disposed.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long significantDispose1Count;

            /// <summary>
            /// The number of times unmanaged resources have been released.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long significantRelease1Count;

            /// <summary>
            /// The number of times disposal of managed resources was skipped because
            /// this object instance was already disposed.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long redundantDispose1Count;

            /// <summary>
            /// The number of times release of unmanaged resources was skipped
            /// because this object instance was already disposed.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long redundantRelease1Count;

            /// <summary>
            /// The number of times the destructor of this class has been called.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long destroyCount;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// A static field marked with neutral command flags.
            /// </summary>
            [CommandFlags(CommandFlags.None)]
            private static long neutralStaticField = 1;

            /// <summary>
            /// A static field marked with safe command flags.
            /// </summary>
            [CommandFlags(CommandFlags.Safe)]
            private static long safeStaticField = 2;

            /// <summary>
            /// A static field marked with unsafe command flags.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private static long unsafeStaticField = 3;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// Non-zero if this object instance is currently being disposed.
            /// </summary>
            private bool disposing;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// An instance field marked with neutral command flags.
            /// </summary>
            [CommandFlags(CommandFlags.None)]
            private long neutralInstanceField = 4;

            /// <summary>
            /// An instance field marked with safe command flags.
            /// </summary>
            [CommandFlags(CommandFlags.Safe)]
            private long safeInstanceField = 5;

            /// <summary>
            /// An instance field marked with unsafe command flags.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            private long unsafeInstanceField = 6;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            [CommandFlags(CommandFlags.Unsafe)]
            public Automatic()
            {
                Interlocked.Increment(ref createCount);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Static Methods
            /// <summary>
            /// This method creates a new instance of this class.
            /// </summary>
            /// <returns>
            /// The newly created object instance.
            /// </returns>
            [CommandFlags(CommandFlags.Safe)]
            public static object Create()
            {
                Interlocked.Increment(ref staticCount);

                return new Automatic();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method invokes a static operation marked with neutral command
            /// flags.
            /// </summary>
            /// <returns>
            /// The resulting value.
            /// </returns>
            [CommandFlags(CommandFlags.None)]
            public static long NeutralStaticMethod()
            {
                Interlocked.Increment(ref staticCount);

                return Interlocked.Increment(
                    ref neutralStaticField);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method invokes a static operation marked with neutral command
            /// flags.
            /// </summary>
            /// <param name="intValue">
            /// The integer value to use.
            /// </param>
            /// <returns>
            /// The resulting value.
            /// </returns>
            [CommandFlags(CommandFlags.None)]
            public static long NeutralStaticMethod(
                int intValue /* in */
                )
            {
                Interlocked.Increment(ref staticCount);

                return Interlocked.Add(
                    ref neutralStaticField, intValue);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method invokes a static operation marked with neutral command
            /// flags.
            /// </summary>
            /// <param name="stringValue">
            /// The string value to use, which must be convertible to an integer.
            /// </param>
            /// <returns>
            /// The resulting value.
            /// </returns>
            [CommandFlags(CommandFlags.None)]
            public static long NeutralStaticMethod(
                string stringValue /* in */
                )
            {
                Interlocked.Increment(ref staticCount);

                int intValue = 0;
                Result error = null;

                if (Value.GetInteger2(
                        stringValue, IntegerValueFlags, null,
                        ref intValue, ref error) != ReturnCode.Ok)
                {
                    throw new ScriptException(error);
                }

                return NeutralStaticMethod(intValue);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method invokes a static operation marked with neutral command
            /// flags.
            /// </summary>
            /// <param name="intValue">
            /// The integer value to use.
            /// </param>
            /// <param name="stringValue">
            /// The string value to use, which must be convertible to an integer.
            /// </param>
            /// <returns>
            /// The resulting value.
            /// </returns>
            [CommandFlags(CommandFlags.None)]
            public static long NeutralStaticMethod(
                int intValue,      /* in */
                string stringValue /* in */
                )
            {
                Interlocked.Increment(ref staticCount);

                return NeutralStaticMethod(intValue) +
                    NeutralStaticMethod(stringValue);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method invokes a static operation marked with safe command
            /// flags.
            /// </summary>
            /// <returns>
            /// The resulting value.
            /// </returns>
            [CommandFlags(CommandFlags.Safe)]
            public static long SafeStaticMethod()
            {
                Interlocked.Increment(ref staticCount);

                return Interlocked.Increment(
                    ref safeStaticField);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method invokes a static operation marked with safe command
            /// flags.
            /// </summary>
            /// <param name="intValue">
            /// The integer value to use.
            /// </param>
            /// <returns>
            /// The resulting value.
            /// </returns>
            [CommandFlags(CommandFlags.Safe)]
            public static long SafeStaticMethod(
                int intValue /* in */
                )
            {
                Interlocked.Increment(ref staticCount);

                return Interlocked.Add(
                    ref safeStaticField, intValue);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method invokes a static operation marked with safe command
            /// flags.
            /// </summary>
            /// <param name="stringValue">
            /// The string value to use, which must be convertible to an integer.
            /// </param>
            /// <returns>
            /// The resulting value.
            /// </returns>
            [CommandFlags(CommandFlags.Safe)]
            public static long SafeStaticMethod(
