        #region ICommand Test Class
        /// <summary>
        /// This class implements a script-based <see cref="ICommand" /> that, when
        /// executed, evaluates a configured script command or dispatches to a
        /// configured executable entity.  It is used during testing.
        /// </summary>
        [CommandFlags(CommandFlags.NoPopulate | CommandFlags.NoAdd)]
        [ObjectId("36efb842-527f-4ffa-8978-adc3c8fdce99")]
        public sealed class Command : ICommand
        {
            #region Private Data
            //
            // NOTE: The script command to evaluate when this command instance
            //       is executed (this only applies if the "useIExecute" flag
            //       is false).
            //
            /// <summary>
            /// The script command to evaluate when this command instance is executed
            /// (this only applies when the executable entity is not used).
            /// </summary>
            private StringList scriptCommand;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
