            /// executed (this only applies when the executable entity is used).
            /// </summary>
            private IExecute execute;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, the IExecute will be used instead
            //       of the script command.
            //
            /// <summary>
            /// When non-zero, the executable entity will be used instead of the
            /// script command.
            /// </summary>
            private bool useIExecute;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, the arguments to the command
            //       will be appended to the script command to be evaluated
            //       (this only applies if the "useIExecute" flag is false).
            //
            /// <summary>
            /// When non-zero, the arguments to the command will be appended to the
            /// script command to be evaluated (this only applies when the executable
            /// entity is not used).
            /// </summary>
            private bool useExecuteArguments;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, the arguments containing the name
            //       of the command will not be added to the final list of
            //       arguments to the script command.
            //
            /// <summary>
            /// When non-zero, the argument containing the name of the command will
            /// not be added to the final list of arguments to the script command.
            /// </summary>
            private bool skipNameArguments;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, there can be no extra arguments to
            //       the command beyond the name of the command.
            //
            /// <summary>
            /// When non-zero, there can be no extra arguments to the command beyond
            /// the name of the command.
            /// </summary>
            private bool strictNoArguments;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: This keeps track of the number of times the Execute method
            //       of this class handles a command.  This value starts at zero,
            //       is always incremented, and never reset.
            //
            /// <summary>
            /// The number of times the <see cref="Execute" /> method of this class
            /// has handled a command.  This value starts at zero, is always
            /// incremented, and is never reset.
            /// </summary>
            private int executeCount;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="name">
            /// The name of the command.
            /// </param>
            /// <param name="plugin">
            /// The plugin that owns the command, if any.
            /// </param>
            /// <param name="callback">
            /// The execution callback associated with the command, if any.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with the command, if any.
            /// </param>
            /// <param name="commandFlags">
            /// The command flags associated with the command.
            /// </param>
            /// <param name="scriptCommand">
            /// The script command to evaluate when the command is executed.
            /// </param>
            /// <param name="execute">
            /// The executable entity to execute when the command is executed.
            /// </param>
            /// <param name="useIExecute">
            /// Non-zero to use the executable entity instead of the script command.
            /// </param>
            /// <param name="strictNoArguments">
            /// Non-zero to disallow any arguments beyond the name of the command.
            /// </param>
            /// <param name="useExecuteArguments">
            /// Non-zero to append the arguments to the command to the script command
            /// to be evaluated.
            /// </param>
            /// <param name="skipNameArguments">
            /// Non-zero to omit the argument containing the name of the command from
            /// the final list of arguments to the script command.
            /// </param>
            public Command(
                string name,
                IPlugin plugin,
                ExecuteCallback callback,
                IClientData clientData,
                CommandFlags commandFlags,
                StringList scriptCommand,
                IExecute execute,
                bool useIExecute,
                bool strictNoArguments,
                bool useExecuteArguments,
                bool skipNameArguments
                )
            {
                this.name = name;
                this.plugin = plugin;
                this.callback = callback;
                this.clientData = clientData;
                this.commandFlags = commandFlags;
                this.scriptCommand = scriptCommand;
                this.execute = execute;
                this.useIExecute = useIExecute;
                this.strictNoArguments = strictNoArguments;
                this.useExecuteArguments = useExecuteArguments;
                this.skipNameArguments = skipNameArguments;
                this.executeCount = 0;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method returns the name of this command.
            /// </summary>
            /// <returns>
            /// The name of this command.
            /// </returns>
            private string GetCommandName()
            {
                return this.Name;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether this command is allowed to be used
            /// with arguments beyond the name of the command.
            /// </summary>
            /// <param name="arguments">
            /// The arguments to the command.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the command is allowed to be used with the specified
            /// arguments; otherwise, false.
            /// </returns>
            private bool AllowedToUseArguments(
                ArgumentList arguments,
                ref Result error
                )
            {
                if (!strictNoArguments)
                    return true;

                int nameIndex = 0; /* NOTE: Compat: Tcl */
                int nextIndex = nameIndex + 1;

                if ((arguments == null) || (arguments.Count <= nextIndex))
                    return true;

                error = String.Format(
                    "wrong # args: should be \"{0}\"", GetCommandName());

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the arguments to pass when evaluating the script
            /// command.
            /// </summary>
            /// <param name="arguments">
            /// The arguments to the command.
            /// </param>
            /// <returns>
            /// The arguments to use, or null if the arguments should not be used.
            /// </returns>
            private ArgumentList GetArgumentsForExecute(
                ArgumentList arguments
                )
            {
                return useExecuteArguments ? arguments : null;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the index of the first argument to use when
            /// evaluating the script command.
            /// </summary>
            /// <param name="arguments">
            /// The arguments to the command.
            /// </param>
            /// <returns>
            /// The index of the first argument to use.
            /// </returns>
            private int GetStartIndexForArguments(
                ArgumentList arguments
                )
            {
                if (!skipNameArguments)
                    return 0;

                int nameIndex = 0; /* NOTE: Compat: Tcl */
                int nextIndex = nameIndex + 1;

                if ((arguments == null) || (arguments.Count < nextIndex))
                    return 0;

                return nextIndex;
            }
            #endregion

