            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecute Members
            /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
            /// <summary>
            /// This method executes this command, dispatching to either the
            /// configured executable entity or the configured script command.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the command is being executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this command, if any.
            /// </param>
            /// <param name="arguments">
            /// The arguments to the command, including the command name.
            /// </param>
            /// <param name="result">
            /// Upon success, this parameter will contain the result produced by the
            /// command; upon failure, it will contain an appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public ReturnCode Execute(
                Interpreter interpreter,
                IClientData clientData,
                ArgumentList arguments,
                ref Result result
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (arguments == null)
                {
                    result = "invalid argument list";
                    return ReturnCode.Error;
                }

                int nameIndex = 0; /* NOTE: Compat: Tcl */
                int nextIndex = nameIndex + 1;

                if (arguments.Count < nextIndex)
                {
                    result = String.Format(
                        "wrong # args: should be \"{0} ?arg ...?\"",
                        GetCommandName());

                    return ReturnCode.Error;
                }

                //
                // NOTE: Does this command accept arguments beyond the
                //       name of the command?
                //
                if (!AllowedToUseArguments(arguments, ref result))
                    return ReturnCode.Error;

                Interlocked.Increment(ref executeCount);

                if (useIExecute)
                {
                    //
                    // NOTE: Re-dispatch to the configured IExecute
                    //       instance and return its results verbatim.
                    //
                    string commandName = EntityOps.GetName(
                        execute as IIdentifierName);

                    if (commandName == null)
                        commandName = arguments[nameIndex];

                    return interpreter.Execute(
                        commandName, execute, clientData, arguments,
                        ref result);
                }
                else
                {
                    //
                    // NOTE: Evaluate the configured script command, maybe
                    //       adding all the local arguments, and return the
                    //       results verbatim.
                    //
                    string name = StringList.MakeList(GetCommandName());

                    ICallFrame frame = interpreter.NewTrackingCallFrame(name,
                        CallFrameFlags.Evaluate | CallFrameFlags.Test |
                        CallFrameFlags.Command);

                    interpreter.PushAutomaticCallFrame(frame);

                    ReturnCode code = interpreter.EvaluateScript(
                        ScriptOps.GetArgumentsForExecute(this,
                        scriptCommand, GetArgumentsForExecute(arguments),
                        GetStartIndexForArguments(arguments)), 0, ref result);

                    if (code == ReturnCode.Error)
                    {
                        /* IGNORED */
                        Engine.AddErrorInformation(interpreter, result,
                            String.Format("{0}    (\"{1}\" body line {2})",
                                Environment.NewLine, GetCommandName(),
                                Interpreter.GetErrorLine(interpreter)));
                    }

                    //
                    // NOTE: Pop the original call frame that we pushed above and
                    //       any intervening scope call frames that may be leftover
                    //       (i.e. they were not explicitly closed).
                    //
                    /* IGNORED */
                    interpreter.PopScopeCallFramesAndOneMore();
                    return code;
                }
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Unsupported Commands Test Class
        /// <summary>
        /// This class implements a command that exposes a collection of
        /// unsupported, non-standard sub-commands used to exercise various
        /// internal interpreter behaviors during testing.
        /// </summary>
        [CommandFlags(
            CommandFlags.Unsafe | CommandFlags.NonStandard |
            CommandFlags.NoPopulate | CommandFlags.NoAdd
        )]
        [ObjectId("4dce989d-fa4d-4458-b8b0-f0e78709549b")]
        [ObjectGroup("test")]
        private sealed class Unsupported : _Commands.Core
        {
            #region Private Data
            //
            // HACK: Which thread, if any, currently holds the lock?
            //
            /// <summary>
            /// The identifier of the thread that currently holds the lock, or
            /// zero if no thread currently holds the lock.
            /// </summary>
            private long lockThreadId = 0;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="commandData">
            /// The command data used to populate the new instance.  This
            /// parameter may be null.
            /// </param>
            public Unsupported(
                ICommandData commandData /* in */
                )
                : base(commandData)
            {
                // do nothing.
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IEnsemble Members
            /// <summary>
            /// The collection of sub-commands supported by this command.
            /// </summary>
            private readonly EnsembleDictionary subCommands =
                new EnsembleDictionary(new string[] {
                "evaluateWithLock", "evaluateWithTimedLock",
                "evaluateWithUnset", "evaluateWithoutEvents",
                "getVariableValueOrDefault", "setCallerVariableValue"
            });

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the collection of sub-commands supported by this command.
            /// </summary>
            public override EnsembleDictionary SubCommands
            {
                get { return subCommands; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Static Methods
            /// <summary>
            /// This method gets the synchronization object associated with the
            /// specified opaque object instance, if any.
            /// </summary>
            /// <param name="object">
            /// The opaque object instance whose value is used as the
            /// synchronization object.  This parameter may be null.
            /// </param>
            /// <returns>
            /// The synchronization object, or null if it is not available.
            /// </returns>
            private static object GetSyncRoot(
                IObject @object /* in: OPTIONAL */
                )
            {
                return (@object != null) ? @object.Value : null;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            #region Threading Cooperative Locking Diagnostic Methods
            /// <summary>
            /// This method gets the identifier of the thread that currently
            /// holds the lock, if any.
            /// </summary>
            /// <returns>
            /// The identifier of the thread that currently holds the lock, or
            /// zero if no thread currently holds the lock.
            /// </returns>
            private long MaybeWhoHasLock()
            {
                return Interlocked.CompareExchange(ref lockThreadId, 0, 0);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method records the current thread as the holder of the lock
            /// when the lock has been acquired.
            /// </summary>
            /// <param name="locked">
            /// Non-zero if the lock has been acquired by the current thread.
            /// </param>
            private void MaybeSomebodyHasLock(
                bool locked /* in */
                )
            {
                if (locked)
                {
                    /* IGNORED */
                    Interlocked.CompareExchange(ref lockThreadId,
                        GlobalState.GetCurrentLockThreadId(), 0);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method clears the record of the current thread as the holder
            /// of the lock when the lock has been released.
            /// </summary>
            /// <param name="locked">
            /// Non-zero if the lock was previously acquired by the current
            /// thread.
            /// </param>
            private void MaybeNobodyHasLock(
                bool locked /* in */
                )
            {
                if (locked)
                {
                    /* IGNORED */
                    Interlocked.CompareExchange(ref lockThreadId,
                        0, GlobalState.GetCurrentLockThreadId());
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Threading Cooperative Locking Methods
            /// <summary>
            /// This method attempts to acquire the lock on the specified
            /// synchronization object without blocking.
            /// </summary>
            /// <param name="syncRoot">
            /// The synchronization object to lock.  This parameter may be null,
            /// in which case nothing is done.
            /// </param>
            /// <param name="locked">
            /// Upon success, this parameter is set to non-zero if the lock was
            /// acquired by the current thread.
            /// </param>
            private void TryLock(
                object syncRoot, /* in */
                ref bool locked  /* out */
                )
            {
                if (syncRoot == null)
                    return;

                locked = Monitor.TryEnter(syncRoot);
                MaybeSomebodyHasLock(locked);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method attempts to acquire the lock on the specified
            /// synchronization object, waiting up to the specified timeout.
            /// </summary>
            /// <param name="syncRoot">
            /// The synchronization object to lock.  This parameter may be null,
            /// in which case nothing is done.
            /// </param>
            /// <param name="timeout">
            /// The maximum number of milliseconds to wait for the lock.
            /// </param>
            /// <param name="locked">
            /// Upon success, this parameter is set to non-zero if the lock was
            /// acquired by the current thread.
            /// </param>
            private void TryLock(
                object syncRoot, /* in */
                int timeout,     /* in */
                ref bool locked  /* out */
                )
            {
                if (syncRoot == null)
                    return;

                locked = Monitor.TryEnter(syncRoot, timeout);
                MaybeSomebodyHasLock(locked);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the lock on the specified synchronization
            /// object when it has been acquired.
            /// </summary>
            /// <param name="syncRoot">
            /// The synchronization object to unlock.  This parameter may be
            /// null, in which case nothing is done.
            /// </param>
            /// <param name="locked">
            /// On input, non-zero if the lock has been acquired by the current
            /// thread.  Upon return, this parameter is set to zero if the lock
            /// was released.
            /// </param>
            private void ExitLock(
                object syncRoot, /* in */
                ref bool locked  /* in, out */
                )
            {
                if (syncRoot == null)
                    return;

                if (locked)
                {
                    MaybeNobodyHasLock(locked);
                    Monitor.Exit(syncRoot);
                    locked = false;
                }
            }
            #endregion
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecute Members
            /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
            /// <summary>
            /// This method executes one of the unsupported test sub-commands
            /// supported by this command.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the command is being executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this command, if any.
            /// </param>
            /// <param name="arguments">
            /// The arguments to the command, including the sub-command name.
            /// </param>
            /// <param name="result">
            /// Upon success, this parameter will contain the result produced by
            /// the sub-command; upon failure, it will contain an appropriate
            /// error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public override ReturnCode Execute(
                Interpreter interpreter, /* in */
                IClientData clientData,  /* in */
                ArgumentList arguments,  /* in */
                ref Result result        /* out */
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (arguments == null)
                {
                    result = "invalid argument list";
                    return ReturnCode.Error;
                }

                int argumentCount = arguments.Count;

                if (argumentCount < 2)
                {
                    result = String.Format(
                        "wrong # args: should be \"{0} option ?arg ...?\"",
                        this.Name);

                    return ReturnCode.Error;
                }

                ReturnCode code;
                string subCommand = arguments[1];
                bool tried = false;

                code = ScriptOps.TryExecuteSubCommandFromEnsemble(
                    interpreter, this, clientData, arguments, false,
                    null, ref subCommand, ref tried, ref result);

                if ((code != ReturnCode.Ok) || tried)
                    goto done;

                Result error; /* REUSED */

                switch (subCommand)
                {
                    case "evaluateWithLock":
                        {
                            if (argumentCount == 4)
                            {
                                IObject @object = null;

                                if (interpreter.GetObject(
                                        arguments[2], LookupFlags.Default,
                                        ref @object, ref result) != ReturnCode.Ok)
                                {
                                    code = ReturnCode.Error;
                                    goto done;
                                }

                                object syncRoot = GetSyncRoot(@object);
                                bool locked = false;

                                if (syncRoot != null)
                                {
                                    try
                                    {
                                        TryLock(syncRoot,
                                            ref locked); /* TRANSACTIONAL */

                                        if (locked)
                                        {
                                            code = interpreter.EvaluateScript(
                                                arguments[3], ref result);
                                        }
                                        else
                                        {
                                            TraceOps.LockTrace(
                                                "Execute",
                                                typeof(Unsupported).Name, false,
                                                TracePriority.LockError3,
                                                MaybeWhoHasLock());

                                            result = "could not lock object";
                                            code = ReturnCode.Error;
                                        }
                                    }
                                    finally
                                    {
                                        ExitLock(syncRoot,
                                            ref locked); /* TRANSACTIONAL */
                                    }
                                }
                                else
                                {
                                    try
                                    {
                                        interpreter.InternalSoftTryLock(
                                            ref locked); /* TRANSACTIONAL */

                                        if (locked)
                                        {
                                            code = interpreter.EvaluateScript(
                                                arguments[3], ref result);
                                        }
                                        else
                                        {
                                            TraceOps.LockTrace(
                                                "Execute",
                                                typeof(Unsupported).Name, false,
                                                TracePriority.LockError3,
                                                MaybeWhoHasLock());

                                            result = "could not lock interpreter";
                                            code = ReturnCode.Error;
                                        }
                                    }
                                    finally
                                    {
                                        interpreter.InternalExitLock(
                                            ref locked); /* TRANSACTIONAL */
                                    }
                                }
                            }
                            else
                            {
                                result = String.Format(
                                    "wrong # args: should be \"{0} {1} object script\"",
                                    this.Name, subCommand);

                                code = ReturnCode.Error;
                            }
                            break;
                        }
                    case "evaluateWithTimedLock":
                        {
                            if (argumentCount == 5)
                            {
                                IObject @object = null;

                                if (interpreter.GetObject(
                                        arguments[2], LookupFlags.Default,
                                        ref @object, ref result) != ReturnCode.Ok)
                                {
                                    code = ReturnCode.Error;
                                    goto done;
                                }

                                int? timeout = null;

                                if (Value.GetNullableInteger2(
                                        arguments[3], ValueFlags.AnyInteger,
                                        interpreter.InternalCultureInfo,
                                        ref timeout, ref result) != ReturnCode.Ok)
                                {
                                    code = ReturnCode.Error;
                                    goto done;
                                }

                                if (timeout == null)
                                {
                                    timeout = interpreter.GetTimeout(
                                        TimeoutType.Script, ref result);
                                }

                                object syncRoot = GetSyncRoot(@object);
                                bool locked = false;

                                if (syncRoot != null)
                                {
                                    try
                                    {
                                        TryLock(syncRoot, (int)timeout,
                                            ref locked); /* TRANSACTIONAL */

                                        if (locked)
                                        {
                                            code = interpreter.EvaluateScript(
                                                arguments[4], ref result);
                                        }
                                        else
                                        {
                                            TraceOps.LockTrace(
                                                "Execute",
                                                typeof(Unsupported).Name, false,
                                                TracePriority.LockError3,
                                                MaybeWhoHasLock());

                                            result = "could not lock object";
                                            code = ReturnCode.Error;
                                        }
                                    }
                                    finally
                                    {
                                        ExitLock(syncRoot,
                                            ref locked); /* TRANSACTIONAL */
                                    }
                                }
                                else
                                {
                                    try
                                    {
                                        interpreter.InternalTryLock((int)timeout,
                                            ref locked); /* TRANSACTIONAL */

                                        if (locked)
                                        {
                                            code = interpreter.EvaluateScript(
                                                arguments[4], ref result);
                                        }
                                        else
                                        {
                                            TraceOps.LockTrace(
                                                "Execute",
                                                typeof(Unsupported).Name, false,
                                                TracePriority.LockError3,
                                                MaybeWhoHasLock());

                                            result = "could not lock interpreter";
                                            code = ReturnCode.Error;
                                        }
                                    }
                                    finally
                                    {
                                        interpreter.InternalExitLock(
                                            ref locked); /* TRANSACTIONAL */
                                    }
                                }
                            }
                            else
                            {
                                result = String.Format(
                                    "wrong # args: should be \"{0} {1} object timeout script\"",
                                    this.Name, subCommand);

                                code = ReturnCode.Error;
                            }
                            break;
                        }
                    case "evaluateWithUnset":
                        {
                            if (argumentCount >= 3)
                            {
                                ObjectDictionary dictionary = null;

                                if (argumentCount >= 4)
                                {
                                    dictionary = new ObjectDictionary();

                                    for (int argumentIndex = 3;
                                            argumentIndex < argumentCount;
                                            argumentIndex++)
                                    {
                                        string varName = arguments[argumentIndex];

                                        if (varName == null)
                                            continue;

                                        dictionary[varName] = null;
                                    }
                                }

                                VariableFlags variableFlags = VariableFlags.NoComplain;

                                try
                                {
                                    code = interpreter.EvaluateScript(
                                        arguments[2], ref result);

                                    if (code == ReturnCode.Ok)
                                        variableFlags |= VariableFlags.Success;
                                }
                                finally
                                {
                                    if (dictionary != null)
                                    {
                                        int unsetOk = 0;

                                        error = null;

                                        if (interpreter.UnsetVariables(
                                                variableFlags, dictionary,
                                                false, ref unsetOk,
                                                ref error) == ReturnCode.Ok)
                                        {
                                            TraceOps.DebugTrace(String.Format(
                                                "UnsetVariables: unsetOk = {0}",
                                                unsetOk), typeof(Unsupported).Name,
                                                TracePriority.CleanupDebug2);
                                        }
                                        else
                                        {
                                            TraceOps.DebugTrace(String.Format(
                                                "UnsetVariables: error = {0}",
                                                FormatOps.WrapOrNull(error)),
                                                typeof(Unsupported).Name,
                                                TracePriority.CleanupError);
                                        }
                                    }
                                }
                            }
                            else
                            {
                                result = String.Format(
                                    "wrong # args: should be \"{0} {1} script ?varName ...?\"",
                                    this.Name, subCommand);

                                code = ReturnCode.Error;
                            }
                            break;
                        }
                    case "evaluateWithoutEvents":
                        {
                            if (argumentCount == 3)
                            {
                                IEventManager eventManager = interpreter.EventManager;

                                if (!EventOps.ManagerIsOk(eventManager))
                                {
                                    result = "event manager not available";
                                    code = ReturnCode.Error;

                                    goto done;
                                }

                                bool savedEnabled = eventManager.Enabled;

                                try
                                {
                                    eventManager.Enabled = false;

                                    code = interpreter.EvaluateScript(
                                        arguments[2], ref result);
                                }
                                finally
                                {
                                    eventManager.Enabled = savedEnabled;
                                }
                            }
                            else
                            {
                                result = String.Format(
                                    "wrong # args: should be \"{0} {1} script\"",
                                    this.Name, subCommand);

                                code = ReturnCode.Error;
                            }
                            break;
                        }
                    case "getVariableValueOrDefault":
                        {
                            if ((argumentCount >= 4) && (argumentCount <= 5))
                            {
                                string existsVarName = null;

                                if (argumentCount == 5)
                                {
                                    existsVarName = arguments[4];

                                    if (String.IsNullOrEmpty(existsVarName))
                                        existsVarName = null;
                                }

                                lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
                                {
                                    Result value = null;

                                    error = null; /* NOT USED */

                                    if (interpreter.GetVariableValue(
                                            arguments[2], ref value,
                                            ref error) == ReturnCode.Ok)
                                    {
                                        if ((existsVarName != null) &&
                                            (interpreter.SetVariableValue(
                                                existsVarName, true.ToString(),
                                                ref result) != ReturnCode.Ok))
                                        {
                                            code = ReturnCode.Error;
                                            goto done;
                                        }

                                        result = value;
                                    }
                                    else
                                    {
                                        if ((existsVarName != null) &&
                                            (interpreter.SetVariableValue(
                                                existsVarName, false.ToString(),
                                                ref result) != ReturnCode.Ok))
                                        {
                                            code = ReturnCode.Error;
                                            goto done;
                                        }

                                        result = arguments[3];
                                    }
                                }
                            }
                            else
                            {
                                result = String.Format(
                                    "wrong # args: should be \"{0} {1} valueVarName defaultValue ?existsVarName?\"",
                                    this.Name, subCommand);

                                code = ReturnCode.Error;
                            }
                            break;
                        }
                    case "setCallerVariableValue":
                        {
                            if (argumentCount == 4)
                            {
                                string varName = arguments[2];

                                if (String.IsNullOrEmpty(varName))
                                    varName = null;

                                if (varName != null)
                                {
                                    lock (interpreter.InternalSyncRoot) /* TRANSACTIONAL */
                                    {
                                        FrameResult frameResult;
                                        ICallFrame frame = null;

                                        frameResult = interpreter.GetCallFrame(
                                            1.ToString(), ref frame, ref result);

                                        if (frameResult != FrameResult.Invalid)
                                        {
                                            code = interpreter.SetVariableValue2(
                                                VariableFlags.None, frame, varName,
                                                arguments[3], ref result);
                                        }
                                        else
                                        {
                                            code = ReturnCode.Error;
                                        }
                                    }
                                }
                            }
                            else
                            {
                                result = String.Format(
                                    "wrong # args: should be \"{0} {1} varName varValue\"",
                                    this.Name, subCommand);

                                code = ReturnCode.Error;
                            }
                            break;
                        }
                    default:
                        {
                            result = ScriptOps.BadSubCommand(
                                interpreter, null, null,
                                subCommand, this, null, null);

                            code = ReturnCode.Error;
                            break;
                        }
                }

            done:

                return code;
            }
            #endregion
        }
        #endregion

