        #region IEnsemble Test Class
        /// <summary>
        /// This class implements a minimal <see cref="IExecute" /> that also
        /// exposes a collection of sub-commands, used to exercise the
        /// <see cref="IEnsemble" /> interface during testing.
        /// </summary>
        [ObjectId("bd7f00ed-3621-4fde-985c-e55d09ece914")]
        public sealed class Ensemble : IExecute, IEnsemble
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class with an empty collection of
            /// sub-commands.
            /// </summary>
            public Ensemble()
            {
                this.subCommands = new EnsembleDictionary();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class using the specified
            /// collection of sub-command names.
            /// </summary>
            /// <param name="collection">
            /// The collection of sub-command names to add.  This parameter may
            /// be null.
            /// </param>
            public Ensemble(
                IEnumerable<string> collection
                )
            {
                AddSubCommands(collection);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class using the specified
            /// sub-command names.
            /// </summary>
            /// <param name="args">
            /// The sub-command names to add.
            /// </param>
            public Ensemble(
                params string[] args
                )
            {
                AddSubCommands(args);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method adds the specified collection of sub-command names to
            /// the collection of sub-commands.
            /// </summary>
            /// <param name="collection">
            /// The collection of sub-command names to add.  This parameter may
            /// be null.
            /// </param>
            /// <returns>
            /// The number of sub-command names that were added.
            /// </returns>
            private int AddSubCommands(
                IEnumerable<string> collection
                )
            {
                if (collection != null)
                {
                    if (subCommands == null)
                        subCommands = new EnsembleDictionary();

                    int oldCount = subCommands.Count;

                    foreach (string item in collection)
                    {
                        if (item == null)
                            continue;

                        subCommands[item] = null;
                    }

                    return subCommands.Count - oldCount;
                }

                return 0;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method adds this object instance to the specified
            /// interpreter.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to add this object instance to.
            /// </param>
            /// <param name="name">
            /// The name to use for this object instance within the interpreter.
            /// </param>
            /// <param name="clientData">
            /// The client data to associate with this object instance, if any.
            /// </param>
            /// <param name="token">
            /// Upon success, this parameter will contain the token associated
            /// with the newly added object instance.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public ReturnCode AddToInterpreter(
                Interpreter interpreter,
                string name,
                IClientData clientData,
                ref long token,
                ref Result error
                )
            {
                return Helpers.AddToInterpreter(
                    interpreter, name, this, clientData, ref token,
                    ref error);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IEnsemble Members
            /// <summary>
            /// The collection of sub-commands exposed by this object instance.
            /// </summary>
            private EnsembleDictionary subCommands;
            /// <summary>
            /// Gets or sets the collection of sub-commands exposed by this
            /// object instance.
            /// </summary>
            public EnsembleDictionary SubCommands
            {
                get { return subCommands; }
                set { subCommands = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecute Members
            /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
            /// <summary>
            /// This method executes this object instance.  This implementation
            /// always throws <see cref="NotImplementedException" />.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which this object instance is being
            /// executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this object instance, if any.
            /// </param>
            /// <param name="arguments">
            /// The arguments to this object instance.
            /// </param>
            /// <param name="result">
            /// Upon success, this parameter will contain the result produced by
            /// this object instance; upon failure, it will contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public ReturnCode Execute(
                Interpreter interpreter,
                IClientData clientData,
                ArgumentList arguments,
                ref Result result
                )
            {
                throw new NotImplementedException();
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ISubCommand Test Class
        /// <summary>
        /// This class implements a sub-command that dispatches either to a
        /// configured executable entity or to a configured script command, used
        /// to exercise the <see cref="ISubCommand" /> interface during testing.
        /// </summary>
        [ObjectId("b9d6a0c9-8bca-4558-8b55-68334118978f")]
        public sealed class SubCommand : ISubCommand
        {
            #region Private Data
            //
            // NOTE: The script command to evaluate when this sub-command
            //       instance is executed (this only applies if the
            //       "useIExecute" flag is false).
            //
            /// <summary>
            /// The script command to evaluate when this sub-command instance is
            /// executed (this only applies if the "useIExecute" flag is zero).
            /// </summary>
            private StringList scriptCommand;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: The IExecute to execute when this sub-command instance
            //       is executed (this only applies if the "useIExecute" flag
            //       is true).
            //
            /// <summary>
            /// The executable entity to execute when this sub-command instance
            /// is executed (this only applies if the "useIExecute" flag is
            /// non-zero).
            /// </summary>
            private IExecute execute;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: This is the index into the argument list where the name
            //       of the sub-command is.
            //
            /// <summary>
            /// The index into the argument list at which the name of the
            /// sub-command is located.
            /// </summary>
            private int nameIndex;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, the IExecute will be used instead
            //       of the script command.
            //
            /// <summary>
            /// When non-zero, the executable entity will be used instead of the
            /// script command.
            /// </summary>
            private bool useIExecute;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, the arguments to the sub-command
            //       will be appended to the script command to be evaluated
            //       (this only applies if the "useIExecute" flag is false).
            //
            /// <summary>
            /// When non-zero, the arguments to the sub-command will be appended
            /// to the script command to be evaluated (this only applies if the
            /// "useIExecute" flag is zero).
            /// </summary>
            private bool useExecuteArguments;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, the arguments containing names
            //       of the command and sub-command will not be added to the
            //       final list of arguments to the script command.
            //
            /// <summary>
            /// When non-zero, the arguments containing the names of the command
            /// and sub-command will not be added to the final list of arguments
            /// to the script command.
            /// </summary>
            private bool skipNameArguments;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: When this is non-zero, there can be no extra arguments
            //       to the sub-command beyond the names of the command and
            //       sub-command.
            //
            /// <summary>
            /// When non-zero, there can be no extra arguments to the sub-command
            /// beyond the names of the command and sub-command.
            /// </summary>
            private bool strictNoArguments;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: This keeps track of the number of times the Execute
            //       method of this class handles a sub-command.  This value
            //       starts at zero, is always incremented, and never reset.
            //
            /// <summary>
            /// The number of times the Execute method of this class has handled
            /// a sub-command.  This value starts at zero, is always incremented,
            /// and is never reset.
            /// </summary>
            private int executeCount;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="name">
            /// The name of the sub-command.
            /// </param>
            /// <param name="command">
            /// The command that this sub-command belongs to, if any.
            /// </param>
            /// <param name="callback">
            /// The execution callback associated with this sub-command, if any.
            /// </param>
            /// <param name="clientData">
            /// The client data to associate with this sub-command, if any.
            /// </param>
            /// <param name="commandFlags">
            /// The command flags to associate with this sub-command.
            /// </param>
            /// <param name="scriptCommand">
            /// The script command to evaluate when this sub-command is executed
            /// (this only applies if the <paramref name="useIExecute" /> flag is
            /// zero).
            /// </param>
            /// <param name="execute">
            /// The executable entity to execute when this sub-command is
            /// executed (this only applies if the
            /// <paramref name="useIExecute" /> flag is non-zero).
            /// </param>
            /// <param name="nameIndex">
            /// The index into the argument list at which the name of the
            /// sub-command is located.
            /// </param>
            /// <param name="useIExecute">
            /// Non-zero to use the executable entity instead of the script
            /// command.
            /// </param>
            /// <param name="strictNoArguments">
            /// Non-zero to disallow any extra arguments to the sub-command
            /// beyond the names of the command and sub-command.
            /// </param>
            /// <param name="useExecuteArguments">
            /// Non-zero to append the arguments to the sub-command to the script
            /// command to be evaluated.
            /// </param>
            /// <param name="skipNameArguments">
            /// Non-zero to omit the arguments containing the names of the
            /// command and sub-command from the final argument list.
            /// </param>
            public SubCommand(
                string name,
                ICommand command,
                ExecuteCallback callback,
                IClientData clientData,
                CommandFlags commandFlags,
                StringList scriptCommand,
                IExecute execute,
                int nameIndex,
                bool useIExecute,
                bool strictNoArguments,
                bool useExecuteArguments,
                bool skipNameArguments
                )
            {
                this.name = name;
                this.command = command;
                this.callback = callback;
                this.clientData = clientData;
                this.commandFlags = commandFlags;
                this.scriptCommand = scriptCommand;
                this.execute = execute;
                this.nameIndex = nameIndex;
                this.useIExecute = useIExecute;
                this.strictNoArguments = strictNoArguments;
                this.useExecuteArguments = useExecuteArguments;
                this.skipNameArguments = skipNameArguments;
                this.executeCount = 0;

                ///////////////////////////////////////////////////////////////////////////////////////

                SetupSubCommands();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method gets the name to use for this sub-command when
            /// formatting error messages.
            /// </summary>
            /// <returns>
            /// The name to use for this sub-command.
            /// </returns>
            private string GetCommandName()
            {
                return ScriptOps.GetNameForExecute(null, this);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets up the collection of sub-commands handled by
            /// this object instance.
            /// </summary>
            private void SetupSubCommands()
            {
                //
                // NOTE: We only handle one sub-command at a time and it is
                //       always handled locally (i.e. using null ISubCommand
                //       instance).
                //
                subCommands = new EnsembleDictionary();
                subCommands.Add(this.Name, null);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether this sub-command is allowed to be
            /// used with the specified arguments.
            /// </summary>
            /// <param name="arguments">
            /// The arguments to the sub-command.  This parameter may be null.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the sub-command is allowed to be used with the specified
            /// arguments; otherwise, false.
            /// </returns>
            private bool AllowedToUseArguments(
                ArgumentList arguments,
                ref Result error
                )
            {
                if (!strictNoArguments)
                    return true;

                int nameIndex = this.NameIndex;
                int nextIndex = nameIndex + 1;

                if ((arguments == null) || (arguments.Count <= nextIndex))
                    return true;

                error = String.Format(
                    "wrong # args: should be \"{0}\"", GetCommandName());

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method gets the arguments to pass along when this
            /// sub-command is executed.
            /// </summary>
            /// <param name="arguments">
            /// The arguments to the sub-command.  This parameter may be null.
            /// </param>
            /// <returns>
            /// The arguments to pass along, or null if no arguments should be
            /// passed along.
            /// </returns>
            private ArgumentList GetArgumentsForExecute(
                ArgumentList arguments
                )
            {
                return useExecuteArguments ? arguments : null;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method gets the index of the first argument to pass along
            /// when this sub-command is executed.
            /// </summary>
            /// <param name="arguments">
            /// The arguments to the sub-command.  This parameter may be null.
            /// </param>
            /// <returns>
            /// The index of the first argument to pass along.
            /// </returns>
            private int GetStartIndexForArguments(
                ArgumentList arguments
                )
            {
                if (!skipNameArguments)
                    return 0;

                int nameIndex = this.NameIndex;
                int nextIndex = nameIndex + 1;

                if ((arguments == null) || (arguments.Count < nextIndex))
                    return 0;

                return nextIndex;
            }
