            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecute Members
            /* CodeBrix.Platform.TclTk._Components.Public.Delegates.ExecuteCallback */
            /// <summary>
            /// This method executes this sub-command, dispatching to either the
            /// configured executable entity or the configured script command.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the sub-command is being
            /// executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this sub-command, if any.
            /// </param>
            /// <param name="arguments">
            /// The arguments to the sub-command, including the sub-command name.
            /// </param>
            /// <param name="result">
            /// Upon success, this parameter will contain the result produced by
            /// the sub-command; upon failure, it will contain an appropriate
            /// error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public ReturnCode Execute(
                Interpreter interpreter,
                IClientData clientData,
                ArgumentList arguments,
                ref Result result
                )
            {
                if (interpreter == null)
                {
                    result = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (arguments == null)
                {
                    result = "invalid argument list";
                    return ReturnCode.Error;
                }

                int nameIndex = this.NameIndex;
                int nextIndex = nameIndex + 1;

                if (arguments.Count < nextIndex)
                {
                    result = String.Format(
                        "wrong # args: should be \"{0} ?arg ...?\"",
                        GetCommandName());

                    return ReturnCode.Error;
                }

                string subCommand = arguments[nameIndex];

                if (!StringOps.SubCommandEquals(subCommand, this.Name))
                {
                    result = ScriptOps.BadSubCommand(
                        interpreter, null, null, subCommand, this, null,
                        null);

                    return ReturnCode.Error;
                }

                //
                // NOTE: Does this sub-command accept arguments beyond
                //       the names of the command and sub-command?
                //
                if (!AllowedToUseArguments(arguments, ref result))
                    return ReturnCode.Error;

                Interlocked.Increment(ref executeCount);

                if (useIExecute)
                {
                    //
                    // NOTE: Re-dispatch to the configured IExecute
                    //       instance and return its results verbatim.
                    //
                    string commandName = EntityOps.GetName(
                        execute as IIdentifierName);

                    if (commandName == null)
                        commandName = arguments[nameIndex - 1];

                    return interpreter.Execute(
                        commandName, execute, clientData, arguments,
                        ref result);
                }
                else
                {
                    //
                    // NOTE: Evaluate the configured script command, maybe
                    //       adding all the local arguments, and return the
                    //       results verbatim.
                    //
                    string name = StringList.MakeList(GetCommandName());

                    ICallFrame frame = interpreter.NewTrackingCallFrame(name,
                        CallFrameFlags.Evaluate | CallFrameFlags.Test |
                        CallFrameFlags.SubCommand);

                    interpreter.PushAutomaticCallFrame(frame);

                    ReturnCode code = interpreter.EvaluateScript(
                        ScriptOps.GetArgumentsForExecute(this,
                        scriptCommand, GetArgumentsForExecute(arguments),
                        GetStartIndexForArguments(arguments)), 0, ref result);

                    if (code == ReturnCode.Error)
                    {
                        /* IGNORED */
                        Engine.AddErrorInformation(interpreter, result,
                            String.Format("{0}    (\"{1}\" body line {2})",
                                Environment.NewLine, GetCommandName(),
                                Interpreter.GetErrorLine(interpreter)));
                    }

                    //
                    // NOTE: Pop the original call frame that we pushed above and
                    //       any intervening scope call frames that may be leftover
                    //       (i.e. they were not explicitly closed).
                    //
                    /* IGNORED */
                    interpreter.PopScopeCallFramesAndOneMore();
                    return code;
                }
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region GetStringPlugin Test Class
        /// <summary>
        /// This class implements a plugin that maintains a collection of named
        /// strings, both per-instance and shared, used to exercise the plugin
        /// string-lookup subsystem during testing.
        /// </summary>
        [ObjectId("62bc8b71-3214-4ef2-b783-c41a93761f31")]
        [PluginFlags(
            PluginFlags.System | PluginFlags.Static |
            PluginFlags.NoCommands | PluginFlags.NoFunctions |
            PluginFlags.NoPolicies | PluginFlags.NoTraces |
            PluginFlags.Test)]
        public class GetStringPlugin : _Plugins.Default, IDisposable
        {
            #region Private Constants
            //
            // HACK: These are purposely not read-only.
            //
            /// <summary>
            /// The default value indicating whether the shared (static) strings
            /// should be consulted when looking up a string.
            /// </summary>
            private static bool DefaultUseStatic = true;
            /// <summary>
            /// The default value indicating whether the per-instance strings
            /// should be consulted when looking up a string.
            /// </summary>
            private static bool DefaultUseInstance = true;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The object used to synchronize access to the per-instance
            /// strings.
            /// </summary>
            private readonly object syncRoot = new object();

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The collection of per-instance strings maintained by this plugin.
            /// </summary>
            private StringDictionary strings;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// When non-zero, the shared (static) strings will be consulted when
            /// looking up a string.
            /// </summary>
            private bool useStatic; /* NO-LOCK */
            /// <summary>
            /// When non-zero, the per-instance strings will be consulted when
            /// looking up a string.
            /// </summary>
            private bool useInstance; /* NO-LOCK */
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="pluginData">
            /// The plugin data used to populate the new instance.  This
            /// parameter may be null.
            /// </param>
            public GetStringPlugin(
                IPluginData pluginData /* in */
                )
                : base(pluginData)
            {
                this.Flags |= AttributeOps.GetPluginFlags(GetType().BaseType) |
                    AttributeOps.GetPluginFlags(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method initializes the per-instance string state maintained
            /// by this plugin.
            /// </summary>
            private void Initialize()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (strings == null)
                        strings = new StringDictionary();
                }

                useStatic = DefaultUseStatic;
                useInstance = DefaultUseInstance;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method terminates the per-instance string state maintained
            /// by this plugin, releasing any associated resources.
            /// </summary>
            private void Terminate()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (strings != null)
                    {
                        strings.Clear();
                        strings = null;
                    }
                }

                useStatic = false;
                useInstance = false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method gets the number of per-instance strings maintained by
            /// this plugin.
            /// </summary>
            /// <param name="response">
            /// Upon success, this parameter will contain the number of
            /// per-instance strings.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            private ReturnCode Count(
                ref object response, /* out */
                ref Result error     /* out */
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (strings != null)
                    {
                        response = strings.Count;
                        return ReturnCode.Ok;
                    }
                    else
                    {
                        error = "strings not available";
                        return ReturnCode.Error;
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method gets the names of the per-instance strings maintained
            /// by this plugin.
            /// </summary>
            /// <param name="response">
            /// Upon success, this parameter will contain the names of the
            /// per-instance strings.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            private ReturnCode List(
                ref object response, /* out */
                ref Result error     /* out */
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (strings != null)
                    {
                        response = strings.KeysToString(null, false);
                        return ReturnCode.Ok;
                    }
                    else
                    {
                        error = "strings not available";
                        return ReturnCode.Error;
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method removes all per-instance strings maintained by this
            /// plugin.
            /// </summary>
            /// <param name="response">
            /// Upon success, this parameter will contain the number of
            /// per-instance strings that were removed.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            private ReturnCode Clear(
                ref object response, /* out */
                ref Result error     /* out */
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (strings != null)
                    {
                        response = strings.Count;
                        strings.Clear();

                        return ReturnCode.Ok;
                    }
                    else
                    {
                        error = "strings not available";
                        return ReturnCode.Error;
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method adds a new per-instance string with the specified
            /// name and value.
            /// </summary>
            /// <param name="name">
            /// The name of the string to add.
            /// </param>
            /// <param name="value">
            /// The value of the string to add.  This parameter may be null.
            /// </param>
            /// <param name="response">
            /// Upon success, this parameter will be set to null.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            private ReturnCode Add(
                string name,         /* in */
                string value,        /* in */
                ref object response, /* out */
                ref Result error     /* out */
                )
            {
                if (name != null)
                {
                    lock (syncRoot) /* TRANSACTIONAL */
                    {
                        if (strings != null)
                        {
                            strings.Add(name, value);
                            response = null;

                            return ReturnCode.Ok;
                        }
                        else
                        {
                            error = "strings not available";
                            return ReturnCode.Error;
                        }
                    }
                }
                else
                {
                    error = "invalid string name";
                    return ReturnCode.Error;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method changes the value of an existing per-instance string
            /// with the specified name, or adds it if it does not exist.
            /// </summary>
            /// <param name="name">
            /// The name of the string to change.
            /// </param>
            /// <param name="value">
            /// The new value of the string.  This parameter may be null.
            /// </param>
            /// <param name="response">
            /// Upon success, this parameter will be set to null.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            private ReturnCode Change(
                string name,         /* in */
                string value,        /* in */
                ref object response, /* out */
                ref Result error     /* out */
                )
            {
                if (name != null)
                {
                    lock (syncRoot) /* TRANSACTIONAL */
                    {
                        if (strings != null)
                        {
                            strings[name] = value;
                            response = null;

                            return ReturnCode.Ok;
                        }
                        else
                        {
                            error = "strings not available";
                            return ReturnCode.Error;
                        }
                    }
                }
                else
                {
                    error = "invalid string name";
                    return ReturnCode.Error;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method removes the per-instance string with the specified
            /// name.
            /// </summary>
            /// <param name="name">
            /// The name of the string to remove.
            /// </param>
            /// <param name="response">
            /// Upon success, this parameter will contain non-zero if a string
            /// was removed.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            private ReturnCode Remove(
                string name,         /* in */
                ref object response, /* out */
                ref Result error     /* out */
                )
            {
                if (name != null)
                {
                    lock (syncRoot) /* TRANSACTIONAL */
                    {
                        if (strings != null)
                        {
                            response = strings.Remove(name);
                            return ReturnCode.Ok;
                        }
                        else
                        {
                            error = "strings not available";
                            return ReturnCode.Error;
                        }
                    }
                }
                else
                {
                    error = "invalid string name";
                    return ReturnCode.Error;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IState Members
            /// <summary>
            /// This method initializes this plugin within the specified
            /// interpreter.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which this plugin is being
            /// initialized.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this plugin, if any.
            /// </param>
            /// <param name="result">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public override ReturnCode Initialize(
                Interpreter interpreter, /* in */
                IClientData clientData,  /* in */
                ref Result result        /* out */
                )
            {
                CheckDisposed();

                Initialize();

                return base.Initialize(interpreter, clientData, ref result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method terminates this plugin within the specified
            /// interpreter.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which this plugin is being terminated.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this plugin, if any.
            /// </param>
            /// <param name="result">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public override ReturnCode Terminate(
                Interpreter interpreter, /* in */
                IClientData clientData,  /* in */
                ref Result result        /* out */
                )
            {
                CheckDisposed();

                Terminate();

                return base.Terminate(interpreter, clientData, ref result);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecuteRequest Members
            /// <summary>
            /// This method executes a request directed at this plugin, handling
            /// the string-management requests and delegating any others to the
            /// base plugin.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the request is being executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this plugin, if any.
            /// </param>
            /// <param name="request">
            /// The request to execute.  This parameter may be null.
            /// </param>
            /// <param name="response">
            /// Upon success, this parameter will contain the response produced by
            /// the request.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public override ReturnCode Execute(
                Interpreter interpreter, /* in */
                IClientData clientData,  /* in */
                object request,          /* in */
                ref object response,     /* out */
                ref Result error         /* out */
                )
            {
                CheckDisposed();

                //
                // NOTE: This method is not supposed to raise an error under
                //       normal conditions when faced with an unrecognized
                //       request.  It simply does nothing and lets the base
                //       plugin handle it.
                //
                if (request is string[])
                {
                    string[] stringRequest = (string[])request;

                    ArgumentList arguments = new ArgumentList(
                        (IEnumerable<string>)stringRequest);

                    int argumentCount; /* REUSED */

                    ///////////////////////////////////////////////////////////////////////////////////

                    if (_RuntimeOps.MatchRequestName(
                            arguments, "countStrings", out argumentCount) &&
                        (argumentCount == 1))
                    {
                        return Count(ref response, ref error);
                    }

                    ///////////////////////////////////////////////////////////////////////////////////

                    if (_RuntimeOps.MatchRequestName(
                            arguments, "listStrings", out argumentCount) &&
                        (argumentCount == 1))
                    {
                        return List(ref response, ref error);
                    }

                    ///////////////////////////////////////////////////////////////////////////////////

                    if (_RuntimeOps.MatchRequestName(
                            arguments, "clearStrings", out argumentCount) &&
                        (argumentCount == 1))
                    {
                        return Clear(ref response, ref error);
                    }

                    ///////////////////////////////////////////////////////////////////////////////////

                    if (_RuntimeOps.MatchRequestName(
                            arguments, "addString", out argumentCount) &&
                        (argumentCount == 3))
                    {
                        return Add(arguments[1], arguments[2], ref response, ref error);
                    }

                    ///////////////////////////////////////////////////////////////////////////////////

                    if (_RuntimeOps.MatchRequestName(
                            arguments, "changeString", out argumentCount) &&
                        (argumentCount == 3))
                    {
                        return Change(arguments[1], arguments[2], ref response, ref error);
                    }

                    ///////////////////////////////////////////////////////////////////////////////////

                    if (_RuntimeOps.MatchRequestName(
                            arguments, "removeString", out argumentCount) &&
                        (argumentCount == 2))
                    {
                        return Remove(arguments[1], ref response, ref error);
                    }
                }

                ///////////////////////////////////////////////////////////////////////////////////////

                //
                // NOTE: If this point is reached the request was not handled.
                //       Call our base plugin and let it attempt to handle the
                //       request.
                //
                return base.Execute(
                    interpreter, clientData, request, ref response, ref error);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IPlugin Members
            /// <summary>
            /// This method gets the value of the named string, consulting the
            /// per-instance, shared, and base-class strings in turn.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the string is being looked up.
            /// </param>
            /// <param name="name">
            /// The name of the string to look up.  This parameter may be null.
            /// </param>
            /// <param name="cultureInfo">
            /// The culture to use when looking up the string, if any.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The value of the named string, or null if it could not be found.
            /// </returns>
            public override string GetString(
                Interpreter interpreter, /* in */
                string name,             /* in */
                CultureInfo cultureInfo, /* in */
                ref Result error         /* out */
                )
            {
                CheckDisposed();

                string value; /* REUSED */
                Result localError; /* REUSED */
                ResultList errors = null;

                ///////////////////////////////////////////////////////////////////////////////////////

                #region Instance (Private) Strings
                if (useInstance)
                {
                    if (name != null)
                    {
                        lock (syncRoot) /* TRANSACTIONAL */
                        {
                            if ((strings != null) &&
                                strings.TryGetValue(name, out value))
                            {
                                return value; /* MAY BE NULL */
                            }
                        }
                    }

                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(String.Format(
                        "instance {0} has no string named {1}",
                        FormatOps.WrapHashCode(this),
                        FormatOps.WrapOrNull(name)));
                }
                #endregion

                ///////////////////////////////////////////////////////////////////////////////////////

                #region Static (Shared) Strings
                if (useStatic)
                {
                    localError = null;

                    value = TestGetString(
                        interpreter, name, cultureInfo, ref localError);

                    if (value != null)
                        return value;

                    if (localError != null)
                    {
                        if (errors == null)
                            errors = new ResultList();

                        errors.Add(localError);
                    }
                }
                #endregion

                ///////////////////////////////////////////////////////////////////////////////////////

                #region Base Class Strings (None?)
                localError = null;

                value = base.GetString(
                    interpreter, name, cultureInfo, ref localError);

                if (value != null)
                    return value;

                if (localError != null)
                {
                    if (errors == null)
                        errors = new ResultList();

                    errors.Add(localError);
                }
                #endregion

                ///////////////////////////////////////////////////////////////////////////////////////

                if (errors != null)
                    error = errors;

                return null;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources used by this object instance.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(GetStringPlugin).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected virtual void Dispose(
                bool disposing /* in */
                )
            {
                TraceOps.DebugTrace(String.Format(
                    "Dispose: called, disposing = {0}, disposed = {1}",
                    disposing, disposed), typeof(GetStringPlugin).Name,
                    TracePriority.CleanupDebug);

                if (!disposed)
                {
                    if (disposing)
                    {
                        ////////////////////////////////////
                        // dispose managed resources here...
                        ////////////////////////////////////

                        Terminate();
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~GetStringPlugin()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

