        #region StatusFormTraceListener Test Class
#if WINFORMS
        /// <summary>
        /// This class implements a trace listener that forwards trace output to
        /// an interpreter status form, used to exercise the status-reporting
        /// subsystem.
        /// </summary>
        [ObjectId("0863138b-fc02-4ce7-9003-6e1589576857")]
        public class StatusFormTraceListener : TraceListener, IGetInterpreter
        {
            #region Private Data
            /// <summary>
            /// The interpreter associated with this trace listener.
            /// </summary>
            private Interpreter interpreter;
            /// <summary>
            /// The client data associated with this trace listener, if any.
            /// </summary>
            private IClientData clientData;
            /// <summary>
            /// The timeout, in milliseconds, to use when reporting status, if
            /// any.
            /// </summary>
            private int? timeout;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to associate with this trace listener.
            /// </param>
            /// <param name="clientData">
            /// The client data to associate with this trace listener, if any.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, to use when reporting status, if
            /// any.
            /// </param>
            public StatusFormTraceListener(
                Interpreter interpreter, /* in */
                IClientData clientData,  /* in: OPTIONAL */
                int? timeout             /* in: OPTIONAL */
                )
                : this(interpreter, clientData, timeout, null)
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter to associate with this trace listener.
            /// </param>
            /// <param name="clientData">
            /// The client data to associate with this trace listener, if any.
            /// </param>
            /// <param name="timeout">
            /// The timeout, in milliseconds, to use when reporting status, if
            /// any.
            /// </param>
            /// <param name="name">
            /// The name for this trace listener.
            /// </param>
            public StatusFormTraceListener(
                Interpreter interpreter, /* in */
                IClientData clientData,  /* in: OPTIONAL */
                int? timeout,            /* in: OPTIONAL */
                string name              /* in */
                )
                : base(name)
            {
                this.interpreter = interpreter;
                this.clientData = clientData;
                this.timeout = timeout;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IGetInterpreter Members
            /// <summary>
            /// Gets the interpreter associated with this trace listener.
            /// </summary>
            public Interpreter Interpreter
            {
                get { CheckDisposed(); return interpreter; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method reports the specified message to the interpreter
            /// status form.
            /// </summary>
            /// <param name="message">
            /// The message to report.  This parameter may be null.
            /// </param>
            /// <param name="newLine">
            /// Non-zero to append a line terminator to the message.
            /// </param>
            private void WriteCore(
                string message, /* in */
                bool newLine    /* in */
                )
            {
                if (interpreter != null)
                {
                    if (newLine && (message != null)) /* REDUNDANT */
                    {
                        message = String.Format(
                            "{0}{1}", message, Environment.NewLine);
                    }

                    ReturnCode code;
                    Result error = null;

                    code = interpreter.ReportStatus(
                        clientData, message, timeout, ref error);

                    if (code != ReturnCode.Ok)
                        DebugOps.Complain(interpreter, code, error);
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Diagnostics.TraceListener Overrides
            /// <summary>
            /// This method closes this trace listener, stopping the status
            /// report on the interpreter.
            /// </summary>
            public override void Close()
            {
                CheckDisposed();

                if (interpreter != null)
                {
                    ReturnCode code;
                    Result error = null;

                    code = interpreter.StopStatus(
                        clientData, timeout, ref error);

                    if (code != ReturnCode.Ok)
                        DebugOps.Complain(interpreter, code, error);
                }

                base.Close();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method flushes this trace listener, clearing the status text
            /// on the interpreter.
            /// </summary>
            public override void Flush() /* HACK: This means to clear the text box. */
            {
                CheckDisposed();

                if (interpreter != null)
                {
                    ReturnCode code;
                    Result error = null;

                    code = interpreter.ClearStatus(
                        clientData, timeout, ref error);

                    if (code != ReturnCode.Ok)
                        DebugOps.Complain(interpreter, code, error);
                }

                base.Flush();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reports the specified message to the interpreter
            /// status form.
            /// </summary>
            /// <param name="message">
            /// The message to report.  This parameter may be null.
            /// </param>
            public /* abstract */ override void Write(
                string message /* in */
                )
            {
                CheckDisposed();

                WriteCore(message, false);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reports the specified message, followed by a line
            /// terminator, to the interpreter status form.
            /// </summary>
            /// <param name="message">
            /// The message to report.  This parameter may be null.
            /// </param>
            public /* abstract */ override void WriteLine(
                string message /* in */
                )
            {
                CheckDisposed();

                WriteCore(message, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether this trace listener is thread
            /// safe.
            /// </summary>
            public override bool IsThreadSafe
            {
                get { CheckDisposed(); return true; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(StatusFormTraceListener).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The number of nested calls to the dispose method currently in
            /// progress.
            /// </summary>
            private int disposeLevels;
            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected override void Dispose(
                bool disposing /* in */
                )
            {
                int levels = Interlocked.Increment(ref disposeLevels);

                try
                {
                    if (levels == 1)
                    {
                        try
                        {
                            if (!disposed)
                            {
                                if (disposing)
                                {
                                    ////////////////////////////////////
                                    // dispose managed resources here...
                                    ////////////////////////////////////

                                    /* NO RESULT */
                                    DebugOps.RemoveTraceListener(this);

                                    ////////////////////////////////////

                                    Close();
                                }
                            }
                        }
                        finally
                        {
                            base.Dispose(disposing);

                            disposed = true;
                        }
                    }
                }
                finally
                {
                    Interlocked.Decrement(ref disposeLevels);
                }

                //////////////////////////////////////
                // release unmanaged resources here...
                //////////////////////////////////////
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~StatusFormTraceListener()
            {
                Dispose(false);
            }
            #endregion
        }
#endif
        #endregion

