        /// <summary>
        /// This class implements a trace listener that buffers trace
        /// messages before forwarding them to an inner trace listener, used
        /// to exercise the tracing subsystem.
        /// </summary>
        [ObjectId("437d590d-843b-4f96-a7a5-4a89957ce154")]
        public class BufferedTraceListener : TraceListener, IBufferedTraceListener
        {
            #region Private Constants
            //
            // HACK: This is purposely not read-only.
            //
            /// <summary>
            /// The default initial capacity of the message buffer.
            /// </summary>
            private static int DefaultInitialCapacity = 10;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The error message used when the inner trace listener is missing.
            /// </summary>
            private static readonly string NoTraceListenerError = "inner trace listener missing";
            /// <summary>
            /// The error message used when the inner trace listener is invalid.
            /// </summary>
            private static readonly string BadTraceListenerError = "bad inner trace listener";
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The object used to synchronize access to this object instance.
            /// </summary>
            private readonly object syncRoot = new object();

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The identifier to assign to the next buffered message.
            /// </summary>
            private long nextId;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The list of buffered messages, each consisting of an identifier, the
            /// message text, and whether it was written with a line terminator.
            /// </summary>
            private IList<IAnyTriplet<long, string, bool>> messages;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            private BufferedTraceListener()
            {
                InitializeMessages();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="listener">
            /// The inner trace listener that buffered messages will be forwarded
            /// to.
            /// </param>
            /// <param name="flags">
            /// The flags used to configure the behavior of this trace listener.
            /// </param>
            /// <param name="initialCapacity">
            /// The initial capacity of the message buffer.
            /// </param>
            /// <param name="maximumCapacity">
            /// The maximum capacity of the message buffer.
            /// </param>
            private BufferedTraceListener(
                TraceListener listener,
                BufferedTraceFlags flags,
                int initialCapacity,
                int maximumCapacity
                )
                : this()
            {
                this.traceListener = listener;
                this.flags = flags;
                this.initialCapacity = initialCapacity;
                this.maximumCapacity = maximumCapacity;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Static "Factory" Methods
            /// <summary>
            /// This method creates a new instance of this class.
            /// </summary>
            /// <param name="listener">
            /// The inner trace listener that buffered messages will be forwarded
            /// to.
            /// </param>
            /// <param name="flags">
            /// The flags used to configure the behavior of this trace listener.
            /// </param>
            /// <param name="initialCapacity">
            /// The initial capacity of the message buffer.
            /// </param>
            /// <param name="maximumCapacity">
            /// The maximum capacity of the message buffer.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created trace listener.
            /// </returns>
            public static TraceListener Create(
                TraceListener listener,
                BufferedTraceFlags flags,
                int initialCapacity,
                int maximumCapacity,
                ref Result error /* NOT USED */
                )
            {
                return new BufferedTraceListener(
                    listener, flags, initialCapacity, maximumCapacity);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method installs the specified buffered trace listener into the
            /// appropriate trace listener collection.
            /// </summary>
            /// <param name="listener">
            /// The buffered trace listener to install.
            /// </param>
            /// <param name="type">
            /// The type of the existing trace listener to wrap.  This parameter
            /// may be null.
            /// </param>
            /// <param name="listenerType">
            /// The type of trace listener to create when no existing trace listener
            /// is available.
            /// </param>
            /// <param name="clientData">
            /// The client data to use when creating a trace listener.  This
            /// parameter may be null.
            /// </param>
            /// <param name="debug">
            /// Non-zero to use the debug trace listener collection; otherwise, the
            /// trace trace listener collection is used.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
            /// error code.
            /// </returns>
            public static ReturnCode Install(
                BufferedTraceListener listener,
                Type type,
                TraceListenerType listenerType,
                IClientData clientData,
                bool debug,
                ref Result error
                )
            {
                if (listener == null)
                {
                    error = "invalid buffered trace listener";
                    return ReturnCode.Error;
                }

                TraceListenerCollection listeners = DebugOps.GetListeners(
                    debug);

                if (listeners == null)
                {
                    error = "invalid trace listener collection";
                    return ReturnCode.Error;
                }

                int count = listeners.Count;

                if (count > 0)
                {
                    bool found = false;
                    Result localError = null;

                    for (int index = 0; index < count; index++)
                    {
                        TraceListener innerListener = listeners[index];

                        if (innerListener == null)
                            continue;

                        if (innerListener is BufferedTraceListener)
                        {
                            localError = "trace listener already installed";
                            continue;
                        }

                        if ((type == null) || Object.ReferenceEquals(
                                innerListener.GetType(), type))
                        {
                            listener.TraceListener = innerListener;

                            listeners.RemoveAt(index);
                            listeners.Insert(index, listener);

                            found = true;
                            break;
                        }
                    }

                    if (found)
                        return ReturnCode.Ok;

                    if (localError != null)
                        error = localError;
                    else
                        error = "trace listener is not installed";

                    return ReturnCode.Error;
                }
                else if (type == null)
                {
                    TraceListener innerListener = listener.CreateTraceListener(
                        listenerType, clientData, ref error);

                    if (innerListener == null)
                        return ReturnCode.Error;

                    //
                    // HACK: This if statement cannot be hit unless
                    //       our CreateTraceListener method ends up
                    //       being overridden in a derived class.
                    //
                    if (innerListener is BufferedTraceListener)
                    {
                        innerListener.Dispose();
                        innerListener = null;

                        error = "trace listener already installed";
                        return ReturnCode.Error;
                    }

                    listener.TraceListener = innerListener;
                    listeners.Add(listener);

                    return ReturnCode.Ok;
                }
                else
                {
                    error = "no trace listeners are installed";
                    return ReturnCode.Error;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method uninstalls a buffered trace listener from the
            /// appropriate trace listener collection.
            /// </summary>
            /// <param name="debug">
            /// Non-zero to use the debug trace listener collection; otherwise, the
            /// trace trace listener collection is used.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
            /// error code.
            /// </returns>
            public static ReturnCode Uninstall(
                bool debug,
                ref Result error
                )
            {
                TraceListenerCollection listeners = DebugOps.GetListeners(
                    debug);

                if (listeners == null)
                {
                    error = "invalid trace listener collection";
                    return ReturnCode.Error;
                }

                int count = listeners.Count;

                if (count == 0)
                {
                    error = "no trace listeners are installed";
                    return ReturnCode.Error;
                }

                bool found = false;

                for (int index = count - 1; index >= 0; index--)
                {
                    BufferedTraceListener listener =
                        listeners[index] as BufferedTraceListener;

                    if (listener != null)
                    {
                        listeners.RemoveAt(index);

                        TraceListener innerListener = null;

                        if (!listener.IsTakeOwnership())
                            innerListener = listener.TraceListener;

                        listener.Dispose();
                        listener = null;

                        if (innerListener != null)
                            listeners.Insert(index, innerListener);

                        found = true;
                        break;
                    }
                }

                if (found)
                    return ReturnCode.Ok;

                error = "trace listener is not installed";
                return ReturnCode.Error;
            }
            #endregion

