            /// <summary>
            /// This method closes the inner trace listener.
            /// </summary>
            /// <param name="throwOnError">
            /// Non-zero to throw an exception if the inner trace listener is
            /// missing or invalid.
            /// </param>
            private void CloseTraceListener(
                bool throwOnError
                )
            {
                TraceListener listener;

                GetTraceListener(out listener);

                if (listener == null)
                {
                    if (!throwOnError)
                        return;

                    throw new InvalidOperationException(NoTraceListenerError);
                }

                if (Object.ReferenceEquals(listener, this))
                {
                    if (!throwOnError)
                        return;

                    throw new InvalidOperationException(BadTraceListenerError);
                }

                listener.Close(); /* throw */
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method flushes the inner trace listener.
            /// </summary>
            /// <param name="throwOnError">
            /// Non-zero to throw an exception if the inner trace listener is
            /// missing or invalid.
            /// </param>
            private void FlushTraceListener(
                bool throwOnError
                )
            {
                TraceListener listener;

                GetTraceListener(out listener);

                if (listener == null)
                {
                    if (!throwOnError)
                        return;

                    throw new InvalidOperationException(NoTraceListenerError);
                }

                if (Object.ReferenceEquals(listener, this))
                {
                    if (!throwOnError)
                        return;

                    throw new InvalidOperationException(BadTraceListenerError);
                }

                listener.Flush(); /* throw */
            }

