            /// <summary>
            /// This method flushes the inner trace listener in response to a
            /// close, when so configured.
            /// </summary>
            /// <returns>
            /// True if the inner trace listener was flushed; otherwise, false.
            /// </returns>
            protected virtual bool MaybeFlushTraceListenerForClose()
            {
                if (IsNeverFlush() || !IsFlushOnClose())
                    return false;

                /* NO RESULT */
                FlushTraceListener(false); /* throw */

                return true;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method flushes the inner trace listener in response to the
            /// message buffer being emptied, when so configured.
            /// </summary>
            /// <returns>
            /// True if the inner trace listener was flushed; otherwise, false.
            /// </returns>
            protected virtual bool MaybeFlushTraceListenerForEmpty()
            {
                if (IsNeverFlush() || !IsFlushOnEmpty())
                    return false;

                /* NO RESULT */
                FlushTraceListener(false); /* throw */

                return true;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method flushes the inner trace listener, when so configured.
            /// </summary>
            /// <param name="close">
            /// Non-zero if the flush is being performed in response to a close;
            /// otherwise, it is being performed in response to the message buffer
            /// being emptied.
            /// </param>
            /// <returns>
            /// True if the inner trace listener was flushed; otherwise, false.
            /// </returns>
            protected virtual bool MaybeFlushTraceListener(
                bool close
                )
            {
                return close ?
                    MaybeFlushTraceListenerForClose() :
                    MaybeFlushTraceListenerForEmpty();
