            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method formats the specified buffered message.
            /// </summary>
            /// <param name="anyTriplet">
            /// The buffered message to format.
            /// </param>
            /// <param name="useNewLine">
            /// Non-zero to honor the line terminator associated with the message.
            /// </param>
            /// <returns>
            /// The formatted message.
            /// </returns>
            protected virtual string GetString(
                IAnyTriplet<long, string, bool> anyTriplet,
                bool useNewLine
                )
            {
                if (anyTriplet == null)
                    return null;

                string formatted = GetString(
                    anyTriplet.Y, useNewLine && anyTriplet.Z);

                if (!FlagOps.HasFlags(
                        flags, BufferedTraceFlags.FormatWithId, true))
                {
                    return formatted;
                }

                return String.Format("{0}: {1}", anyTriplet.X, formatted);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method formats the specified message.
            /// </summary>
            /// <param name="message">
            /// The message to format.  This parameter may be null.
            /// </param>
            /// <param name="newLine">
            /// Non-zero to append a line terminator.
            /// </param>
            /// <returns>
            /// The formatted message.
            /// </returns>
            protected virtual string GetString(
                string message,
                bool newLine
                )
            {
                if (message != null)
                {
                    if (!newLine)
                        return message;

                    return String.Format(
                        "{0}{1}", message, Environment.NewLine);
                }
                else if (newLine)
                {
                    return Environment.NewLine;
                }
                else
                {
                    return null;
                }
            }
            #endregion

