            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Message Buffer Methods
            /// <summary>
            /// This method initializes the message buffer.
            /// </summary>
            protected virtual void InitializeMessages()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    messages = new List<IAnyTriplet<long, string, bool>>(
                        (initialCapacity < 0) ? DefaultInitialCapacity :
                        initialCapacity);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method counts duplicate buffered messages, when so configured.
            /// </summary>
            /// <param name="messageCounts">
            /// Upon return, this parameter will contain the counts of duplicate
            /// messages.
            /// </param>
            protected virtual void CountMessages(
                ref MessageCountDictionary messageCounts
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (messages == null)
                        return;

                    bool coalesceDuplicates = FlagOps.HasFlags(
                        flags, BufferedTraceFlags.CoalesceDuplicates, true);

                    if (!coalesceDuplicates)
                        return;

                    bool consecutiveDuplicates = FlagOps.HasFlags(
                        flags, BufferedTraceFlags.ConsecutiveDuplicates, true);

                    if (messageCounts == null)
                        messageCounts = new MessageCountDictionary();

                    int messageCount = messages.Count;

                    for (int index = 0; index < messageCount; index++)
                    {
                        IAnyTriplet<long, string, bool> anyTriplet1 =
                            messages[index];

                        if (anyTriplet1 == null)
                            continue;

                        string formatted1 = GetString(anyTriplet1);

                        if (formatted1 == null)
                            continue;

                        if (consecutiveDuplicates)
                        {
                            if (index <= 0)
                                continue;

                            IAnyTriplet<long, string, bool> anyTriplet2 =
                                messages[index - 1];

                            if (anyTriplet2 == null)
                                continue;

                            string formatted2 = GetString(anyTriplet2);

                            if (formatted2 == null)
                                continue;

                            if (!SharedStringOps.SystemEquals(
                                    formatted1, formatted2))
                            {
                                continue;
                            }
                        }

                        long duplicateCount;

                        if (messageCounts.TryGetValue(
                                formatted1, out duplicateCount))
                        {
                            messageCounts[formatted1] = ++duplicateCount;
                        }
                        else
                        {
                            duplicateCount = 1;
                            messageCounts.Add(formatted1, duplicateCount);
                        }
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method empties the message buffer, writing each buffered
            /// message to the inner trace listener.
            /// </summary>
            /// <returns>
            /// True if any messages were written; otherwise, false.
            /// </returns>
            protected virtual bool EmptyMessages()
            {
                MessageCountDictionary messageCounts = null;

                CountMessages(ref messageCounts);

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (messages == null)
                        return false;

                    bool wrote = false;
                    string formatString;

                    if (FlagOps.HasFlags(
                            flags, BufferedTraceFlags.NoRepeatedCount, true))
                    {
                        formatString = "{0}";
                    }
                    else
                    {
                        formatString = "(repeated {1} {2}) {0}";
                    }

                    int messageCount = messages.Count;

                    for (int index = 0; index < messageCount; index++)
                    {
                        IAnyTriplet<long, string, bool> anyTriplet =
                            messages[index];

                        if (anyTriplet == null)
                            continue;

                        string formatted = GetString(anyTriplet);

                        if (formatted == null)
                            continue;

                        string message = anyTriplet.Y;
                        bool newLine = anyTriplet.Z;
                        long duplicateCount;

                        if ((messageCounts != null) && messageCounts.TryGetValue(
                                formatted, out duplicateCount))
                        {
                            if (duplicateCount == Count.Invalid)
                                continue;

                            if (duplicateCount > 1)
                            {
                                duplicateCount--;

                                WriteToTraceListener(String.Format(
                                    formatString, message, duplicateCount,
                                    duplicateCount > 1 ? "times" : "time"),
                                    newLine); /* throw */

                                messageCounts[formatted] = Count.Invalid;
                                wrote = true;
                            }
                            else
                            {
                                WriteToTraceListener(message, newLine); /* throw */
                                wrote = true;
                            }
                        }
                        else
                        {
                            WriteToTraceListener(message, newLine); /* throw */
                            wrote = true;
                        }
                    }

                    messages.Clear();

                    return wrote;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method empties the message buffer when it has reached its
            /// maximum capacity.
            /// </summary>
            /// <returns>
            /// True if any messages were written; otherwise, false.
            /// </returns>
            protected virtual bool MaybeEmptyMessages()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (messages == null)
                        return false;

                    if (maximumCapacity < 0)
                        return false;

                    if (messages.Count < maximumCapacity)
                        return false;
                }

                return EmptyMessages();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method adds the specified message to the message buffer.
            /// </summary>
            /// <param name="message">
            /// The message to add.
            /// </param>
            /// <param name="newLine">
            /// Non-zero if the message was written with a line terminator.
            /// </param>
            protected virtual void AddMessage(
                string message,
                bool newLine
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (messages == null)
                        return;

                    messages.Add(new AnyTriplet<long, string, bool>(
                        GetNextId(), message, newLine));
                }
            }
            #endregion
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IBufferedTraceListener Members
            /// <summary>
            /// This method empties any buffered messages, when appropriate, and
            /// then flushes the inner trace listener.
            /// </summary>
            /// <returns>
            /// True if the buffers were flushed; otherwise, false.
            /// </returns>
            public virtual bool MaybeFlushBuffers()
            {
                CheckDisposed();

                /* NO RESULT */
                CheckMessagesAndFlushTraceListener();

                return true;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Diagnostics.TraceListener Overrides
            /// <summary>
            /// This method empties any buffered messages, when appropriate,
            /// flushes the inner trace listener, and then closes it.
            /// </summary>
            public override void Close()
            {
                CheckDisposed();

                if (!IsBufferingDisabled() && IsEmptyOnClose())
                {
                    if (EmptyMessages() || IsIgnoreEmptyOnClose())
                    {
                        /* IGNORED */
                        MaybeFlushTraceListener(false);
                    }
                }

                /* IGNORED */
                MaybeFlushTraceListener(true);

                /* NO RESULT */
                CloseTraceListener(true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method empties any buffered messages, when appropriate, and
            /// then flushes the inner trace listener.
            /// </summary>
            public override void Flush()
            {
                CheckDisposed();

                /* NO RESULT */
                CheckMessagesAndFlushTraceListener();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method buffers the specified message, writing it to the inner
            /// trace listener when buffering is disabled.
            /// </summary>
            /// <param name="message">
            /// The message to write.
            /// </param>
            public /* abstract */ override void Write(
                string message
                )
            {
                CheckDisposed();

                if (IsBufferingDisabled())
                {
                    WriteTraceListener(message);
                }
                else
                {
                    AddMessage(message, false);

                    if (MaybeEmptyMessages())
                    {
                        /* IGNORED */
                        MaybeFlushTraceListener(false);
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method buffers the specified message, followed by a line
            /// terminator, writing it to the inner trace listener when buffering
            /// is disabled.
            /// </summary>
            /// <param name="message">
            /// The message to write.
            /// </param>
            public /* abstract */ override void WriteLine(
                string message
                )
            {
                CheckDisposed();

                if (IsBufferingDisabled())
                {
                    WriteLineTraceListener(message);
                }
                else
                {
                    AddMessage(message, true);

                    if (MaybeEmptyMessages())
                    {
                        /* IGNORED */
                        MaybeFlushTraceListener(false);
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether this trace listener is thread
            /// safe.
            /// </summary>
            public override bool IsThreadSafe
            {
                get { CheckDisposed(); return true; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method writes all buffered messages to the specified file.
            /// </summary>
            /// <param name="fileName">
            /// The path of the file to write to.
            /// </param>
            /// <param name="encoding">
            /// The character encoding to use.  This parameter may be null.
            /// </param>
            /// <param name="append">
            /// Non-zero to append to the file; otherwise, the file is overwritten.
            /// </param>
            /// <param name="clear">
            /// Non-zero to clear the message buffer after writing.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, an appropriate
            /// error code.
            /// </returns>
            public ReturnCode Dump(
                string fileName,
                Encoding encoding,
                bool append,
                bool clear,
                ref Result error
                )
            {
                CheckDisposed();

                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (messages == null)
                    {
                        error = "no messages available";
                        return ReturnCode.Error;
                    }

                    try
                    {
                        using (StreamWriter streamWriter = GetStreamWriter(
                                fileName, encoding, append))
                        {
                            foreach (IAnyTriplet<long, string, bool> anyTriplet
                                    in messages)
                            {
                                if (anyTriplet == null)
                                    continue;

                                string messageString = GetString(
                                    anyTriplet, false);

                                if (messageString == null)
                                    continue;

                                if (anyTriplet.Z)
                                    streamWriter.WriteLine(messageString);
                                else
                                    streamWriter.Write(messageString);
                            }

                            streamWriter.Flush();
                        }

                        if (clear)
                            messages.Clear();

                        return ReturnCode.Ok;
                    }
                    catch (Exception e)
                    {
                        error = e;
                    }
                }

                return ReturnCode.Error;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(BufferedTraceListener).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method disposes of the message buffer.
            /// </summary>
            private void DisposeMessages()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (messages != null)
                    {
                        messages.Clear();
                        messages = null;
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method disposes of the inner trace listener, when it is owned
            /// by this trace listener.
            /// </summary>
            /// <param name="resetTakeOwnership">
            /// Non-zero to disable taking ownership of the inner trace listener
            /// after disposing of it.
            /// </param>
            private void DisposeTraceListener(
                bool resetTakeOwnership
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (traceListener != null)
                    {
                        if (IsTakeOwnership())
                        {
                            traceListener.Dispose();

                            if (resetTakeOwnership)
                                DisableTakeOwnership();
                        }

                        traceListener = null;
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The number of nested calls to the dispose method currently in
            /// progress.
            /// </summary>
            private int disposeLevels;
            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected override void Dispose(
                bool disposing
                )
            {
                int levels = Interlocked.Increment(ref disposeLevels);

                try
                {
                    if (levels == 1)
                    {
                        try
                        {
                            if (!disposed)
                            {
                                if (disposing)
                                {
                                    ////////////////////////////////////
                                    // dispose managed resources here...
                                    ////////////////////////////////////

                                    /* NO RESULT */
                                    DebugOps.RemoveTraceListener(this);

                                    ////////////////////////////////////

                                    DisposeMessages();
                                    DisposeTraceListener(true);
                                }
                            }
                        }
                        finally
                        {
                            base.Dispose(disposing);

                            disposed = true;
                        }
                    }
                }
                finally
                {
                    Interlocked.Decrement(ref disposeLevels);
                }

                //////////////////////////////////////
                // release unmanaged resources here...
                //////////////////////////////////////
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~BufferedTraceListener()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

