        #region ProvideEntropy Test Class
        /// <summary>
        /// This class implements a source of entropy backed by a random
        /// number generator, used to exercise the cryptographic subsystem.
        /// </summary>
        [ObjectId("a919e528-368a-4f65-923d-dae131432c4c")]
        public class ProvideEntropy : IProvideEntropy, IDisposable
        {
            #region Private Data
            /// <summary>
            /// The random number generator used as the source of entropy.
            /// </summary>
            private RandomNumberGenerator randomNumberGenerator;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
