            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="randomNumberGenerator">
            /// The random number generator to use as the source of entropy.
            /// </param>
            public ProvideEntropy(
                RandomNumberGenerator randomNumberGenerator /* in */
                )
            {
                this.randomNumberGenerator = randomNumberGenerator;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method throws <see cref="TraceException" /> if this object
            /// instance has not been initialized.
            /// </summary>
            private void CheckInitialized()
            {
                if (randomNumberGenerator == null)
                {
                    throw new TraceException(String.Format(
                        "instance {0} of {1} is closed",
                        FormatOps.WrapHashCode(this),
                        typeof(ProvideEntropy)));
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method initializes the source of entropy, if it has not already
            /// been initialized.
            /// </summary>
            private void PrivateInitialize()
            {
                if (randomNumberGenerator == null)
                    randomNumberGenerator = new RNGCryptoServiceProvider();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the source of entropy.
            /// </summary>
            private void PrivateReset()
            {
                /* IGNORED */
                ObjectOps.TryDisposeOrTrace<RandomNumberGenerator>(
                    ref randomNumberGenerator);

                randomNumberGenerator = null;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method initializes this object instance.
            /// </summary>
            public void Initialize()
            {
                CheckDisposed();

                PrivateInitialize();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets this object instance, releasing its source of
            /// entropy.
            /// </summary>
            public void Reset()
            {
                CheckDisposed();

                PrivateReset();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IProvideEntropy Members
            /// <summary>
            /// This method fills the specified array with random bytes.
            /// </summary>
            /// <param name="data">
            /// Upon return, this parameter will contain the random bytes.
            /// </param>
            public void GetBytes(
                byte[] data /* in, out */
                )
            {
                CheckDisposed();
                CheckInitialized();

                if (randomNumberGenerator != null)
                    randomNumberGenerator.GetBytes(data);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method fills the specified array with random, non-zero bytes.
            /// </summary>
            /// <param name="data">
            /// Upon return, this parameter will contain the random bytes.
            /// </param>
            public void GetNonZeroBytes(
                byte[] data /* in, out */
                )
            {
                CheckDisposed();
                CheckInitialized();

                if (randomNumberGenerator != null)
                    randomNumberGenerator.GetNonZeroBytes(data);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method fills the specified array with random bytes.
            /// </summary>
            /// <param name="data">
            /// Upon return, this parameter will contain the random bytes.
            /// </param>
            public void GetBytes(
                ref byte[] data /* in, out */
                )
            {
                CheckDisposed();
                CheckInitialized();

                if (randomNumberGenerator != null)
                    randomNumberGenerator.GetBytes(data);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method fills the specified array with random, non-zero bytes.
            /// </summary>
            /// <param name="data">
            /// Upon return, this parameter will contain the random bytes.
            /// </param>
            public void GetNonZeroBytes(
                ref byte[] data /* in, out */
                )
            {
                CheckDisposed();
                CheckInitialized();

                if (randomNumberGenerator != null)
                    randomNumberGenerator.GetNonZeroBytes(data);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources used by this object instance.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, null))
                {
                    throw new ObjectDisposedException(
                        typeof(ProvideEntropy).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
