        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region RandomTextReader Test Class
        /// <summary>
        /// This class implements a text reader that produces a stream of
        /// pseudo-random characters, used to exercise the I/O subsystem.
        /// </summary>
        [ObjectId("e3e81934-9413-4e89-b042-08363a08f2b2")]
        public class RandomTextReader : TextReader
        {
            #region Private Constants
            //
            // HACK: This is purposely not read-only.
            //
            /// <summary>
            /// The default number of characters produced by an instance of this
            /// class when no length has been specified.
            /// </summary>
            private static int DefaultLength = 16;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The source of entropy used to produce random characters.
            /// </summary>
            private IProvideEntropy provideEntropy;
            /// <summary>
            /// The number of characters remaining to be produced; a non-positive
            /// value indicates the default length should be used.
            /// </summary>
            private int length;
            /// <summary>
            /// The value of the next character to be read, cached by a previous
            /// call to the Peek method; null if no value has been cached.
            /// </summary>
            private int? peek;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Protected Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="length">
            /// The number of characters to produce.
            /// </param>
            protected RandomTextReader(
                int length /* in */
                )
                : base()
            {
                this.length = length;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="provideEntropy">
            /// The source of entropy used to produce random characters.  This
            /// parameter may be null.
            /// </param>
            /// <param name="length">
            /// The number of characters to produce.
            /// </param>
            protected RandomTextReader(
                IProvideEntropy provideEntropy, /* in: OPTIONAL */
                int length                      /* in */
                )
                : base()
            {
                this.provideEntropy = provideEntropy;
                this.length = length;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Static "Factory" Methods
            /// <summary>
            /// This method creates a new instance of this class.
            /// </summary>
            /// <param name="length">
            /// The number of characters to produce.
            /// </param>
            /// <returns>
            /// The newly created text reader.
            /// </returns>
            public static TextReader Create(
                int length /* in */
                )
            {
                return new RandomTextReader(length);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a new instance of this class.
            /// </summary>
            /// <param name="provideEntropy">
            /// The source of entropy used to produce random characters.  This
            /// parameter may be null.
            /// </param>
            /// <param name="length">
            /// The number of characters to produce.
            /// </param>
            /// <returns>
            /// The newly created text reader.
            /// </returns>
            public static TextReader Create(
                IProvideEntropy provideEntropy, /* in: OPTIONAL */
                int length                      /* in */
                )
            {
                return new RandomTextReader(provideEntropy, length);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Protected IProvideEntropy Methods
            /// <summary>
            /// This method throws <see cref="TraceException" /> if this text reader
            /// has not been initialized.
            /// </summary>
            protected virtual void CheckInitialized()
            {
                if (provideEntropy == null)
                {
                    throw new TraceException(String.Format(
                        "instance {0} of {1} is closed",
                        FormatOps.WrapHashCode(this),
                        typeof(RandomTextReader)));
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates the random number generator used as the source
            /// of entropy.
            /// </summary>
            /// <returns>
            /// The newly created random number generator.
            /// </returns>
            protected virtual RandomNumberGenerator GetRandomNumberGenerator()
            {
                return new RNGCryptoServiceProvider();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method initializes the source of entropy, if it has not already
            /// been initialized.
            /// </summary>
            protected virtual void MaybeInitialize()
            {
                if (provideEntropy == null)
                {
                    RandomNumberGenerator randomNumberGenerator =
                        GetRandomNumberGenerator();

                    if (randomNumberGenerator != null)
                    {
                        provideEntropy = new ProvideEntropy(
                            randomNumberGenerator);
                    }
                    else
                    {
                        provideEntropy = new ProvideEntropy();
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method disposes of the source of entropy, if any.
            /// </summary>
            protected virtual void MaybeDispose()
            {
                /* IGNORED */
                ObjectOps.TryDisposeOrTrace<IProvideEntropy>(
                    ref provideEntropy);

                provideEntropy = null;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            //
            // HACK: This method does not consume any of the stated
            //       capacity for this instance.
            //
            /// <summary>
            /// This method returns a random count, modulo the effective length,
            /// suitable for use as the length of a randomly generated line.
            /// </summary>
            /// <returns>
            /// A random count.
            /// </returns>
            private int GetRandomCount()
            {
                byte[] data = new byte[sizeof(int)];

                if (provideEntropy != null)
                    provideEntropy.GetBytes(data);

                int count = BitConverter.ToInt32(data, 0);

                if (count == Int32.MinValue)
                    count = Int32.MaxValue;
                else if (count < 0)
                    count = -count;

                return count % GetLength();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the effective length, using the default length
            /// when none has been configured.
            /// </summary>
            /// <returns>
            /// The effective length.
            /// </returns>
            private int GetLength()
            {
                return (length > 0) ? length : DefaultLength;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method fills the specified buffer with random data.
            /// </summary>
            /// <param name="data">
            /// Upon return, this parameter will contain the random data.
            /// </param>
            /// <param name="consume">
            /// The number of characters to consume from the configured length.
            /// </param>
            /// <param name="crLf">
            /// If not null, this value is used as a replacement for any carriage
            /// return or line feed bytes in the random data.  This parameter may
            /// be null.
            /// </param>
            private void PrivateRead(
                byte[] data, /* in, out */
                int consume, /* in */
                byte? crLf   /* in: OPTIONAL */
                )
            {
                if ((data != null) && (provideEntropy != null))
                {
                    //
                    // NOTE: If the "crLf" parameter is not null, its
                    //       value will be used as a replacement for
                    //       carriage return -AND- line feed values,
                    //       e.g. for use by ReadLine methods.
                    //
                    if (crLf != null)
                    {
                        int dataLength = data.Length;
                        byte[] localData = new byte[dataLength];

                        provideEntropy.GetBytes(localData);

                        for (int index = 0; index < dataLength; index++)
                        {
                            byte byteValue = localData[index];

                            if ((byteValue == Characters.CarriageReturn) ||
                                (byteValue == Characters.LineFeed))
                            {
                                localData[index] = (byte)crLf;
                            }
                        }

                        Array.Copy(localData, data, dataLength);
                    }
                    else
                    {
                        provideEntropy.GetBytes(data);
                    }

                    if (length > 0)
                        length -= consume;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method fills the specified buffer with random characters.
            /// </summary>
            /// <param name="data">
            /// Upon return, this parameter will contain the random characters.
            /// </param>
            /// <param name="startIndex">
            /// The index into the buffer at which to begin storing characters.
            /// </param>
            /// <param name="count">
            /// On input, the maximum number of characters to produce; upon return,
            /// the number of characters actually produced.
            /// </param>
            private void PrivateRead(
                char[] data,    /* in, out */
                int startIndex, /* in */
                ref int count   /* in, out */
                )
            {
                if ((data != null) && (provideEntropy != null))
                {
                    bool success = false;

                    try
                    {
                       int newCount = count;

                       if ((length > 0) && (newCount > length))
                           newCount = length;

                        byte[] localData = new byte[newCount];

                        provideEntropy.GetBytes(localData);

                        //
                        // NOTE: Ideally, an overload of Array.Copy
                        //       could be used here; however, that
                        //       is frustrated by mismatched types;
                        //       the random number generator gives
                        //       bytes, not chars.
                        //
                        // HACK: This will only produce chars with
                        //       values that will fit into a byte,
                        //       which is fine for our use cases.
                        //
                        int dataLength = data.Length;
                        int dataIndex = startIndex;

                        for (int index = 0; index < newCount; index++)
                        {
                            if ((dataIndex < 0) ||
                                (dataIndex >= dataLength))
                            {
                                break;
                            }

                            data[dataIndex++] = ConversionOps.ToChar(
                                localData[index]);
                        }

                        count = newCount;
                        success = true;
                    }
                    finally
                    {
                        if (success && (length > 0))
                        {
                            if (count > length)
                                length = 0; /* CONSUME ALL */
                            else
                                length -= count; /* CONSUME X */
                        }
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method validates the specified buffer and then fills it with
            /// random characters, throwing an exception if the buffer is invalid.
            /// </summary>
            /// <param name="buffer">
            /// Upon return, this parameter will contain the random characters.
            /// </param>
            /// <param name="startIndex">
            /// The index into the buffer at which to begin storing characters.
            /// </param>
            /// <param name="count">
            /// On input, the maximum number of characters to produce; upon return,
            /// the number of characters actually produced.
            /// </param>
            private void PrivateReadOrThrow(
                char[] buffer,  /* in, out */
                int startIndex, /* in */
                ref int count   /* in, out */
                )
            {
                if (buffer == null)
                    throw new ArgumentNullException("buffer");

                int bufferLength = buffer.Length;

                if (bufferLength == 0)
                {
                    if (count == 0)
                        return;

                    throw new ArgumentException(
                        "no space in buffer");
                }

                if ((bufferLength - startIndex) < count)
                {
                    throw new ArgumentOutOfRangeException(
                        "not enough space in buffer");
                }

                PrivateRead(buffer, startIndex, ref count);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method initializes this text reader.
            /// </summary>
            public virtual void Initialize()
            {
                CheckDisposed();

                MaybeInitialize();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets this text reader, releasing its source of
            /// entropy.
            /// </summary>
            public virtual void Reset()
            {
                CheckDisposed();

                MaybeDispose();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.IO.TextReader Overrides
            /// <summary>
            /// This method closes this text reader, releasing its source of
            /// entropy.
            /// </summary>
            public override void Close()
            {
                CheckDisposed();
                CheckInitialized();

                MaybeDispose();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the next available character without consuming
            /// it.
            /// </summary>
            /// <returns>
            /// The next available character, or a negative value if no more
            /// characters are available.
            /// </returns>
            public override int Peek()
            {
                CheckDisposed();
                CheckInitialized();

                if (peek != null)
                    return (int)peek;

                if (length == 0)
                    return ChannelStream.EndOfFile;

                byte[] data = new byte[sizeof(int)];

                PrivateRead(data, data.Length, null);

                peek = BitConverter.ToInt32(data, 0);
                return (int)peek;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reads the next character and consumes it.
            /// </summary>
            /// <returns>
            /// The next character, or a negative value if no more characters are
            /// available.
            /// </returns>
            public override int Read()
            {
                CheckDisposed();
                CheckInitialized();

                if (peek != null)
                {
                    int read = (int)peek;

                    if (length > 0)
                        length--;  /* CONSUME 1 */

                    peek = null;
                    return read;
                }

                if (length == 0)
                    return ChannelStream.EndOfFile;

                byte[] data = new byte[sizeof(int)];

                PrivateRead(data, data.Length, null);

                return BitConverter.ToInt32(data, 0);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reads up to the specified number of characters into the
            /// specified buffer.
            /// </summary>
            /// <param name="buffer">
            /// Upon return, this parameter will contain the characters read.
            /// </param>
            /// <param name="index">
            /// The index into the buffer at which to begin storing characters.
            /// </param>
            /// <param name="count">
            /// The maximum number of characters to read.
            /// </param>
            /// <returns>
            /// The number of characters read.
            /// </returns>
            public override int Read(
                char[] buffer, /* in, out */
                int index,     /* in */
                int count      /* in */
                )
            {
                CheckDisposed();
                CheckInitialized();

                PrivateReadOrThrow(buffer, index, ref count);
                return count;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reads up to the specified number of characters into the
            /// specified buffer.
            /// </summary>
            /// <param name="buffer">
            /// Upon return, this parameter will contain the characters read.
            /// </param>
            /// <param name="index">
            /// The index into the buffer at which to begin storing characters.
            /// </param>
            /// <param name="count">
            /// The maximum number of characters to read.
            /// </param>
            /// <returns>
            /// The number of characters read.
            /// </returns>
            public override int ReadBlock(
                char[] buffer, /* in, out */
                int index,     /* in */
                int count      /* in */
                )
            {
                CheckDisposed();
                CheckInitialized();

                PrivateReadOrThrow(buffer, index, ref count);
                return count;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reads a line of random characters.
            /// </summary>
            /// <returns>
            /// A line of random characters.
            /// </returns>
            public override string ReadLine()
            {
                CheckDisposed();
                CheckInitialized();

                int count = GetRandomCount();
                byte[] data = new byte[count];

                PrivateRead(data, data.Length, 0);

                return ArrayOps.ToRawString(data);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reads all remaining random characters.
            /// </summary>
            /// <returns>
            /// All remaining random characters.
            /// </returns>
            public override string ReadToEnd()
            {
                CheckDisposed();
                CheckInitialized();

                int count = GetLength();
                byte[] data = new byte[count];

                PrivateRead(data, data.Length, null);

                return ArrayOps.ToRawString(data);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, null))
                {
                    throw new ObjectDisposedException(
                        typeof(RandomTextReader).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected override void Dispose(
                bool disposing
                )
            {
                try
                {
                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            MaybeDispose();
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////
                    }
                }
                finally
                {
                    base.Dispose(disposing);

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~RandomTextReader()
            {
                Dispose(false);
            }
            #endregion
        }
