        public class ScriptTraceListener : TraceListener
        {
            #region Private Data
            /// <summary>
            /// The number of trace operations currently in progress on this
            /// object instance.
            /// </summary>
            private int traceLevels = 0;
            /// <summary>
            /// The number of times the interpreter lock could not be acquired
            /// while processing a trace operation.
            /// </summary>
            private int traceLockError = 0;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
