        #region TraceException Test Class
        /// <summary>
        /// This class implements an exception that counts how many times it has
        /// been created, used to exercise the tracing subsystem.
        /// </summary>
#if SERIALIZATION
        [Serializable()]
#endif
        [ObjectId("265edb17-053e-4cb6-ac68-ccb15b126bb2")]
        public class TraceException : ScriptException
        {
            #region Private Static Data
            /// <summary>
            /// The number of times an instance of this class has been created.
            /// </summary>
            private static long count;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public TraceException()
                : base()
            {
                IncrementCount();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="message">
            /// The message that describes the error.
            /// </param>
            public TraceException(
                string message
                )
                : base(message)
            {
                IncrementCount();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="message">
            /// The message that describes the error.
            /// </param>
            /// <param name="innerException">
            /// The exception that is the cause of this exception, if any.
            /// </param>
            public TraceException(
                string message,
                Exception innerException
                )
                : base(message, innerException)
            {
                IncrementCount();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="code">
            /// The return code associated with this exception.
            /// </param>
            /// <param name="result">
            /// The result associated with this exception.
            /// </param>
            public TraceException(
                ReturnCode code,
                Result result
                )
                : base(code, result)
            {
                IncrementCount();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="code">
            /// The return code associated with this exception.
            /// </param>
            /// <param name="result">
            /// The result associated with this exception.
            /// </param>
            /// <param name="innerException">
            /// The exception that is the cause of this exception, if any.
            /// </param>
            public TraceException(
                ReturnCode code,
                Result result,
                Exception innerException
                )
                : base(code, result, innerException)
            {
                IncrementCount();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Protected Constructors
#if SERIALIZATION
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="info">
            /// The object that holds the serialized object data.
            /// </param>
            /// <param name="context">
            /// The contextual information about the source or destination.
            /// </param>
            protected TraceException(
                SerializationInfo info,
                StreamingContext context
                )
                : base(info, context)
            {
                // do nothing.
            }
#endif
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Protected Methods
            /// <summary>
            /// This method increments the count of how many times an instance
            /// of this class has been created.
            /// </summary>
            protected void IncrementCount()
            {
                Interlocked.Increment(ref count);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Introspection Support Methods
            //
            // NOTE: Used by the _Hosts.Default.BuildEngineInfoList method.
            //
            /// <summary>
            /// This method adds introspection information about this class to
            /// the specified list.
            /// </summary>
            /// <param name="list">
            /// The list to add the introspection information to.  This
            /// parameter may be null.
            /// </param>
            /// <param name="detailFlags">
            /// The flags used to control the level of detail included in the
            /// introspection information.
            /// </param>
            public static new void AddInfo(
                StringPairList list,    /* in, out */
                DetailFlags detailFlags /* in */
                )
            {
                if (list == null)
                    return;

                bool empty = HostOps.HasEmptyContent(detailFlags);
                StringPairList localList = new StringPairList();

                if (empty || (count != 0))
                    localList.Add("Count", count.ToString());

                if (localList.Count > 0)
                {
                    list.Add((IPair<string>)null);
                    list.Add("Trace Exception");
                    list.Add((IPair<string>)null);
                    list.Add(localList);
                }
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region ThrowTraceListener Test Class
        /// <summary>
        /// This class implements a trace listener that throws an exception when
        /// selected trace operations are performed, used to exercise the
        /// tracing subsystem.
        /// </summary>
        [ObjectId("a786ad1f-2797-4f8e-a86a-fd9b8e675036")]
        public class ThrowTraceListener : TraceListener
        {
            #region Private Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            private ThrowTraceListener()
            {
                // do nothing.
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// Non-zero if an exception should be thrown when the trace
            /// listener is closed.
            /// </summary>
            private bool throwOnClose;
            /// <summary>
            /// Gets or sets a value indicating whether an exception should be
            /// thrown when the trace listener is closed.
            /// </summary>
            public virtual bool ThrowOnClose
            {
                get { CheckDisposed(); return throwOnClose; }
                set { CheckDisposed(); throwOnClose = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Non-zero if an exception should be thrown when the trace
            /// listener is flushed.
            /// </summary>
            private bool throwOnFlush;
            /// <summary>
            /// Gets or sets a value indicating whether an exception should be
            /// thrown when the trace listener is flushed.
            /// </summary>
            public virtual bool ThrowOnFlush
            {
                get { CheckDisposed(); return throwOnFlush; }
                set { CheckDisposed(); throwOnFlush = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Non-zero if an exception should be thrown when a message is
            /// written to the trace listener.
            /// </summary>
            private bool throwOnWrite;
            /// <summary>
            /// Gets or sets a value indicating whether an exception should be
            /// thrown when a message is written to the trace listener.
            /// </summary>
            public virtual bool ThrowOnWrite
            {
                get { CheckDisposed(); return throwOnWrite; }
                set { CheckDisposed(); throwOnWrite = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Non-zero if an exception should be thrown when a message line is
            /// written to the trace listener.
            /// </summary>
            private bool throwOnWriteLine;
            /// <summary>
            /// Gets or sets a value indicating whether an exception should be
            /// thrown when a message line is written to the trace listener.
            /// </summary>
            public virtual bool ThrowOnWriteLine
            {
                get { CheckDisposed(); return throwOnWriteLine; }
                set { CheckDisposed(); throwOnWriteLine = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Static "Factory" Methods
            /// <summary>
            /// This method creates a new instance of this class.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created trace listener.
            /// </returns>
            public static TraceListener Create(
                ref Result error /* NOT USED */
                )
            {
                return new ThrowTraceListener();
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Diagnostics.TraceListener Overrides
            /// <summary>
            /// This method closes the trace listener, throwing an exception
            /// when so configured.
            /// </summary>
            public override void Close()
            {
                CheckDisposed();

                if (ThrowOnClose)
                    throw new TraceException();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method flushes the trace listener, throwing an exception
            /// when so configured.
            /// </summary>
            public override void Flush()
            {
                CheckDisposed();

                if (ThrowOnFlush)
                    throw new TraceException();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes the specified message, throwing an exception
            /// when so configured.
            /// </summary>
            /// <param name="message">
            /// The message to write.
            /// </param>
            public /* abstract */ override void Write(
                string message
                )
            {
                CheckDisposed();

                if (ThrowOnWrite)
                    throw new TraceException();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes the specified message, followed by a line
            /// terminator, throwing an exception when so configured.
            /// </summary>
            /// <param name="message">
            /// The message to write.
            /// </param>
            public /* abstract */ override void WriteLine(
                string message
                )
            {
                CheckDisposed();

                if (ThrowOnWriteLine)
                    throw new TraceException();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether this trace listener is thread
            /// safe.
            /// </summary>
            public override bool IsThreadSafe
            {
                get { CheckDisposed(); return true; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(ThrowTraceListener).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected override void Dispose(
                bool disposing
                )
            {
                try
                {
                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            throwOnClose = false;
                            throwOnFlush = false;
                            throwOnWrite = false;
                            throwOnWriteLine = false;

                            ////////////////////////////////////

                            /* NO RESULT */
                            DebugOps.RemoveTraceListener(this);
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////
                    }
                }
                finally
                {
                    base.Dispose(disposing);

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~ThrowTraceListener()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region IBufferedTraceListener
        /// <summary>
        /// This interface defines a trace listener that supports flushing any
        /// buffered trace output.
        /// </summary>
        [ObjectId("f6ed23fe-6efa-4d07-b48a-ab215dc288b0")]
        public interface IBufferedTraceListener
        {
            /// <summary>
            /// This method flushes any buffered trace output.
            /// </summary>
            /// <returns>
            /// True if the buffers were flushed; otherwise, false.
            /// </returns>
            bool MaybeFlushBuffers();
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region DatabaseTraceListener Test Class
#if DATA
        /// <summary>
        /// This class implements a trace listener that writes trace output to a
        /// database table, used to exercise the tracing subsystem.
        /// </summary>
        [ObjectId("513e5392-29d9-4a84-a7c2-2407122b5eac")]
        public class DatabaseTraceListener : TraceListener, IBufferedTraceListener
        {
            #region Private Constants
            //
            // NOTE: This is the initial buffer capacity for trace message
            //       output.  For optimal performance, it should be large
            //       enough for at least one entire fully detailed logical
            //       line of output.
            //
            /// <summary>
            /// The initial buffer capacity, in bytes, used for trace message
            /// output.
            /// </summary>
            private static readonly int BufferCapacity = 20480; /* 20KB */

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Transaction Isolation Level (System.Data)
            //
            // NOTE: This is the isolation level when starting a database
            //       transaction to be used for inserting trace events in
            //       the target database.
            //
            /// <summary>
            /// The transaction isolation level used when starting a database
            /// transaction to insert trace events.
            /// </summary>
            private static readonly IsolationLevel DefaultIsolationLevel =
                IsolationLevel.Unspecified;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region SQL DML Statements
            //
            // NOTE: This is used to insert a single row with two columns,
            //       one for the new trace message and one for the new
            //       trace category.  It must work with any SQL database.
            //
            /// <summary>
            /// The SQL command text template used to insert a single trace
            /// event row into the target database table.
            /// </summary>
            private static readonly string InsertCommandText =
                "INSERT INTO {0} ({1}, {2}) VALUES ({3}, {4});";
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDbDataParameter Names
            /// <summary>
            /// The name of the command parameter that holds the trace message.
            /// </summary>
            private static readonly string MessageParameterName = "@message";
            /// <summary>
            /// The name of the command parameter that holds the trace category.
            /// </summary>
            private static readonly string CategoryParameterName = "@category";
            #endregion
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The object used to synchronize access to this object instance.
            /// </summary>
            private readonly object syncRoot = new object();
            /// <summary>
            /// The number of trace operations currently in progress on this
            /// object instance.
            /// </summary>
            private int traceLevels = 0;
            /// <summary>
            /// The database connection used to insert trace events.
            /// </summary>
            private IDbConnection connection;
            /// <summary>
            /// The database transaction used to insert trace events.
            /// </summary>
            private IDbTransaction transaction;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The buffer used to accumulate trace message output prior to
            /// writing it to the database.
            /// </summary>
            private StringBuilder buffer;
            /// <summary>
            /// The trace category associated with the buffered trace message
            /// output.
            /// </summary>
            private string bufferCategory;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            private DatabaseTraceListener()
            {
                buffer = StringBuilderFactory.CreateNoCache(BufferCapacity); /* EXEMPT */
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context that the database connections will be
            /// created in.
            /// </param>
            /// <param name="dbConnectionType">
            /// The type of database connection to create.
            /// </param>
            /// <param name="publicKeyToken">
            /// The public key token of the assembly that contains the database
            /// connection type.  This parameter may be null.
            /// </param>
            /// <param name="assemblyFileName">
            /// The file name of the assembly that contains the database
            /// connection type.  This parameter may be null.
            /// </param>
            /// <param name="typeName">
            /// The name of the database connection type.  This parameter may be
            /// null.
            /// </param>
            /// <param name="type">
            /// The database connection type.  This parameter may be null.
            /// </param>
            /// <param name="connectionString">
            /// The connection string used to connect to the target database.
            /// </param>
            /// <param name="tableName">
            /// The name of the table that trace events are inserted into.
            /// </param>
            /// <param name="messageColumnName">
            /// The name of the column that holds the trace message.
            /// </param>
            /// <param name="categoryColumnName">
            /// The name of the column that holds the trace category.
            /// </param>
            /// <param name="autoFlush">
            /// Non-zero if the database transaction should be committed after
            /// each trace event is inserted.
            /// </param>
            /// <param name="autoCommit">
            /// Non-zero if the database transaction should be committed (rather
            /// than rolled back) when it is closed.
            /// </param>
            private DatabaseTraceListener(
                Interpreter interpreter,
                DbConnectionType dbConnectionType,
                byte[] publicKeyToken,
                string assemblyFileName,
                string typeName,
                Type type,
                string connectionString,
                string tableName,
                string messageColumnName,
                string categoryColumnName,
                bool autoFlush,
                bool autoCommit
                )
                : this()
            {
                this.interpreter = interpreter;
                this.dbConnectionType = dbConnectionType;
                this.publicKeyToken = publicKeyToken;
                this.assemblyFileName = assemblyFileName;
                this.typeName = typeName;
                this.type = type;
                this.connectionString = connectionString;
                this.tableName = tableName;
                this.messageColumnName = messageColumnName;
                this.categoryColumnName = categoryColumnName;
                this.autoFlush = autoFlush;
                this.autoCommit = autoCommit;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Static "Factory" Methods
            /// <summary>
            /// This method creates a new instance of this class.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context that the database connections will be
            /// created in.
            /// </param>
            /// <param name="dbConnectionType">
            /// The type of database connection to create.
            /// </param>
            /// <param name="publicKeyToken">
            /// The public key token of the assembly that contains the database
            /// connection type.  This parameter may be null.
            /// </param>
            /// <param name="assemblyFileName">
            /// The file name of the assembly that contains the database
            /// connection type.  This parameter may be null.
            /// </param>
            /// <param name="typeName">
            /// The name of the database connection type.  This parameter may be
            /// null.
            /// </param>
            /// <param name="type">
            /// The database connection type.  This parameter may be null.
            /// </param>
            /// <param name="connectionString">
            /// The connection string used to connect to the target database.
            /// </param>
            /// <param name="tableName">
            /// The name of the table that trace events are inserted into.
            /// </param>
            /// <param name="messageColumnName">
            /// The name of the column that holds the trace message.
            /// </param>
            /// <param name="categoryColumnName">
            /// The name of the column that holds the trace category.
            /// </param>
            /// <param name="autoFlush">
            /// Non-zero if the database transaction should be committed after
            /// each trace event is inserted.
            /// </param>
            /// <param name="autoCommit">
            /// Non-zero if the database transaction should be committed (rather
            /// than rolled back) when it is closed.
            /// </param>
            /// <returns>
            /// The newly created trace listener.
            /// </returns>
            public static TraceListener Create(
                Interpreter interpreter,
                DbConnectionType dbConnectionType,
                byte[] publicKeyToken,
                string assemblyFileName,
                string typeName,
                Type type,
                string connectionString,
                string tableName,
                string messageColumnName,
                string categoryColumnName,
                bool autoFlush,
                bool autoCommit
                )
            {
                return new DatabaseTraceListener(
                    interpreter, dbConnectionType, publicKeyToken,
                    assemblyFileName, typeName, type, connectionString,
                    tableName, messageColumnName, categoryColumnName,
                    autoFlush, autoCommit);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method creates a database connection using the configured
            /// connection settings.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created database connection, or null if it could not
            /// be created.
            /// </returns>
            private IDbConnection CreateDbConnection(
                ref Result error
                )
            {
                IDbConnection connection = null;

                if (DataOps.CreateDbConnection(
                        interpreter, dbConnectionType, publicKeyToken,
                        connectionString, assemblyFileName, typeName,
                        typeName, type,
                        ObjectOps.GetDefaultObjectValueFlags(),
                        ref connection, ref error) == ReturnCode.Ok)
                {
                    return connection;
                }

                return null;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method opens the database connection, complaining if it
            /// cannot be opened.
            /// </summary>
            /// <returns>
            /// True if the database connection was opened; otherwise, false.
            /// </returns>
            private bool OpenDbConnection()
            {
                Result error = null;

                if (OpenDbConnection(ref error))
                    return true;
                else
                    Complain(ReturnCode.Error, error);

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method opens the database connection.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the database connection was opened; otherwise, false.
            /// </returns>
            private bool OpenDbConnection(
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (connection != null)
                        return true;

                    IDbConnection localConnection = CreateDbConnection(
                        ref error);

                    if (localConnection == null)
                        return false;

                    try
                    {
                        localConnection.Open(); /* throw */

                        connection = localConnection;
                        return true;
                    }
                    catch (Exception e)
                    {
                        error = e;
                    }

                    return false;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method begins a database transaction, complaining if it
            /// cannot be started.
            /// </summary>
            /// <returns>
            /// True if the database transaction was begun; otherwise, false.
            /// </returns>
            private bool BeginDbTransaction()
            {
                Result error = null;

                if (BeginDbTransaction(ref error))
                    return true;
                else
                    Complain(ReturnCode.Error, error);

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method begins a database transaction.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the database transaction was begun; otherwise, false.
            /// </returns>
            private bool BeginDbTransaction(
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (transaction != null)
                        return true;

                    if (connection == null)
                    {
                        error = "invalid connection";
                        return false;
                    }

                    IDbTransaction localTransaction = null;

                    try
                    {
                        localTransaction = connection.BeginTransaction(
                            DefaultIsolationLevel); /* throw */

                        if (localTransaction != null)
                        {
                            transaction = localTransaction;
                            return true;
                        }
                        else
                        {
                            error = "unable to begin transaction";
                        }
                    }
                    catch (Exception e)
                    {
                        error = e;
                    }

                    return false;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method inserts a single trace event row into the target
            /// database table, complaining on failure.
            /// </summary>
            /// <param name="message">
            /// The trace message to insert.
            /// </param>
            /// <param name="category">
            /// The trace category to insert.
            /// </param>
            /// <returns>
            /// True if the trace event row was inserted; otherwise, false.
            /// </returns>
            private bool InsertTraceRowIntoDb(
                string message,
                string category
                )
            {
                Result error = null;

                if (InsertTraceRowIntoDb(
                        message, category, ref error))
                {
                    return true;
                }
                else
                {
                    Complain(ReturnCode.Error, error);
                }

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method inserts a single trace event row into the target
            /// database table.
            /// </summary>
            /// <param name="message">
            /// The trace message to insert.
            /// </param>
            /// <param name="category">
            /// The trace category to insert.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the trace event row was inserted; otherwise, false.
            /// </returns>
            private bool InsertTraceRowIntoDb(
                string message,
                string category,
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (connection == null)
                    {
                        error = "invalid connection";
                        return false;
                    }

                    try
                    {
                        using (IDbCommand command = connection.CreateCommand())
                        {
                            if (command == null)
                            {
                                error = "could not create command";
                                return false;
                            }

                            DataOps.CheckIdentifier("TableName", tableName);

                            DataOps.CheckIdentifier(
                                "MessageColumnName", messageColumnName);

                            DataOps.CheckIdentifier(
                                "CategoryColumnName", categoryColumnName);

                            command.CommandText = DataOps.FormatCommandText(
                                InsertCommandText, 2, tableName,
                                messageColumnName, categoryColumnName,
                                MessageParameterName, CategoryParameterName);

                            IDbDataParameter messageParameter = command.CreateParameter();

                            if (messageParameter == null)
                            {
                                error = "could not create message parameter";
                                return false;
                            }

                            messageParameter.ParameterName = MessageParameterName;
                            messageParameter.Value = message;

                            IDbDataParameter categoryParameter = command.CreateParameter();

                            if (categoryParameter == null)
                            {
                                error = "could not create category parameter";
                                return false;
                            }

                            categoryParameter.ParameterName = CategoryParameterName;
                            categoryParameter.Value = category;

                            command.Parameters.Add(messageParameter);
                            command.Parameters.Add(categoryParameter);

                            if (command.ExecuteNonQuery() <= 0) /* Did we do anything? */
                            {
                                error = "trace event was not inserted";
                                return false;
                            }
                        }

                        return true;
                    }
                    catch (Exception e)
                    {
                        error = e;
                    }

                    return false;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method commits the database transaction, complaining on
            /// failure.
            /// </summary>
            /// <returns>
            /// True if the database transaction was committed; otherwise,
            /// false.
            /// </returns>
            private bool CommitDbTransaction()
            {
                Result error = null;

                if (CommitDbTransaction(ref error))
                    return true;
                else
                    Complain(ReturnCode.Error, error);

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method commits the database transaction.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the database transaction was committed; otherwise,
            /// false.
            /// </returns>
            private bool CommitDbTransaction(
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (transaction != null)
                    {
                        try
                        {
                            transaction.Commit(); /* throw */
                            transaction = null;

                            return true;
                        }
                        catch (Exception e)
                        {
                            error = e;
                        }
                    }
                    else
                    {
                        error = "invalid transaction";
                    }

                    return false;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method rolls back the database transaction, complaining on
            /// failure.
            /// </summary>
            /// <returns>
            /// True if the database transaction was rolled back; otherwise,
            /// false.
            /// </returns>
            private bool RollbackDbTransaction()
            {
                Result error = null;

                if (RollbackDbTransaction(ref error))
                    return true;
                else
                    Complain(ReturnCode.Error, error);

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method rolls back the database transaction.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the database transaction was rolled back; otherwise,
            /// false.
            /// </returns>
            private bool RollbackDbTransaction(
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (transaction != null)
                    {
                        try
                        {
                            transaction.Rollback(); /* throw */
                            transaction = null;

                            return true;
                        }
                        catch (Exception e)
                        {
                            error = e;
                        }
                    }
                    else
                    {
                        error = "invalid transaction";
                    }

                    return false;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method closes the database connection, complaining on
            /// failure.
            /// </summary>
            /// <returns>
            /// True if the database connection was closed; otherwise, false.
            /// </returns>
            private bool CloseDbConnection()
            {
                Result error = null;

                if (CloseDbConnection(ref error))
                    return true;
                else
                    Complain(ReturnCode.Error, error);

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method closes the database connection.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the database connection was closed; otherwise, false.
            /// </returns>
            private bool CloseDbConnection(
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (connection != null)
                    {
                        try
                        {
                            connection.Close(); /* throw */
                            connection = null;

                            return true;
                        }
                        catch (Exception e)
                        {
                            error = e;
                        }
                    }
                    else
                    {
                        error = "invalid connection";
                    }

                    return false;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method closes the database transaction, complaining on
            /// failure.
            /// </summary>
            /// <returns>
            /// True if the database transaction was closed; otherwise, false.
            /// </returns>
            private bool CloseDbTransaction()
            {
                Result error = null;

                if (CloseDbTransaction(ref error))
                    return true;
                else
                    Complain(ReturnCode.Error, error);

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method closes the database transaction, either committing
            /// or rolling it back based on the auto-commit setting.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the database transaction was closed; otherwise, false.
            /// </returns>
            private bool CloseDbTransaction(
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    return autoCommit ?
                        CommitDbTransaction(ref error) :
                        RollbackDbTransaction(ref error);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method updates the message buffer with the specified trace
            /// message, optionally producing the complete buffered message when
            /// a line is complete.
            /// </summary>
            /// <param name="message">
            /// On input, the trace message to buffer; upon return, this
            /// parameter may contain the complete buffered message.
            /// </param>
            /// <param name="category">
            /// The trace category associated with the message.
            /// </param>
            /// <param name="newLine">
            /// Non-zero if the trace message completes a line.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the message buffer was updated; otherwise, false.
            /// </returns>
            private bool MaybeUpdateMessageBuffer(
                ref string message, /* in, out */
                string category,    /* in */
                bool newLine,       /* in */
                ref Result error    /* out */
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (buffer == null)
                    {
                        if (newLine)
                        {
                            return true; /* LEGAL */
                        }
                        else
                        {
                            error = "buffer not available";
                            return false; /* ILLEGAL */
                        }
                    }

                    if (!newLine || (buffer.Length > 0))
                    {
                        if (!CheckCategory(category, ref error))
                            return false; /* ILLEGAL */

                        if (newLine)
                        {
                            if (message != null)
                                buffer.AppendLine(message);

                            message = buffer.ToString();
                        }
                        else if (message != null)
                        {
                            buffer.Append(message);
                        }
                    }

                    return true; /* LEGAL */
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the message buffer and its associated trace
            /// category.
            /// </summary>
            private void MaybeResetMessageBuffer()
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (buffer != null)
                        buffer.Length = 0;

                    if (bufferCategory != null)
                        bufferCategory = null;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method verifies that the specified trace category matches
            /// the category associated with the buffered trace message output.
            /// </summary>
            /// <param name="category">
            /// The trace category to check.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the trace category matches; otherwise, false.
            /// </returns>
            private bool CheckCategory(
                string category,
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if ((category != null) && (bufferCategory != null) &&
                        !SharedStringOps.SystemEquals(category, bufferCategory))
                    {
                        error = String.Format(
                            "buffer category mismatch got {0}, expected {1}",
                            FormatOps.WrapOrNull(category), FormatOps.WrapOrNull(
                            bufferCategory));

                        return false;
                    }

                    return true;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes a trace message to the database, using the
            /// configured auto-flush setting.
            /// </summary>
            /// <param name="message">
            /// The trace message to write.
            /// </param>
            /// <param name="category">
            /// The trace category associated with the message.
            /// </param>
            /// <param name="newLine">
            /// Non-zero if the trace message completes a line.
            /// </param>
            /// <returns>
            /// True if the trace message was written; otherwise, false.
            /// </returns>
            private bool MaybeWriteToDb(
                string message,
                string category,
                bool newLine
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    return MaybeWriteToDb(
                        message, category, newLine, autoFlush);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes a trace message to the database, complaining
            /// on failure.
            /// </summary>
            /// <param name="message">
            /// The trace message to write.
            /// </param>
            /// <param name="category">
            /// The trace category associated with the message.
            /// </param>
            /// <param name="newLine">
            /// Non-zero if the trace message completes a line.
            /// </param>
            /// <param name="flush">
            /// Non-zero if the database transaction should be committed after
            /// the trace message is written.
            /// </param>
            /// <returns>
            /// True if the trace message was written; otherwise, false.
            /// </returns>
            private bool MaybeWriteToDb(
                string message,
                string category,
                bool newLine,
                bool flush
                )
            {
                Result error = null;

                if (MaybeWriteToDb(
                        message, category, newLine, flush, ref error))
                {
                    return true;
                }
                else
                {
                    Complain(ReturnCode.Error, error);
                }

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes a trace message to the database.
            /// </summary>
            /// <param name="message">
            /// The trace message to write.
            /// </param>
            /// <param name="category">
            /// The trace category associated with the message.
            /// </param>
            /// <param name="newLine">
            /// Non-zero if the trace message completes a line.
            /// </param>
            /// <param name="flush">
            /// Non-zero if the database transaction should be committed after
            /// the trace message is written.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// True if the trace message was written; otherwise, false.
            /// </returns>
            private bool MaybeWriteToDb(
                string message,
                string category,
                bool newLine,
                bool flush,
                ref Result error
                )
            {
                lock (syncRoot) /* TRANSACTIONAL */
                {
                    if (newLine)
                    {
                        if (!OpenDbConnection(ref error))
                            return false;

                        if (!BeginDbTransaction(ref error))
                            return false;

                        string localMessage = message;

                        if (!MaybeUpdateMessageBuffer(
                                ref localMessage, category, newLine,
                                ref error))
                        {
                            return false;
                        }

                        if (!InsertTraceRowIntoDb(
                                localMessage, category, ref error))
                        {
                            return false;
                        }

                        if (flush && !CommitDbTransaction(ref error))
                            return false;

                        /* NO RESULT */
                        MaybeResetMessageBuffer();
                    }
                    else
                    {
                        string localMessage = message;

                        if (!MaybeUpdateMessageBuffer(
                                ref localMessage, category, newLine,
                                ref error))
                        {
                            return false;
                        }
                    }

                    return true;
                }
            }
            #endregion

