            /// This method determines whether this trace listener is currently
            /// usable.
            /// </summary>
            /// <returns>
            /// True if this trace listener is usable; otherwise, false.
            /// </returns>
            protected virtual bool IsUsable()
            {
                //
                // NOTE: Since this class uses the complaint subsystem,
                //       both directly and indirectly, it is not usable
                //       if there is a complaint pending.
                //
                return !DebugOps.IsComplainPending();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reports a complaint using the interpreter context
            /// associated with this trace listener.
            /// </summary>
            /// <param name="code">
            /// The return code associated with the complaint.
            /// </param>
            /// <param name="result">
            /// The result associated with the complaint.
            /// </param>
            protected virtual void Complain(
                ReturnCode code,
                Result result
                )
            {
                Interpreter localInterpreter;

                lock (syncRoot)
                {
                    localInterpreter = interpreter;
                }

                Complain(localInterpreter, code, result);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method reports a complaint using the specified interpreter
            /// context.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context to use when reporting the complaint.
            /// </param>
            /// <param name="code">
            /// The return code associated with the complaint.
            /// </param>
            /// <param name="result">
            /// The result associated with the complaint.
            /// </param>
            protected virtual void Complain(
                Interpreter interpreter,
                ReturnCode code,
                Result result
                )
            {
                //
                // NOTE: This should be legal even though the complaint
                //       subsystem (potentially) calls into this trace
                //       listener (e.g. via the Trace.Write, which uses
                //       the Trace.Listeners collection) because all of
                //       the TraceListener method overrides avoid doing
                //       any processing when a complaint is pending.
                //
                DebugOps.Complain(interpreter, code, result);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IBufferedTraceListener Members
            /// <summary>
            /// This method flushes any buffered trace message output to the
            /// database.
            /// </summary>
            /// <returns>
            /// True if the buffers were flushed; otherwise, false.
            /// </returns>
            public virtual bool MaybeFlushBuffers()
            {
                CheckDisposed();

                if (!IsUsable())
                    return false;

                int levels = Interlocked.Increment(ref traceLevels);

                try
                {
                    if (levels == 1)
                        return MaybeWriteToDb(null, null, true);
                    else
                        return false;
                }
                finally
                {
                    Interlocked.Decrement(ref traceLevels);
                }
            }
            #endregion

