            public override void Close()
            {
                CheckDisposed();

                if (!IsUsable())
                    return;

                int levels = Interlocked.Increment(ref traceLevels);

                try
                {
                    if (levels == 1)
                    {
                        /* IGNORED */
                        CloseDbConnection();
                    }
                }
                finally
                {
                    Interlocked.Decrement(ref traceLevels);
                }
            }

