        #region TraceListener Test Class
        /// <summary>
        /// This class implements a trace listener that writes trace output to a
        /// file, used to exercise the tracing subsystem.
        /// </summary>
        [ObjectId("73634227-a942-4f0f-be47-1d395e1a9750")]
        public sealed class Listener : TraceListener
        {
            #region Private Constants
            //
            // HACK: These are purposely not marked as read-only.
            //
            /// <summary>
            /// The default character encoding used when writing trace output.
            /// </summary>
            private static Encoding DefaultEncoding = Encoding.UTF8;
            /// <summary>
            /// The default size, in bytes, of the buffer used when writing trace
            /// output.
            /// </summary>
            private static int DefaultBufferSize = 1024;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Data
            /// <summary>
            /// The path of the file that trace output is written to.
            /// </summary>
            private string path;
            /// <summary>
            /// The underlying stream that trace output is written to.
            /// </summary>
            private Stream stream;
            /// <summary>
            /// The character encoding used when writing trace output.
            /// </summary>
            private Encoding encoding;

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The buffer used when writing trace output.
            /// </summary>
            private byte[] buffer;
            /// <summary>
            /// Non-zero if the buffer should automatically expand to fit a
            /// requested size.
            /// </summary>
            private bool expandBuffer;
            /// <summary>
            /// Non-zero if the buffer should always be zeroed before being
            /// returned.
            /// </summary>
            private bool zeroBuffer;
            /// <summary>
            /// Non-zero if the underlying stream should be kept open for the
            /// entire lifetime of this object instance.
            /// </summary>
            private bool keepOpen;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            internal Listener()
                : base()
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="name">
            /// The name for this trace listener.  This parameter may be null.
            /// </param>
            internal Listener(
                string name /* in: may be NULL. */
                )
                : base(name)
            {
                // do nothing.
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="name">
            /// The name for this trace listener.  This parameter may be null.
            /// </param>
            /// <param name="path">
            /// The path of the file that trace output will be written to.
            /// </param>
            /// <param name="encoding">
            /// The character encoding to use when writing trace output.  This
            /// parameter may be null.
            /// </param>
            /// <param name="bufferSize">
            /// The size, in bytes, of the buffer to use when writing trace
            /// output.  This parameter may be zero.
            /// </param>
            /// <param name="flags">
            /// The flags used to configure the behavior of this trace listener.
            /// This parameter may be null.
            /// </param>
            public Listener(
                string name,       /* in: may be NULL. */
                string path,       /* in */
                Encoding encoding, /* in: may be NULL. */
                int bufferSize,    /* in: may be zero. */
                LogFlags? flags    /* in: may be NULL. */
                )
                : this(name)
            {
                SetupPath(path);
                SetupEncoding(encoding);
                SetupFlags(flags);

                ///////////////////////////////////////////////////////////////////////////////////////

                /* IGNORED */
                MaybeCreateOrZeroBuffer(bufferSize);

                ///////////////////////////////////////////////////////////////////////////////////////

                //
                // NOTE: If underlying stream is supposed to be kept open,
                //       start now.
                //
                if (keepOpen) SetupStream(); /* throw */
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method sets up the path of the file that trace output will
            /// be written to.
            /// </summary>
            /// <param name="path">
            /// The path of the file that trace output will be written to.
            /// </param>
            private void SetupPath(
                string path
                )
            {
                this.path = path;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method closes and then re-opens the underlying stream.
            /// </summary>
            private void SetupStream()
            {
                CloseStream();
                OpenStream();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method flushes any buffered data to the underlying stream.
            /// </summary>
            private void FlushStream()
            {
                if (stream != null)
                    stream.Flush();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method closes the underlying stream, if it is open.
            /// </summary>
            private void CloseStream()
            {
                if (stream != null)
                {
                    stream.Close();
                    stream = null;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method opens the underlying stream, if it is not already
            /// open.
            /// </summary>
            private void OpenStream()
            {
                if (stream == null)
                {
                    stream = new FileStream(
                        path, FileMode.Append, FileAccess.Write,
                        FileShare.ReadWrite); /* throw */
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets up the character encoding used when writing
            /// trace output.
            /// </summary>
            /// <param name="encoding">
            /// The character encoding to use when writing trace output.  This
            /// parameter may be null, in which case the default encoding is
            /// used.
            /// </param>
            private void SetupEncoding(
                Encoding encoding
                )
            {
                this.encoding = (encoding != null) ?
                    encoding : DefaultEncoding;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets up the flags that configure the behavior of
            /// this trace listener.
            /// </summary>
            /// <param name="flags">
            /// The flags used to configure the behavior of this trace listener.
            /// This parameter may be null.
            /// </param>
            private void SetupFlags(
                LogFlags? flags
                )
            {
                //
                // NOTE: Should the allocated buffer automatically expand
                //       to fit a request size?  If this is false, a brand
                //       new buffer will be allocated each time a request
                //       size cannot be satisfied by the existing buffer.
                //
                expandBuffer = FlagOps.HasFlags(flags, LogFlags.ExpandBuffer, true);

                //
                // NOTE: Should the existing buffer always be zeroed before
                //       being returned?
                //
                zeroBuffer = FlagOps.HasFlags(flags, LogFlags.ZeroBuffer, true);

                //
                // NOTE: Should the underlying stream be kept open for the
                //       entire lifetime of this object instance?
                //
                keepOpen = FlagOps.HasFlags(flags, LogFlags.KeepOpen, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: This method uses "strategy #1", use the existing buffer
            //       verbatim if it's already large enough; otherwise, replace
            //       the existing buffer with one of the larger size and then
            //       return it.
            //
            /// <summary>
            /// This method returns a buffer of at least the specified size,
            /// reusing the existing buffer when it is already large enough.
            /// </summary>
            /// <param name="bufferSize">
            /// The minimum size, in bytes, of the buffer to return.
            /// </param>
            /// <returns>
            /// A buffer of at least the specified size.
            /// </returns>
            private byte[] MaybeCreateOrZeroBuffer(
                int bufferSize
                )
            {
                if (bufferSize <= 0)
                    bufferSize = DefaultBufferSize;

                if ((buffer == null) || (buffer.Length < bufferSize))
                    buffer = new byte[bufferSize];
                else if (zeroBuffer)
                    Array.Clear(buffer, 0, buffer.Length);

                return buffer;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: This method uses "strategy #2", use the existing buffer
            //       verbatim if it's already large enough; otherwise, create
            //       a new buffer of the requested size and return it.
            //
            /// <summary>
            /// This method returns a buffer of at least the specified size,
            /// reusing the existing buffer when it is already large enough;
            /// otherwise, a new buffer of the requested size is created and
            /// returned.
            /// </summary>
            /// <param name="bufferSize">
            /// The minimum size, in bytes, of the buffer to return.
            /// </param>
            /// <returns>
            /// A buffer of at least the specified size.
            /// </returns>
            private byte[] GetOrCreateBuffer(
                int bufferSize
                )
            {
                if (bufferSize <= 0)
                    bufferSize = DefaultBufferSize;

                if ((buffer != null) && (bufferSize <= buffer.Length))
                {
                    if (zeroBuffer)
                        Array.Clear(buffer, 0, buffer.Length);

                    return buffer;
                }

                return new byte[bufferSize];
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // NOTE: Figure out which buffer management strategy to use and
            //       then return the appropriate buffer.
            //
            /// <summary>
            /// This method figures out which buffer management strategy to use
            /// and then returns a buffer of at least the specified size.
            /// </summary>
            /// <param name="bufferSize">
            /// The minimum size, in bytes, of the buffer to return.
            /// </param>
            /// <returns>
            /// A buffer of at least the specified size.
            /// </returns>
            private byte[] GetBuffer(
                int bufferSize
                )
            {
                return expandBuffer ?
                    MaybeCreateOrZeroBuffer(bufferSize) :
                    GetOrCreateBuffer(bufferSize);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method encodes the specified message and produces the
            /// buffer, offset, and count needed to write it to the underlying
            /// stream.
            /// </summary>
            /// <param name="message">
            /// The message to encode.  This parameter may be null.
            /// </param>
            /// <param name="buffer">
            /// Upon return, this parameter will contain the buffer holding the
            /// encoded message.
            /// </param>
            /// <param name="offset">
            /// Upon return, this parameter will contain the offset, in bytes,
            /// into the buffer where the encoded message begins.
            /// </param>
            /// <param name="count">
            /// Upon return, this parameter will contain the number of bytes of
            /// encoded message in the buffer.
            /// </param>
            private void GetWriteParameters(
                string message,
                ref byte[] buffer,
                ref int offset,
                ref int count
                )
            {
                if (encoding == null)
                    throw new InvalidOperationException();

                if (message == null)
                {
                    buffer = null; offset = 0; count = 0;
                    return;
                }

                int byteCount = encoding.GetByteCount(message);
                byte[] localBuffer = GetBuffer(byteCount);

                encoding.GetBytes(
                    message, 0, message.Length, localBuffer, 0);

                buffer = localBuffer; offset = 0; count = byteCount;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// Gets the path of the file that trace output is written to.
            /// </summary>
            public string Path
            {
                get { CheckDisposed(); return path; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets the character encoding used when writing trace output.
            /// </summary>
            public Encoding Encoding
            {
                get { CheckDisposed(); return encoding; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Diagnostics.TraceListener Overrides
            /// <summary>
            /// This method closes the underlying stream and releases any
            /// resources associated with this trace listener.
            /// </summary>
            public override void Close()
            {
                CheckDisposed();

                CloseStream();
                base.Close();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method flushes any buffered data to the underlying stream.
            /// </summary>
            public override void Flush()
            {
                CheckDisposed();

                FlushStream();
                base.Flush();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes the specified message to the underlying
            /// stream.
            /// </summary>
            /// <param name="message">
            /// The message to write.
            /// </param>
            public /* abstract */ override void Write(
                string message
                )
            {
                CheckDisposed();

                try
                {
                    if (!keepOpen)
                        OpenStream();

                    if (stream == null)
                        throw new InvalidOperationException();

                    byte[] buffer = null; int offset = 0; int count = 0;

                    GetWriteParameters(
                        message, ref buffer, ref offset, ref count);

                    if ((buffer == null) || (count == 0))
                        return;

                    stream.Write(buffer, offset, count);
                }
                finally
                {
                    if (!keepOpen)
                        CloseStream();
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method writes the specified message, followed by a line
            /// terminator, to the underlying stream.
            /// </summary>
            /// <param name="message">
            /// The message to write.
            /// </param>
            public /* abstract */ override void WriteLine(
                string message
                )
            {
                CheckDisposed();

                Write(message);
                Write(Environment.NewLine);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                    throw new ObjectDisposedException(typeof(Listener).Name);
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            protected override void Dispose(
                bool disposing
                )
            {
                try
                {
                    if (!disposed)
                    {
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            /* NO RESULT */
                            DebugOps.RemoveTraceListener(this);

                            ////////////////////////////////////

                            Close();
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////
                    }
                }
                finally
                {
                    base.Dispose(disposing);

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~Listener()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region IDisposable Test Class
        /// <summary>
        /// This class implements a test object that tracks how many times it
        /// has been created, accessed, disposed, and finalized, used to
        /// exercise the disposal subsystem.
        /// </summary>
        [ObjectId("4b0d4629-b42f-4cfa-adb6-5943e098961c")]
        public sealed class Disposable :
#if ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
            ScriptMarshalByRefObject,
#endif
            IMaybeDisposed, IDisposable
        {
            #region Private Static Data
            /// <summary>
            /// The number of times an instance of this class has been created.
            /// </summary>
            private static long createCount;
            /// <summary>
            /// The number of times any member of an instance of this class has
            /// been accessed.
            /// </summary>
            private static long instanceCount;
            /// <summary>
            /// The number of times the public dispose method has been called on
            /// instances of this class.
            /// </summary>
            private static long dispose0Count;
            /// <summary>
            /// The number of times an instance of this class has been disposed
            /// explicitly for the first time.
            /// </summary>
            private static long significantDispose1Count;
            /// <summary>
            /// The number of times an instance of this class has been released
            /// for the first time.
            /// </summary>
            private static long significantRelease1Count;
            /// <summary>
            /// The number of times an instance of this class has been disposed
            /// redundantly.
            /// </summary>
            private static long redundantDispose1Count;
            /// <summary>
            /// The number of times an instance of this class has been released
            /// redundantly.
            /// </summary>
            private static long redundantRelease1Count;
            /// <summary>
            /// The number of times an instance of this class has been finalized.
            /// </summary>
            private static long destroyCount;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public Disposable()
            {
                id = GlobalState.NextId(); /* EXEMPT */

                Interlocked.Increment(ref createCount);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IMaybeDisposed Members
            /// <summary>
            /// Gets a value indicating whether this object instance has been
            /// disposed.
            /// </summary>
            public bool Disposed
            {
                //
                // NOTE: *WARNING* Do not uncomment this CheckDisposed
                //       call as that would defeat the purpose of this
                //       method and may interfere with the associated
                //       test cases.
                //
                get
                {
                    // CheckDisposed(); /* EXEMPT */

                    Interlocked.Increment(ref instanceCount);

                    return disposed;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether this object instance is in the
            /// process of being disposed.
            /// </summary>
            public bool Disposing
            {
                //
                // NOTE: *WARNING* Do not uncomment this CheckDisposed
                //       call as that would defeat the purpose of this
                //       method and may interfere with the associated
                //       test cases.
                //
                get
                {
                    // CheckDisposed(); /* EXEMPT */

                    Interlocked.Increment(ref instanceCount);

                    return disposing;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// The unique identifier for this object instance.
            /// </summary>
            private long id;
            /// <summary>
            /// Gets the unique identifier for this object instance.
            /// </summary>
            public long Id
            {
                get
                {
                    CheckDisposed();

                    Interlocked.Increment(ref instanceCount);

                    return id;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// The name associated with this object instance.
            /// </summary>
            private string name;
            /// <summary>
            /// Gets or sets the name associated with this object instance.
            /// </summary>
            public string Name
            {
                get
                {
                    CheckDisposed();

                    Interlocked.Increment(ref instanceCount);

                    return name;
                }
                set
                {
                    CheckDisposed();

                    Interlocked.Increment(ref instanceCount);

                    name = value;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Object Overrides
            /// <summary>
            /// This method returns a string representation of this object
            /// instance.
            /// </summary>
            /// <returns>
            /// The string representation of this object instance.
            /// </returns>
            public override string ToString()
            {
                //
                // NOTE: *WARNING* Do not uncomment this CheckDisposed
                //       call as that would defeat the purpose of this
                //       method and may interfere with the associated
                //       test cases.
                //
                // CheckDisposed();

                Interlocked.Increment(ref instanceCount);

                return String.Format(
                    "id = {0}, disposing = {1}, disposed = {2}",
                    id, disposing, disposed);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Non-zero if this object instance has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws <see cref="ObjectDisposedException" /> if this
            /// object instance has been disposed.
            /// </summary>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed &&
                    Engine.IsThrowOnDisposed(null, false))
                {
                    throw new ObjectDisposedException(
                        typeof(Disposable).Name);
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Non-zero if this object instance is in the process of being
            /// disposed.
            /// </summary>
            private bool disposing;
            /// <summary>
            /// This method releases resources used by this object instance.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from the
            /// <see cref="IDisposable.Dispose" /> method; otherwise, this method
            /// is being called from the destructor.
            /// </param>
            private /* protected virtual */ void Dispose(
                bool disposing
                )
            {
                if (disposed)
                {
                    //
                    // NOTE: Keep track of the number of times our type is
                    //       redundantly disposed and/or collected by the
                    //       GC.
                    //
                    if (disposing)
                        Interlocked.Increment(ref redundantDispose1Count);

                    Interlocked.Increment(ref redundantRelease1Count);
                }
                else
                {
                    try
                    {
                        //
                        // NOTE: Keep track of whether we are being disposed
                        //       via the destructor (i.e. likely via the GC)
                        //       or explicitly via the public Dispose method.
                        //
                        this.disposing = disposing;

                        //
                        // NOTE: Also keep track of the number of times our
                        //       type is first disposed and/or collected by
                        //       the GC.
                        //
                        if (disposing)
                        {
                            ////////////////////////////////////
                            // dispose managed resources here...
                            ////////////////////////////////////

                            Interlocked.Increment(
                                ref significantDispose1Count);
                        }

                        //////////////////////////////////////
                        // release unmanaged resources here...
                        //////////////////////////////////////

                        Interlocked.Increment(
                            ref significantRelease1Count);
                    }
                    finally
                    {
                        //
                        // NOTE: This object is now disposed.  Test cases
                        //       may query the property associated with
                        //       this field to discover this fact.
                        //
                        // base.Dispose(disposing);

                        disposed = true;
                    }
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources used by this object instance.
            /// </summary>
            public void Dispose()
            {
                Interlocked.Increment(ref instanceCount);

                Dispose(true);
                GC.SuppressFinalize(this);

                Interlocked.Increment(ref dispose0Count);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes an instance of this class.
            /// </summary>
            ~Disposable()
            {
                Dispose(false);

                Interlocked.Increment(ref destroyCount);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region IFunction Test Classes
        #region IFunction Test Class #1
        /// <summary>
        /// This class implements a test function that evaluates its argument as
        /// an expression, used to exercise the expression engine.
        /// </summary>
        [ObjectId("a61370f5-215a-41a3-af8f-196fcf8f3cc4")]
        [FunctionFlags(FunctionFlags.Safe | FunctionFlags.NoPopulate)]
        [Arguments(Arity.Unary)]
        [ObjectGroup("test")]
        public sealed class Function1 : _Functions.Default
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="functionData">
            /// The data used to create the function.
            /// </param>
            public Function1(
                IFunctionData functionData
                )
                : base(functionData)
            {
                this.Flags |= AttributeOps.GetFunctionFlags(GetType().BaseType) |
                    AttributeOps.GetFunctionFlags(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecuteArgument Members
            /// <summary>
            /// This method executes the function, evaluating its single
            /// argument as an expression, used to exercise the expression
            /// engine.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the function is being executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this function, if any.
            /// </param>
            /// <param name="arguments">
            /// The arguments to the function.
            /// </param>
            /// <param name="value">
            /// Upon success, this parameter will contain the value produced by
            /// the function.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public override ReturnCode Execute(
                Interpreter interpreter,
                IClientData clientData,
                ArgumentList arguments,
                ref Argument value,
                ref Result error
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (arguments == null)
                {
                    error = "invalid argument list";
                    return ReturnCode.Error;
                }

                ReturnCode code;

                if (arguments.Count == 2)
                {
                    string text = arguments[1];
                    Result result = null;

                    code = Engine.EvaluateExpression(
                        interpreter, text, ref result);

                    if (code == ReturnCode.Ok)
                        value = StringList.MakeList(text, result);
                    else
                        error = result;
                }
                else
                {
                    error = ScriptOps.WrongNumberOfArguments(
                        this, 1, arguments, "expr");

                    code = ReturnCode.Error;
                }

                return code;
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region IFunction Test Class #2
        /// <summary>
        /// This class implements a test function that optionally disposes the
        /// interpreter before evaluating an expression, used to exercise the
        /// expression engine.
        /// </summary>
        [ObjectId("f7051cc9-57b1-4307-b4b6-1216811b9d39")]
        [FunctionFlags(FunctionFlags.Unsafe | FunctionFlags.NoPopulate)]
        [Arguments(Arity.Binary)]
        [ObjectGroup("test")]
        public sealed class Function2 : _Functions.Default
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="functionData">
            /// The data used to create the function.
            /// </param>
            public Function2(
                IFunctionData functionData
                )
                : base(functionData)
            {
                this.Flags |= AttributeOps.GetFunctionFlags(GetType().BaseType) |
                    AttributeOps.GetFunctionFlags(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecuteArgument Members
            /// <summary>
            /// This method executes the function, optionally disposing the
            /// interpreter and then evaluating an expression, used to exercise
            /// the expression engine.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the function is being executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this function, if any.
            /// </param>
            /// <param name="arguments">
            /// The arguments to the function.
            /// </param>
            /// <param name="value">
            /// Upon success, this parameter will contain the value produced by
            /// the function.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public override ReturnCode Execute(
                Interpreter interpreter,
                IClientData clientData,
                ArgumentList arguments,
                ref Argument value,
                ref Result error
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (arguments == null)
                {
                    error = "invalid argument list";
                    return ReturnCode.Error;
                }

                if (arguments.Count != (this.Arguments + 1)) /* 3 */
                {
                    error = ScriptOps.WrongNumberOfArguments(
                        this, 1, arguments, "bool expr");

                    return ReturnCode.Error;
                }

                ReturnCode code = ReturnCode.Ok;

                bool boolValue = false;

                if (Engine.ToBoolean(
                        arguments[1], interpreter.InternalCultureInfo,
                        ref boolValue, ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }

                if (boolValue)
                {
                    try
                    {
                        //
                        // NOTE: This is being done purely for expression
                        //       engine testing purposes only.  Normally,
                        //       the containing interpreter should NOT be
                        //       disposed from inside of a custom command
                        //       or function.
                        //
                        if (interpreter != null)
                        {
                            interpreter.Dispose();
                            interpreter = null;
                        }

                        code = ReturnCode.Ok;
                    }
                    catch (Exception e)
                    {
                        error = e;
                        code = ReturnCode.Error;
                    }
                }

                string text = arguments[2];

                if ((code == ReturnCode.Ok) && !String.IsNullOrEmpty(text))
                {
                    Result result = null;

                    code = Engine.EvaluateExpression(
                        interpreter, text, ref result);

                    if (code == ReturnCode.Ok)
                        value = StringList.MakeList(text, result);
                    else
                        error = result;
                }

                return code;
            }
            #endregion
        }
        #endregion

