        #region IFunction Test Class #3
        /// <summary>
        /// This class implements a test function that conditionally invokes a
        /// command, used to exercise the expression engine.
        /// </summary>
        [ObjectId("c06da159-fe1f-4482-85ec-1b4c3bf4d0d0")]
        [FunctionFlags(FunctionFlags.Unsafe | FunctionFlags.NoPopulate)]
        [Arguments(Arity.Any)]
        [ObjectGroup("test")]
        public sealed class Function3 : _Functions.Default
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="functionData">
            /// The data used to create the function.
            /// </param>
            public Function3(
                IFunctionData functionData
                )
                : base(functionData)
            {
                this.Flags |= AttributeOps.GetFunctionFlags(GetType().BaseType) |
                    AttributeOps.GetFunctionFlags(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IExecuteArgument Members
            /// <summary>
            /// This method executes the function, conditionally invoking a
            /// command based on the value of its first (boolean) argument.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter context in which the function is being executed.
            /// </param>
            /// <param name="clientData">
            /// The client data associated with this function, if any.
            /// </param>
            /// <param name="arguments">
            /// The arguments to the function.
            /// </param>
            /// <param name="value">
            /// Upon success, this parameter will contain the value produced by
            /// the function.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public override ReturnCode Execute(
                Interpreter interpreter,
                IClientData clientData,
                ArgumentList arguments,
                ref Argument value,
                ref Result error
                )
            {
                if (interpreter == null)
                {
                    error = "invalid interpreter";
                    return ReturnCode.Error;
                }

                if (arguments == null)
                {
                    error = "invalid argument list";
                    return ReturnCode.Error;
                }

                if (arguments.Count < 3)
                {
                    error = ScriptOps.WrongNumberOfArguments(
                        this, 1, arguments, "bool arg ?arg ...?");

                    return ReturnCode.Error;
                }

                bool boolValue = false;

                if (Engine.ToBoolean(
                        arguments[1], interpreter.InternalCultureInfo,
                        ref boolValue, ref error) != ReturnCode.Ok)
                {
                    return ReturnCode.Error;
                }

                ReturnCode code;

                if (boolValue)
                {
                    Result result = null;

                    code = interpreter.Invoke(arguments[2], clientData,
                        ArgumentList.GetRange(arguments, 2), ref result);

                    if (code == ReturnCode.Ok)
                        value = result;
                    else
                        error = result;
                }
                else
                {
                    value = ArgumentList.GetRange(
                        arguments, 1, Index.Invalid, false).ToString();

                    code = ReturnCode.Ok;
                }

                return code;
            }
            #endregion
        }
        #endregion

