        #region Generic Dictionary Class
        /// <summary>
        /// This class provides a generic dictionary type used by the test
        /// suite, adding convenience methods for bulk population and string
        /// conversion.
        /// </summary>
        /// <typeparam name="TKey">
        /// The type of the keys in the dictionary.
        /// </typeparam>
        /// <typeparam name="TValue">
        /// The type of the values in the dictionary.
        /// </typeparam>
#if SERIALIZATION
        [Serializable()]
#endif
        [ObjectId("51e22e50-4079-48f6-83eb-e48cb49c7ea3")]
        public sealed class GenericDictionary<TKey, TValue> : Dictionary<TKey, TValue>
        {
            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public GenericDictionary()
                : base()
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="collection">
            /// The keys used to initially populate this dictionary.
            /// </param>
            public GenericDictionary(
                IEnumerable<TKey> collection
                )
                : this(collection, null)
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="elements">
            /// The keys used to initially populate this dictionary.
            /// </param>
            public GenericDictionary(
                params TKey[] elements
                )
                : this((IEnumerable<TKey>)elements)
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="keys">
            /// The keys used to initially populate this dictionary.
            /// </param>
            /// <param name="values">
            /// The values used to initially populate this dictionary.
            /// </param>
            public GenericDictionary(
                IEnumerable<TKey> keys,
                IEnumerable<TValue> values
                )
                : this()
            {
                Add(keys, values);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Protected Constructors
#if SERIALIZATION
            /// <summary>
            /// Constructs an instance of this class.  This constructor supports
            /// deserialization.
            /// </summary>
            /// <param name="info">
            /// The serialization information used to populate this instance.
            /// </param>
            /// <param name="context">
            /// The streaming context for the deserialization operation.
            /// </param>
            private GenericDictionary(
                SerializationInfo info,
                StreamingContext context
                )
                : base(info, context)
            {
                // do nothing.
            }
#endif
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Add Methods
            /// <summary>
            /// This method adds the specified keys and values to this
            /// dictionary, pairing each key with the corresponding value.
            /// </summary>
            /// <param name="keys">
            /// The keys to add.  This parameter may be null.
            /// </param>
            /// <param name="values">
            /// The values to associate with the keys.  This parameter may be
            /// null, in which case the default value is used for each key.
            /// </param>
            public void Add(
                IEnumerable<TKey> keys,
                IEnumerable<TValue> values
                )
            {
                if (keys == null)
                    return;

                IEnumerator<TKey> keyEnumerator = keys.GetEnumerator();

                IEnumerator<TValue> valueEnumerator = (values != null) ?
                    values.GetEnumerator() : null;

                bool moreValues = (valueEnumerator != null);

                while (keyEnumerator.MoveNext())
                {
                    TKey key = keyEnumerator.Current;
                    TValue value = default(TValue);

                    if (moreValues)
                    {
                        if (valueEnumerator.MoveNext())
                            value = valueEnumerator.Current;
                        else
                            moreValues = false;
                    }

                    this.Add(key, value);
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region ToString Methods
            /// <summary>
            /// This method converts this dictionary to a string, including only
            /// those entries whose values match the specified pattern.
            /// </summary>
            /// <param name="pattern">
            /// The pattern to match against each value, or null to include all
            /// entries.
            /// </param>
            /// <param name="noCase">
            /// Non-zero if the pattern matching should be case-insensitive.
            /// </param>
            /// <returns>
            /// The string representation of this dictionary.
            /// </returns>
            public string ToString(
                string pattern,
                bool noCase
                )
            {
                return GenericOps<TKey, TValue>.DictionaryToString(
                    this, Index.Invalid, Index.Invalid, ToStringFlags.None,
                    Characters.SpaceString, pattern, noCase);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region System.Object Overrides
            /// <summary>
            /// This method converts this dictionary to a string, including all
            /// entries.
            /// </summary>
            /// <returns>
            /// The string representation of this dictionary.
            /// </returns>
            public override string ToString()
            {
                return ToString(null, false);
            }
            #endregion
        }
        #endregion

