        /// <summary>
        /// This class provides a remoting connection authorizer used by the
        /// test suite that permits connections only from the loopback address.
        /// </summary>
        [ObjectId("008a9889-79c4-4a75-af68-1bbb56a349b3")]
        public sealed class RemoteAuthorizer : IAuthorizeRemotingConnection
        {
            #region IAuthorizeRemotingConnection Members
            /// <summary>
            /// This method determines whether the connecting end point is
            /// authorized to use this remoting connection, allowing only the
            /// loopback address.
            /// </summary>
            /// <param name="endPoint">
            /// The end point of the connecting client.
            /// </param>
            /// <returns>
            /// True if the connecting end point is authorized; otherwise,
            /// false.
            /// </returns>
            public bool IsConnectingEndPointAuthorized(EndPoint endPoint)
            {
                IPEndPoint ipEndPoint = endPoint as IPEndPoint;

                if ((ipEndPoint != null) &&
                    (ipEndPoint.Address != null) &&
                    (ipEndPoint.Address.Equals(IPAddress.Loopback)))
                {
                    return true;
                }

                return false;
            }
            ///////////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method determines whether the connecting identity is
            /// authorized to use this remoting connection.
            /// </summary>
            /// <param name="identity">
            /// The identity of the connecting client.
            /// </param>
            /// <returns>
            /// True if the connecting identity is authorized; otherwise, false.
            /// </returns>
            public bool IsConnectingIdentityAuthorized(
                IIdentity identity
                )
            {
                return true;
            }
            #endregion
        }
#endif
        #endregion

