            /// </summary>
            /// <returns>
            /// The current date and time, in Coordinated Universal Time (UTC).
            /// </returns>
            public DateTime Now()
            {
                CheckDisposed();

                return TimeOps.GetUtcNow();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method shuts down the remoting channel associated with this
            /// object and disconnects it, on behalf of a remote client.
            /// </summary>
            /// <returns>
            /// True if the channel was successfully stopped and unregistered;
            /// otherwise, false.
            /// </returns>
            public bool Exit()
            {
                CheckDisposed();

#if REMOTING
                try
                {
                    TcpServerChannel channel = ChannelServices.GetChannel(
                        RemotingChannelName) as TcpServerChannel;

                    if (channel != null)
                    {
                        if (RemotingServices.Disconnect(this))
                        {
                            channel.StopListening(null);
                            ChannelServices.UnregisterChannel(channel);

                            return true;
                        }
                    }
                }
                catch (Exception e)
                {
                    TraceOps.DebugTrace(
                        e, typeof(RemoteObject).Name,
                        TracePriority.RemotingError);
                }
#endif

                return false;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method evaluates the specified script using a shared
            /// interpreter, on behalf of a remote client.
            /// </summary>
            /// <param name="text">
            /// The script to evaluate.
            /// </param>
            /// <param name="engineFlags">
            /// The engine flags to use while evaluating the script.
            /// </param>
            /// <param name="substitutionFlags">
            /// The substitution flags to use while evaluating the script.
            /// </param>
            /// <param name="eventFlags">
            /// The event flags to use while evaluating the script.
            /// </param>
            /// <param name="expressionFlags">
            /// The expression flags to use while evaluating the script.
            /// </param>
            /// <param name="result">
            /// Upon success, this parameter will contain the result of the
            /// script evaluation; upon failure, it will contain an appropriate
            /// error message.
            /// </param>
            /// <returns>
            /// <see cref="ReturnCode.Ok" /> on success; otherwise, a different
            /// return code indicating the type of failure.
            /// </returns>
            public ReturnCode Evaluate(
                string text,
                EngineFlags engineFlags,
                SubstitutionFlags substitutionFlags,
                EventFlags eventFlags,
                ExpressionFlags expressionFlags,
                ref Result result
                )
            {
                CheckDisposed();

                return Engine.EvaluateScript(
                    Interpreter.GetAny(), text,
                    engineFlags, substitutionFlags,
                    eventFlags, expressionFlags,
                    ref result);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            //
            // HACK: We can never unset the variable that contains the transparent
            //       proxy reference unless this class implements IDisposable because
            //       the transparent proxy "pretends" to implement it, thereby fooling
            //       our TryDisposeObject function.
            //
            /// <summary>
            /// This method releases all resources held by this object and
            /// suppresses finalization.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Stores a value indicating whether this object has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this object has already been
            /// disposed.  It is called at the start of most members to guard
            /// against use after disposal.
            /// </summary>
            /// <exception cref="ObjectDisposedException">
            /// Thrown when this object has been disposed and the engine is
            /// configured to throw on use of a disposed object.
            /// </exception>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                    throw new ObjectDisposedException(typeof(RemoteObject).Name);
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the resources held by this object.  It
            /// implements the standard dispose pattern.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from
            /// <see cref="Dispose()" /> (i.e. deterministically); zero if it is
            /// being called from the finalizer.  When non-zero, managed
            /// resources are released.
            /// </param>
            private /* protected virtual */ void Dispose(bool disposing)
            {
                if (!disposed)
                {
                    //if (disposing)
                    //{
                    //    ////////////////////////////////////
                    //    // dispose managed resources here...
                    //    ////////////////////////////////////
                    //}

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes this object, releasing any resources that were not
            /// released by an explicit call to <see cref="Dispose()" />.
            /// </summary>
            ~RemoteObject()
            {
                Dispose(false);
            }
            #endregion
        }
