        #region ScriptInterpreterSettings Test Class
        /// <summary>
        /// This class holds the settings used by the test suite when creating
        /// child interpreters, tracking whether each setting was explicitly
        /// specified and supplying default values otherwise.
        /// </summary>
        [ObjectId("b44825c3-339d-44bd-a388-03a151d855b2")]
        public sealed class ScriptInterpreterSettings :
#if ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
            ScriptMarshalByRefObject,
#endif
            IHaveInterpreter, IHaveClientData, IDisposable
        {
            #region Private Constants
            //
            // HACK: These are purposely not read-only.
            //
            /// <summary>
            /// The default value indicating whether an isolated interpreter is
            /// desired.
            /// </summary>
            private static bool DefaultIsolated = false;
            /// <summary>
            /// The default value indicating whether a safe interpreter is
            /// desired.
            /// </summary>
            private static bool DefaultSafe = false;
            /// <summary>
            /// The default value indicating whether security is desired.
            /// </summary>
            private static bool DefaultSecurity = false;

            ///////////////////////////////////////////////////////////////////////////////////////////

            //
            // HACK: This is purposely not read-only.
            //
#if USE_NAMESPACES
            /// <summary>
            /// The default value indicating whether namespace support is
            /// desired.
            /// </summary>
            private static bool DefaultNamespaces = true;
#else
            /// <summary>
            /// The default value indicating whether namespace support is
            /// desired.
            /// </summary>
            private static bool DefaultNamespaces = false;
#endif
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public ScriptInterpreterSettings()
            {
                // do nothing.
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IGetClientData / ISetClientData Members
            /// <summary>
            /// Stores the client data associated with this object.
            /// </summary>
            private IClientData clientData;
            /// <summary>
            /// Gets or sets the client data associated with this object.
            /// </summary>
            public IClientData ClientData
            {
                get { CheckDisposed(); return clientData; }
                set { CheckDisposed(); clientData = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IGetInterpreter / ISetInterpreter Members
            /// <summary>
            /// Stores the interpreter associated with this object.
            /// </summary>
            private Interpreter interpreter;
            /// <summary>
            /// Gets or sets the interpreter associated with this object.
            /// </summary>
            public Interpreter Interpreter
            {
                get { CheckDisposed(); return interpreter; }
                set { CheckDisposed(); interpreter = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// Stores the token associated with this object.
            /// </summary>
            private ulong? token;
            /// <summary>
            /// Gets or sets the token associated with this object.
            /// </summary>
            public ulong? Token
            {
                get { CheckDisposed(); return token; }
                set { CheckDisposed(); token = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the rule set associated with this object.
            /// </summary>
            private IRuleSet ruleSet;
            /// <summary>
            /// Gets or sets the rule set associated with this object.
            /// </summary>
            public IRuleSet RuleSet
            {
                get { CheckDisposed(); return ruleSet; }
                set { CheckDisposed(); ruleSet = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores a value indicating whether an isolated interpreter is
            /// desired, or null to use the default.
            /// </summary>
            private bool? isolated;
            /// <summary>
            /// Gets or sets a value indicating whether an isolated interpreter
            /// is desired, or null to use the default.
            /// </summary>
            public bool? Isolated
            {
                get { CheckDisposed(); return isolated; }
                set { CheckDisposed(); isolated = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether an isolated interpreter is
            /// desired, falling back to the default when not explicitly set.
            /// </summary>
            public bool IsolatedOrDefault
            {
                get
                {
                    CheckDisposed();

                    if (isolated != null)
                        return (bool)isolated;

                    return DefaultIsolated;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores a value indicating whether a safe interpreter is desired,
            /// or null to use the default.
            /// </summary>
            private bool? safe;
            /// <summary>
            /// Gets or sets a value indicating whether a safe interpreter is
            /// desired, or null to use the default.
            /// </summary>
            public bool? Safe
            {
                get { CheckDisposed(); return safe; }
                set { CheckDisposed(); safe = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether a safe interpreter is desired,
            /// falling back to the value from the associated interpreter or the
            /// default when not explicitly set.
            /// </summary>
            public bool SafeOrDefault
            {
                get
                {
                    CheckDisposed();

                    if (safe != null)
                        return (bool)safe;

                    if (interpreter != null)
                        return interpreter.InternalIsSafe();

                    return DefaultSafe;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores a value indicating whether security is desired, or null
            /// to use the default.
            /// </summary>
            private bool? security;
            /// <summary>
            /// Gets or sets a value indicating whether security is desired, or
            /// null to use the default.
            /// </summary>
            public bool? Security
            {
                get { CheckDisposed(); return security; }
                set { CheckDisposed(); security = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether security is desired, falling
            /// back to the value from the associated interpreter or the default
            /// when not explicitly set.
            /// </summary>
            public bool SecurityOrDefault
            {
                get
                {
                    CheckDisposed();

                    if (security != null)
                        return (bool)security;

                    if (interpreter != null)
                        return interpreter.HasSecurity();

                    return DefaultSecurity;
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores a value indicating whether namespace support is desired,
            /// or null to use the default.
            /// </summary>
            private bool? namespaces;
            /// <summary>
            /// Gets or sets a value indicating whether namespace support is
            /// desired, or null to use the default.
            /// </summary>
            public bool? Namespaces
            {
                get { CheckDisposed(); return namespaces; }
                set { CheckDisposed(); namespaces = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Gets a value indicating whether namespace support is desired,
            /// falling back to the value from the associated interpreter or the
            /// default when not explicitly set.
            /// </summary>
            public bool NamespacesOrDefault
            {
                get
                {
                    CheckDisposed();

                    if (namespaces != null)
                        return (bool)namespaces;

                    if (interpreter != null)
                        return interpreter.InternalAreNamespacesEnabled();

                    return DefaultNamespaces;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method retrieves the values of all the settings tracked by
            /// this object, applying default values where appropriate.
            /// </summary>
            /// <param name="interpreter">
            /// Upon return, this parameter will contain the interpreter
            /// associated with this object.
            /// </param>
            /// <param name="clientData">
            /// Upon return, this parameter will contain the client data
            /// associated with this object.
            /// </param>
            /// <param name="token">
            /// Upon return, this parameter will contain the token associated
            /// with this object.
            /// </param>
            /// <param name="ruleSet">
            /// Upon return, this parameter will contain the rule set associated
            /// with this object.
            /// </param>
            /// <param name="isolated">
            /// Upon return, this parameter will contain a value indicating
            /// whether an isolated interpreter is desired.
            /// </param>
            /// <param name="safe">
            /// Upon return, this parameter will contain a value indicating
            /// whether a safe interpreter is desired.
            /// </param>
            /// <param name="security">
            /// Upon return, this parameter will contain a value indicating
            /// whether security is desired.
            /// </param>
            /// <param name="namespaces">
            /// Upon return, this parameter will contain a value indicating
            /// whether namespace support is desired.
            /// </param>
            internal void GetProperties(
                out Interpreter interpreter, /* out */
                out IClientData clientData,  /* out */
                out ulong? token,            /* out */
                out IRuleSet ruleSet,        /* out */
                out bool isolated,           /* out */
                out bool safe,               /* out */
                out bool security,           /* out */
                out bool namespaces          /* out */
                )
            {
                interpreter = this.Interpreter;
                clientData = this.ClientData;
                token = this.Token;
                ruleSet = this.RuleSet;

                ///////////////////////////////////////////////////////////////////////////////////////

                isolated = this.IsolatedOrDefault;
                safe = this.SafeOrDefault;
                security = this.SecurityOrDefault;
                namespaces = this.NamespacesOrDefault;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

#if APPDOMAINS && ISOLATED_INTERPRETERS
            /// <summary>
            /// This method computes the isolated portion of the creation flags
            /// derived from the specified interpreter and interpreter settings.
            /// </summary>
            /// <param name="interpreter">
            /// The interpreter whose creation flags should be considered.  This
            /// parameter may be null.
            /// </param>
            /// <param name="interpreterSettings">
            /// The interpreter settings whose creation flags should be
            /// considered.  This parameter may be null.
            /// </param>
            /// <returns>
            /// The isolated portion of the combined creation flags.
            /// </returns>
            internal CreateFlags GetIsolatedCreateFlags(
                Interpreter interpreter,                 /* in */
                IInterpreterSettings interpreterSettings /* in */
                )
            {
                CreateFlags createFlags = CreateFlags.None;

                if (interpreter != null)
                    createFlags |= interpreter.CreateFlags;

                if (interpreterSettings != null)
                    createFlags |= interpreterSettings.CreateFlags;

                return createFlags & CreateFlags.IsolatedMask;
            }
#endif
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable "Pattern" Members
            /// <summary>
            /// Stores a value indicating whether this object has been disposed.
            /// </summary>
            private bool disposed;
            /// <summary>
            /// This method throws an exception if this object has already been
            /// disposed.  It is called at the start of most members to guard
            /// against use after disposal.
            /// </summary>
            /// <exception cref="InterpreterDisposedException">
            /// Thrown when this object has been disposed and the engine is
            /// configured to throw on use of a disposed object.
            /// </exception>
            private void CheckDisposed() /* throw */
            {
#if THROW_ON_DISPOSED
                if (disposed && Engine.IsThrowOnDisposed(null, false))
                {
                    throw new InterpreterDisposedException(
                        typeof(ScriptInterpreterSettings));
                }
#endif
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method releases the resources held by this object.  It
            /// implements the standard dispose pattern.
            /// </summary>
            /// <param name="disposing">
            /// Non-zero if this method is being called from
            /// <see cref="Dispose()" /> (i.e. deterministically); zero if it is
            /// being called from the finalizer.  When non-zero, managed
            /// resources are released.
            /// </param>
            private /* protected virtual */ void Dispose(
                bool disposing /* in */
                )
            {
                if (!disposed)
                {
                    if (disposing)
                    {
                        ////////////////////////////////////
                        // dispose managed resources here...
                        ////////////////////////////////////

                        interpreter = null; /* NOT OWNED */
                        clientData = null; /* NOT OWNED */
                        token = null;
                        ruleSet = null; /* NOT OWNED */

                        ////////////////////////////////////

                        isolated = null;
                        safe = null;
                        security = null;
                        namespaces = null;
                    }

                    //////////////////////////////////////
                    // release unmanaged resources here...
                    //////////////////////////////////////

                    disposed = true;
                }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region IDisposable Members
            /// <summary>
            /// This method releases all resources held by this object and
            /// suppresses finalization.
            /// </summary>
            public void Dispose()
            {
                Dispose(true);
                GC.SuppressFinalize(this);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Destructor
            /// <summary>
            /// Finalizes this object, releasing any resources that were not
            /// released by an explicit call to <see cref="Dispose()" />.
            /// </summary>
            ~ScriptInterpreterSettings()
            {
                Dispose(false);
            }
            #endregion
        }
        #endregion

