        #region ScriptRules Test Class
        /// <summary>
        /// This class provides helper methods used by the test suite to create
        /// individual include and exclude rules for commands and policies.
        /// </summary>
        [ObjectId("c0bd9a32-cec6-4a92-bc60-56e6cd48be55")]
        public static class ScriptRules
        {
            #region Public Constants
            /// <summary>
            /// A shared, pre-built empty rule instance.
            /// </summary>
            public static readonly IRule Empty = _Public.Rule.Empty;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method wraps the specified pattern strings as an
            /// enumerable sequence.
            /// </summary>
            /// <param name="args">
            /// The pattern strings to wrap.
            /// </param>
            /// <returns>
            /// An enumerable sequence containing the specified pattern strings.
            /// </returns>
            private static IEnumerable<string> MakePatterns(
                params string[] args /* in */
                )
            {
                return args;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method creates a rule that includes any command.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule IncludeAnyCommand(
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Include, IdentifierKind.Command,
                    MatchMode.Glob, RegexOptions.None, MakePatterns(
                    Characters.Asterisk.ToString()), null, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule that excludes any command.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule ExcludeAnyCommand(
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Exclude, IdentifierKind.Command,
                    MatchMode.Glob, RegexOptions.None, MakePatterns(
                    Characters.Asterisk.ToString()), null, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule that includes a command matching the
            /// specified name exactly.
            /// </summary>
            /// <param name="name">
            /// The exact command name to match.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule IncludeExactCommand(
                string name,     /* in */
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Include, IdentifierKind.Command,
                    MatchMode.Exact, RegexOptions.None, MakePatterns(
                    name), null, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule that excludes a command matching the
            /// specified name exactly.
            /// </summary>
            /// <param name="name">
            /// The exact command name to match.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule ExcludeExactCommand(
                string name,     /* in */
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Exclude, IdentifierKind.Command,
                    MatchMode.Exact, RegexOptions.None, MakePatterns(
                    name), null, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule that includes any policy.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule IncludeAnyPolicy(
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Include, IdentifierKind.Policy,
                    MatchMode.Glob, RegexOptions.None, MakePatterns(
                    Characters.Asterisk.ToString()), null, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule that excludes any policy.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule ExcludeAnyPolicy(
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Exclude, IdentifierKind.Policy,
                    MatchMode.Glob, RegexOptions.None, MakePatterns(
                    Characters.Asterisk.ToString()), null, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule that includes a policy matching the
            /// specified name exactly.
            /// </summary>
            /// <param name="name">
            /// The exact policy name to match.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule IncludeExactPolicy(
                string name,     /* in */
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Include, IdentifierKind.Policy,
                    MatchMode.Exact, RegexOptions.None, MakePatterns(
                    name), null, true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule that excludes a policy matching the
            /// specified name exactly.
            /// </summary>
            /// <param name="name">
            /// The exact policy name to match.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule.
            /// </returns>
            public static IRule ExcludeExactPolicy(
                string name,     /* in */
                ref Result error /* out: NOT USED */
                )
            {
                return new _Rule(
                    null, RuleType.Exclude, IdentifierKind.Policy,
                    MatchMode.Exact, RegexOptions.None, MakePatterns(
                    name), null, true);
            }
            #endregion
        }
        #endregion

