        #region ScriptRuleSets Test Class
        /// <summary>
        /// This class provides helper methods used by the test suite to create
        /// rule sets pre-populated with common rules.
        /// </summary>
        [ObjectId("9f34bf00-4715-4c72-8a3e-2307cb373542")]
        public static class ScriptRuleSets
        {
            #region Public Methods
            /// <summary>
            /// This method creates a rule set containing a single rule that
            /// includes any command.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule set, or null if it could not be created.
            /// </returns>
            public static IRuleSet CreateCommand(
                ref Result error /* out */
                )
            {
                bool success = false;
                IRuleSet ruleSet = null;
                IRule rule = null;

                try
                {
                    ruleSet = RuleSet.Create(ref error);

                    if (ruleSet == null)
                        return null;

                    rule = ScriptRules.IncludeAnyCommand(
                        ref error);

                    if (rule == null)
                        return null;

                    if (!ruleSet.AddRule(rule, ref error))
                        return null;

                    success = true;
                    return ruleSet;
                }
                finally
                {
                    if (!success)
                    {
                        if (rule != null)
                        {
                            /* IGNORED */
                            ObjectOps.TryDisposeOrTrace<IRule>(
                                ref rule);

                            rule = null;
                        }

                        if (ruleSet != null)
                        {
                            /* IGNORED */
                            ObjectOps.TryDisposeOrTrace<IRuleSet>(
                                ref ruleSet);

                            ruleSet = null;
                        }
                    }
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method creates a rule set containing a single rule that
            /// includes any policy.
            /// </summary>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The newly created rule set, or null if it could not be created.
            /// </returns>
            public static IRuleSet CreatePolicy(
                ref Result error /* out */
                )
            {
                bool success = false;
                IRuleSet ruleSet = null;
                IRule rule = null;

                try
                {
                    ruleSet = RuleSet.Create(ref error);

                    if (ruleSet == null)
                        return null;

                    rule = ScriptRules.IncludeAnyPolicy(
                        ref error);

                    if (rule == null)
                        return null;

                    if (!ruleSet.AddRule(rule, ref error))
                        return null;

                    success = true;
                    return ruleSet;
                }
                finally
                {
                    if (!success)
                    {
                        if (rule != null)
                        {
                            /* IGNORED */
                            ObjectOps.TryDisposeOrTrace<IRule>(
                                ref rule);

                            rule = null;
                        }

                        if (ruleSet != null)
                        {
                            /* IGNORED */
                            ObjectOps.TryDisposeOrTrace<IRuleSet>(
                                ref ruleSet);

                            ruleSet = null;
                        }
                    }
                }
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region RuleSetClientData Test Class
        /// <summary>
        /// This class provides a client data container used by the rule set
        /// related test commands to track the state of rule set definition,
        /// loading, and inclusion.
        /// </summary>
        [ObjectId("39ad692e-bf4f-4225-860a-8d7cb107a92c")]
        public sealed class RuleSetClientData : ClientData
        {
            #region Private Data
            /// <summary>
            /// Stores the current rule set definition nesting level.
            /// </summary>
            private int defineLevels;
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Constructors
            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            public RuleSetClientData()
                : this(null, null)
            {
                // do nothing.
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Constructs an instance of this class.
            /// </summary>
            /// <param name="data">
            /// The client data value to store.
            /// </param>
            /// <param name="ruleSet">
            /// The rule set to associate with this object.
            /// </param>
            public RuleSetClientData(
                object data,     /* in */
                IRuleSet ruleSet /* in */
                )
                : base(data)
            {
                this.ruleSet = ruleSet;

                ///////////////////////////////////////////////////////////////////////////////////////

                InitializeForLoad(false);
                InitializeForDefine(false);
                InitializeForInclude(false);
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Private Methods
            /// <summary>
            /// This method initializes the directory used to load rule set
            /// files.
            /// </summary>
            /// <param name="force">
            /// Non-zero to reinitialize the state even if it has already been
            /// initialized.
            /// </param>
            private void InitializeForLoad(
                bool force
                )
            {
                if (force || (ruleSetDirectory == null))
                    ruleSetDirectory = PathOps.GetUserRuleSetDirectory();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method initializes the directory used to locate included
            /// rule set files.
            /// </summary>
            /// <param name="force">
            /// Non-zero to reinitialize the state even if it has already been
            /// initialized.
            /// </param>
            private void InitializeForInclude(
                bool force
                )
            {
                if (force || (includeDirectory == null))
                    includeDirectory = PathOps.GetUserRuleSetDirectory();
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method initializes the state used while defining rule sets
            /// and rules.
            /// </summary>
            /// <param name="force">
            /// Non-zero to reinitialize the state even if it has already been
            /// initialized.
            /// </param>
            private void InitializeForDefine(
                bool force
                )
            {
                if (force || (ruleSets == null))
                    ruleSets = new RuleSetDictionary();

                if (force || (rules == null))
                    rules = new RuleDictionary();

                if (force || (defineRuleSet == null))
                    defineRuleSet = null;
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Properties
            /// <summary>
            /// Stores the dictionary of rule sets associated with this object.
            /// </summary>
            private RuleSetDictionary ruleSets;
            /// <summary>
            /// Gets or sets the dictionary of rule sets associated with this
            /// object.
            /// </summary>
            public RuleSetDictionary RuleSets
            {
                get { return ruleSets; }
                set { ruleSets = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the dictionary of rules associated with this object.
            /// </summary>
            private RuleDictionary rules;
            /// <summary>
            /// Gets or sets the dictionary of rules associated with this
            /// object.
            /// </summary>
            public RuleDictionary Rules
            {
                get { return rules; }
                set { rules = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the rule set associated with this object.
            /// </summary>
            private IRuleSet ruleSet;
            /// <summary>
            /// Gets or sets the rule set associated with this object.
            /// </summary>
            public IRuleSet RuleSet
            {
                get { return ruleSet; }
                set { ruleSet = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the directory used to locate rule set files.
            /// </summary>
            private string ruleSetDirectory;
            /// <summary>
            /// Gets or sets the directory used to locate rule set files.
            /// </summary>
            public string RuleSetDirectory
            {
                get { return ruleSetDirectory; }
                set { ruleSetDirectory = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the file name of the current rule set.
            /// </summary>
            private string ruleSetFileName;
            /// <summary>
            /// Gets or sets the file name of the current rule set.
            /// </summary>
            public string RuleSetFileName
            {
                get { return ruleSetFileName; }
                set { ruleSetFileName = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the rule set currently being defined.
            /// </summary>
            private IRuleSet defineRuleSet;
            /// <summary>
            /// Gets or sets the rule set currently being defined.
            /// </summary>
            public IRuleSet DefineRuleSet
            {
                get { return defineRuleSet; }
                set { defineRuleSet = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the directory used to locate included rule set files.
            /// </summary>
            private string includeDirectory;
            /// <summary>
            /// Gets or sets the directory used to locate included rule set
            /// files.
            /// </summary>
            public string IncludeDirectory
            {
                get { return includeDirectory; }
                set { includeDirectory = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the command token that should always be added.
            /// </summary>
            private long alwaysAddCommandToken;
            /// <summary>
            /// Gets or sets the command token that should always be added.
            /// </summary>
            public long AlwaysAddCommandToken
            {
                get { return alwaysAddCommandToken; }
                set { alwaysAddCommandToken = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores a value indicating whether processing should stop upon
            /// encountering an error.
            /// </summary>
            private bool stopOnError;
            /// <summary>
            /// Gets or sets a value indicating whether processing should stop
            /// upon encountering an error.
            /// </summary>
            public bool StopOnError
            {
                get { return stopOnError; }
                set { stopOnError = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores a value indicating whether rules should be moved rather
            /// than copied.
            /// </summary>
            private bool moveRules;
            /// <summary>
            /// Gets or sets a value indicating whether rules should be moved
            /// rather than copied.
            /// </summary>
            public bool MoveRules
            {
                get { return moveRules; }
                set { moveRules = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the string builder used to accumulate output.
            /// </summary>
            private StringBuilder builder;
            /// <summary>
            /// Gets or sets the string builder used to accumulate output.
            /// </summary>
            public StringBuilder Builder
            {
                get { return builder; }
                set { builder = value; }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// Stores the list of tokens associated with this object.
            /// </summary>
            private LongList tokens;
            /// <summary>
            /// Gets or sets the list of tokens associated with this object.
            /// </summary>
            public LongList Tokens
            {
                get { return tokens; }
                set { tokens = value; }
            }
            #endregion

            ///////////////////////////////////////////////////////////////////////////////////////////

            #region Public Methods
            /// <summary>
            /// This method resolves the specified definition type, translating
            /// an automatic definition type into a concrete one based on the
            /// current state.
            /// </summary>
            /// <param name="definitionType">
            /// The definition type to translate.
            /// </param>
            /// <returns>
            /// The translated definition type.
            /// </returns>
            public DefinitionType TranslateDefinitionType(
                DefinitionType definitionType
                )
            {
                if (definitionType != DefinitionType.Automatic)
                    return definitionType;

                return (defineRuleSet != null) ?
                    DefinitionType.Rule : DefinitionType.RuleSet;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method resets the state used while defining rule sets and
            /// rules back to its initial values.
            /// </summary>
            public void ResetForDefine()
            {
                InitializeForDefine(true);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method increments the rule set definition nesting level.
            /// </summary>
            /// <returns>
            /// The resulting rule set definition nesting level.
            /// </returns>
            public int EnterDefineLevel()
            {
                return Interlocked.Increment(ref defineLevels);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method decrements the rule set definition nesting level.
            /// </summary>
            /// <returns>
            /// The resulting rule set definition nesting level.
            /// </returns>
            public int ExitDefineLevel()
            {
                return Interlocked.Decrement(ref defineLevels);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method sets the rule set being defined to the specified
            /// value, saving the previous value so it can be restored later.
            /// </summary>
            /// <param name="ruleSet">
            /// The rule set to make the one currently being defined.
            /// </param>
            /// <param name="savedRuleSet">
            /// Upon return, this parameter will contain the rule set that was
            /// previously being defined.
            /// </param>
            public void BeginDefineRuleSet(
                IRuleSet ruleSet,
                ref IRuleSet savedRuleSet
                )
            {
                savedRuleSet = defineRuleSet;
                defineRuleSet = ruleSet;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method restores the rule set being defined to the value
            /// that was active prior to a matching call to
            /// <see cref="BeginDefineRuleSet" />.
            /// </summary>
            /// <param name="savedRuleSet">
            /// The previously saved rule set being defined.  Upon return, this
            /// parameter will be set to null.
            /// </param>
            public void EndDefineRuleSet(
                ref IRuleSet savedRuleSet
                )
            {
                defineRuleSet = savedRuleSet;
                savedRuleSet = null;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method records the specified rule set file name as the
            /// current one, saving the previous value and updating the include
            /// directory based on the new file name.
            /// </summary>
            /// <param name="fileName">
            /// The rule set file name to make current.
            /// </param>
            /// <param name="savedFileName">
            /// Upon return, this parameter will contain the previously current
            /// rule set file name.
            /// </param>
            public void BeginRuleSetFile(
                string fileName,
                ref string savedFileName
                )
            {
                savedFileName = ruleSetFileName;
                ruleSetFileName = fileName;

                if (!String.IsNullOrEmpty(fileName))
                {
                    includeDirectory = Path.GetDirectoryName(
                        fileName);
                }
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method restores the rule set file name that was active
            /// prior to a matching call to <see cref="BeginRuleSetFile" />,
            /// updating the include directory accordingly.
            /// </summary>
            /// <param name="savedFileName">
            /// The previously saved rule set file name.  Upon return, this
            /// parameter will be set to null.
            /// </param>
            public void EndRuleSetFile(
                ref string savedFileName
                )
            {
                if (!String.IsNullOrEmpty(savedFileName))
                {
                    includeDirectory = Path.GetDirectoryName(
                        savedFileName);
                }
                else
                {
                    InitializeForInclude(true);
                }

                ruleSetFileName = savedFileName;
                savedFileName = null;
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method builds the fully qualified file name for an included
            /// rule set file, based on the current include directory.
            /// </summary>
            /// <param name="nameOnly">
            /// The file name, without any directory or extension.
            /// </param>
            /// <param name="error">
            /// Upon failure, this parameter will be modified to contain an
            /// appropriate error message.
            /// </param>
            /// <returns>
            /// The fully qualified file name, or null if it cannot be built.
            /// </returns>
            public string IncludeFileName(
                string nameOnly,
                ref Result error
                )
            {
                if (String.IsNullOrEmpty(includeDirectory))
                {
                    error = String.Format(
                        "invalid include directory {0}",
                        FormatOps.WrapOrNull(includeDirectory));

                    return null;
                }

                if (!Directory.Exists(includeDirectory))
                {
                    error = String.Format(
                        "include directory {0} does not exist",
                        FormatOps.WrapOrNull(includeDirectory));

                    return null;
                }

                return Path.Combine(
                    includeDirectory, String.Format("{0}{1}",
                    nameOnly, FileExtension.RuleSet));
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method adds a collection of token values to the list of
            /// tokens maintained by this object, creating that list if it does
            /// not already exist.
            /// </summary>
            /// <param name="collection">
            /// The collection of token values to add.  This parameter may be
            /// null.
            /// </param>
            public void AddTokens(
                IEnumerable<long> collection
                )
            {
                if (tokens == null)
                    tokens = new LongList();

                if (collection != null)
                    tokens.AddRange(collection);
            }

            ///////////////////////////////////////////////////////////////////////////////////////////

            /// <summary>
            /// This method returns the accumulated string content and releases
            /// the underlying string builder back to its cache.
            /// </summary>
            /// <returns>
            /// The accumulated string content, or null if there is none.
            /// </returns>
            public string GetStringAndRelease()
            {
                return StringBuilderCache.GetStringAndRelease(ref builder);
            }
            #endregion
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region IInterpreter Support Methods
#if THREADING
        /// <summary>
        /// This method gets the engine context associated with the specified
        /// interpreter, without creating one if it does not already exist.
