        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region IPlugin Support Methods
        /// <summary>
        /// This method initializes the named strings maintained by this class,
        /// populating them with the built-in test data.
        /// </summary>
        /// <param name="force">
        /// Non-zero to reinitialize the strings even if they have already been
        /// initialized.
        /// </param>
        public static void TestInitializeStrings(
            bool force /* in */
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (strings != null)
                {
                    if (!force)
                        return;
                }
                else
                {
                    strings = new StringDictionary();
                }

                ///////////////////////////////////////////////////////////////////////////////////////

#if XML
                string key = TestGetScriptStreamXmlDataHash();

                if (key != null)
                {
                    strings[String.Format("0x{0}", key)] =
                        TestGetScriptStreamXmlData();

                    strings[String.Format("0x{0}.harpy", key)] =
                        TestGetScriptStreamXmlDataCertificate();

                    strings[String.Format("0x{0}_block1_signature", key)] =
                        TestGetScriptStreamXmlBlock1Signature();

                    strings[String.Format("0x{0}_block2_signature", key)] =
                        TestGetScriptStreamXmlBlock2Signature();
                }
#endif
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method clears and discards all named strings maintained by this
        /// class.
        /// </summary>
        public static void TestResetStrings()
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (strings != null)
                {
                    strings.Clear();
                    strings = null;
                }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method adds or changes the value of a named string maintained
        /// by this class.
        /// </summary>
        /// <param name="name">
        /// The name of the string to add or change.
        /// </param>
        /// <param name="value">
        /// The new value for the named string.
        /// </param>
        /// <param name="result">
        /// Upon success, receives a status message; upon failure, receives
        /// information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestChangeString(
            string name,
            string value,
            ref Result result
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (strings == null)
                {
                    result = "named strings unavailable";
                    return ReturnCode.Error;
                }

                if (name == null)
                {
                    result = "invalid string name";
                    return ReturnCode.Error;
                }

                if (strings.ContainsKey(name))
                {
                    strings[name] = value;
                    result = "changed";
                }
                else
                {
                    strings.Add(name, value);
                    result = "added";
                }

                return ReturnCode.Ok;
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method removes a named string maintained by this class.
        /// </summary>
        /// <param name="name">
        /// The name of the string to remove.
        /// </param>
        /// <param name="result">
        /// Upon success, receives a status message; upon failure, receives
        /// information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestRemoveString(
            string name,
            ref Result result
            )
        {
            lock (staticSyncRoot) /* TRANSACTIONAL */
            {
                if (strings == null)
                {
                    result = "named strings unavailable";
                    return ReturnCode.Error;
                }

                if (name == null)
                {
                    result = "invalid string name";
                    return ReturnCode.Error;
                }

                if (strings.Remove(name))
                {
                    result = "removed";
                    return ReturnCode.Ok;
                }
                else
                {
                    result = String.Format(
                        "missing named string {0}",
                        FormatOps.WrapOrNull(name));

                    return ReturnCode.Error;
                }
            }
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method looks up the value of a named string maintained by this
        /// class.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use, if any.
        /// </param>
        /// <param name="name">
        /// The name of the string to look up.
        /// </param>
        /// <param name="cultureInfo">
        /// The culture to use, if any.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// The value of the named string, which may be null, or null if no
        /// string with the specified name was found.
        /// </returns>
        public static string TestGetString(
            Interpreter interpreter,
            string name,
            CultureInfo cultureInfo,
            ref Result error
            )
        {
            if (name != null)
            {
                lock (staticSyncRoot) /* TRANSACTIONAL */
                {
                    string value;

                    if ((strings != null) &&
                        strings.TryGetValue(name, out value))
                    {
                        return value; /* MAY BE NULL */
                    }
                }
            }

            error = String.Format(
                "type {0} has no string named {1}",
                FormatOps.TypeName(typeof(Default)),
                FormatOps.WrapOrNull(name));

            return null;
        }
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////////

        #region Conditional Public Static Methods
#if XML
        /// <summary>
        /// This method reads one or more scripts from the specified XML, using
        /// the XML processing options associated with the supplied interpreter,
        /// for use in testing.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use, if any.
        /// </param>
        /// <param name="encoding">
        /// The character encoding to use, if any.
        /// </param>
        /// <param name="xml">
        /// The XML containing the script blocks to read.
        /// </param>
        /// <param name="clientData">
        /// On input, optional client data to use; on output, possibly updated
        /// client data.
        /// </param>
        /// <param name="scripts">
        /// Upon success, receives the scripts that were read.
        /// </param>
        /// <param name="text">
        /// Upon success, receives the combined script text.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestReadScriptXml(
            Interpreter interpreter,          /* in */
            Encoding encoding,                /* in */
            string xml,                       /* in */
            ref IClientData clientData,       /* in, out */
            ref IEnumerable<IScript> scripts, /* out */
            ref string text,                  /* out */
            ref Result error                  /* out */
            )
        {
            XmlErrorTypes retryXml = XmlErrorTypes.None;
            bool validateXml = false;
            bool relaxedXml = false;
            bool allXml = false;

            if (interpreter != null)
            {
                interpreter.QueryXmlProperties(
                    ref retryXml, ref validateXml,
                    ref relaxedXml, ref allXml);
            }

            bool canRetry = false; /* NOT USED */

            return TestReadScriptXml(
                interpreter, encoding, xml, retryXml, validateXml,
                relaxedXml, allXml, ref clientData, ref scripts,
                ref text, ref canRetry, ref error);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method reads one or more scripts from the specified XML using
        /// the supplied options, for use in testing.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use, if any.
        /// </param>
        /// <param name="encoding">
        /// The character encoding to use, if any.
        /// </param>
        /// <param name="xml">
        /// The XML containing the script blocks to read.
        /// </param>
        /// <param name="retryTypes">
        /// The kinds of XML error that should permit a retry.
        /// </param>
        /// <param name="validate">
        /// Non-zero to validate the XML against its schema.
        /// </param>
        /// <param name="relaxed">
        /// Non-zero to use relaxed XML processing rules.
        /// </param>
        /// <param name="all">
        /// Non-zero to read all script blocks; otherwise, only the applicable
        /// ones are read.
        /// </param>
        /// <param name="clientData">
        /// On input, optional client data to use; on output, possibly updated
        /// client data.
        /// </param>
        /// <param name="scripts">
        /// Upon success, receives the scripts that were read.
        /// </param>
        /// <param name="text">
        /// Upon success, receives the combined script text.
        /// </param>
        /// <param name="canRetry">
        /// Upon failure, receives a value indicating whether the operation may
        /// be retried.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestReadScriptXml(
            Interpreter interpreter,          /* in */
            Encoding encoding,                /* in */
            string xml,                       /* in */
            XmlErrorTypes retryTypes,         /* in */
            bool validate,                    /* in */
            bool relaxed,                     /* in */
            bool all,                         /* in */
            ref IClientData clientData,       /* in, out */
            ref IEnumerable<IScript> scripts, /* out */
            ref string text,                  /* out */
            ref bool canRetry,                /* out */
            ref Result error                  /* out */
            )
        {
            EngineFlags engineFlags = EngineFlags.None;
            SubstitutionFlags substitutionFlags = SubstitutionFlags.Default;
            EventFlags eventFlags = EventFlags.Default;
            ExpressionFlags expressionFlags = ExpressionFlags.Default;

            if (interpreter != null)
            {
                engineFlags = interpreter.EngineFlags;
                substitutionFlags = interpreter.SubstitutionFlags;
                eventFlags = interpreter.EngineEventFlags;
                expressionFlags = interpreter.ExpressionFlags;
            }

            return Engine.ReadScriptXml(
                interpreter, encoding, xml, retryTypes, validate, relaxed,
                all, ref engineFlags, ref substitutionFlags, ref eventFlags,
                ref expressionFlags, ref clientData, ref scripts, ref text,
                ref canRetry, ref error);
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method reads application settings from an XML configuration
        /// file, merging them into the supplied collection when one is present.
        /// </summary>
        /// <param name="fileName">
        /// The name of the XML file to read.
        /// </param>
        /// <param name="appSettings">
        /// On input, an optional existing collection to merge the read settings
        /// into; on output, the merged or newly read application settings.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestReadFromXmlFile(
            string fileName,                     /* in */
            ref NameValueCollection appSettings, /* in, out */
            ref Result error                     /* out */
            )
        {
            NameValueCollection localAppSettings;
            Result localError = null;

            localAppSettings = ConfigurationOps.ReadFromXmlFile(
                fileName, ref localError);

            if (localAppSettings == null)
            {
                error = localError;
                return ReturnCode.Error;
            }

            if (appSettings != null)
            {
                ConfigurationOps.MergeAppSettings(
                    ref appSettings, localAppSettings, true, false);
            }
            else
            {
                appSettings = localAppSettings;
            }

            return ReturnCode.Ok;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method writes the specified application settings to an XML
        /// configuration file.
        /// </summary>
        /// <param name="fileName">
        /// The name of the XML file to write.
        /// </param>
        /// <param name="appSettings">
        /// The application settings to write.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestWriteSettingsToXmlFile(
            string fileName,                 /* in */
            NameValueCollection appSettings, /* in */
            ref Result error                 /* out */
            )
        {
            return ConfigurationOps.WriteToXmlFile(
                fileName, appSettings, ref error);
        }

