        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method returns the Harpy certificate (containing the signature)
        /// associated with the built-in test XML script data.
        /// </summary>
        /// <returns>
        /// The certificate document, as a string.
        /// </returns>
        public static string TestGetScriptStreamXmlDataCertificate() /* TestScriptStreamXml.xml.harpy */
        {
            return String.Format(
                "<?xml version=\"1.0\" encoding=\"utf-8\"?>{0}" +
                "<Certificate xmlns=\"{1}\"{0}" +
                "             xmlns:xsi=\"http://www.w3.org/2001/XMLSchema-instance\"{0}" +
                "             xmlns:xsd=\"http://www.w3.org/2001/XMLSchema\">{0}" +
                "  <Protocol>None</Protocol>{0}" +
                "  <Vendor>Mistachkin Systems</Vendor>{0}" +
                "  <Id>7ef95cfe-37ee-41dd-a30c-bc342683d96d</Id>{0}" +
                "  <HashAlgorithm>SHA512</HashAlgorithm>{0}" +
                "  <EntityType>Script</EntityType>{0}" +
                "  <TimeStamp>2020-11-20T02:16:24.9461003Z</TimeStamp>{0}" +
                "  <Duration>-1.00:00:00</Duration>{0}" +
                "  <Key>0x{2}</Key>{0}" +
                "  <Signature>{0}{3}</Signature>{0}" +
                "</Certificate>{0}", Characters.DosNewLine, Xml.SignatureNamespaceUri,
                PublicKeyToken.Class0, TestGetScriptStreamXmlDataSignature()
            );
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method reads the built-in test XML script stream, optionally
        /// evaluates it, and collects the results.  It is used to exercise the
        /// XML script reading and signature checking support.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use.
        /// </param>
        /// <param name="fault">
        /// Non-zero to purposely corrupt the XML script so that it fails
        /// signature checking.
        /// </param>
        /// <param name="original">
        /// Non-zero to use the original (unprocessed) script text; otherwise,
        /// the processed text is used.
        /// </param>
        /// <param name="write">
        /// Non-zero to write the intermediate results to the interactive host.
        /// </param>
        /// <param name="result">
        /// Upon success, receives the collected results; upon failure, receives
        /// information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestScriptStreamXml(
            Interpreter interpreter,
            bool fault,
            bool original,
            bool write,
            ref Result result
            )
        {
            string value = TestGetScriptStreamXmlData();

            if (fault && (value != null))
            {
                //
                // HACK: Purposely corrupt the returned XML script, so
                //       it will fail signature checking.
                //
                value = value.Replace(
                    "11b0bd2a-bc99-4639-9727-dc38efacaca1",
                    Guid.Empty.ToString());
            }

            ReturnCode code;
            ResultList results = null;
            Result localResult; /* REUSED */
            string extra = null;

            using (StringReader stringReader = new StringReader(value))
            {
                EngineFlags engineFlags = EngineFlags.ForceSoftEof;
                string originalText = null;
                string text = null;
                bool canRetry = false; /* NOT USED */

                localResult = null;

                code = Engine.ReadScriptStream(
                    interpreter, null, stringReader, 0, Count.Invalid,
                    ref engineFlags, ref originalText, ref text,
                    ref canRetry, ref localResult);

                if (code == ReturnCode.Ok)
                    localResult = original ? originalText : text;

                if (localResult != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(localResult);
                }

                extra = stringReader.ReadToEnd();

                if (extra != null)
                {
                    if (results == null)
                        results = new ResultList();

                    results.Add(extra);
                }
            }

            IInteractiveHost interactiveHost = write ?
                interpreter.GetInteractiveHost() : null;

            if (!write || (interactiveHost != null))
            {
                if (write)
                {
                    interactiveHost.WriteResultLine(code, localResult);
                    interactiveHost.WriteLine();

                    interactiveHost.WriteResultLine(code, extra);
                    interactiveHost.WriteLine();
                }

                if (code == ReturnCode.Ok)
                {
                    string text = localResult;

                    localResult = null;

                    code = Engine.EvaluateScript(
                        interpreter, text, ref localResult);

                    if (localResult != null)
                    {
                        if (results == null)
                            results = new ResultList();

                        results.Add(localResult);
                    }
                }

                if (write)
                    interactiveHost.WriteResultLine(code, localResult);
            }

            result = results;
            return code;
        }
#endif

