        //
        // HACK: This will *NOT* build using Mono/XBuild.  Additionally,
        //       this method will not execute correctly on Mono due to a
        //       missing constructor for TcpServerChannel and incomplete
        //       support for .NET Remoting in general.
        //
#if !MONO && !MONO_BUILD && NETWORK && REMOTING
        /// <summary>
        /// This method determines whether the previously registered .NET
        /// Remoting server channel is available.
        /// </summary>
        /// <returns>
        /// True if the channel is available; otherwise, false.
        /// </returns>
        public static bool TestRemotingHaveChannel()
        {
            TcpServerChannel channel;
            Result error;

            if (TestRemotingTryGetChannel(true, out channel, out error))
                return true;

            return false;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method attempts to obtain the previously registered .NET
        /// Remoting server channel.
        /// </summary>
        /// <param name="trace">
        /// Non-zero to emit diagnostic tracing when an error is encountered.
        /// </param>
        /// <param name="channel">
        /// Upon success, receives the registered server channel; otherwise,
        /// receives null.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// True if the channel was successfully obtained; otherwise, false.
        /// </returns>
        public static bool TestRemotingTryGetChannel(
            bool trace,
            out TcpServerChannel channel,
            out Result error
            )
        {
            channel = null;
            error = null;

            try
            {
                channel = ChannelServices.GetChannel(
                    RemotingChannelName) as TcpServerChannel;

                return (channel != null);
            }
            catch (Exception e)
            {
                if (trace)
                {
                    TraceOps.DebugTrace(
                        e, typeof(RemoteObject).Name,
                        TracePriority.RemotingError);
                }

                error = e;
            }

            return false;
        }

        ///////////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This method sets up a .NET Remoting server channel and registers a
        /// well-known service type for use in testing.
        /// </summary>
        /// <param name="interpreter">
        /// The interpreter context to use, if any.
        /// </param>
        /// <param name="port">
        /// The TCP port on which the server channel should listen.
        /// </param>
        /// <param name="uri">
        /// The object URI under which the well-known service type should be
        /// registered.
        /// </param>
        /// <param name="mode">
        /// The activation mode for the registered well-known service type.
        /// </param>
        /// <param name="trace">
        /// Non-zero to emit diagnostic tracing when an error is encountered.
        /// </param>
        /// <param name="error">
        /// Upon failure, receives information about the error.
        /// </param>
        /// <returns>
        /// <see cref="ReturnCode.Ok" /> on success; otherwise, an error code.
        /// </returns>
        public static ReturnCode TestRemoting(
            Interpreter interpreter,
            int port,
            string uri,
            WellKnownObjectMode mode,
            bool trace,
            ref Result error
            )
        {
            try
            {
                IDictionary sinkProperties = new Hashtable();

                //
                // NOTE: Allow all types to be used.
                //
                sinkProperties.Add("typeFilterLevel", "Full");

                BinaryServerFormatterSinkProvider sinkProvider =
                    new BinaryServerFormatterSinkProvider(
                        sinkProperties, null);

                IDictionary channelProperties = new Hashtable();

                channelProperties.Add("name", RemotingChannelName);
                channelProperties.Add("port", port);

                //
                // NOTE: Default value of "true" causes client to
                //       fail on Windows XP after the first test.
                //
                // BUGBUG: This may not actually work on Windows XP.
                //
                // channelProperties.Add("exclusiveAddressUse", false);

                //
                // NOTE: Value of "true" causes client hang when
                //       no config is used to setup the channel.
                //
                channelProperties.Add("secure", false);

                TcpServerChannel channel = new TcpServerChannel(
                    channelProperties, sinkProvider, new RemoteAuthorizer());

                ChannelServices.RegisterChannel(channel, false);

                RemotingConfiguration.RegisterWellKnownServiceType(
                    typeof(RemoteObject), uri, mode);

                return ReturnCode.Ok;
            }
            catch (Exception e)
            {
                if (trace)
                {
                    TraceOps.DebugTrace(
                        e, typeof(RemoteObject).Name,
                        TracePriority.RemotingError);
                }

                error = e;
            }

            return ReturnCode.Error;
        }
#endif

